import ExpressionService from './ExpressionService';
import {IndexRobotResult} from 'jibo-common-types';
import {PromiseUtils as Async} from 'jibo-cai-utils';
import parentLog from './log';

const log = parentLog.createChild('IndexRobot');

export default class IndexRobot {

    private resumeMotionControlTimeoutMillis:number = 15000;

    public async index():Promise<IndexRobotResult> {
        const result:IndexRobotResult = await Async.promisify<IndexRobotResult>(cb => this._index(cb), false);
        return result;
    }

    private _index(callback:(result:IndexRobotResult) => void) {
        if(process.env.RUNMODE !== 'ON_ROBOT') {
            return callback(IndexRobotResult.SUCCEEDED);
        }
        const bodyOutput = ExpressionService.instance.bodyOutput;
        // pause motion output
        log.debug("Robot will index now, pausing body output!");
        bodyOutput.setPaused(true);

        // get motion interface and current DOFs
        const motionInterface = bodyOutput.getMotionInterface();
        const dofs = motionInterface.getMotionDOFNames();

        // save off current index counter
        const prevDofs = [];
        for (let i=0; i<dofs.length; i++) {
            let dofState = motionInterface.getState(dofs[i]);
            if (dofState) {
                prevDofs.push(dofState.getIndexCount());
            }
        }

        let counter = 100;

        // run the loop every 100ms; timeout after some time?
        const interval = setInterval(() => {
            counter--;
            if (counter < 0) {
                clearInterval(interval);
                this._resumeMotionControl(IndexRobotResult.TIMEOUT, callback);
                return;
            }

            // check if we're done now
            if (!motionInterface.isConnected()) {
                //log.debug("Waiting for connection to body service...");
                return;
            }

            // check to see if all the DOFs are already indexed
            let allIndexed = true;
            for (let i = 0; i < dofs.length; i++)
            {
                const dofState = motionInterface.getState(dofs[i]);
                if (!dofState.isIndexed() || (prevDofs[i] === dofState.getIndexCount()))
                {
                    allIndexed = false;
                    break;
                }
            }
            if (allIndexed) {
                clearInterval(interval);
                this._resumeMotionControl(IndexRobotResult.SUCCEEDED, callback);
                return;
            }
            else if (motionInterface.hasLockout() || motionInterface.hasFault()) {
                clearInterval(interval);
                this._resumeMotionControl(IndexRobotResult.FAULT, callback);
                return;
            }

            // set a command for each DOF
            for (let i = 0; i < dofs.length; i++) {
                const dofState = motionInterface.getState(dofs[i]);
                if (dofState.isIndexed() && (prevDofs[i] !== dofState.getIndexCount())) {
                    // indexed, hold still
                    // setCommand(dofName, commandMode, commandValue, velocityLimit, accelerationLimit, currentLimit)
                    motionInterface.setCommand(dofs[i], 4, [0], null, 1, null);
                }
                else {
                    // not indexed, spin counter-clockwise
                    // setCommand(dofName, commandMode, commandValue, velocityLimit, accelerationLimit, currentLimit)
                    motionInterface.setCommand(dofs[i], 4, [-1], null, 1, null);
                }
            }

            // send the motion command to the body service
            motionInterface.sendCommand();
        }, 100);
    }

    private _resumeMotionControl(indexingResult:IndexRobotResult, callback:(result:IndexRobotResult) => void) {
        const resumeMotionControlTimeoutHandle = setTimeout(() => {
            if (indexingResult === IndexRobotResult.SUCCEEDED) {
                // if it takes too long to resume motion control following success, resolve with: TIMEOUT
                log.warn("Indexing succeeded, but resuming motion control timed out, returning TIMEOUT.");
                callback(IndexRobotResult.TIMEOUT);
            }
            else if (indexingResult === IndexRobotResult.TIMEOUT) {
                // if it takes too long to resume motion control following timeout, resolve with: TIMEOUT
                log.warn("Indexing timed out, and resuming motion control timed out as well, returning TIMEOUT.");
                callback(IndexRobotResult.TIMEOUT);
            }
            else { // FAULT
                // if it takes too long to resume motion control following a fault, resolve with: FAULT
                log.warn("Indexing encountered a fault, and resuming motion control timed out, returning FAULT.");
                callback(IndexRobotResult.FAULT);
            }
        }, this.resumeMotionControlTimeoutMillis);

        ExpressionService.instance.bodyOutput.setPaused(false, () => {
            // successfully resumed motion control, resolve with indexing result
            clearTimeout(resumeMotionControlTimeoutHandle);
            callback(indexingResult);  // if we've already timed out from above, this will have no effect
        });
    }

}
