    /** Unload a given kb slice from memory and remove it from disk.
     * Also removes any sub-kbs inside this slice. For example, if you
     * remove '/jibo', that would also remove '/jibo/loop', '/jibo/settings'
     * and all other kb slices under '/jibo'.
     */
    removeSlice(req:JiboServerRequest, res:JiboServerResponse) {
        let kbName = querystring.unescape(req.params.kbname);
        if (kbName === '/jibo/loop' && this.loopManager) {
            this.loopManager.shutdown( (err) => {
                log.iferr(err);
                if (err) {
                    throw err;
                }
                this.loopManager = null;
                this.removeSlice(req, res);
            });
        } else {
            // release the model and any submodels
            Object.keys(this.kbdbs).forEach( (name) => {
                if ((kbName === name) || (name.startsWith(kbName+'/'))) {
                    delete this.kbdbs[kbName];
                    kb.databaseManager.release(kbName);
                }
            });

            let directory = KnowledgeDatabase.getKbDirectory(kbName);

            // just a sanity check to prevent '/' or '.' or 'C:\'
            // minimum path is either /opt/jibo/Knowledge or [~]/.jibo/kb
            directory = path.normalize(directory);
            if (directory.length < 8) {
                throw new Error('not comfortable with kb slice directory name '+directory);
            } else {
                log.info('removing kb slice', directory);
                rimraf(directory, {disableGlob: true}, (err) => {
                    this.finish(res, err);
                });
            }
        }
    }


    /** Unload all kb slices from memory, stop the Loop Manager, and
     * delete the ENTIRE KNOWLEDGEBASE!
     */
    removeKbEverything(req:JiboServerRequest, res:JiboServerResponse) {
        this.loopManager.shutdown( (err) => {
            log.iferr(err);
            if (err) {
                throw err;
            }
            this.loopManager = null;

            // release all the models
            this.kbdbs = null;

            // get the root directory of the entire kb
            let rootDirectory = KnowledgeDatabase.getRootDirectory();

            // just a sanity check to prevent '/' or '.' or 'C:\'
            // minimum path is either /opt/jibo/Knowledge or [~]/.jibo/kb
            rootDirectory = path.normalize(rootDirectory);
            if (rootDirectory.length < 8) {
                throw new Error('not comfortable with kb root directory name '+rootDirectory);
            } else {
                log.warn('removing the entire kb at', rootDirectory);
                rimraf(rootDirectory, {disableGlob: true}, (err) => {
                    if (err) {
                        throw err;
                    }
                    // put back the kb root directory stub
                    fs.mkdir(rootDirectory, (err) => {
                        this.finish(res, err);
                    });
                });
            }
        });
    }


