    /**
     * Overrides onBackupRequest() method in HTTPService. Backs up all knowledge
     * base files into tar archives, which goes into the appropriate backup
     * folder.
     *
     * @method KBService#onBackupRequest
     * @param req {JiboServerRequest} request to service
     * @param res {JiboServerResponse} response to send from service.
     * @protected
     */
    protected onBackupRequest(req:JiboServerRequest, res:JiboServerResponse) {
        let params = req.body;
        let backupDirectory = params.directory;

        let finishFunc = (code) => {
            this.sendJson(res, {}, code);
        };

        // Make sure directory exists
        try {
            fsextra.ensureDirSync(backupDirectory);
        } catch(err) {
            log.error('error creating backup directory', err);
            finishFunc(500);
            return;
        }

        let backupFile:string = path.join(backupDirectory, 'kb-backup.tar');

        // get the root directory of the entire kb
        let kbDirectory = KnowledgeDatabase.getRootDirectory();
        if (params.dataDirectory) {
            // If an alternate data directory is specified, use that
            kbDirectory = params.dataDirectory;
        }

        // just a sanity check to prevent '/' or '.' or 'C:\'
        // minimum path is either /opt/jibo/Knowledge or [~]/.jibo/kb
        kbDirectory = path.normalize(kbDirectory);

        // Get rid of the backup file, so we can replace it
        rimraf(backupFile, {disableGlob: true}, (err) => {
            if (err) {
                log.warn('Error removing backup file ', err);
                finishFunc(500);
            }

            // Now, create a file stream to write backup tar with
            // When file stream is finished, backup is complete
            let fsStream:fs.WriteStream = fs.createWriteStream(backupFile);
            fsStream.on('error', (error) => {
                log.error('Error backing up Knowledge Base service', error);
                finishFunc(500);
            });
            fsStream.on('finish', (error) => {
                if (error) {
                    log.error('Error backing up Knowledge Base service', error);
                    finishFunc(500);
                } else {
                    finishFunc(204);
                }
            });

            // Write data to TAR and pipe it to file stream
            tarFs.pack(kbDirectory)
                .pipe(fsStream);

        });

        return;
    }


    /**
     * Overrides onRestoreRequest() method in HTTPService. Restores all knowledge
     * base files from tar archive into KB's data folder
     *
     * @method KBService#onRestoreRequest
     * @param req {JiboServerRequest} request to service
     * @param res {JiboServerResponse} response to send from service.
     * @protected
     */
    protected onRestoreRequest(req:JiboServerRequest, res:JiboServerResponse) {

        // Before we do anything else, we should close all the slices that are
        // open in memory. If they are requested again, they will be reloaded
        // from disk (if still there).
        //
        // Note that any HTTP requests of type REGULAR_REQUEST will be blocked
        // by the semaphore mechanism while the closing is happening. The
        // semaphore will be released by the call in finishFunc()
        Object.keys(this.kbdbs).forEach( (name) => {
            delete this.kbdbs[name];
            kb.databaseManager.release(name);
        });

        let params = req.body;
        let backupDirectory = params.directory;

        // get the root directory of the entire kb
        let kbDirectory = KnowledgeDatabase.getRootDirectory();
        if (params.dataDirectory) {
            // If an alternate data directory is specified, use that
            kbDirectory = params.dataDirectory;
        }

        let finishFunc = (code) => {
            // put back the kb root directory stub
            fs.mkdir(kbDirectory, (err) => {
                this.sendJson(res, {}, code);
            });
        };

        // Make sure directory exists
        try {
            fsextra.ensureDirSync(backupDirectory);
        } catch(err) {
            log.error('error creating backup directory', err);
            finishFunc(500);
            return;
        }

        let backupFile:string = path.join(backupDirectory, 'kb-backup.tar');

        // just a sanity check to prevent '/' or '.' or 'C:\'
        // minimum path is either /opt/jibo/Knowledge or [~]/.jibo/kb
        kbDirectory = path.normalize(kbDirectory);

        // Here, we should stop the Knowledge Base from running -- ask John F

        // Get rid of everything currently in KB data folder
        rimraf(kbDirectory, {disableGlob: true}, (err) => {
            if (err) {
                log.error('Error removing KB data folder ', err);
                finishFunc(500);
            }

            // Read in tar file with file stream, piping it to unzipping/untarring
            // code
            let fsStream:fs.ReadStream = fs.createReadStream(backupFile);
            fsStream.pipe(tarFs.extract(kbDirectory))
                .on('finish', (err) => {
                    if (err) {
                        log.error('Problem extracting tar stream', err);
                        finishFunc(500);
                    } else {
                        finishFunc(204);
                    }
                });

            fsStream.on('error', (err) => {
                if (err) {
                    log.error('problem with POST stream', err);
                    finishFunc(500);
                }
            });
        });

        return;
    }


