import {
    HTTPWSService,
    JiboServerRequest,
    JiboServerResponse,
    ServiceOptions,
} from 'jibo-service-framework';
import parentLog from '../log';
import PerformanceServiceSim from '../../sim-services/performance/PerformanceServiceSim';
import Router = require('router');
import {SSMService} from '../../SSMService';
import WebSocket = require('ws');


export interface IPerformanceService {
    log(time: number, type: string, description?: string): void;
    init(callback: (error?: Error) => void): void;
}


class PerformanceService extends HTTPWSService implements IPerformanceService, SSMService {

    private static _instance: PerformanceService;

    private _log = parentLog.createChild('PerformanceService');
    //milliseconds since Epoch to add to all process.hrtime() calls.
    private _baseTime: number;

    static get instance(): IPerformanceService {
        if(PerformanceService._instance) {
            return PerformanceService._instance;
        }
        return PerformanceServiceSim.instance;
    }

    constructor(options: ServiceOptions, rootDir: string) {
        super('performance', options, rootDir);
        if (PerformanceService._instance) {
            throw new Error('Cannot instantiate PerformanceService more than once');
        }
        PerformanceService._instance = this;
        //calculate our base time for handling hrtimes
        this._baseTime = Date.now();
        const time = process.hrtime();
        this._baseTime -= time[0] * 1000 + time[1] / 1000000;
        this._log.info('Instantiated');
    }

    init(callback: (error?: Error) => void): void {
        super.init((error: Error) => {
            if(error) {
                return callback(error);
            }
            this._log.info('Initialized');
            callback();
        });
    }

    routes(url: Router): void {
        super.routes(url);
        url.post('/log', (req: JiboServerRequest, res: JiboServerResponse) => {
            let data = '';
            req.on('data', chunk => data += chunk);
            req.on('end', () => {
                let message: {time: number, type: string, description: string};
                try {
                    message = JSON.parse(data);
                }
                catch (e) {
                    this._log.warn('Performance service cannot parse ', data);
                    return this.sendJson(res, {
                        status: 'error',
                        message: 'could not parse json',
                        json: data,
                    }, 400);
                }
                this.log(message.time, message.type, message.description);
                this.sendJson(res, {status: 'OK'});
            });
        });
    }

    log(time: number, type: string, description?: string): void {
        this.connections.forEach((client: WebSocket) => {
            this.sendWsJson(client, {
                time,
                type,
                description: description || '',
            });
        });
    }

    /*
     * Get the high precision time in milliseconds since the epoch
     */
    now(): number {
        const time = process.hrtime();
        //add the high resolution time (in milliseconds) to the base time
        return this._baseTime + time[0] * 1000 + time[1] / 1000000;
    }

    protected onMessage(message: any, client: WebSocket): void {
        this._log.log('onMessage', message);
        // Listen for time pings and respond with a local time stamp
        // This is used for basic time synchronization between the devices
        // of client's of the performance service and it's own device
        // This should be used by clients to implement Christian's clock synchronization Algorithm:
        // https://en.m.wikipedia.org/wiki/Cristian%27s_algorithm
        if(message.type === 'time-ping'){
            // We respond using the log call so that you see time sync pings in the performance service
            // and connected clients get the time-pong response
            this.sendWsJson(client, {
                time: this.now(),
                type: 'time-pong',
                // Send it's description back as it should include a unique ping id
                description: message.description
            });
        }
    }
}

export default PerformanceService;
