import SegmentAnalytics = require('@jibo/analytics-node');
import {systemManager} from 'jibo-service-clients';
import RunMode from '../RunMode';
import findRoot = require('find-root');
import path = require('path');

import parentLog from '../../log';
const log = parentLog.createChild('Analytics');

/**
 * @description Provides an interface to the analytics API (segment).
 * @interface Analytics.AnalyticsAccount
 * @private
 */


export interface AnalyticsContext {
    ssm_version:string;
    be_version:string;
    platform_version:string;
    release_version:string;
}

export default class Analytics {

    private static _instance:Analytics;

    private _context:AnalyticsContext;
    private _robotName:string;

    /**
     * The current segment API instance being used.
     * @name Analytics._segmentAnalytics
     * @type {AnalyticsNode.Analytics}
     * @private
     */
    private _segmentAnalytics:SegmentAnalytics;

    public static createInstance():Analytics {
        return new Analytics();
    }

    public static get instance():Analytics {
        return Analytics._instance;
    }

    /**
     * Create new Analytics
     * @class Analytics
     * @private
     */
    constructor() {

        //overwritten entirely in _initContext
        this._context = {
            ssm_version: "",
            be_version: "",
            platform_version: "",
            release_version: ""
        };

        this._robotName = null;
        Analytics._instance = this;
    }


    /**
     * Initialize Analytics instance
     * @class Analytics
     * @private
     */
    public init(callback:() => void):void {
        systemManager.getMode((err, data) => {

            // default to 'Jibo Robot Skills - dev' key
            let segmentKey = "Iw6EWJHfEfZqZWUstvcmPFBl752zVqTg";

            if (data && data !== 'int-developer') {
                // if not in int-developer mode, then use 'Jibo Robot Skills - prod' key
                segmentKey = "eKTraeQ8jzBijVo5oIP6fvERY616XexN";
            }

            if (RunMode.runMode === RunMode.RunMode.SIMULATOR) {
                this._segmentAnalytics = <any>{
                    LOG_TO_CONSOLE: false,
                    track: function(data) {
                        if (this.LOG_TO_CONSOLE) {
                            console.log('SegmentAnalytics Debugging: tracked ', data);
                        }
                    },
                    identify: function(data) {
                        if (this.LOG_TO_CONSOLE) {
                            console.log('SegmentAnalytics Debugging: identified ', data);
                        }
                    }
                };
            } else {
                this._segmentAnalytics = new SegmentAnalytics(segmentKey);
                //prevent analytics module from actually sending data if unit testing
                if ('sinon' in global) {
                    (this._segmentAnalytics as any).queue.push = function(){/*noop*/};
                }
            }

            log.info("Adding segment instance", segmentKey);

            // fetch robot name
            systemManager.getIdentity((err, data) => {
                if (data) {
                    this._robotName = data.name;
                }

                this._initContext(callback);
            });
        });
    }


    /**
     * Log an analytics event.
     * @method Analytics.logEvent
     * @param {String} event The event id.
     * @param {Object} properties The properties sent to segment.
     * @private
     */
    public logEvent(event:string, properties:any={}): void {
        if (this._segmentAnalytics) {
            //attach robot name to everything
            properties.robot_name = this._robotName;

            //attach hour in 24 hour time to all skill events - can't get it in local time otherwise
            properties.event_hour = new Date().getHours();

            this._segmentAnalytics.track({
                userId: "SSM", // don't really care about userId here...
                event: event,
                properties: properties,
                context: this._context,
                timestamp: new Date()
            });
        } else {
            throw new Error('Analytics: logEvent requires a valid segmentAnalytics instance.');
        }
    }

    private _initContext(done:() => void){
        try{
            this._context.release_version = require('/opt/jibo/Jibo/Skills/jibo-tbd/package.json').version;
        }
        catch(err){
            log.warn('no full-stack release number found', err);
            this._context.release_version = '8.67.5309';
        }

        try{
            this._context.be_version = require('/opt/jibo/Jibo/Skills/@be/be/package.json').version;
        }
        catch(err){
            log.warn('no Be version number found', err);
            this._context.be_version = '8.67.5309';
        }

        const root:string = findRoot(__dirname);
        const packageInfo:any = require(path.join(root, 'package.json'));
        this._context.ssm_version = packageInfo.version;

        systemManager.getVersion( (err, platformVersion) => {
            if(err || !platformVersion){
                log.warn('no platform version number found', err);
                this._context.platform_version = '8.67.5309';
            }
            else{
                this._context.platform_version = platformVersion;
            }
            done();
        });
    }
}
