import Router = require('router');
const uuid = require('uuid');
import {JiboServerRequest, JiboServerResponse, ServiceOptions, HTTPWSService, WebSocket} from 'jibo-service-framework';
import http = require("http");
//import {EventEmitter} from 'events';
import {SSMService} from '../../SSMService';

import parentLog from '../log';
const log = parentLog.createChild('Notifications');

class NotificationsService extends HTTPWSService implements SSMService {

    private static _instance:NotificationsService;
    private _queue:any;

    public static get instance():NotificationsService {
        return NotificationsService._instance;
    }

    constructor(options:ServiceOptions, rootDir:string) {
        super('notifications', options, rootDir);
        if (NotificationsService._instance) {
            throw new Error('Cannot instantiate NotificationsService more than once');
        }
        NotificationsService._instance = this;

        //console.log('Notifications --> initialized');
        this._queue = [];

        log.info("Instantiated");
    }

    public init(callback: (err?:Error)=>void) {
        super.init((err:Error) => {
            log.info('Initialized');
            callback(err);
        });
    }

    protected onMessage(command:any, client:WebSocket):void {
        return;
    }

    public onConnection(client:WebSocket, request:http.IncomingMessage):void {
        super.onConnection(client, request);
        /*if(client.url === '/tts_tokens') {
            //this.tokensSocket = client;
        }
        else if(client.url === '/tts_phones') {
            //this.phonesSocket = client;
        }*/
    }

    public routes(url:Router) {
        super.routes(url);

        url.post('/notifications', (req:JiboServerRequest, res:JiboServerResponse) => {
            this.createNotification(req, res);
        });

        url.put('/notifications/:id', (req:JiboServerRequest, res:JiboServerResponse) => {
            this.updateNotification(req, res);
        });

        url.get('/notifications', (req:JiboServerRequest, res:JiboServerResponse) => {
            this.getAllNotifications(req, res);
        });

        url.delete('/notifications/:id', (req:JiboServerRequest, res:JiboServerResponse) => {
            this.deleteNotification(req, res);
        });

        url.delete('/notifications', (req:JiboServerRequest, res:JiboServerResponse) => {
            this.deleteAllNotifications(req, res);
        });

        /*
        url.get('/tts_stop', (req:JiboServerRequest, res:JiboServerResponse) => {
            this.onStop(req, res);
        });*/
    }

    private createNotification(req:JiboServerRequest, res:JiboServerResponse) {
        // Add the notification to our queue
            // Add unique identifier first
        req.body.id = uuid.v4();
        this._queue.push(req.body);

        this.sendJson( res, req.body, 200 );

        // Emit event locally and over listening websockets
        this.notifyEmit('notification-created', req.body);
    }

    private updateNotification(req:JiboServerRequest, res:JiboServerResponse) {
        // Find the notification
        const notification = this._queue.find( notification => notification.id === req.params.id );

        if( notification === undefined ) {
            this.sendJson( res, {}, 404 );
            return;
        }

        // Update any of the provided fields
        notification.type = req.body.type ? req.body.type : notification.type;
        notification.title = req.body.title ? req.body.title : notification.title;
        notification.description = req.body.description ? req.body.description : notification.description;

        this.sendJson( res, notification, 200 );

        // Emit event locally and over listening websockets
        this.notifyEmit('notification-updated', notification);
    }

    private getAllNotifications(req:JiboServerRequest, res:JiboServerResponse) {
        let body:any = this._queue;
        this.sendJson(res, body, 200);
    }

    private deleteNotification(req:JiboServerRequest, res:JiboServerResponse) {
        // Find the notification
        const notificationIndex = this._queue.findIndex( notification => notification.id === req.params.id );

        if( notificationIndex === -1 ) {
            this.sendJson( res, {}, 404 );
            return;
        }

        this._queue.splice(notificationIndex, 1);

        this.sendJson( res, {}, 200 );

        // Emit event locally and over listening websockets
        this.notifyEmit('notification-deleted', req.params.id);
    }

    private deleteAllNotifications(req:JiboServerRequest, res:JiboServerResponse) {

        this._queue = [];

        this.sendJson( res, {}, 200 );

        // Emit event locally and over listening websockets
        this.notifyEmit('notifications-all-deleted', undefined);
    }

    /*
     * Emits events locally and over websockets
     */
    private notifyEmit(eventName, event){

        // Notify EventEmitter listeners
        this.emit(eventName, event);

        // Notify listening websockets
        this.connections.forEach( (websocket) => {
            this.sendWsJson( websocket, {
                eventName,
                event
            });
        });
    }
}


export default NotificationsService;
