//import { JiboServerRequest, JiboServerResponse} from 'jibo-service-framework';
import JiboError from './JiboError';
import ErrorServiceUtil from './ErrorServiceUtil';

//a class which acts as a mechanism to report errors to the error service when mocking errors
class DebugErrorReporter {
    private _errorCodeMap: { [key:string]:JiboError; } = {};
    // a mapping of support error codes to the same string support code
    private _activeErrorCodes: { [key:string]:JiboError; } = {};
    private _lastErrorCodes: { [key:string]:JiboError; } = {};

    private _reportPlatformErrorCallback: (message: { codes: Array<string>})=>void = null;
    private _addSSMErrorCallback: (supportErrorId:string)=>boolean = null;
    private _removeSSMErrorCallback: (supportErrorId:string)=>boolean = null;

    constructor(errorCodeMap:{ [key:string]:JiboError; }, addSSMErrorCallback:(supportErrorId:string)=>boolean, removeSSMErrorCallback:(supportErrorId:string)=>boolean, reportPlatformErrorCallback:(message:any)=>void) {
        this._errorCodeMap = errorCodeMap;
        this._addSSMErrorCallback = addSSMErrorCallback;
        this._removeSSMErrorCallback = removeSSMErrorCallback;
        this._reportPlatformErrorCallback = reportPlatformErrorCallback;

        setInterval(this._platformErrorTick.bind(this), 1000);
    }

    // parse the mocked errors and send a response to the client providing which errors to mock
    public mockErrorRequest(mockErrorsJson:{ codes:Array<string> }): void {
        this._activeErrorCodes = {};
        for(let i = 0; i < mockErrorsJson.codes.length; ++i) {
            let supportErrorCodeId = mockErrorsJson.codes[i];

            if(this._errorCodeMap.hasOwnProperty(supportErrorCodeId)) {
                this._activeErrorCodes[supportErrorCodeId] = this._errorCodeMap[supportErrorCodeId];
            }
        }

        this._updateSSMErrors();
        this._lastErrorCodes = this._activeErrorCodes;
    }

    private _updateSSMErrors(): void {
        Object.keys(this._activeErrorCodes).forEach((errorCodeId)=>{
            if(this._errorCodeMap.hasOwnProperty(errorCodeId) && !this._errorCodeMap[errorCodeId].platformCode) {
                this._addSSMErrorCallback(errorCodeId);
            }
        });

        let removedErrors = ErrorServiceUtil.getNonOccurringElements(this._lastErrorCodes, this._activeErrorCodes);
        for(let i = 0; i < removedErrors.length; ++i) {
            // only remove the error if there is no platform code (which means it's an SSM only error)
            if(!removedErrors[i].platformCode) {
                this._removeSSMErrorCallback(removedErrors[i].id);
            }
        }
    }

    // executed on a timer (on the robot this is broadcast at 10Hz) to deliver a list of error codes to whoever is listening to the /error/codes endpoint
    private _platformErrorTick(): void {
        let activePlatformErrors = [];
        Object.keys(this._activeErrorCodes).forEach((errorCodeId)=>{
            if(this._errorCodeMap.hasOwnProperty(errorCodeId) && this._errorCodeMap[errorCodeId].platformCode) {
                // add the platform code to the list to report to the error service
                // the error service will translate the platform code to the support error code
                activePlatformErrors.push(this._errorCodeMap[errorCodeId].platformCode);
            }
        });
        let platformErrorCodesMessage = {
            codes: activePlatformErrors
        };
        this._reportPlatformErrorCallback(platformErrorCodesMessage);
    }
}

export default DebugErrorReporter;
