    /*
        Returns an array of saved network entries
     */
    public async getSavedNetworks():Promise<SavedNetworkEntry[]> {
        const data = await this.networkManager.getNetworks();
        //data is a raw string of the saved profiles in wpa_supplicant
        let networkArray:Array<SavedNetworkEntry> = [];
        const networks = data.split('\n');
        for (let i = 0; i < networks.length; ++i) {
            let data:Array<string> = networks[i].split('\t');

            const _network = data[1];
            if (_network) {
                const _index = data[0];
                const _current = (data[3] === '[CURRENT]');
                const _enabled = (!data[3].includes('[DISABLED]'));
                networkArray.push({
                    index: _index,
                    ssid: _network,
                    current: _current,
                    enabled: _enabled
                });
            }
        }
        return networkArray;
    }

    /*
     networkID = string - key in wpa_cli list_networks
     networkData = NetworkData(can be null; only required on new networks)
     callback = required

     Checks conf file to see if static or not.
     if not, it will reset the config file to be dhcp - via systemManager
     if it is, it will adjsut the config file to be static - via systemManager
     Called from updateActiveNetworksDictionary
     */
    public async selectNetwork(networkID:string, networkData:NetworkData): Promise<string> {
        //Only occurs when managed through wifimanager
        if (!networkData) {
            const networkData = await this.getSavedNetworks();
            const foundNetwork = networkData.find((item) => item.index === networkID);
            if (!foundNetwork) {
                return Promise.reject(new Error('Network not found'));
            }
            //read from networks.conf to see if the network being searched for is static or dhcp
            const data = await this._getInterfaceSettings(foundNetwork.ssid);
            //if not null, it's static
            if (data) {
                try {
                    await this._configureNetworkSettings(NetworkType.STATIC, data);
                } catch (error) {
                    // try to remove entry from saved settings
                    await this._removeInterfaceSetting(networkID);
                    return Promise.reject(error);
                }
                await this.adjustStatusPolling(networkID);
                return "success";
            } else {
                // is DHCP
                await this._configureNetworkSettings(NetworkType.DHCP, null);
                await this.adjustStatusPolling(networkID);
                return 'success';
            }
        } else {
            //only occurs when user adds a network
            //systemManager will look up the conf in the configureNetworkSettings call
            try {
                await this._saveInterfaceSettings(networkData);
            } catch (e) {
                log.error("Save Interface Settings Failure");
                return Promise.reject(e);
            }
            if (networkData.networkType === NetworkType.DHCP) {
                try {
                    await this._configureNetworkSettings(NetworkType.DHCP, null);
                } catch (error) {
                    log.error("DHCP Failure Settings!");
                    return Promise.reject(error);
                }
                await this.adjustStatusPolling(networkID);
                return 'success';
            } else if (networkData.networkType === NetworkType.STATIC) {
                log.info("Setting network as a static network!");
                const data = await this.getSavedNetworks();
                //check to make sure network exists in the saved networks
                const foundNetwork = data.some((item) => item.ssid === networkData.ssid);

                if (foundNetwork) {
                    try {
                        await this._configureNetworkSettings(NetworkType.STATIC, networkData.staticSettings);
                    } catch (error) {
                            // try to remove entry from saved settings
                        await this._removeInterfaceSetting(networkData.ssid);
                        return Promise.reject(error);
                    }
                    //selects the network
                    await this.adjustStatusPolling(networkID);
                    return 'success';
                } else {
                    return Promise.reject(new Error("Could not select network " + networkData.ssid));
                }
            }
        }
    }

    /*
     Confirms that jibo is actually connected
     Checks that Jibo is connected to AP
     then checks that Jibo has an IP Address
     then checks that Jibo can talk to the internet
     then checks that Jibo can talk to the jibo server

     Emits specific error code associated to any of these failing.
     */
    public async verifyConnection(): Promise<ErrorCode> {
        //cancel a scheduled verification if we had one, and nullify the the variable if this is
        //the triggered verification
        if (this.nextVerify) {
            clearTimeout(this.nextVerify);
            this.nextVerify = null;
        }
        let data:string;
        try {
            data = await this.status();
        } catch (err) {
            return new ErrorCode(666, "BAD THINGS ARE HAPPENING: " + err);
        }
        //Check if Jibo detects connection to AP
        if (data.indexOf('COMPLETED') === -1) {
            return new ErrorCode(1, "Did not connect to the Access Point");
        }
        //Check if it has an IP Address
        if (data.indexOf('ip_address=') === -1) {
            return new ErrorCode(2, "Could Not Obtain IP Address");
        }

        if (TEST_JIBO_SERVER) {
            try {
                await this._checkJiboServers();
            } catch (err) {
                log.debug("VerifyConnection #3 (Jibo Servers): " + err);
                this._wifiService.emit("internet-disconnected");
                ErrorService.instance.addError(NO_INTERNET_ERROR);
                //if we don't have a verification scheduled, then we should keep checking until
                //we are connected
                if (!this.nextVerify) {
                    this.nextVerify = setTimeout(() => this.verifyConnection(), FAILED_VERIFY_INTERVAL);
                }
                return new ErrorCode(4, "Cannot Ping Jibo Servers");
            }
            log.debug("VerifyConnection #3 (Jibo Servers): OK");
            this._wifiService.emit("internet-connected");
            ErrorService.instance.removeError(NO_INTERNET_ERROR);
            //cancel a scheduled verification if one got scheduled during async checks, because we
            //are now connected
            if (this.nextVerify) {
                clearTimeout(this.nextVerify);
                this.nextVerify = null;
            }
            return null;
        } else {
            return null;
        }
    }

    public setNetwork(networkId, options:SetNetworkOptions): Promise<any> {
        let cmd:string;
        if(options.ssid) {
            cmd = networkId + " ssid " + '\"' + options.ssid + '\"' ;
        } else if(options.hidden) {
            cmd = networkId + " scan_ssid 1";
        } else if(options.psk) {
            //psk will be null on Open
            cmd = networkId + " psk " + '\"' + options.psk + '\"' ;
        } else if(options.security) {
            switch(options.security) {
                case('WPA-PSK'):
                    cmd = networkId + " key_mgmt WPA-PSK";
                    break;
                case('WPA2-PSK'):
                    cmd = networkId + " key_mgmt WPA-PSK";
                    break;
                case('OPEN'):
                    cmd = networkId + " key_mgmt NONE";
                    break;
            }
        }
        return promisify((cb) => SystemManagerClient.instance.setNetwork(cmd, cb));
    }

