    /*
     Increase status listen frequency until:
     connected or failure to connect.
     Allows very precise state listening to determine exact failure
     point(ie: Exchange, DHCP, etc)
     */
    private async adjustStatusPolling(networkID): Promise<void> {
        this.connecting = true;
        this.statusListen(STATUS_INTERVAL);
        await promisify((cb) => SystemManagerClient.instance.selectNetwork(networkID, cb));
        await promisify((cb) => SystemManagerClient.instance.enableNetwork(networkID, cb));
    }

