import {Node, Model} from 'jibo-kb';
import {JSC} from '../../clients/jibo-server';
import SyncManager from './SyncManager';
import kb from '../../clients/KBClient';

import parentLog from './log';
const log = parentLog.createChild('Holiday');


const SYNC_PERIODIC_SECONDS = 6 * 3600;  // 6 hours

const KB_SLICE_NAME = '/jibo/holidays';
const KB_LOOP_NAME = '/jibo/loop';


export type ErrCallback = (err?:Error)=>void;
export type IdCallback = (err, id?:string)=>void;
export type ChangedCallback = (err?:Error, changed?:boolean)=>void;


/**
 * @description Synchronize the holiday list in the cloud with a copy in the
 * KB. Syncing is one-way. Polls the cloud server in the background
 * every 6 hours and adds/removes/updates the holiday kb slice as
 * needed. Forces the local copy to match the cloud, all local changes
 * will (eventually) be overwritten by what is in the cloud.
 *
 * @class HolidayManager
 * @param {string} httpUrl Url to the KB service
 * @param {boolean} [enableCloud=true] Enables the cloud checking. If false, no cloud calls will be done.
 */
class HolidayManager extends SyncManager {
    private model:Model;
    private rootNode:Node;
    private personClient:any;

    constructor(httpUrl:string, enableCloud:boolean=true) {
        super(httpUrl, 'holidays', SYNC_PERIODIC_SECONDS * 1000, enableCloud);
    }


    public init(callback:ErrCallback) {
        super.init( (err) => {
            log.iferr(err, 'super.init()');
            if (err) {
                callback(err);
            } else {
                let baseModel = kb.createModel(KB_SLICE_NAME, this.httpUrl);

                // start cache. we load up the cache and never release it
                // which is not usually a good thing to do, but since we own
                // all changes to ths slice (it must exactly match the cloud)
                // we can get away with it here.
                this.model = baseModel.begin();
                this._preloadHolidayModel( () => {
                    log.info('local cached holidays loaded, count: ', this._holidaysSize());
                    if (SyncManager.canSkipFullSync) {
                        // let things proceed and do the first sync in the background
                        log.info('doing first full sync in the background');
                        callback();
                        callback = ()=>{return;};
                    }
                    if (this.enableCloud) {
                        log.info('starting holiday cloud syncing...');
                        this._syncWithCloud((/*err*/) => {
                            log.info('local holidays count after syncing: ', this._holidaysSize());
                            callback();
                            this._syncOnNotification('HolidayUpdated');
                            this._startSyncTimer();
                        });
                    } else {
                        callback();
                    }
                });
            }
        });
    }


    protected _syncWithCloud(callback:ChangedCallback) {
        this._setupClients();
        this._startTimer();
        this._lookupLoopId( (err, loopId) => {
            if (!err) {
                this.personClient.listHolidays({loopId: loopId}, (err, data) => {
                    this._endTimer('JSC server call Person#listHolidays()');
                    log.iferr(err, 'JSC server call Person#listHolidays()');
                    if (!err) {
                        this._applyHolidayChanges(data, (err, changed) => {
                            log.iferr(err, '_applyHolidayChanges');
                            callback(err, changed);
                        });
                    } else {
                        callback(err);
                    }
                });
            } else {
                callback(err);
            }
        });
    }


    protected _updated(callback:ErrCallback) {
        // Emit a HolidayUpdated event; KBService will broadcast this over
        // a WebSocket so that KB Models (like MediaModel) can listen for it
        log.info('holiday list was updated; emitting a HolidayUpdated event');
        this.emit('HolidayUpdated');
        process.nextTick(callback);
    }


    private _preloadHolidayModel(callback:ErrCallback) {
        this.model.loadRoot( (err, rootNode) => {
            log.iferr(err, 'model.loadRoot');
            this.rootNode = rootNode;
            this.model.loadLayers(rootNode, 'holiday', (err) => {
                log.iferr(err, 'loadLayers holiday');
                callback();
            });
        });
    }


    private _fetchHolidays():Node[] {
        return this.model.fetch(this.rootNode.getEdges('holiday'));
    }


    private _holidaysSize():number {
        let holidays = this._fetchHolidays();
        return holidays.length;
    }


    private _setupClients() {
        if (!this.personClient) {
            this.personClient = new JSC.Person();
        }
    }


    private _lookupLoopId(callback:IdCallback) {
        let loop = new Model(KB_LOOP_NAME, this.httpUrl);
        loop.loadRoot( (err, root) => {
            log.iferr(err, 'loop.loadRoot');
            if (!err) {
                callback(null, root.data.id);
            } else {
                callback(err);
            }
        });
    }


    private _applyHolidayChanges(cloudHolidays:any[], callback:ChangedCallback) {
        let model = this.model;
        let rootNode = this.rootNode;
        let newHolidays = [];
        let sameHolidays = [];
        let removeHolidays = [];
        let eventIds = {};

        let localHolidays = this._fetchHolidays();


        // make sameHolidays list (common holidays) and newHolidays list (new holidays)
        cloudHolidays.forEach( (cloudHoliday) => {
            if (!cloudHoliday.eventId) {
                log.warn('holiday record missing eventId, skipping it', cloudHoliday);
                return;
            }
            if (eventIds[cloudHoliday.eventId]) {
                log.warn('holiday record has a duplicate eventId, skipping it', cloudHoliday);
                return;
            }
            eventIds[cloudHoliday.eventId] = true;
            let found = false;
            for (let i=0; i<localHolidays.length; i++) {
                let localHoliday = localHolidays[i];
                if (cloudHoliday.eventId === localHoliday._id) {
                    sameHolidays.push(cloudHoliday);
                    found = true;
                    break;
                }
            }
            if (!found) {
                newHolidays.push(cloudHoliday);
            }
        });

        // make removeHolidays list (holidays no longer listed)
        localHolidays.forEach( (localHoliday) => {
            let found = false;
            for (let i=0; i<cloudHolidays.length; i++) {
                let cloudHoliday = cloudHolidays[i];
                if (cloudHoliday.eventId === localHoliday._id) {
                    found = true;
                    break;
                }
            }
            if (!found) {
                removeHolidays.push(localHoliday);
            }
        });

        // now we begin the work of comparing things looking for changes
        let holidaysChanged = false;

        // first try to load any new holidays in case they are actually reactivated old holidays
        let newHolidayIds = newHolidays.map( (holiday) => {return holiday.eventId;} );
        model.load(newHolidayIds, (err) => {  // get them into the cache
            log.iferr(err, 'model.load');

            // process new holidays
            newHolidays.forEach( (newHoliday) => {
                let oldNode = this.model.fetch(newHoliday.eventId, true);
                let newNode;
                if (oldNode) {
                    newNode = oldNode;
                } else {
                    //newNode = this.model.createNode(Node);  // can't because of cloud imposed id
                    newNode = new Node('holiday');
                    newNode._id = newHoliday.eventId;
                    this.model.pool[0].adoptNodeAsOurOwn(newNode);
                    this.model.cache.add(newNode);
                }

                this._applyCloudHolidayToLocalHoliday(newHoliday, newNode);
                rootNode.addEdges(newNode, 'holiday');
                holidaysChanged = true;
            });

            // process common holidays
            sameHolidays.forEach( (sameHoliday) => {
                let sameNode = this.model.fetch(sameHoliday.eventId);
                let changed = this._applyCloudHolidayToLocalHoliday(sameHoliday, sameNode);
                if (changed) {
                    holidaysChanged = true;
                }
            });

            // process holidays removed from cloud
            removeHolidays.forEach( (removeLocalHoliday) => {
                rootNode.removeEdges(removeLocalHoliday, 'holiday');
                // we remove them from the list of holiday edges, but
                // we don't delete the removed node itself on purpose
                // it might come back someday, and other kb nodes might
                // be pointing to it
                holidaysChanged = true;
            });

            if (holidaysChanged) {
                log.info('holidays changed. saving...');
                this.model.saveLayers(rootNode, 'holiday', (err) => {
                    log.iferr(err, 'model.saveLayers');
                    log.info('finished saving holidays');
                    log.debug('new holidays', this._fetchHolidays());
                    callback(null, holidaysChanged);
                });
            } else {
                callback();
            }
        });
    }


    // update a holiday node
    private _applyCloudHolidayToLocalHoliday(cloudHoliday:Object, localHolidayNode:Node):boolean {
        let changed = this._syncObjectStrict(cloudHoliday, localHolidayNode.data);
        return changed;
    }
}


export default HolidayManager;
