import Router = require('router');
import http = require("http");
import {EventEmitter} from 'events';
import {JiboServerRequest, JiboServerResponse, ServiceOptions, HTTPWSService, WebSocket} from 'jibo-service-framework';
import { TTSPromptParser, TTSPlaybackMode } from './TTSPromptParser';
import {Lexer, Tagger} from 'pos';
import parentLog from '../log';
import {SSMService} from '../../SSMService';
import PerformanceService from '../../services/performance/PerformanceService';
const log = parentLog.createChild('TTS');

//standin for window.performance.now()
const performance = {
    now: () => {
        const time = process.hrtime();
        return time[0] * 1000 + time[1] / 1000000;
    }
};

const Regexs = {
	ids: /(?:^|\s)[a-z0-9-]{8,45}(?:$|\s)/ig, // ID, CRC, UUID's
	number: /[0-9]*\.[0-9]+|[0-9]+(?=\W)/ig,
	space: /\s+/ig,
	unblank: /\S/,
	email: /[-!#$%&'*+\/0-9=?A-Z^_a-z{|}~](?:\.?[-!#$%&'*+\/0-9=?A-Z^_a-z`{|}~])*@[a-zA-Z0-9](?:-?\.?[a-zA-Z0-9])*(?:\.[a-zA-Z](?:-?[a-zA-Z0-9])*)+/gi,
	urls: /(?:https?:\/\/)(?:[\da-z\.-]+)\.(?:[a-z\.]{2,6})(?:[\/\w\.\-\?#]*)*\/?/ig,
	punctuation: /[\.]{3}|[\/\.\,\?\!\"\:\;\$\(\)\#]/ig
};

interface Token {
    name:string;
    start:number;
}

class TokenWorker extends EventEmitter {
    private _stopped:boolean = false;
    private _startTime:number;

    constructor(private tokens:Array<Token>, private ttsService:TTSService, private realTime: boolean, private res:JiboServerResponse) {
        super();
        this.update = this.update.bind(this);
        this.ttsService.emit('sending-tokens');
    }

    public stop() {
        this._stopped = true;
        this.ttsService.sendJson(this.res, {
            Status: 'OK',
            Message: 'Speaking TTS'
        }, 204);
    }

    public start() {
        this._startTime = performance.now();
        this.update();
    }

    private update() {
        if(!this._stopped) {
            let delta:number = performance.now() - this._startTime;

            let speed: number = this.realTime ? 1000 : 1;

            if(delta > this.tokens[0].start * speed) {
                let token:Token = this.tokens.shift();
                this.ttsService.emit('token', token.name);
            }
            if(this.tokens.length === 0){
                this.ttsService.sendWsJson(this.ttsService.tokensSocket, this.ttsService.returnType('', 0, 'STOP'));

                // Generate same performance service message that the native implementation does
                PerformanceService.instance.log(Date.now(), 'TTS', 'SPEAK_REQUEST_COMPLETE' );
                this.stop();
                this.emit('stop');
                this.removeAllListeners();
            }
            else {
                setImmediate(this.update);
            }
        }
    }
}

 /**
  * @class TTSService
  */
class TTSService extends HTTPWSService implements SSMService {

    public static TTSPromptParser:typeof TTSPromptParser = TTSPromptParser;
    private static _instance:TTSService;


    public tokensSocket:WebSocket;

    private mode = TTSPlaybackMode.Incremental;
    private phonesSocket:WebSocket;
    private currentWorker:TokenWorker;
    private lexer:Lexer;
    private tagger:Tagger;

    public static get instance():TTSService {
        return TTSService._instance;
    }

    constructor(options:ServiceOptions, rootDir:string) {
        super('tts', options, rootDir);
        if (TTSService._instance) {
            throw new Error('Cannot instantiate TTSService more than once');
        }
        TTSService._instance = this;
        this.lexer = new Lexer();
        this.lexer.regexs = [Regexs.urls, Regexs.ids, Regexs.number, Regexs.space, Regexs.email, Regexs.punctuation];
        this.tagger = new Tagger();
        log.info("Instantiated");
    }

    public setMode(mode: TTSPlaybackMode|string) {
        let _mode = TTSPlaybackMode[mode] || TTSPlaybackMode.Incremental;
        if (!_mode) {
            _mode = TTSPlaybackMode.Incremental;
            console.warn(`Invalid TTS playback mode '${mode}', using '${_mode}'`);
        }
        this.mode = _mode;
    }

    public toggleDevMode():void {
        console.warn(`Deprecated, please use 'setMode'`);
        if (this.mode !== TTSPlaybackMode.Incremental) {
            this.mode  = TTSPlaybackMode.Incremental;
        }
        else {
            this.mode  = TTSPlaybackMode.Instant;
        }
    }

    public init(callback: (err?:Error)=>void) {
        super.init((err:Error) => {
            log.info('Initialized');
            callback(err);
        });
    }

    protected onMessage(command:any, client:WebSocket):void {
        return;
    }

    public onConnection(client:WebSocket, request:http.IncomingMessage):void {
        super.onConnection(client, request);
        if(client.url === '/tts_tokens') {
            this.tokensSocket = client;
        }
        else if(client.url === '/tts_phones') {
            this.phonesSocket = client;
        }
    }

    public routes(url:Router) {
        super.routes(url);

        url.post('/tts_token_times', (req:JiboServerRequest, res:JiboServerResponse) => {
            this.onTokenTimes(req, res);
        });

        url.post('/tts_speak', (req:JiboServerRequest, res:JiboServerResponse) => {
            this.onSpeak(req, res);
        });

        url.get('/tts_stop', (req:JiboServerRequest, res:JiboServerResponse) => {
            this.onStop(req, res);
        });

        url.post('/tts_lex', (req: JiboServerRequest, res: JiboServerResponse) => {
            this.onGetPOSTokens(req, res);
        });

        url.post('/tts_pos_tagging', (req: JiboServerRequest, res: JiboServerResponse) => {
            this.onGetPOSTags(req, res);
        });
    }


    public returnType(word, ts, status){
        return {
            token: word,
            timestamp: ts,
            status: status,
            moreinfo: []
        };
    }

    private onTokenTimes(req:JiboServerRequest, res:JiboServerResponse) {
        req.on('data', (chunk:string) => {
            let data:any = JSON.parse(chunk);

            // Sync up the playback mode of TTSPromptParser with the devMode before using it
            const parser = new TTSPromptParser(this.mode);
            const promptTokens = parser.createPromptAndTokens(data.prompt);

            let body:any = {
                tokentimes: {
                    tokens: promptTokens[1]
                }
            };
            this.sendJson(res, body, 200);
        });
    }

    private onSpeak(req:JiboServerRequest, res:JiboServerResponse) {
        req.on('data', (chunk:string) => {
            let data:any = JSON.parse(chunk);
            this.stopCurrentWorker();

            // Sync up the playback mode of TTSPromptParser with the devMode before using it
            const parser = new TTSPromptParser(this.mode);
            const promptTokens = parser.createPromptAndTokens(data.prompt);
            const realTime = (this.mode === TTSPlaybackMode.Incremental);

            if( promptTokens[1].length) {
                this.currentWorker = new TokenWorker(promptTokens[1], this, realTime, res);
                this.currentWorker.on('stop', () => {
                    this.currentWorker.removeAllListeners();
                    this.currentWorker = null;
                });
                this.currentWorker.start();
            }
            else {
                let body:any = {
                    statusText: "Error: No prompt provided to TTS speak"
                };
                this.sendJson(res, body, 500);
            }
        });
    }

    private stopCurrentWorker():void {
        if(this.currentWorker) {
            this.currentWorker.stop();
            this.currentWorker.removeAllListeners();
            this.currentWorker = null;
        }
        this.emit('stop');
    }

    private onStop(req:JiboServerRequest, res:JiboServerResponse) {
        let body:any = {
            Status: 'OK',
            Message: 'Stopping TTS'
        };
        this.sendJson(res, body, 200);
        this.stopCurrentWorker();
        this.sendWsJson(this.tokensSocket, this.returnType('', 0, 'STOP'));
    }

    private onGetPOSTokens(req:JiboServerRequest, res:JiboServerResponse) {
        req.on('data', (chunk:string) => {
            res.setHeader('Content-Type', 'json');
            try {
                let data:any = JSON.parse(chunk);
                if (data.text || data.text === "") { // accepts empty string ""
                    let tokens = this.lexer.lex(data.text);
                    let result = {
                        tokens: tokens
                    };
                    res.statusCode = 200;
                    res.end(JSON.stringify(result));
                } else {
                    res.statusCode = 400;
                    res.end(JSON.stringify({
                        error: "Missing input property `text`"
                    }));
                }
            } catch (err) {
                res.statusCode = 400;
                res.end(JSON.stringify({
                    error: "Failed to parse the input"
                }));
            }
        });
    }

    private onGetPOSTags(req:JiboServerRequest, res:JiboServerResponse) {
        req.on('data', (chunk: string) => {
            res.setHeader('Content-Type', 'json');
            try {
                let data:any = JSON.parse(chunk);
                if (data.tokens) {
                    let tokentags = this.tagger.tag(data.tokens);
                    let result = {
                        tokentags: tokentags
                    };
                    res.statusCode = 200;
                    res.end(JSON.stringify(result));
                } else {
                    res.statusCode = 400;
                    res.end(JSON.stringify({
                        error: "Missing input property `tokens`"
                    }));
                }
            } catch (err) {
                res.statusCode = 400;
                res.end(JSON.stringify({
                    error: "Failed to parse the input"
                }));
            }

        });
    }
}

export default TTSService;
