import WebSocket = require('ws');
import path = require('path');
import fs = require('fs');
import findRoot = require('find-root');
import {SkillRecord} from "jibo-client-framework";
import GlobalManagerService from "../../services/global-manager/GlobalManagerService";
import {
    ServiceOptions, HTTPWSService,
    JiboServerRequest, JiboServerResponse
} from 'jibo-service-framework';
import Router = require('router');
import {SSMService} from '../../SSMService';

interface SkillsServiceOptions extends ServiceOptions {
    skillsBaseDir?:string;
}

class SkillsServiceSim extends HTTPWSService implements SSMService {

    private static _instance:SkillsServiceSim;
    public currentSkill:SkillRecord;

    public static get instance():SkillsServiceSim {
        return SkillsServiceSim._instance;
    }

    constructor(public options:SkillsServiceOptions, rootDir:string) {
        super('skills-service', options, rootDir);
        if (SkillsServiceSim._instance) {
            throw new Error('Cannot instantiate SkillsServiceSim more than once');
        }
        this.currentSkill = {
            name: "@be/be",
            path: "/"
        };
        SkillsServiceSim._instance = this;
    }

    public init(callback:(error?:Error) => void) {
        super.init(callback);
    }

    /**
     * Called when a client sends a message over WebSocket
     * @param command
     * @param client
     */
    protected onMessage(command:any, client:WebSocket):void {
        // Allow listeners to see the message
        this.emit('command', command, client);

        if (command.command === 'initDone') {
            //get the launch rule for the global listener
            if(this.options.skillsBaseDir) {
                let skillPath:string = this.options.skillsBaseDir;
                let packagePath:string = path.join(this.options.skillsBaseDir, 'package.json');
                if(fs.statSync(skillPath).isDirectory() && fs.existsSync(packagePath)) {
                    let packageJson:any = require(packagePath);
                    this.currentSkill.name = packageJson.name;
                    this.currentSkill.path = skillPath;
                    this.sendWsJson(client, {
                        command: 'show'
                    });
                }
            }
            else {
                this.sendWsJson(client, {
                    command: 'show'
                });
            }
        }
        else if (command.command === 'finished') {
            if(this.currentSkill.name === '@be/be') {
                let relaunchResults:any = {};
                relaunchResults.nlu = {
                    entities: {
                        skill: '@be/idle'
                    }
                };
                relaunchResults.status = "GOT-PARSE";
                GlobalManagerService.instance.handleSkillLaunch(relaunchResults);
            }
        }
    }

    public routes(url:Router):void {
        super.routes(url);

        url.get('/version', (req:JiboServerRequest, res:JiboServerResponse) => {
            const root:string = findRoot(__dirname);
            const packageInfo:any = require(path.join(root, 'package.json'));
            this.sendJson(res, {version: packageInfo.version});
        });
    }
}

export default SkillsServiceSim;
