import async = require('async');

import {Node, Model} from 'jibo-kb';
import kb from '../../clients/KBClient';
import {mediaManager} from 'jibo-service-clients';
import {JSC} from '../../clients/jibo-server';
import SyncManager from './SyncManager';

import parentLog from './log';
const log = parentLog.createChild('MediaList');

//standin for window.performance.now()
const performance = {
    now: () => {
        const time = process.hrtime();
        return time[0] * 1000 + time[1] / 1000000;
    }
};


const SYNC_PERIODIC_SECONDS = 60 * 60 * 2;  // every 2 hours just in case we missed a notification
const UPLOAD_PERIODIC_SECONDS = 60 * 5;  // check for pending uploads every 5 minutes
const NOTIFICATIONS_FLUSH_PERIOD = 10000;  // 10 seconds

const KB_SLICE_NAME = '/jibo/media';
const KB_LOOP_NAME = '/jibo/loop';


interface ThumbnailsResponse {
    [name:string]:string;  // uuid for each thumbnail
}

interface StorePhotoResponse {
    id:string;
    thumbnails:ThumbnailsResponse;
}

export type ErrCallback = (err?:Error)=>void;
export type StorePhotoCallback = (err:Error, response?:StorePhotoResponse) => void;
export type ChangedCallback = (err?:Error, changed?:boolean)=>void;

export interface Thumbnails {
    [name: string]: [number, number];
}


/** Synchronize the media list in the cloud with a copy in the
 * KB. Syncing is one-way. Polls the cloud server in the background
 * once a minute adds/removes/updates the media kb slice as
 * needed. Forces the local copy to match the cloud, all local changes
 * will (eventually) be overwritten by what is in the cloud.
 *
 * @class MediaListManager
 * @param {string} httpUrl Url to the KB service
 * @param {boolean} [enableCloud=true] Enables the cloud checking. If
 * false, no cloud calls will be done.
 */
class MediaListManager extends SyncManager {
    private model:Model;
    private rootNode:Node;
    private mediaClient:any;
    private mediaUrl:string;
    private proxyUrl:string;
    private loopId:string;
    private ownerId:string;
    private issuedReferenceMediaTypeWarning;
    private mediaManagerClient: typeof mediaManager;
    private uploadHappening:boolean;
    private uploadAgain:boolean;
    private uploadTimer:NodeJS.Timer;

    constructor(httpUrl:string, enableCloud:boolean=true) {
        super(httpUrl, 'media list', SYNC_PERIODIC_SECONDS * 1000, enableCloud);
    }


    public init(callback:ErrCallback) {
        super.init( (err) => {
            log.iferr(err, 'super.init()');
            if (err) {
                callback(err);
            } else {
                let baseModel = kb.createModel(KB_SLICE_NAME, this.httpUrl);

                // start cache. we load up the cache and never release it
                // which is not usually a good thing to do, but since we own
                // all changes to ths slice (it must exactly match the cloud)
                // we can get away with it here.
                this.model = baseModel.begin();
                this._preloadMediaModel( (err) => {
                    if (err) {
                        log.error('Error preloading media model', err);
                    } else {
                        log.info('local cached media list loaded, count: ', this._mediaSize());
                    }
                    if (SyncManager.canSkipFullSync) {
                        // let things proceed and do the first sync in the background
                        log.info('doing first full sync in the background');
                        callback();
                        callback = ()=>{return;};
                    }
                    if (this.enableCloud) {
                        log.info('starting media list cloud syncing...');
                        this._syncWithCloud((/*err*/) => {
                            log.info('local media list count after syncing: ', this._mediaSize());
                            this._createClients( (err) => {
                                if (err) {
                                    log.error('error initing service clients', err);
                                } else {
                                    log.info('service clients created successfully');
                                }
                                this._syncOnNotification('MediaCreated');
                                this._syncOnNotification('MediaDeleted');
                                callback();
                                this._startSyncTimer();
                                this._startUploadTimer();
                            });
                        });
                    } else {
                        callback();
                    }
                });
            }
        });
    }


    /** Update the KB to reflect the cloud changes
     * from a photo stored with `jibo.media.storePhoto()`.
     * Currently just causes a full sync of the media list.
     * @method MediaListManager#storePhoto
     * @param {Function} [callback] Called when done.
     */
    public storePhoto(data, callback:StorePhotoCallback) {
        this._setupLoopAndOwnerId( (err) => {
            if (err) {
                callback(err);
            } else {
                let contentIDs:string[] = [];
                contentIDs.push(data.id);
                Object.keys(data.thumbnails).forEach( (name:string) => {
                    contentIDs.push(data.thumbnails[name]);
                });
                // the mediaType is a hack here since we are
                // giving multiple contentIDs and only one media
                // type, but it's only used to establish the file
                // extension, since they are all photos it's ok.
                let mediaType = mediaManager.MediaType.image;
                this.mediaManagerClient.adopt(contentIDs, mediaType, (err) => {
                    if (err) {
                        callback(err);
                    } else {
                        // first make up some nodes and update the KB locally
                        // as close as we can guess as to how it will
                        // eventually be when synced with the server after the
                        // photos are uploaded

                        let photoNode = this._createNodeWithId(data.id, this.model, 'media');
                        photoNode.data = {
                            path: data.id,
                            type: mediaType,
                            loopId: this.loopId,
                            accountId: this.ownerId,
                            isDeleted: false,
                            isEncrypted: true,
                            created: photoNode.created  // best guess
                        };
                        this.rootNode.addEdges(photoNode, 'media');
                        this.rootNode.addEdges(photoNode, 'pending-upload');

                        let thumbNodes = [];
                        Object.keys(data.thumbnails).forEach( (name:string) => {
                            let id = data.thumbnails[name];
                            let thumbNode = this._createNodeWithId(id, this.model, 'media');
                            thumbNode.data = {
                                path: id,
                                type: name,
                                reference: photoNode._id,
                                loopId: this.loopId,
                                accountId: this.ownerId,
                                isDeleted: false,
                                isEncrypted: true,
                                created: thumbNode.created  // best guess
                            };
                            thumbNodes.push(thumbNode);
                            thumbNode.addEdges(photoNode, 'reference');
                            this.rootNode.addEdges(thumbNode, 'media');
                            this.rootNode.addEdges(thumbNode, 'pending-upload');
                            photoNode.addEdges(thumbNode, name);
                        });

                        let tasks = [];
                        tasks.push( (done) => {
                            photoNode.save(done);
                        });
                        thumbNodes.forEach( (thumbNode) => {
                            tasks.push( (done) => {
                                thumbNode.save(done);
                            });
                        });
                        tasks.push( (done) => {
                            this.rootNode.save(done);
                        });

                        async.series<any, Error>(tasks, (err) => {
                            if (err) {
                                callback(err);
                            } else {
                                // ok, we are done with the local update, so
                                // cut the client side loose here before we do
                                // the lengthy cloud uploading process
                                let response = {
                                    id: data.id,
                                    // url field is our addition
                                    // point at the media-proxy
                                    url: `${this.proxyUrl}/proxy/media/photo/get?id=${data.id}`,
                                    thumbnails: data.thumbnails
                                };
                                callback(null, response);
                                process.nextTick( () => {
                                    this._processPendingCloudActions();
                                });
                            }
                        });
                    }
                });
            }
        });
    }


    /** Update the KB to reflect the cloud changes from deleting a
     * photo.  Currently just causes a full sync of the media list.
     * @method MediaListManager#deletePhoto
     * @param {Function} [callback] Called when done.
     */
    public deletePhoto(id:string, callback:ErrCallback) {
        this._setupLoopAndOwnerId( (err) => {
            if (err) {
                callback(err);
            } else {
                // first remove the nodes and update the KB locally
                // as close as we can guess as to how it will
                // eventually be when synced with the server after the
                // photos are deleted

                let isDeletedNodes = [];
                let photoNode = this.model.fetch(id);
                if (photoNode) {
                    isDeletedNodes.push(photoNode);
                }
                const mediaList = this._fetchMedia();
                // references are also deleted when the original item is deleted
                mediaList.forEach( (media) => {
                    if (media.data.reference && media.data.reference === id) {
                        isDeletedNodes.push(media);
                    }
                });

                this.rootNode.addEdges(isDeletedNodes, 'pending-delete');

                let tasks = [];
                isDeletedNodes.forEach( (isDeletedNode) => {
                    tasks.push( (done) => {
                        isDeletedNode.data.isDeleted = true;
                        log.debug('setting the isDeleted flag for media node', isDeletedNode._id);
                        isDeletedNode.save(done);
                    });
                });
                tasks.push( (done) => {
                    this.rootNode.save(done);
                });

                async.series<any, Error>(tasks, (err) => {
                    if (err) {
                        callback(err);
                    } else {
                        // ok, we are done with the local update, so
                        // cut the client side loose here before we do
                        // the lengthy cloud deleting process
                        callback(null);
                        process.nextTick( () => {
                            this._processPendingCloudActions();
                        });
                    }
                });
            }
        });
    }


    /** Server side version of `jibo.kb.media.downloadThumbnails()`.
     * Download a list of thumbnails to the local image store.
     * Downloads are stored via the media manager service, no local
     * update of the KB is needed.
     * @method MediaListManager#downloadThumbnails
     * @param {string[]} ids Array of thumnails Content IDs to download.
     * @param {string} mediaType Enumerated type of media.
     * @param {Function} [callback] Called when done.
     */
    public downloadThumbnails(ids:string[], mediaType:mediaManager.MediaType, callback:ErrCallback) {
        ids.forEach( (id) => {
            this.mediaManagerClient.download(id, false, mediaType, (err) => {
                log.iferr(err, 'mediaManagerClient.download');
                callback(err);
            });
        });
    }


    /** Server side version of `jibo.kb.media.downloadPhoto()`.
     * Download a photo to the local image store.
     * Downloads are stored via the media manager service, no local
     * update of the KB is needed.
     * @method MediaListManager#downloadPhoto
     * @param {string} id Content ID of photo to download.
     * @param {string} mediaType Enumerated type of media.
     * @param {Function} [callback] Called when done.
     */
    public downloadPhoto(id:string, mediaType:mediaManager.MediaType, callback:ErrCallback) {
        this.mediaManagerClient.download(id, true, mediaType, (err) => {
            log.iferr(err, 'mediaManagerClient.download');
            callback(err);
        });
    }


    protected _syncWithCloud(callback:ChangedCallback) {
        this._setupClients();
        this._startTimer();
        this._setupLoopAndOwnerId( (err) => {
            if (!err) {
                this._getFullMediaList(this.loopId, (err, data) => {
                    this._endTimer('JSC server call Media#list() (all pages)');
                    log.iferr(err, 'JSC server call Media#list() (all pages)');
                    if (!err) {
                        this._applyMediaChanges(data, (err, changed) => {
                            log.iferr(err, '_applyMediaChanges');
                            callback(err, changed);
                        });
                    } else {
                        callback(err);
                    }
                });
            } else {
                callback(err);
            }
        });
    }


    protected _updated(callback:ErrCallback) {
        // Emit a MediaListChanged event; KBService will broadcast this over
        // a WebSocket so that KB Models (like MediaModel) can listen for it
        log.info('media list was updated; emitting a MediaListChanged event');
        this.emit('MediaListChanged');
        process.nextTick(callback);
    }


    private _processPendingCloudActions() {
        if (this.uploadHappening) {
            this.uploadAgain = true;
        } else {
            // upload pending photos to the cloud
            let pendingUploadIds = this.rootNode.getEdges('pending-upload');
            let pendingDeleteIds = this.rootNode.getEdges('pending-delete');
            if (pendingUploadIds.length || pendingDeleteIds.length) {
                this._cancelUploadTimer();
                this.uploadHappening = true;
                this._suspendNotifications( (resumeNotifications) => {
                    let tasks = [];
                    if (pendingUploadIds.length) {
                        tasks.push( (done) => { this._processPendingUploads(pendingUploadIds, done); } );
                    }
                    if (pendingDeleteIds.length) {
                        tasks.push( (done) => { this._processPendingDeletions(pendingDeleteIds, done); } );
                    }


                    // process in series so that the logic for deleting
                    // what might be a pending upload is easier
                    async.series(tasks, () => {
                        // pause for a bit to hopefully drain away any upload related notifications
                        // to save ourself from unnecessary multiple syncs
                        setTimeout( () => {
                            resumeNotifications();

                            this._notDuringSyncing( (done) => {
                                // sync the local media list to get the changes
                                let timer = performance.now();
                                this._syncWithCloud( (err) => {
                                    let elapsed = Math.round(performance.now() - timer);
                                    log.info('_processPendingCloudActions _syncWithCloud ('+this._mediaSize()+' nodes) took '+elapsed+'ms');
                                    log.iferr(err, '_syncWithCloud');
                                    done();  // release the sync pause
                                    this.uploadHappening = false;
                                    this._startUploadTimer();
                                    if (this.uploadAgain) {
                                        this.uploadAgain = false;
                                        process.nextTick( () => {
                                            this._processPendingCloudActions();
                                        });
                                    } else {
                                        this.emit('_cloudDone');  // used in jibo integration tests
                                    }
                                });
                            });
                        }, NOTIFICATIONS_FLUSH_PERIOD);
                    });
                });
            }
        }
    }


    private _processPendingUploads(pendingUploadIds, callback) {
        let tasks = [];
        pendingUploadIds.forEach( (pendingUploadId) => {
            tasks.push( (done) => {
                let pendingUpload = this.model.fetch(pendingUploadId);
                if (pendingUpload) {
                    let immediate = true;
                    let keeplocal = true;
                    let mediaType = pendingUpload.data.type;
                    let reference = pendingUpload.data.reference || null;
                    this.mediaManagerClient.upload(pendingUpload._id, immediate, keeplocal, mediaType, reference, (err) => {
                        if (err) {
                            log.warn('could not upload photo, will try again', pendingUpload._id, err);
                            done();
                        } else {
                            log.info('uploaded', pendingUpload._id);
                            this.rootNode.removeEdges(pendingUpload, 'pending-upload');
                            this.rootNode.save((err) => {
                                log.iferr(err, 'media root node save');
                                done();
                            });
                        }
                    });
                } else {
                    log.error('pending upload node not found, giving up', pendingUploadId);
                    this.rootNode.removeEdges(pendingUploadId, 'pending-upload');
                    this.rootNode.save((err) => {
                        log.iferr(err, 'media root node save');
                        done();
                    });
                }
            });
        });

        // we can't do this in parallel because the
        // reference image must already have been uploaded
        // for the thumbnail upload to succeed.
        log.info('uploading', tasks.length, 'photo'+(tasks.length===1?'':'s'));
        let timer = performance.now();
        async.series(tasks, () => {
            let elapsed = Math.round(performance.now() - timer);
            log.info('photo uploads took '+elapsed+'ms');
            this.emit('_storePhoto');  // used in jibo integration tests
            callback();
        });
    }


    private _processPendingDeletions(pendingDeleteIds, callback) {
        // note: media nodes are not (currently) removed, the are just marked as `isDeleted=true`.
        let tasks = [];
        let pendingUploadIds = this.rootNode.getEdges('pending-upload');  // see what didn't get uploaded yet
        pendingDeleteIds.forEach( (pendingDeleteId) => {
            if (pendingUploadIds.includes(pendingDeleteId)) {
                // wait until it's been uploaded before we delete it
                log.warn('skipping pending delete until it has been uploaded', pendingDeleteId);
                return;
            }

            tasks.push( (done) => {
                let pendingDelete = this.model.fetch(pendingDeleteId);
                if (!pendingDelete) {
                    log.error('pending delete node not found, giving up', pendingDeleteId);
                    this.rootNode.removeEdges(pendingDeleteId, 'pending-delete');
                    this.rootNode.save((err) => {
                        log.iferr(err, 'media root node save');
                        return done();
                    });
                }

                // delete the photo in the cloud
                let immediate = true;
                let deleteLocal = false;
                let deleteRemote = true;
                let mediaType = mediaManager.MediaType.image;
                this.mediaManagerClient.delete(pendingDeleteId, immediate, deleteLocal, deleteRemote, mediaType, (err) => {
                    if (err) {
                        log.error('could not delete photo photo', pendingDeleteId, err);
                        return done();
                    }
                    this.rootNode.removeEdges(pendingDelete, 'pending-delete');
                    this.rootNode.save((err) => {
                        log.iferr(err, 'media root node save');
                        done();
                    });
                });
            });
        });

        log.info('deleting', tasks.length, 'photo'+(tasks.length===1?'':'s'));
        let timer = performance.now();
        async.series(tasks, () => {
            let elapsed = Math.round(performance.now() - timer);
            log.info('photo deletions took '+elapsed+'ms');
            this.emit('_deletePhoto');  // used in jibo integration tests
            callback();
        });
    }


    private _startUploadTimer() {
        this.uploadTimer = global.setTimeout( () => { this._processPendingCloudActions(); }, UPLOAD_PERIODIC_SECONDS * 1000);
    }


    private _cancelUploadTimer() {
        if (this.uploadTimer) {
            clearTimeout(this.uploadTimer);
            this.uploadTimer = undefined;
        }
    }


    private _getFullMediaList(loopId:string, callback:(err, list?)=>void) {
        // Get all pages of the media list in one list.
        //
        // Media.list() only returns 50 records at a time.
        // Except thumbnails will always be returned along with main image,
        // and only main images count towards the 50 images limit.
        // To go beyond that you need to use the before/after params:
        //   1) Request list with no params
        //   2) Get the `created` timestamp of the oldest (first) image,
        //      let's call it `currentBefore`.
        //   3) Request list with `{before: currentBefore}`
        //   4) Repeat steps 2 and 3 until you get an empty list.

        let list = [];

        let nextPage = (before?) => {
            this.mediaClient.list({loopIds: [loopId], before: before}, (err, data) => {
                if (err) {
                    callback(err);
                } else {
                    if (data.length) {
                        list = data.concat(list);
                        nextPage(data[0].created);
                    } else {
                        callback(null, list);
                    }
                }
            });
        };

        nextPage();
    }


    private _preloadMediaModel(callback:ErrCallback) {
        this.model.loadRoot( (err, rootNode) => {
            this.rootNode = rootNode;
            if (err) {
                log.error('model.loadRoot', err);
                return callback(err);
            } else {
                // Don't even try to load layers if the loadRoot failed
                // Trying to do this lead to callback never being called
                // which froze the SSM initialization
                this.model.loadLayers(rootNode, 'media', (err) => {
                    log.iferr(err, 'loadLayers media');
                    callback();
                });
            }
        });
    }


    private _fetchMedia():Node[] {
        return this.model.fetch(this.rootNode.getEdges('media'));
    }


    private _mediaSize():number {
        let media = this._fetchMedia();
        return media.length;
    }


    private _setupClients() {
        if (!this.mediaClient) {
            this.mediaClient = new JSC.Media();
        }
    }


    private _setupLoopAndOwnerId(callback:ErrCallback) {
        if (this.loopId) {
            process.nextTick(callback);
        } else {
            let loop = new Model(KB_LOOP_NAME, this.httpUrl);
            loop.loadRoot( (err, root) => {
                log.iferr(err, 'loop.loadRoot');
                if (!err) {
                    this.loopId = root.data.id;
                    this.ownerId = root.getEdges('owner')[0];
                }
                callback(err);
            });
        }
    }


    private _applyMediaChanges(cloudMediaList:any[], callback:ChangedCallback) {
        let model = this.model;
        let rootNode = this.rootNode;
        let newMedia = [];
        let sameMedia = [];
        let removeMedia = [];
        let mediaChanged = false;
        let hangingEdges = false;

        let localMediaList = this._fetchMedia();
        let pendingUploadIds = this.rootNode.getEdges('pending-upload');
        let pendingDeleteIds = this.rootNode.getEdges('pending-delete');

        // make sameMedia list (common media) and newMedia list (new media)
        cloudMediaList.forEach( (cloudMedia) => {
            let found = false;
            for (let i=0; i<localMediaList.length; i++) {
                let localMedia = localMediaList[i];
                if (!localMedia) {
                    // edge was pointing to nothing so set the media
                    // changed flag so edges are updated and saved below
                    mediaChanged = true;
                    continue;
                }

                if (cloudMedia.path === localMedia._id) {
                    sameMedia.push(cloudMedia);
                    found = true;
                    break;
                }
            }
            if (!found) {
                newMedia.push(cloudMedia);
            }
        });

        // make removeMedia list (media no longer listed)
        localMediaList.forEach( (localMedia) => {
            if (!localMedia) {
                // edge was pointing to nothing so set the hanging
                // edges flag so edges are updated and saved below
                hangingEdges = true;
                return;
            }

            // "delete" any items pending delete by marking the `isDeleted` flag
            if (pendingDeleteIds.includes(localMedia._id)) {
                // local media item is pending deletion, make sure it is marked as such
                if (!localMedia.data.isDeleted) {
                    localMedia.data.isDeleted = true;
                    mediaChanged = true;
                }
            }

            if (pendingUploadIds.includes(localMedia._id)) {
                // local media item is pending upload, don't remove it
                return;
            }

            let found = false;
            for (let i=0; i<cloudMediaList.length; i++) {
                let cloudMedia = cloudMediaList[i];
                if (cloudMedia.path === localMedia._id) {
                    found = true;
                    break;
                }
            }

            if (!found) {
                removeMedia.push(localMedia);
            }
        });

        if (hangingEdges) {
            log.warn('media list had edges with no nodes, removing hanging edges');
            // set the mediaChanged flag to force the edges to be updated below
            mediaChanged = true;
        }

        // now we begin the work of comparing things looking for changes

        // first try to load any new media in case they are actually reactivated old media
        let newMediaIds = newMedia.map( (media) => {return media.path;} );
        model.load(newMediaIds, (err) => {  // get them into the cache
            log.iferr(err, 'model.load');

            // process new media
            newMedia.forEach( (media) => {
                let oldNode = this.model.fetch(media.path, true);
                let newNode;
                if (oldNode) {
                    newNode = oldNode;
                } else {
                    //newNode = this.model.createNode(Node);  // can't because of cloud imposed id
                    newNode = this._createNodeWithId(media.path, this.model, 'media');
                }

                this._applyCloudMediaToLocalMedia(media, newNode);
                mediaChanged = true;
            });

            // process common media
            sameMedia.forEach( (media) => {
                let sameNode = this.model.fetch(media.path);
                let changed = this._applyCloudMediaToLocalMedia(media, sameNode);
                if (changed) {
                    mediaChanged = true;
                }
            });

            // process media removed from cloud
            removeMedia.forEach( (removeLocalMedia) => {
                mediaChanged = true;
            });

            // update the rootNode 'media' edges
            if (mediaChanged) {
                // remove all existing 'media' edges
                rootNode.removeEdges(rootNode.getEdges('media'), 'media');
                // add the edges back in cloud order
                cloudMediaList.forEach( (cloudMedia) => {
                    rootNode.addEdges(cloudMedia.path, 'media');
                });
                // also account for the pending uploads
                pendingUploadIds.forEach( (pendingUploadId) => {
                    rootNode.addEdges(pendingUploadId, 'media');
                });
            }

            // adjust edges so images point to thumbnails and thumbnails point to images
            let edgesChanged = this._setupThumbnailEdges();
            if (edgesChanged) {
                mediaChanged = true;
            }

            if (mediaChanged) {
                log.info('media list changed. saving...');
                this.model.saveLayers(rootNode, 'media', (err) => {
                    log.iferr(err, 'model.saveLayers');
                    // remove the no longer attached nodes
                    let chain = Promise.resolve();
                    removeMedia.forEach( (node) => {
                        chain.then(node.remove());
                    });
                    chain.then( () => {
                        log.info('finished saving media list');
                        callback(null, mediaChanged);
                    });
                });
            } else {
                callback();
            }
        });
    }


    // update a media node
    private _applyCloudMediaToLocalMedia(cloudMedia:Object, localMediaNode:Node):boolean {
        let changed = this._syncObjectStrict(cloudMedia, localMediaNode.data);
        return changed;
    }


    // adjust edges so images point to thumbnails and thumbnails point to images
    private _setupThumbnailEdges():boolean {
        let changed = false;
        const mediaList = this._fetchMedia();
        // point items with references (thumbnails) back to original
        mediaList.forEach( (media) => {
            if (media.data.reference) {
                let original = this.model.fetch(media.data.reference);
                if (!original) {
                    log.warn('can not find original media for thumbnail, skipping', media._id);
                } else {
                    let oldReferences = media.getEdges('reference');
                    if (!oldReferences.length) {
                        media.addEdges(original, 'reference');
                        changed = true;
                    } else {
                        if (oldReferences.length !== 1 || oldReferences[0] !== original._id) {
                            media.removeEdges(oldReferences, 'reference');
                            media.addEdges(original, 'reference');
                            changed = true;
                        }
                    }
                }
            }
        });

        // point originals to items that reference them (thumbnails)
        mediaList.forEach( (media) => {
            let newEdgesSet = {};  // build up the edges and compare at the end
            mediaList.forEach( (newReference) => {
                if (newReference.data.reference === media._id) {
                    // it points to us, so let's point back to it
                    let mediaType = newReference.data.type;
                    if (!mediaType) {
                        log.warn('thumbnail missing media type, skipping', newReference._id);
                    } else {
                        if (mediaType === 'reference' && !this.issuedReferenceMediaTypeWarning) {
                            // it might be a problem someday. an edge for a media type of 'reference'
                            // might conflict with a backward edge pointing to the original (which
                            // is always named 'reference'). but it also means a media node is both
                            // a thumbnail, and has it's own thumbnail, so could probable ignore this.
                            log.warn('there is at least one media item with media type "reference"', newReference._id);
                            this.issuedReferenceMediaTypeWarning = true;
                        }
                        if (newEdgesSet[mediaType]) {
                            // not a big deal, we still handle it (ordering might be a problem), but odd
                            log.warn('media has multiple thumbnails with same media type', mediaType, media._id, newReference._id);
                        }
                        newEdgesSet[mediaType] = newEdgesSet[mediaType] || [];
                        newEdgesSet[mediaType].push(newReference._id);
                    }
                }
            });

            // update edges on node if needed
            let newEdgeTypes = Object.keys(newEdgesSet);
            if (newEdgeTypes.length) {
                // has thumbnails, sync up the edges
                let oldEdgeTypes = Object.keys(media.edges || {});  // TODO make KB Node method for getting all edge types
                newEdgeTypes.forEach( (newEdgeType) => {
                    if (!oldEdgeTypes.includes(newEdgeType)) {
                        // it's new
                        media.addEdges(newEdgesSet[newEdgeType], newEdgeType);
                        changed = true;
                    } else {
                        // it's on both, compare 'em
                        let oldEdges = media.getEdges(newEdgeType);
                        let newEdges = newEdgesSet[newEdgeType];
                        let needsUpdate = false;
                        if (oldEdges.length !== newEdges.length) {
                            needsUpdate = true;
                        } else {
                            for (let i=0; i<oldEdges.length; i++) {
                                // this testing logic means simple ordering changes
                                // will cause an update, and i'm ok with that
                                if (oldEdges[i] !== newEdges[i]) {
                                    needsUpdate = true;
                                    break;
                                }
                            }
                        }
                        if (needsUpdate) {
                            media.removeEdges(oldEdges, newEdgeType);
                            media.addEdges(newEdges, newEdgeType);
                            changed = true;
                        }
                    }
                });

                // remove any oldEdgeTypes that don't appear in the new list
                // except not `reference` (if the node actually has a reference)
                oldEdgeTypes.forEach( (oldEdgeType) => {
                    if (oldEdgeType !== 'reference' || !media.data.reference) {
                        if (!newEdgeTypes.includes(oldEdgeType)) {
                            // no longer in the edge types, remove it
                            media.removeEdges(media.getEdges(oldEdgeType), oldEdgeType);
                            changed = true;
                        }
                    }
                });
            } else {
                // no thumbnails, so clear out any edges (except maybe not 'reference' edges)
                let oldEdgeTypes = Object.keys(media.edges || {});  // TODO make node method for getting all edge types
                oldEdgeTypes.forEach( (oldEdgeType) => {
                    // clear out all the edges, except ignore 'reference' edges
                    // for nodes that have an actual reference
                    // those edges are taken care of above
                    if (oldEdgeType !== 'reference' || !media.data.reference) {
                        media.removeEdges(media.getEdges(oldEdgeType), oldEdgeType);
                        changed = true;
                    }
                });
            }
        });

        return changed;
    }


    private _createClients(callback) {
        this._getServiceRecord('media', (err, record) => {
            log.iferr(err, 'SyncManager._getServiceRecord');
            if (!err) {
                this.mediaUrl = `http://${record.host}:${record.port}/media`;
            }
            this._getServiceRecord('media-manager', (err, record) => {
                log.iferr(err, 'SyncManager._getServiceRecord');
                //this.mediaManagerClient = new MediaManagerServer();  // in an ideal world
                this.mediaManagerClient = mediaManager;  // for now
                this.mediaManagerClient.init(record, parentLog, (err) => {
                    log.iferr(err, 'SyncManager._mediaManagerClient.init');
                    this._getServiceRecord('media-proxy', (err, record) => {
                        log.iferr(err, 'SyncManager._getServiceRecord');
                        if (!err) {
                            this.proxyUrl = `http://${record.host}:${record.port}`;
                        }
                        callback();
                    });
                });
            });
        });
    }
}


export default MediaListManager;
