import * as path from 'path';
import * as url from 'url';
import axios from 'axios';
import async = require('async');

import {Node, UserNode, Model, Asset} from 'jibo-kb';
import {JSC} from '../../clients/jibo-server';
import kb from '../../clients/KBClient';
import SyncManager from './SyncManager';
import EnrollmentLoopInformer from './EnrollmentLoopInformer';

import parentLog from './log';
const log = parentLog.createChild('Loop');


const PERIODIC_SECONDS = 60 * 60 * 2;  // every 2 hours just in case we missed a notification

const KB_SLICE_NAME = '/jibo/loop';


export type ErrCallback = (err?:Error)=>void;
export type HasCallback = (err?:Error, hasIt?:boolean)=>void;
export type ChangedCallback = (err?:Error, changed?:boolean)=>void;

export enum Gender {
    male = 'male',
    female = 'female',
    other = 'other',
}

export interface AccountUpdateParams {
    _id: string;
    birthday?: number;
    email?: string;
    firstName?: string;
    gender?: Gender;
    lastName?: string;
    password?: string;
}

export interface LoopUpdatePhoneticNameParams {
    loopId: string;
    id: string;  // member id
    phoneticName?: string;
}

export interface LoopSetEnrollmentParams {
    loopId: string;
    id: string;  // member id
    face?: boolean;
    voice?:boolean;
}

export interface LoopSuspendParams {
    loopId: string;
}

interface LoopInformer {
    update(loop:UserNode[]):Promise<void>;
}


/** Synchronize the loop in the KB with the cloud, one-way.
 * Polls the cloud server in the background every 2 hours and
 * adds/removes/updates loop members as needed. Forces the loop to
 * match the cloud, all local loop changes will (eventually) be
 * overwritten by the LoopManager.
 *
 * Also informs the NLU and ASR services of all the names (and
 * associated ids) of the loop members upon startup, and again each
 * time anything in the loop changes.
 *
 * @class LoopManager
 * @param {string} httpUrl Url to the KB service
 * @param {boolean} [enableCloud=true] Enables the cloud checking. If
 * false, no cloud calls will be done. The NLU will still be informed
 * of the loop member names for whatever loop information is found
 * cached in the KB. The ASR service will *not* be informed.
 */
class LoopManager extends SyncManager {
    private robotAccountId:string;
    private model:Model;
    private rootNode:Node;
    private accountClient:any;
    private loopClient:any;
    private loopInformers:LoopInformer[];

    constructor(httpUrl:string, enableCloud:boolean=true) {
        super(httpUrl, 'loop', PERIODIC_SECONDS * 1000, enableCloud);
        this.loopInformers = [];
    }


    public init(callback:ErrCallback) {
        log.info('initing LoopManager');
        super.init( (err) => {
            log.iferr(err, 'super.init');
            if (err) {
                callback(err);
            } else {
                //this.onRobot = true;  // useful for debugging ASR loop informer
                this._initCredentials( (err) => {
                    let baseModel = kb.createModel(KB_SLICE_NAME, this.httpUrl);

                    // start cache. we load up the cache and never release it
                    // which is not usually a good thing to do, but since we own
                    // all loop changes (loop must exactly match the cloud) we can
                    // get away with it here. we might change our mind about this.
                    this.model = baseModel.begin();
                    this._preloadLoopModel( () => {
                        log.info('local cached loop loaded, members: ', this._loopSize());
                        this._setupLoopInformers( () => {
                            // premptively update with the locally cached loop just in case we can't sync
                            this._updateLoopInformers( () => {
                                const lastCredentialsHash = this.rootNode.data.lastFullSyncCredentialsHash;
                                this._setupCanSkipFullSync(lastCredentialsHash);
                                if (err || SyncManager.canSkipFullSync) {
                                    // let things proceed and do the first sync in the background
                                    log.info('doing first full sync in the background');
                                    callback();
                                    callback = ()=>{return;};
                                }
                                if (this.enableCloud) {
                                    log.info('starting loop cloud syncing...');
                                    this._syncWithCloud((/*err*/) => {
                                        let size = this._loopSize();
                                        log.info('local loop members: ', size);
                                        if (size === 0) {
                                            log.error('This robot does not have a loop!');
                                        }
                                        this._syncOnNotification('AccountUpdated');
                                        this._syncOnNotification('LoopUpdated');
                                        // update things that care about the loop again now that
                                        // we have synced any changes with with the cloud
                                        this._updateLoopInformers( (err) => {
                                            log.iferr(err, 'error updating loop informers');
                                            callback();  // don't let loop informer errors hold things up
                                        });
                                        this._startSyncTimer();
                                    });
                                } else {
                                    if (this._loopSize() === 0) {
                                        log.error('This robot does not have a loop!');
                                    }
                                    callback();
                                }
                            });
                        });
                    });
                });
            }
        });
    }


    /** Stop syncing and release the kb model.
     * @param {Function} callback Called when done
     * @method LoopManager#shutdown
     */
    public shutdown(callback:ErrCallback) {
        this._notDuringSyncing( (done) => {
            // don't call 'done', we don't want to resume syncing
            delete this.model;
            this.isShutdown = true;
            callback(null);
        });
    }


    /** Update account info locally and in the cloud.
     * Pauses cloud syncing, waits until any in-progress sycing is
     * finished, then updates the cloud and the local kb. Syncing is
     * then resumed.
     * @method LoopManager#accountUpdate
     * @param {object} params Account update parameters as defined by
     * jibo-server-clinet Account#update()
     * @param {function} callback Called when done
     */
    // this isn't currently used and it might now need some fixing because
    // account.update doesn't have the _id param anymore, and can't update
    // accounts other than the account the credentials are for. for more info
    // see SDK-932 and Confluence doc "Migration from 2.12 to 3.0 of JSC"
    public accountUpdate(params:AccountUpdateParams, callback:ErrCallback) {
        let account = new JSC.Account();

        this._notDuringSyncing( (done) => {
            account.update(params, (err, data) => {
                log.iferr(err, 'JSC.Acount.update');
                if (err) {
                    done();  // release the sync pause
                    callback(err);
                } else {
                    // proactively update the local kb so we have the
                    // change now instead of after the next loop
                    // polling cycle
                    let user = this.model.fetch(params._id);
                    if (!user) {
                        // not in the current in-memory loop, so no need to update
                        done();  // release the sync pause
                        callback(err);
                    } else {
                        Object.keys(params).forEach( (field) => {
                            if (field !== '_id') {
                                user.data[field] = params[field];
                            }
                        });
                        // someday the loop informers will care about
                        // these changes and here is where we would
                        // inform them
                        user.save( (err) => {
                            done(); // release the sync pause
                            callback(err);
                        });
                    }
                }
            });
        });
    }


    /** Update phoneticName locally and in the cloud.  Pauses cloud
     * syncing, waits until any in-progress sycing is finished, then
     * updates the cloud and the local kb. Syncing is then resumed.
     * @method LoopManager#loopUpdatePhoneticName
     * @param {object} params updatePhoneticName parameters as defined by
     * jibo-server-clinet Loop#updatePhoneticName()
     * @param {function} callback Called when done
     */
    public loopUpdatePhoneticName(params:LoopUpdatePhoneticNameParams, callback:ErrCallback) {
        let loop = new JSC.Loop();

        this._notDuringSyncing( (done) => {
            loop.updatePhoneticName(params, (err, data) => {
                log.iferr(err, 'JSC.Loop.updatePhoneticName');
                if (err) {
                    done();  // release the sync pause
                    callback(err);
                } else {
                    // proactively update the local kb so we have the
                    // change now instead of after the next loop
                    // polling cycle
                    //let user = this._findByMemberId(params.id);
                    let user = this.model.fetch(params.id);
                    if (!user) {
                        // not in the current in-memory loop, so no need to update
                        done();  // release the sync pause
                        callback(err);
                    } else {
                        user.data.phoneticName = params.phoneticName;
                        // someday the loop informers will care about
                        // these changes and here is where we would
                        // inform them
                        user.save( (err) => {
                            done(); // release the sync pause
                            callback(err);
                        });
                    }
                }
            });
        });
    }


    /** Update enrollment flags locally and in the cloud.
     * Pauses cloud syncing, waits until any in-progress sycing is
     * finished, then updates the cloud and the local kb. Syncing is
     * then resumed.
     * @method LoopManager#loopSetEnrollment
     * @param {object} params Enrollment parameters as defined by
     * jibo-server-clinet Loop#setEnrollment()
     * @param {function} callback Called when done
     */
    public loopSetEnrollment(params:LoopSetEnrollmentParams, callback:ErrCallback) {
        let loop = new JSC.Loop();

        this._notDuringSyncing( (done) => {
            loop.setEnrollment(params, (err, data) => {
                log.iferr(err, 'JSC.Loop.setEnrollment');
                if (err) {
                    done();  // release the sync pause
                    callback(err);
                } else {
                    // proactively update the local kb so we have the
                    // change now instead of after the next loop
                    // polling cycle
                    let user = this.model.fetch(params.id);
                    if (!user) {
                        // not in the current in-memory loop, so no need to update
                        done();  // release the sync pause
                        callback(err);
                    } else {
                        ['face', 'voice'].forEach( (field) => {
                            if (field in params) {
                                user.data.enrolled = user.data.enrolled || {};
                                user.data.enrolled[field] = params[field];
                            }
                        });
                        // someday the loop informers will care about
                        // these changes and here is where we would
                        // inform them
                        user.save( (err) => {
                            done(); // release the sync pause
                            callback(err);
                        });
                    }
                }
            });
        });
    }


    /** Suspends the loop in the cloud.
     * Pauses cloud syncing, waits until any in-progress sycing is
     * finished, then updates the cloud and the local kb. Syncing is
     * then resumed.
     * @method LoopManager#loopSuspend
     * @param {object} params Enrollment parameters as defined by
     * jibo-server-clinet Loop#setEnrollment()
     * @param {function} callback Called when done
     */
    public loopSuspend(params:LoopSuspendParams, callback:ErrCallback) {
        let loop = new JSC.Loop();

        this._notDuringSyncing( (done) => {
            loop.suspendLoop(params, (err, data) => {
                log.iferr(err, 'JSC.Loop.loopSuspend');
                done();  // release the sync pause
                callback(err);
            });
        });
    }


    /** Check if the loop has a backup of the key.
     * @method LoopManager#hasKeyBackup
     * @param {object} params Enrollment parameters as defined by
     * jibo-server-clinet Loop#setEnrollment()
     * @param {function} callback Called when done
     */
    public hasKeyBackup(loopId:string, callback:HasCallback) {
        let keyClient = new JSC.Key();
        // this is the same method used by the mobile app to test for a key backup
        keyClient.restore({passwordHash: 'X', loopId: loopId}, (err, data) => {
            let hasKeyBackup;
            if (err) {
                if (err.code === 'BACKUP_PASSWORD_WRONG') {
                    hasKeyBackup = true;
                } else {
                    // if no key backup code will be BACKUP_NOT_FOUND
                    hasKeyBackup = false;
                }
            } else {
                // No err?? I guess "X" actually was their passwordHash!?
                hasKeyBackup = true;
            }
            callback(null, hasKeyBackup);
        });
    }


    protected _syncWithCloud(callback:ChangedCallback) {
        this._setupClients();
        this._setupRobotAccountId( (err) => {
            if (err) {
                this._errorOnce('_setupRobotAccountId ' + err.toString());
            }
            if (!err) {
                this._startTimer();
                this.loopClient.list({}, (err, data) => {
                    this._endTimer('JSC server call Loop#list()');
                    log.iferr(err, 'JSC server call Loop#list()');
                    if (!err) {
                        if (this._isLoopGood(data)) {
                            let loop = data[0];
                            this._filterOutInvitedChildren(loop);
                            this._applyLoopChanges(loop, (err, changed) => {
                                log.iferr(err, '_applyLoopChanges');
                                callback(err, changed);
                            });
                        } else {
                            callback(new Error('no loop'));
                        }
                    } else {
                        callback(err);
                    }
                });
            } else {
                callback(err);
            }
        });
    }


    protected _updated(callback:ErrCallback) {
        this.emit('LoopUpdated');
        this._updateLoopInformers(callback);
    }


    private _preloadLoopModel(callback:ErrCallback) {
        log.info('loading root node');
        this.model.loadRoot( (err, rootNode) => {
            log.iferr(err, 'model.loadRoot');
            this.rootNode = rootNode;
            this.model.loadLayers(rootNode, ['owner', 'user'], (err) => {
                log.iferr(err, 'loadLayers owner, user');
                callback();
            });
        });
    }


    private _fetchLoop():Node[] {
        return this.model.fetch(this.rootNode.getEdges('user'));
    }


    private _loopSize():number {
        let loop = this._fetchLoop();
        return loop.length;
    }


    private _setupLoopInformers(callback) {
        this.loopInformers.push(new EnrollmentLoopInformer());
        if (this.enableCloud && this.onRobot) {
            this._setupClients();
            this._setupRobotAccountId( (err) => {
                log.iferr(err, '_setupRobotAccountId');
                setImmediate(callback);
            });
        } else {
            setImmediate(callback);
        }
    }


    private _updateLoopInformers(callback:ErrCallback) {
        const loop = this._fetchLoop() as UserNode[];
        Promise.all(this.loopInformers.map(informer => informer.update(loop)))
        .catch((err) => {
            log.warn('Unable to update loop informers', err);
        })
        .then(() => callback());
    }


    private _isLoopGood(data:any[]):boolean {
        if (!data || !Number.isInteger(data.length) || data.length === 0) {
            this._errorOnce('JSC Loop#list() account '+this.robotAccountId+' does not have a loop');
            return false;
        }

        if (data.length !== 1) {
            this._errorOnce('JSC Loop#list() account '+this.robotAccountId+' is returning multiple loops');
            return false;
        }

        let loop = data[0];
        let members = loop.members;
        if (!members || !Number.isInteger(members.length) || members.length === 0) {
            this._errorOnce('JSC server call Loop#list() loop has no members');
            return false;
        }

        // list of loop member account ids
        let loopAccountIds = loop.members.map(element => element.accountId);

        // warn if the owner is not in the loop for some reason (but let it pass)
        if (!loopAccountIds.includes(loop.owner)) {
            this._errorOnce('JSC server call Loop#list() owner not in loop for robot '+this.robotAccountId);
        }

        // warn if the robot is not in the loop for some reason (but let it pass)
        if (!loopAccountIds.includes(loop.robot)) {
            this._errorOnce('JSC server call Loop#list() robot '+this.robotAccountId+' not in loop');
        }

        return true;
    }


    /** filter out kids whose parent/guardian has not accepted the agreement, aka 'pending'
     */
    private _filterOutInvitedChildren(loop) {
        loop.members = loop.members.filter( (member) => {
            if (!(member.account.isChild && member.status === 'invited')) {
                return true;
            } else {
                log.debug('filtering out pending loop member', member.id);
                return false;
            }
        });
    }


    private _setupClients() {
        if (!this.loopClient) {
            this.loopClient = new JSC.Loop();
        }
        if (!this.accountClient) {
            this.accountClient = new JSC.Account();
        }
    }


    private _setupRobotAccountId(callback:ErrCallback) {
        if (!this.robotAccountId) {
            this.robotAccountId = this.rootNode.data.robot;
            log.debug('robot id via rootNode', this.robotAccountId);
            if (!this.robotAccountId) {
                // fall back to looking it up via JSC (when loop hasn't been synced yet)
                this._startTimer();
                this.accountClient.get({}, (err, data) => {
                    this._endTimer('JSC server call Account#get()');
                    if (err) {
                        this._errorOnce('JSC server call Account#get() ' + err.toString());
                    }
                    if (!err) {
                        if (!data || !data.length) {
                            this._errorOnce('JSC server call Account#get() did not return our account details');
                            callback(new Error('could not lookup our account'));
                        } else if (data.length !== 1) {
                            this._errorOnce('JSC server call Account#get() returned unexpected multiple results');
                            callback(new Error('could not lookup our account'));
                        } else {
                            this.robotAccountId = data[0].id;
                            log.debug('robot id via JSC', this.robotAccountId);
                            callback();
                        }
                    } else {
                        callback(err);
                    }
                });
            } else {
                setImmediate(callback);
            }
        } else {
            setImmediate(callback);
        }
    }


    private _applyLoopChanges(cloudLoop:any, callback:ChangedCallback) {
        let model = this.model;
        let rootNode = this.rootNode;
        let newLoop = [];
        let sameLoop = [];
        let removeLoop = [];

        let loopNodes = this._fetchLoop();

        // make sameLoop list (common members) and newLoop list (new members)
        cloudLoop.members.forEach( (cloudLoopEntry) => {
            let found = false;
            for (let i=0; i<loopNodes.length; i++) {
                let loopNode = loopNodes[i];
                if (cloudLoopEntry.id === loopNode._id) {
                    sameLoop.push(cloudLoopEntry);
                    found = true;
                    break;
                }
            }
            if (!found) {
                newLoop.push(cloudLoopEntry);
            }
        });

        // make removeLoop list (people no longer listed in loop)
        loopNodes.forEach( (loopNode) => {
            let found = false;
            for (let i=0; i<cloudLoop.members.length; i++) {
                let cloudLoopMember = cloudLoop.members[i];
                if (cloudLoopMember.id === loopNode._id) {
                    found = true;
                    break;
                }
            }
            if (!found) {
                removeLoop.push(loopNode);
            }
        });

        // now we begin the work of comparing things looking for changes
        let loopChanged = false;

        // first do the loop meta data
        loopChanged = this._applyCloudLoopToLocalLoopRootNode(cloudLoop, rootNode);

        // SDK-1046 dict to lookup member id by account id
        let memberIdsByAccountId = {};
        cloudLoop.members.forEach( (member) => {
            if (member.accountId) {
                memberIdsByAccountId[member.accountId] = member.id;
            }
        });

        // set the owner and robot edges

        // we currently assume the owner and robot do not change, so we just set them every time
        rootNode.clearEdges(['owner', 'robot']);

        // add the edge for the owner
        // SDK-1046 use member id, not account id:
        let ownerMemberId = memberIdsByAccountId[cloudLoop.owner];
        rootNode.addEdges(ownerMemberId, 'owner');  // assume owner is in loop and will be synced below

        // add an edge for the robot too. same assumptions (one robot, unchanging, in loop)
        // SDK-1046 use member id, not account id:
        let robotMemberId = memberIdsByAccountId[cloudLoop.robot];
        rootNode.addEdges(robotMemberId, 'robot');  // assume robot is in loop and will be synced below

        // now do the loop members

        // first try to load any new members in case they are actually reactivated old members
        let newLoopMemberIds = newLoop.map( (member) => {return member.id;} );
        model.load(newLoopMemberIds, (err) => {
            log.iferr(err, 'model.load');

            // process new members
            newLoop.forEach( (newLoopEntry) => {
                let oldNode = this.model.fetch(newLoopEntry.id, true);
                let newNode;
                if (oldNode) {
                    newNode = oldNode;
                } else {
                    newNode = this._createNodeWithId(newLoopEntry.id, this.model, 'user');
                }

                let account = newLoopEntry.account;
                this._applyCloudLoopMemberAndAccountToLocalLoopNode(
                    newLoopEntry, account, newNode);
                rootNode.addEdges(newNode, 'user');
                loopChanged = true;
            });

            // process common members
            sameLoop.forEach( (sameLoopEntry) => {
                let sameNode = this.model.fetch(sameLoopEntry.id);

                let account = sameLoopEntry.account;
                let changed = this._applyCloudLoopMemberAndAccountToLocalLoopNode(
                    sameLoopEntry, account, sameNode);
                if (changed) {
                    loopChanged = true;
                }
            });

            // process members removed from loop
            removeLoop.forEach( (removeNode) => {
                rootNode.removeEdges(removeNode, 'user');
                // we remove them from the list of loop members, but
                // we don't delete the removed member's node on purpose
                // it might come back someday, and other kb nodes might
                // be pointing to it
                loopChanged = true;
            });

            this._syncLoopPhotos((err, changed) => {
                if (changed) {
                    loopChanged = true;
                }

                if (!rootNode.data.lastFullSyncTimestamp) {
                    // force older loops to be updated with new credentials hash field
                    log.info('adding credentials hash to unchanged loop');
                    loopChanged = true;
                }

                if (loopChanged) {
                    log.info('loop changed. saving...');
                    rootNode.data.lastFullSyncTimestamp = Number(new Date());
                    rootNode.data.lastFullSyncCredentialsHash = SyncManager.credentialsHash;
                    this.model.saveLayers(rootNode, 'user', (err) => {
                        log.iferr(err, 'model.saveLayers');
                        log.info('finished saving loop');
                        log.debug('new loop', rootNode.getEdges('user'));
                        callback(null, loopChanged);
                    });
                } else {
                    callback();
                }
            });
        });
    }


    // update the rootNode
    private _applyCloudLoopToLocalLoopRootNode(cloudLoop:{}, localLoopRootNode:Node):boolean {
        let loopFields = [
            'id',
            'name',
            'owner',
            'robot',
            'robotFriendlyId',
            'created',
            'updated'
        ];

        let changed = this._syncObject(cloudLoop, localLoopRootNode.data, loopFields);
        return changed;
    }


    // update a member node
    // merges the loop member fields and the account fields into one node
    private _applyCloudLoopMemberAndAccountToLocalLoopNode(cloudLoopEntry:Object, cloudAccount:Object, localLoopNode:Node):boolean {
        let loopMemberFields = [
            'id',
            'loopId',
            'accountId',
            'account',  // TODO this is now redundant and should be eliminated
            'enrolled',
            'status',
            'type',
            'agreementId',
            'nickname',
            'phoneticName',
            'legalGuardianId',
            'created'
        ];
        let accountFields = [
            'email',
            'firstName',
            'lastName',
            'gender',
            'birthday',
            //'isActive',  // no longer synced
            //'roles',     // was never synced (see notes on fields in SDK-975)
            'photoUrl',
            //'facebookConnected',  // no longer synced
            'facebookAccessToken',
            'isChild',
            //'termsAccepted',  // no longer synced
            'phoneNumber',
            'messagingAllowed'
        ];
        let fieldsToRename = {  // note: just on loop member records (for now)
            // when nickName moved from account to loop the casing changed
            // and I don't want people to have to change their code right now (beta 2)
            // TODO might be time to find and rename all `nickName`s
            'nickname': 'nickName'
        };

        // this also merges the two objects into one
        let changed1 = this._syncObject(cloudLoopEntry, localLoopNode.data, loopMemberFields, fieldsToRename);
        let changed2 = this._syncObject(cloudAccount, localLoopNode.data, accountFields);

        return changed1 || changed2;
    }


    private _syncLoopPhotos(callback:ChangedCallback) {
        let changed = false;
        const loop = this._fetchLoop();
        let tasks = [];
        loop.forEach( (user) => {
            const photoUrl = user.data.photoUrl;
            const photoAsset = user.getAssets('photo')[0];

            if (photoUrl) {
                const urlParts = url.parse(photoUrl);
                const pathParts = path.parse(urlParts.pathname);
                const urlFile = pathParts.name;  // filename without ext
                const urlExt = pathParts.ext;  // ext including "."

                let assetFilename = `${urlFile}.photo${urlExt}`;

                if (!photoAsset || photoAsset.filename() !== assetFilename) {
                    // new photo or photo changed
                    const oldAssets = user.getAssets('photo');
                    oldAssets.forEach( (oldAsset) => {
                        // we should consider shifting the old asset to the second slot
                        // and keeping it around to prevent any chance of picture gap
                        tasks.push( (done) => {
                            user.removeAsset(oldAsset, done);
                        });
                    });
                    tasks.push( (done) => {
                        const newAsset = new Asset(assetFilename);
                        newAsset.setRootDir(user.getKb().getDirectory());
                        // Tell axios to return a uint array and convert the
                        // response to a Buffer for Asset#save
                        // https://github.com/axios/axios/issues/513#issuecomment-302558365
                        axios.get(photoUrl, {responseType: 'arraybuffer'})
                        .then(res => {
                            newAsset.save(res.data);
                            user.addAssets(newAsset);  // add it now that it saved successfully
                            changed = true;
                        })
                        .catch(err => {
                            log.error('newAsset.save', err);
                        })
                        .then(() => done());
                    });
                }
            } else {
                if (photoAsset) {
                    // old photo went away, delete it from user node
                    const oldAssets = user.getAssets('photo');
                    oldAssets.forEach( (oldAsset) => {
                        tasks.push( (done) => {
                            user.removeAsset(oldAsset, done);
                            changed = true;
                        });
                    });
                }
            }
        });
        async.series(tasks, () => {
            callback(null, changed);
        });
    }
}


export default LoopManager;
