import axios from 'axios';
import http = require('http');
import httpAdapter = require('axios/lib/adapters/http');
import {media} from 'jibo-service-clients';
import {RequestHandler} from './AssetServer';
import stream = require('stream');
import {VideoType} from 'jibo-command-protocol';

const BOUNDARY = 'VideoBoundary';
//10 seconds to make a request to fetch the asset - after that, it disappears
const AVAILABILITY_TIMEOUT = 10000;

export interface VideoData {
    type: 'video';
    assetUrl: string;
    videoType: string;
}

export default class VideoStreamer implements RequestHandler {
    private nextImagePath:string = null;
    private ongoingResponse:http.ServerResponse = null;
    private pipedImage:stream.Readable = null;
    private isRunning:boolean = false;
    private isSending:boolean = false;
    private selfEndCallback:Function = null;
    private photoMode:media.PhotoType = null;
    private timeout:NodeJS.Timer = null;

    constructor() {
        this.onPhotoTaken = this.onPhotoTaken.bind(this);
    }

    public start(request:VideoData, selfEndCallback:Function):void {
        this.selfEndCallback = selfEndCallback;
        this.isRunning = true;
        switch (request.videoType) {
            case VideoType.Debug:
                this.photoMode = media.PhotoType.DEBUG;
                break;
            case VideoType.Normal:
                this.photoMode = media.PhotoType.PREVIEW;
                break;
        }
        //take the first photo so we have data ready
        this.takeNextPhoto();
        //start timeout if no request is made
        this.timeout = setTimeout(() => {
            this.selfEndCallback();
        }, AVAILABILITY_TIMEOUT);
    }

    public handleRequest(res:http.ServerResponse):void {
        //only hande one response
        if (this.ongoingResponse) {
            res.statusCode = 404;
            res.end();
            return;
        }
        clearTimeout(this.timeout);
        this.ongoingResponse = res;
        res.writeHead(200, {
            'Content-Type': `multipart/x-mixed-replace; boundary=${BOUNDARY}`,
            'Cache-Control': 'no-cache',
            'Connection': 'close',
            'Pragma': 'no-cache'
        });
        this.sendBoundary();
        //write the first file with the image we already took
        this.writeFile(this.nextImagePath);
    }

    public stop():void {
        clearTimeout(this.timeout);
        if (this.ongoingResponse) {
            this.ongoingResponse.end();
            this.ongoingResponse = null;
        }
        if (this.pipedImage) {
            //unpipe the response so we stop writing - don't want to throw errors
            this.pipedImage.unpipe();
            this.pipedImage.removeAllListeners();
            this.pipedImage = null;
        }
        this.isRunning = false;
        this.selfEndCallback = null;
    }

    private takeNextPhoto():void {
        media.takePhoto(media.CameraID.LEFT, this.photoMode, [], false, this.onPhotoTaken);
    }

    private onPhotoTaken(err:Error, response?:media.PhotoResponse):void {
        if (!this.isRunning) {
            return;
        }
        if (err) {
            console.log('take photo error: ', err);
            this.selfEndCallback();
            return;
        }
        if (response) {
            //send the image, or queue it
            this.writeFile(media.getPreviewUrl(response.id));
        }
    }

    private sendBoundary() {
        this.ongoingResponse.write(`--${BOUNDARY}\r\n`);
    }

    private writeFile(path: string) {
        if (!this.isRunning) {
            return;
        }
        if (this.isSending || !this.ongoingResponse) {
            this.nextImagePath = path;
            return;
        }
        //take the next photo so it will be ready once we've finished sending this photo
        this.takeNextPhoto();
        //clear queued image
        this.nextImagePath = null;
        //track that we are sending
        this.isSending = true;
        let hasStarted = false;
        //get the photo data
        axios.get<stream.Readable>(path, {
            responseType: 'stream',
            adapter: httpAdapter,
        }).then(response => {
            const stream = response.data;
            this.pipedImage = stream;
            stream.on('data', (chunk: ArrayBuffer) => {
                if (!this.isRunning) {
                    return;
                }
                if (!hasStarted) {
                    this.ongoingResponse.write(`Content-Type: image/jpeg\r\n`);
                    this.ongoingResponse.write(`Content-Length:${response.headers['content-length']}\r\n\r\n`);
                    hasStarted = true;
                }
                this.ongoingResponse.write(new Buffer(chunk));
            });
            stream.on('end', () => {
                if (!this.isRunning) {
                    return;
                }
                this.isSending = false;
                this.pipedImage = null;
                this.sendBoundary();
                //write next image, if available
                if (this.nextImagePath) {
                    this.writeFile(this.nextImagePath);
                }
            });
        }).catch(err => {
            console.log('ERROR WRITING FILE', err);
            //stop sending stuff
            this.selfEndCallback();
        });
    }
}
