let entityIndex = 0;


/**
 * Notes:
 *
 * The VisualAwareness class in this file (and all its component classes) represents
 * the VisualAwareness JSON object that gets published in the LPS stream:
 * https://confluence.jibo.com/display/ENG/LPS+Service#LPSService-VisualAwareness
 *
 * However, the classes here are a simplified version of the above. Just enough data
 * is published to allow simulated human users ("targets") to appear in the Jibo
 * simulator. It's not necessary to publish a lot of the visual processing data that
 * appears on the actual robot, which is intended to deal with the visually messy
 * state of the real world.
 *
 * Here, in the simulator, we assume that targets (simulated users) are continuous
 * presences and that Jibo is 100% reliable at detecting their existence and
 * location. The goal, when using the simulator, is to make sure that Jibo's
 * reponses to users and their movements model whatever behaviors the skill
 * developer considered to be socially appropriate in context.
 *
 * Places where this data is used:
 *
 * For skills:
 * - Monitor through jibo.lps.motionData()
 *
 * Attention Manager
 * - sdk/packages/jibo-attention-manager/lib/src/DataConverter.js: acceptVision()
 * - skd/packages/jibo-attention-manager/src/VisionModalityHandler.js
 *
 * Behavior Tree in Skill
 * - In Lookat behavior's getTarget(), call jibo.lps.getClosestVisualEntity()
 *
 */

export class Point2 {
    public x:number = 0;
    public y:number = 0;

    constructor(point?:Point2) {
        if(point) {
            this.x = point.x;
            this.y = point.y;
        }
    }
}

export class Point3 extends Point2 {
    public z:number = 0;

    constructor(point?:Point3) {
        super(point);
        if(point) {
            this.z = point.z;
        }
    }
}

export type Timestamp = [number, number];

export class Ray {
    public origin:Point3 = new Point3();
    public dir:Point3 = new Point3();
    public cameraId:number = 0;
    public tag:string = "";
    public timestamp:Timestamp = [0, 0];
    constructor(target:Target) {
        this.dir.x = target.x;
        this.dir.y = target.y;
        this.dir.z = target.z;
    }
}

export class Tracker3D {
    public position:Point3 = new Point3();
    public rotation:Point3 = new Point3();
    public velocity:Point3 = new Point3();
    public angVelocity:Point3 = new Point3();
}

export class Covariance {
    public n11:number = 0;
    public n12:number = 0;
    public n21:number = 0;
    public n22:number = 0;
}

export class Rectangle {
    public left:number = 0;
    public top:number = 0;
    public right:number = 0;
    public bottom:number = 0;
}

export class Tracker2D {
    public id:number = 0;
    public cameraId:number = 0;
    public confidence:number = 0;
    public covariance:Covariance = new Covariance();
    public rectangle:Rectangle = new Rectangle();
    public velocity:Point2 = new Point2();
    public inFOV:boolean = true;
    public occluded:boolean = false;
    public lastUpdate:Timestamp = [0, 0];
    public name:string = '';
    public needModelUpdate:boolean = false;

    constructor(target:Target) {
        this.id = (target.id === undefined) ? 0 : target.id;
    }
}

export class TagEntry {
    public ts:[number, number] = [0, 0];
    public confidence:number = 0;
    public tag:any;
}

export class Tag {
    public key:string;
    public value:TagEntry;
}

export class Detection {
    public confidence:number = 1;
    public timestamp:Timestamp = [0, 0];
}

export class PartEntry {
    public id:number = 0;
    public confidence:number = 0;
    public occluded:boolean = false;
    public tracker:Tracker3D = new Tracker3D();
    public extent: Point3 = new Point3();
    public rays:Ray[] = [];
    public trackers:Tracker2D[] = [];
    public detections:Detection[] = [];

    constructor(target:Target) {
        this.id = (target.id === undefined) ? 0 : target.id;
        this.rays = [new Ray(target)];
        this.trackers = [new Tracker2D(target)];
        this.detections = [new Detection()];
    }
}

export class Part {
    public key:string = "";
    public value:PartEntry;

    constructor(target:Target) {
        this.value = new PartEntry(target);
    }
}

/**
 * Maps to an Entity in the VisualAwareness JSON (see below)
 */
export class Entity {
    public id:number = 0;
    public confidence:number = 1;
    public description:string = '';
    public position:Point3;
    public orientation:Point3 = new Point3();
    public extent:Point3 = new Point3();
    public static:boolean = false;
    public occluded:boolean = false;
    public in_fov:boolean = false;
    public last_measured:Timestamp = [0, 0];
    public tags:Tag[] = [];
    public parts:Part[] = [];

    constructor(target:Target) {
        this.id = target.id === undefined ? entityIndex++ : target.id;
        this.position = new Point3(target);
        this.parts = [new Part(target)];
        this.confidence = 1.0;
        this.description = "vision";
    }

    public updatePosition(point:Point3, timestamp:Timestamp):boolean {
        let newPos:boolean = false;
        if (this.position.x !== point.x ||
            this.position.y !== point.y ||
            this.position.z !== point.z) {
                newPos = true;
            }
        this.position.x = point.x;
        this.position.y = point.y;
        this.position.z = point.z;
        this.parts[0].value.rays[0].dir.x = point.x;
        this.parts[0].value.rays[0].dir.y = point.y;
        this.parts[0].value.rays[0].dir.z = point.z;

        function copyTS(dest:Timestamp) {
            dest[0] = timestamp[0];
            dest[1] = timestamp[1];
        }

        if (newPos) {
            copyTS(this.last_measured);
            let ray:Ray = this.parts[0].value.rays[0];
            copyTS(ray.timestamp);
            let tracker:Tracker2D = this.parts[0].value.trackers[0];
            copyTS(tracker.lastUpdate);
            let detection:Detection = this.parts[0].value.detections[0];
            copyTS(detection.timestamp);
        }
        return newPos;
    }
}

export interface Target extends Point3 {
    id:number;
}

/**
 * Implements structure version of VisualAwareness JSON object.
 * See: https://confluence.jibo.com/display/ENG/LPS+Service#LPSService-VisualAwareness
 *
 * The VisualAwareness contains all the information being tracked using image processing techniques.
 * All 3D coordinates and transformations are in world space. All 2D coordinates and transformations
 * are in image space. The information provided contains the current camera transformations, the
 * entities they are tracking, the component parts of the entities, the pick-rays of the camera to
 * the part, the image trackers associated with each part of each entity. The overall awareness of
 * sectors around the robot is included as well as dynamic lighting information for each sector
 * around the robot.
 */
export default class VisualAwareness {
    public ts:Timestamp = [0, 0];
    public entities:Entity[] = [];

    addTarget(target:Target):void {
        this.entities.push(new Entity(target));
    }

    updateTimestamp(timestamp:Timestamp):void {
        this.ts[0] = timestamp[0];
        this.ts[1] = timestamp[1];
    }

}
