import {SystemManagerClient} from 'jibo-client-framework';
import {systemManager} from 'jibo-service-clients';

class GetConfig {

    getConfig(callback:(err:Error, configPath?:string, mode?:string) => void) {
        //callback(null, __dirname + '/../configs/jibo-ssm-int-developer.json', 'int-developer');
        // yuck...we still need to initialize SystemManagerClient :(
        SystemManagerClient.createInstance('127.0.0.1', 8585);
        systemManager.httpInterface = 'http://127.0.0.1:8585';
        systemManager.getMode((error:Error, mode:string) => {
            if(error) {
                return callback(error);
            }
            callback(null, `/usr/local/etc/jibo-ssm/jibo-ssm-${mode}.json`, mode);
        });
    }
}

export default GetConfig;
