import {
    ALL_CLIENTS_AND_SERVICES,
    ALL_TASKS,
    Callback,
    Client,
    Configuration,
    LATE_CLIENTS,
    LATE_CLIENTS_DEPS,
    PLATFORM_CLIENTS,
    PLATFORM_CLIENTS_DEPS,
    REAL_SERVICES,
    REAL_SERVICE_DEPS,
    Service,
    SIMULATED_SERVICES,
    SIMULATED_SERVICE_DEPS,
    SSMServiceConfigs,
} from './FactoryDeps';
import Analytics from './utils/analytics/Analytics';
import './background';
import BackgroundUtilsManager from './utils/BackgroundUtilsManager';
import ClientInitializer from './ClientInitializer';
import {instantiateService, SSMServiceClass} from './SSMService';
import KBService from './services/kb/KBService';
import {Log} from 'jibo-log';
import {
    NotificationsDispatcher,
    RegistryClient,
    ServiceOptions,
    SystemManagerClient,
} from 'jibo-service-framework';
import parentLog from './log';
import RegistryService from './sim-services/registry/RegistryService';
import * as ServiceClients from 'jibo-service-clients';
import {SkillsServiceOptions} from './services/skills/SkillsService';
import {versionCheck} from './utils/Version';

import async = require('async');
import childProcess = require('child_process');
import findRoot = require('find-root');
import Orchestrator = require('orchestrator');
import path = require('path');
import spawnSync = childProcess.spawnSync;

Log.processName = 'ssm';
const log = parentLog.createChild('Factory');


/* To add a service: and add it to the `REAL_SERVICES` or `SIMULATED_SERVICES`
 * objects in FactoryDeps. To enable in the simulator, also add it to
 * `jibo-cli/src/simulator/client/index.tsx`. To enable in
 * `jibo-integration-tests` add it to `tests/index.js`.
 * Note: many services are disabled in `unit-test` mode.
 */
export default class Factory {

    private _orchestrator: Orchestrator;

    constructor(conf: Configuration, rootDir: string, mode?: string) {
        if(conf.logging) {
            try {
                Log.loadConfig(conf.logging);
            } catch(err) {
                console.error('Error loading logging config', err);
            }
        }
        this._createOrchestrator();
        this._instantiateServices(conf.services, rootDir);
        this._addRegistryServiceTask(conf.RegistryService, rootDir);
        this._addRegistryClientTask(conf.RegistryClient, conf.RegistryService);
        this._addSimulatedServicesInitTasks(conf.services);
        this._addSharedClientsTask(conf.platformVersion);
        this._addPlatformClientsTask();
        this._addRealServicesInitTasks();
        this._addSyncManagersTask();
        this._addNotificationsDispatcherTask();
        this._addLateClientsTask();
        this._addAnalyticsTask();
        this._addBackgroundUtilsTask(conf.services, mode);
        // This task must explicitly depend on all other tasks
        // Orchestration is complete when all included tasks are complete
        this._addAllTask();
    }

    init(callback: Callback): void {
        log.info('Starting orchestrator');
        this._orchestrator.start('All', callback);
    }

    private _createOrchestrator(): void {
        log.info('Creating orchestrator');
        this._orchestrator = new Orchestrator();
        this._orchestrator.onAll(event => {
            const message = `Orchestrator: ${event.src} ${event.task}: ${event.message}`;
            if (event.src === 'err') {
                log.error(message, event.err);
            } else if(['not_found', 'recursion'].includes(event.src)) {
                log.error(message);
            } else {
                log.info(message);
            }
        });
    }

    private _instantiateServices(
        services: SSMServiceConfigs,
        rootDir: string,
    ): void {
        log.info('Creating service instances');
        log.debug(services);
        // First create all the service instances, but don't init them
        Object.keys(services).forEach(serviceName => {
            log.debug('Creating instance of', serviceName);
            const service =
                REAL_SERVICES[serviceName] || SIMULATED_SERVICES[serviceName];
            const options: ServiceOptions = services[serviceName];
            log.debug(service.name);
            instantiateService(service, options, rootDir);
        });
    }

    private _addRegistryServiceTask(serviceOpts: Service, rootDir: string): void {
        log.info('Adding registry service task to orchestrator');
        // Initialize the registry service, if we're in the simulator
        this._orchestrator.add('RegistryService', (done: Callback) => {
            if (serviceOpts) {
                const options: ServiceOptions = serviceOpts;
                instantiateService(RegistryService, options, rootDir);
                RegistryService.instance.init(done);
            } else {
                done();
            }
        });
    }

    private _getRegistryHost(registryClient: Client): string {
        log.info('Getting registry host');
        let host:string = '127.0.0.1';
        if (registryClient) {
            // If a registry host was provided
            if (registryClient.host){
                host = registryClient.host;
            }
            // Fetch the command line's default robot if no registry host was
            // provided
            else {
                const getHostNameScriptPath = path.join(
                    findRoot(__dirname),
                    'bin/utils/get-robot-host.sh',
                );
                host = spawnSync(getHostNameScriptPath)
                    .stdout.toString().trim();
                log.debug(host);
            }
        }
        return host;
    }

    private _addRegistryClientTask(
        registryClient: Client,
        registryService: Service,
    ): void {
        log.info('Adding registry client task to orchestrator');
        // Initialize the registry client
        this._orchestrator.add(
            'RegistryClient',
            ['RegistryService'],
            (done: Callback) => {
                if(!registryService && !registryClient) {
                    return done(new Error('Config must specify either RegistryClient or RegistryService'));
                }
                //now create the registry client
                const host = this._getRegistryHost(registryClient);
                const port = registryService
                    ? RegistryService.instance.port
                    : registryClient.port;
                RegistryClient.createInstance(host, port);
                done();
            },
        );
    }

    private _addSimulatedServicesInitTasks(services: SSMServiceConfigs): void {
        // Initialize the simulated services, which simulate platform services
        // This is done early, since some top-of-stack services may depend on
        // each of them
        Object.keys(SIMULATED_SERVICES).forEach(name => {
            log.info(`Adding simulated-service ${name} init task to orchestrator`);
            const serviceDeps = SIMULATED_SERVICE_DEPS[name] || [];
            const allDeps = ['RegistryClient', ...serviceDeps];
            this._orchestrator.add(name, allDeps, (done: Callback) => {
                if(services[name]) {
                    log.debug(`Starting init for ${name}`);
                    SIMULATED_SERVICES[name].instance.init(done);
                } else {
                    done();
                }
            });
        });
    }

    // Initialize the platform-service clients that are shared with the jibo
    // module
    private _addSharedClientsTask(platformVersion: string): void {
        log.info('Adding shared platform-service clients task to orchestrator');
        this._orchestrator.add(
            'SharedClients',
            ['RegistryClient', 'SystemManagerService'],
            (done: Callback) => {
                RegistryClient.instance.getRecordByName(
                    'system-manager',
                    (err, sysMgrRec) => {
                        if (err) {
                            return done(new Error('Could not find system-manager in registry.'));
                        }
                        // Initialize just the system manager at first
                        ServiceClients.init({}, [{
                            name: sysMgrRec.name,
                            host: RegistryClient.instance.host,
                            port: sysMgrRec.port,
                        }], (error) => {
                            if (error) {
                                done(error as Error);
                            } else {
                                SystemManagerClient.createInstance(
                                    sysMgrRec.host,
                                    sysMgrRec.port,
                                );
                                versionCheck(platformVersion, done);
                            }
                        });
                    },
                );
            },
        );
    }

    private _addPlatformClientsTask(): void {
        log.info('Adding platform-service clients task to orchestrator');
        this._orchestrator.add(
            'PlatformClients',
            PLATFORM_CLIENTS_DEPS,
            (done:Callback) => {
                ClientInitializer.getClientInits(PLATFORM_CLIENTS, (err, tasks) => {
                    if (err) {
                        log.error('Critical error getting initializers for early service clients', err);
                        return done(err);
                    }
                    async.parallel(tasks, done);
                });
            },
        );
    }

    private _addServiceInitTask(Service: SSMServiceClass, deps: string[] = []): void {
        log.info(`Adding ${Service.name} init task to orchestrator`);
        const fullDeps = ['PlatformClients', ...deps];
        this._orchestrator.add(Service.name, fullDeps, (done: Callback) => {
            if(Service.instance) {
                log.debug(`Starting init for ${Service.name}`);
                Service.instance.init((err?: Error) => {
                    // Will leave here in case people want to run
                    // while debugging
                    // console.log(`Error intiializing ${name}`, Service.instance);
                    done(err);
                });
            }
            else {
                done();
            }
        });
    }

    private _addRealServicesInitTasks() {
        log.info('Adding real services init tasks to orchestrator');
        Object.keys(REAL_SERVICES).forEach(name => {
            this._addServiceInitTask(REAL_SERVICES[name], REAL_SERVICE_DEPS[name]);
        });
    }

    private _addSyncManagersTask() {
        log.info('Adding sync managers task to orchestrator');
        this._orchestrator.add('SyncManagers', ['ErrorService', 'KBService'], (done: Callback) => {
            KBService.instance.initSyncManagers(err => {
                // Explicitly continue orchestration even if an error occurs
                done();
            });
        });
    }

    private _addNotificationsDispatcherTask(): void {
        log.info('Adding NotificationsDispatcher task to orchestrator');
        this._orchestrator.add(
            'NotificationsDispatcher',
            ['NotificationsService', 'ServerService'],
            (done: Callback): void => {
                NotificationsDispatcher.instance.init(async err => {
                    if (err) {
                        return done(err);
                    }
                    try {
                        await Log.handleLogLevelNotifications(
                            NotificationsDispatcher.instance,
                            // Save config to disk (persist through reboot)
                            // This is the only place (SSM process) where this
                            // should be set to true, so that the change is only
                            // written to disk once
                            true,
                        );
                    } catch (err) {
                        log.error('Failed to set up log level notification handler', err);
                        return done(err);
                    }
                    done();
                });
            },
        );
    }

    private _addLateClientsTask(): void {
        log.info('Adding late clients task to orchestrator');
        this._orchestrator.add('LateClients', LATE_CLIENTS_DEPS, (done:Callback) => {
            ClientInitializer.getClientInits(LATE_CLIENTS, (err, tasks) => {
                if (err) {
                    log.error('Critical error getting initializers for late service clients', err);
                    return done(err);
                }
                async.parallel(tasks, done);
            });
        });
    }

    private _addAnalyticsTask(): void {
        log.info('Adding analytics task to orchestrator');
        this._orchestrator.add('Analytics', ALL_CLIENTS_AND_SERVICES, (done) => {
            log.info('Initilizing analytics');
            // Now the all services exist, initialize analytics and all
            // background utilities
            const analytics = Analytics.createInstance();
            analytics.init(() => {
                log.info('Analytics initialized');
                done();
            });
        });
    }

    private _addBackgroundUtilsTask(services: SSMServiceConfigs, mode: string): void {
        log.info('Adding BackgroundUtils task to orchestrator');
        this._orchestrator.add('BackgroundUtils', ALL_CLIENTS_AND_SERVICES, (done) => {
            log.info('Initilizing background utilities');
            // Background utilities includes ScreenScheduler and
            // LocationManager, each of which sets up a timeout on init
            BackgroundUtilsManager.initAll(
                mode,
                services.SkillsService
                    ? (services.SkillsService as SkillsServiceOptions).startSkill
                    : undefined,
            );
            log.info('Background utilities initialized');
            done();
        });
    }

    private _addAllTask(): void {
        log.info('Adding All (ending) task to orchestrator');
        this._orchestrator.add('All', ALL_TASKS);
    }
}
