import {Node, Model} from 'jibo-kb';
import {JSC} from '../../clients/jibo-server';
import SyncManager from './SyncManager';
import kb from '../../clients/KBClient';

import parentLog from './log';
const log = parentLog.createChild('Robot');


const SYNC_PERIODIC_SECONDS = 6 * 3600;  // 6 hours

const KB_SLICE_NAME = '/jibo/robot';
const KB_LOOP_NAME = '/jibo/loop';


export type ErrCallback = (err?:Error)=>void;
export type IdCallback = (err, id?:string)=>void;
export type ChangedCallback = (err?:Error, changed?:boolean)=>void;


/**
 * @description Synchronize the robot properties in the cloud with a
 * copy in the KB. Syncing is one-way. Polls the cloud server in the
 * background every 6 hours and adds/removes/updates the robot kb
 * slice as needed. Forces the local copy to match the cloud, all
 * local changes will (eventually) be overwritten by the cloud.
 *
 * @class RobotManager
 * @param {string} httpUrl Url to the KB service
 * @param {boolean} [enableCloud=true] Enables the cloud checking. If false, no cloud calls will be done.
 */
class RobotManager extends SyncManager {
    private model:Model;
    private rootNode:Node;
    private robotClient:any;

    constructor(httpUrl:string, enableCloud:boolean=true) {
        super(httpUrl, 'robot properties', SYNC_PERIODIC_SECONDS * 1000, enableCloud);
    }


    public init(callback:ErrCallback) {
        super.init( (err) => {
            log.iferr(err, 'super.init()');
            if (err) {
                callback(err);
            } else {
                this.model = kb.createModel(KB_SLICE_NAME, this.httpUrl);
                this._preloadRobotModel( () => {
                    log.info('local cached robot properties loaded, count: ', this._robotSize());
                    if (SyncManager.canSkipFullSync) {
                        // let things proceed and do the first sync in the background
                        log.info('doing first full sync in the background');
                        callback();
                        callback = ()=>{return;};
                    }
                    if (this.enableCloud) {
                        log.info('starting robot properties cloud syncing...');
                        this._syncWithCloud((/*err*/) => {
                            log.info('local robot properties count after syncing: ', this._robotSize());
                            this._syncOnNotification('RobotUpdated');
                            callback();
                            this._startSyncTimer();
                        });
                    } else {
                        callback();
                    }
                });
            }
        });
    }


    protected _syncWithCloud(callback:ChangedCallback) {
        this._setupClients();
        this._startTimer();
        this._lookupRobotId( (err, robotId) => {
            if (!err) {
                this.robotClient.getRobot({id: robotId}, (err, data) => {
                    this._endTimer('JSC server call Robot#getRobot()');
                    log.iferr(err, 'JSC server call Robot#getRobot()');
                    if (!err) {
                        this._applyRobotChanges(data, (err, changed) => {
                            log.iferr(err, '_applyRobotChanges');
                            callback(err, changed);
                        });
                    } else {
                        callback(err);
                    }
                });
            } else {
                callback(err);
            }
        });
    }


    protected _updated(callback:ErrCallback) {
        // Emit a RobotChanged event; KBService will broadcast this over
        // a WebSocket so that KB Models (like RobotModel) can listen for it
        log.info('robot properties updated; emitting a RobotChanged event');
        this.emit('RobotUpdated');
        process.nextTick(callback);
    }


    private _preloadRobotModel(callback:ErrCallback) {
        this.model.loadRoot( (err, rootNode) => {
            log.iferr(err, 'model.loadRoot');
            this.rootNode = rootNode;
            callback();
        });
    }


    private _robotSize():number {
        if (!this.rootNode || !this.rootNode.data) {
            return 0;
        }
        return Object.keys(this.rootNode.data).length;
    }


    private _setupClients() {
        if (!this.robotClient) {
            this.robotClient = new JSC.Robot();
        }
    }


    private _lookupRobotId(callback:IdCallback) {
        let loop = new Model(KB_LOOP_NAME, this.httpUrl);
        loop.loadRoot( (err, root) => {
            log.iferr(err, 'loop.loadRoot');
            if (!err) {
                log.debug('using robot id', root.data.robotFriendlyId);
                callback(null, root.data.robotFriendlyId);
            } else {
                callback(err);
            }
        });
    }


    private _applyRobotChanges(cloudRobot:any, callback:ChangedCallback) {
        let rootNode = this.rootNode;

        let newData: any = {};
        Object.assign(newData, cloudRobot.payload);
        newData.id      = cloudRobot.id;
        newData.updated = cloudRobot.updated;
        newData.created = cloudRobot.created;

        let changed = false;
        if (!this._deepEqual(newData, rootNode.data)) {
            rootNode.data = newData;
            changed = true;
        }

        if (changed) {
            log.info('robot changed. saving...');
            rootNode.save( (err) => {
                log.iferr(err, 'rootNode.save');
                log.info('finished saving robot');
                log.debug('new robot properties', rootNode.data);
                callback(null, changed);
            });
        } else {
            callback();
        }
    }
}


export default RobotManager;
