import {expression} from 'jibo-expression-client';
import BodyClient from './clients/BodyClient';
import {PromiseUtils} from 'jibo-cai-utils';
import {RegistrationRecord, RegistryClient} from 'jibo-service-framework';
import * as async from 'async';
import * as services from 'jibo-service-clients';
import {api as jetstream} from '@jibo/jetstream-client';
import log from './log';

const prfy = PromiseUtils.promisify;
const prfyTo = PromiseUtils.promisifyTo;

declare type Callback<T = void> = (err?: Error, result?: T) => void;
declare type InitCallback = (done: Callback) => void;


export default class ClientInitializer {

    public static expression(record: RegistrationRecord): InitCallback {
        return (done: Callback) => {
            expression.init(record.port, {} as any)
            .then(() => done())
            .catch(err => done(err));
        };
    }
    
    public static jetstream(record: RegistrationRecord): InitCallback {
        return (done: Callback) => {
            jetstream.init({hostname: record.host, port: record.port}, log)
            .then(() => done())
            .catch(err => done(err));
        };
    }

    public static getClientInits(
        // Services whose clients we want to init right now
        serviceNames: string[],
        // Callback with an array of init callbacks (void callbacks)
        callback: Callback<async.AsyncFunction<void, Error>[]>,
    ): void {
        const jiboServiceClients: RegistrationRecord[] = [];
        const inits: InitCallback[] = [];
        // Wait for any services that we need, but that aren't yet initialized
        // (can't be found yet in the registry)
        async.each<string, Error>(serviceNames, async (name, callback) => {
            try {
                const record =
                    await ClientInitializer._waitForService(name);
                switch(record.name) {
                    case 'expression':
                        inits.push(ClientInitializer.expression(record));
                        break;
                    case 'jetstream':
                        inits.push(ClientInitializer.jetstream(record));
                        break;
                    case 'body':
                        BodyClient.createInstance('127.0.0.1', record.port);
                        // Fall through
                    case 'audio':
                    case 'media':
                    case 'media-manager':
                    case 'wifi':
                        // Add to the list of clients we want jibo-service-clients
                        // to init
                        jiboServiceClients.push(record);
                        break;
                }
                callback();
            } catch (e) {
                callback(e);
            }
        }, err => {
            if (err) {
                return callback(err);
            }
            inits.push((done: Callback) => {
                services.init({}, jiboServiceClients, done);
            });
            callback(null, inits);
        });
    }

    private static async _waitForService(
        service: string,
    ): Promise<RegistrationRecord> {
        let attempts = 0;
        // Attempt every 1/2 second for one minute before giving up
        while (attempts++ < 120) {
            const [getErr, record] = await prfyTo<RegistrationRecord>(cb =>
                RegistryClient.instance.getRecordByName(service, cb));
            if (getErr) {
                await prfy(cb => setTimeout(cb, 500));
            } else {
                return record;
            }
        }
        throw new Error(`Giving up waiting for ${service} service after one minute`);
    }
}
