import {HTTPClient} from 'jibo-service-framework';
import parentLog from './log';

const log = parentLog.createChild('DevShell');

type ErrCallback = (err?) => void;

class DevShellClient extends HTTPClient {


    private static _instance:DevShellClient;

    public static createInstance(host:string, port:number):DevShellClient {
        return new DevShellClient(host, port);
    }

    constructor(public host:string, public port:number) {
        super(host, port);
        DevShellClient._instance = this;
    }

    resetProxy(serverPort:number, callback:ErrCallback) {
        this.postJSON(`/reset-proxy/${serverPort}`, {}, (err:Error, res:any) => {
            log.iferr(err, 'Error posting');
            callback(err);
        });
    }
}

export default DevShellClient;
