import {SystemManagerClient} from "jibo-client-framework";
import WSListener from './WSListener';
import {PromiseUtils} from 'jibo-cai-utils';
const promisify = PromiseUtils.promisify;
import parentLog from '../log';
const log:typeof parentLog = parentLog.createChild("StatusHandler");

export enum WIFI_STATES {
    INIT = -1,
    SCANNING = 0,
    AUTHENTICATING = 1,
    FOUR_WAY_HANDSHAKE = 2,
    CONNECTED = 3,
    DISCONNECTED = 4
}

const WIFI_STATE_STRINGS = {
    [WIFI_STATES.INIT]: 'INIT',
    [WIFI_STATES.SCANNING]: 'SCANNING',
    [WIFI_STATES.AUTHENTICATING]: 'AUTHENTICATING',
    [WIFI_STATES.FOUR_WAY_HANDSHAKE]: '4WAY_HANDSHAKE',
    [WIFI_STATES.CONNECTED]: 'COMPLETED',
    [WIFI_STATES.DISCONNECTED]: 'DISCONNECTED'
};

const INTERVAL_CONNECTED = 15000;
export const INTERVAL_DISCONNECTED = 5000;
const INTERVAL_BUSY = 1000;

const SCAN_COUNT_BEFORE_DISCONNECT = 5;

const CONNECTED_MESSAGE = /^\s?<3>CTRL-EVENT-CONNECTED/;

/*
Status Handler runs as an event which wil be polled every X amount of time.
This essentially controls all the events that will happen.
*/

export default class StatusHandler implements WSListener {
    //interval timer
    private listener:NodeJS.Timer;
    //callback for when state changes between connected and disconnected
    private stateChangeCallback:(state:WIFI_STATES) => void;
    //previous verbose status
    private lastState:WIFI_STATES;
    //if we are connected to the access point (not full internet connection)
    private assumedConnected:boolean;
    //when disconnected, the state is usually SCANNING, so we should track it to determine
    //if we might be disconnected
    private scanCount:number;

    constructor(){
        this.lastState = WIFI_STATES.INIT;
        this.listener = null;
        this.stateChangeCallback = null;
        this.assumedConnected = false;
        this.scanCount = 0;
        this.onInterval = this.onInterval.bind(this);
        this.statusCB = this.statusCB.bind(this);
    }

    handleWSMessage(message:string):void {
        if (message.match(CONNECTED_MESSAGE)) {
            this.lastState = WIFI_STATES.CONNECTED;
            this.assumedConnected = true;
            this.scanCount = 0;
            if (this.stateChangeCallback) {
                this.stateChangeCallback(this.lastState);
            }
            this.adjustPollRate();
        }
    }

    public status(): Promise<any> {
        return promisify((cb) => SystemManagerClient.instance.wifiStatus(cb));
    }

    public listen(interval:number, listener:(state:WIFI_STATES) => void) {
        this.stateChangeCallback = listener;
        this.setInterval(interval);
    }

    public stopListener(){
        clearInterval(this.listener);
    }

    private setInterval(interval:number) {
        if(this.listener) {
            clearInterval(this.listener);
        }
        this.listener = setInterval(this.onInterval, interval);
    }

    private onInterval():void {
        SystemManagerClient.instance.wifiStatus(this.statusCB);
    }

    //When the status is polled.
    private statusCB(err:Error, data:string) {
        if (err) {
            log.error("statusCB error: " + err);
            return;
        }

        let tempState:WIFI_STATES = WIFI_STATES.INIT;
        //No connection currently
        if (data.indexOf(WIFI_STATE_STRINGS[WIFI_STATES.SCANNING]) > -1) {
            tempState = WIFI_STATES.SCANNING;
        }
        else if (data.indexOf(WIFI_STATE_STRINGS[WIFI_STATES.AUTHENTICATING]) > -1) {
            tempState = WIFI_STATES.AUTHENTICATING;
        }
        else if (data.indexOf(WIFI_STATE_STRINGS[WIFI_STATES.FOUR_WAY_HANDSHAKE]) > -1) {
            tempState = WIFI_STATES.FOUR_WAY_HANDSHAKE;
        }
        else if (data.indexOf(WIFI_STATE_STRINGS[WIFI_STATES.CONNECTED]) > -1) {
            tempState = WIFI_STATES.CONNECTED;
        }
        else if (data.indexOf(WIFI_STATE_STRINGS[WIFI_STATES.DISCONNECTED]) > -1) {
            tempState = WIFI_STATES.DISCONNECTED;
        }

        this.stateCB(tempState);
    }

    /*
     Called everytime the state is polled(default is every two seconds).
     */
    // @TODO - clean up this method (big-ass switch);
    private stateCB(currentState:WIFI_STATES) {
        let adjustRate:boolean = false;
        let doCallback = false;

        if (this.lastState === WIFI_STATES.SCANNING && currentState !== WIFI_STATES.SCANNING) {
            this.scanCount = 0;
        }

        switch (currentState) {
            //Don't foresee when this specific case(-1) will ever happen, but we should catch it in case
            case WIFI_STATES.INIT: //JUST BOOTED
                adjustRate = true;
                break;

            case WIFI_STATES.SCANNING: //SCANNING
                switch (this.lastState) {
                    case WIFI_STATES.SCANNING:
                        //if we are scanning repeatedly for several seconds straight, then assume
                        //that we are disconnected and let WifiManager know
                        //in testing, it seems like a disconnected robot spends a lot of time in a
                        //scanning state
                        if (++this.scanCount === SCAN_COUNT_BEFORE_DISCONNECT) {
                            this.assumedConnected = false;
                            doCallback = true;
                        }
                        break;
                    case WIFI_STATES.INIT: //Jibo went from being turned on -> SCANNING
                    case WIFI_STATES.CONNECTED: //Jibo went from CONNECTED -> SCANNING
                        adjustRate = true;
                        break;
                }
                break;

            case WIFI_STATES.CONNECTED: //CONNECTED
                //perform callback if we previously thought that we were not connected
                doCallback = !this.assumedConnected;
                this.assumedConnected = true;
                if (this.lastState !== WIFI_STATES.CONNECTED) {
                    adjustRate = true;
                }
                break;

            case WIFI_STATES.DISCONNECTED: //DISCONNECTED
                //perform callback if we previously thought that we were connected
                doCallback = this.assumedConnected;
                this.assumedConnected = false;
                switch (this.lastState) {
                    case WIFI_STATES.SCANNING: //Jibo went from SCANNING -> DISCONNECTED
                    case WIFI_STATES.CONNECTED: //Jibo went from CONNECTED -> DISCONNECTED
                        adjustRate = true;
                        break;
                }
                break;
        }

        this.lastState = currentState;

        if (doCallback && this.stateChangeCallback) {
            //Check connection status - wifiManager.inProgress will make sure wifiManager doesn't handle API features
            this.stateChangeCallback(currentState);
        }

        if (adjustRate) {
            this.adjustPollRate();
        }
    }

    private adjustPollRate() {
        switch (this.lastState) {
            case WIFI_STATES.CONNECTED:
                //slow polling when we are connected to access point
                this.setInterval(INTERVAL_CONNECTED);
                break;
            case WIFI_STATES.DISCONNECTED:
                //moderate polling when we are not connected
                this.setInterval(INTERVAL_DISCONNECTED);
                break;
            default:
                //fast polling during scan/process of connection
                this.setInterval(INTERVAL_BUSY);
                break;
        }
    }
}
