import { ServiceOptions, HTTPWSService, JiboServerRequest, JiboServerResponse} from 'jibo-service-framework';
import Router = require('router');
import WebSocket = require('ws');
import parentLog from '../log';
import {SSMService} from '../../SSMService';

class SecureTransferServiceSim extends HTTPWSService implements SSMService {
    private static _instance: SecureTransferServiceSim = null;

    private _log:typeof parentLog = parentLog.createChild('STS');
    private _isUGCKeyReadyToggle:boolean = false;
    private _hasBackupDataToggle:boolean = false;

    public static get instance(): SecureTransferServiceSim {
        return SecureTransferServiceSim._instance;
    }

    constructor(options:ServiceOptions, rootDir: string) {
        super('secure-transfer', options, rootDir);
        if (SecureTransferServiceSim._instance) {
            throw new Error('Cannot instantiate SecureTransferServiceSim more than once');
        }
        SecureTransferServiceSim._instance = this;

        this._log.info("Instantiated");
    }

    public init(callback: (err?:Error)=>void) {
        super.init((err:Error) => {
            this._log.info('Initialized');
            callback(err);
        });
    }

    protected onMessage(message: any, client: WebSocket): void {
        return;
    }

    public toggleBackupDataExists(dataExists:boolean):void {
        this._hasBackupDataToggle = dataExists;
    }

    public toggleUGCKeyReady(isReady:boolean):void {
        this._isUGCKeyReadyToggle = isReady;
    }

    public routes(url:Router):void {
        super.routes(url);

        url.get('/UGCKeyReady', (req:JiboServerRequest, res:JiboServerResponse) => {
            this._isUGCKeyReady(req, res);
        });

        url.get('/hasBackupData', (req:JiboServerRequest, res:JiboServerResponse) => {
            this._hasBackupData(req, res);
        });
    }

    // handles client requests (sim only) on whether the UGC Key is ready or not
    private _isUGCKeyReady(req:JiboServerRequest, res:JiboServerResponse):void {
        try {
            this.sendJson(res, { status: 'OK', isReady: this._isUGCKeyReadyToggle }, 200);
        } catch(ex) {
            this.sendJson(res, { status: 'error', message: ex }, 500);
        }
    }

    // handles client requests (sim only) on whether there exists backup data or not
    private _hasBackupData(req:JiboServerRequest, res:JiboServerResponse):void {
        try {
            this.sendJson(res, { status: 'OK', isReady: this._hasBackupDataToggle }, 200);
        } catch(ex) {
            this.sendJson(res, { status: 'error', message: ex }, 500);
        }
    }
}

export default SecureTransferServiceSim;
