import VisualAwareness from './VisualAwareness';
import Router = require('router');
import AudioAwareness from './AudioAwareness';
import http = require("http");
import {Target} from "./VisualAwareness";
import {Entity} from "./VisualAwareness";
import {AudioEntity} from "./AudioAwareness";
import {Point3} from "./VisualAwareness";
import {JiboServerRequest, JiboServerResponse, ServiceOptions, HTTPWSService, WebSocket} from 'jibo-service-framework';
import {Clock} from 'animation-utilities';
import {SSMService} from '../../SSMService';

import parentLog from '../log';
const log = parentLog.createChild('LPS');

//standin for window.performance.now()
const performance = {
    now: () => {
        const time = process.hrtime();
        return time[0] * 1000 + time[1] / 1000000;
    }
};

class LPSService extends HTTPWSService implements SSMService {

    private static _instance:LPSService;

    //for unit test purposes
    public lastPicturePath:string;

    public visualSocket:WebSocket;
    public audibleSocket:WebSocket;

    public visualAwareness:VisualAwareness = new VisualAwareness();
    public audioAwareness:AudioAwareness = new AudioAwareness();

    private oneTimeAudioAwareness: AudioAwareness;

    private lastUpdate:number;
    private currentAudioId:number;
    private updateLoop:NodeJS.Timer;

    public static get instance():LPSService {
        return LPSService._instance;
    }

    constructor(options:ServiceOptions, rootDir:string) {
        super('lps', options, rootDir);
        if (LPSService._instance) {
            throw new Error('Cannot instantiate LPSService more than once');
        }
        LPSService._instance = this;
        this.onBarcode = this.onBarcode.bind(this);
        this.onDemandDetect = this.onDemandDetect.bind(this);
        this.onFaces = this.onFaces.bind(this);
        this.update = this.update.bind(this);

        log.info("Instantiated");
    }

    public init(callback: (err?:Error)=>void) {
        super.init((err:Error) => {
            this.lastUpdate = performance.now();
            this.updateLoop = setTimeout(this.update, 100);
            log.info('Initialized');
            callback(err);
        });
    }

    public pause(): void {
        if (this.updateLoop) {
            log.info('Pausing LPSService');
            clearTimeout(this.updateLoop);
            this.updateLoop = null;
        }
    }

    public resume(): void {
        if (!this.updateLoop) {
            log.info('Resuming LPSService');
            this.updateLoop = setTimeout(this.update, 100);
        }
    }

    // gets the visual lps entity which matches audio id, or false
    // @private
    public getVisualEntityFromId(id:number) {
        let ent;
        this.visualAwareness.entities.forEach((entity) => {
            if(entity.id === id) {
                ent = entity;
            }
        });
        return ent;
    }

    // Triggers a fake localized HJ event (used from Simulator)
    // @private
    public triggerSimulatedHJEvent() {
        const audioEntity = new AudioEntity(1); // Type 1 is HJ
        const fakePos = new Point3(); // Fake position in front of Jibo
        fakePos.x = 1;
        fakePos.y = 0;
        fakePos.z = 0.7;
        audioEntity.updatePosition(fakePos);
        if (!this.oneTimeAudioAwareness) {
            this.oneTimeAudioAwareness = new AudioAwareness();
        }
        this.oneTimeAudioAwareness.entities.push(audioEntity);
    }

    public triggerAudioEvent(position:Point3) {
        let audioEntity = new AudioEntity();
        audioEntity.updatePosition(position);
        audioEntity.confidence = 100;
        this.audioAwareness.entities.push(audioEntity);
        // keep track of currently sounding audio
        this.currentAudioId = audioEntity.id;
        this.emit('audio-event-start', position, audioEntity.id);
    }

    public triggerAudioEventEnd() {
        // keep track so other events can be fired
        let tempId:number = this.currentAudioId;
        this.emit('audio-event-end', tempId);
        setTimeout(() => {
            this.removeAudioEntityById(tempId);
        }, 3000);
    }

    // gets the audio lps entity which matches audio id, or false
    // @private
    public getAudioEntityFromId(id:number):AudioEntity {
        for(let i = 0; i < this.audioAwareness.entities.length; i++) {
            if(this.audioAwareness.entities[i].id === id) {
                return this.audioAwareness.entities[i];
            }
        }
    }

    public getAudioEntities():AudioEntity[] {
        return this.audioAwareness.entities;
    }


    // removes the audio lps entity which matches audio id, or false if no such entity
    // @private
    public removeAudioEntityById(id:number):boolean {
        // var ent;
        let iter = -1;
        for(let i = 0; i < this.audioAwareness.entities.length; i++) {
            if(this.audioAwareness.entities[i].id === id) {
                iter = i;
                break;
            }
        }
        if(iter !== -1) {
            this.audioAwareness.entities.splice(iter, 1);
            return true;
        }
        return false;
    }

    public onVisualEntityAudio(id) {
        let visualEntity = this.getVisualEntityFromId(id);
        this.triggerAudioEvent(visualEntity.position);
        //this.update();
    }

    public setTargetId(id:number, value:number) {
        this.visualAwareness.entities.forEach((entity) => {
            if(entity.id === id) {
                entity.id = value;
            }
        });
    }

    public getEntities():Entity[] {
        return this.visualAwareness.entities;
    }

    public updateTarget(target:Target) {

        let ent:Entity = this.getVisualEntityFromId(target.id);
        //None of the current entities match this target
        if(!ent) {
            ent = new Entity(target);
            this.visualAwareness.entities.push(ent);
        }
        let ts:[number, number] = Clock.currentTime()._timestamp;
        let needVATSUpdate:boolean = ent.updatePosition(target, ts);
        if (needVATSUpdate) {
            this.visualAwareness.updateTimestamp(ts);
        }
        //this.update(true);
        this.emit('update', target);
    }

    public removeEntity(id:number) {
        let index;
        for(let i = 0; i < this.visualAwareness.entities.length; i++) {
            if(this.visualAwareness.entities[i].id === id) {
                index = i;
                break;
            }
        }
        if(index || index === 0) {
            this.visualAwareness.entities.splice(index, 1);
        }
    }

    protected onMessage(command:any, client:WebSocket):void {
        return;
    }

    public onConnection(client:WebSocket, request:http.IncomingMessage):void {
        super.onConnection(client, request);
        if(client.url === '/lps/visual_awareness') {
            this.visualSocket = client;
        }
        else if(client.url === '/lps/audible_awareness') {
            this.audibleSocket = client;
        }
    }

    protected onClose(client:WebSocket):void {
        if(client === this.audibleSocket) {
            this.audibleSocket = undefined;
        }
        else if(client === this.visualSocket) {
            this.visualSocket = undefined;
        }
    }

    public routes(url:Router) {
        super.routes(url);
        url.post('/lps/barcode', this.onBarcode);
        url.post('/lps/demand_detect', this.onDemandDetect);
        url.post('/lps/faces', this.onFaces);
    }

    private onFaces(req:JiboServerRequest, res:JiboServerResponse) {
        res.writeHead(200, {'Content-Type': 'json'});
        res.end(JSON.stringify(this.visualAwareness.entities));
    }

    private onBarcode(req:JiboServerRequest, res:JiboServerResponse) {
        this.finishNoContent(res, 200);
    }

    private onDemandDetect(req:JiboServerRequest, res:JiboServerResponse) {
        res.writeHead(200, {'Content-Type': 'json'});
        res.end(0);
    }

    private update(force:boolean = false) {
        this.updateLoop = setTimeout(this.update, 100);
        let now:number = performance.now();
        if(now - this.lastUpdate >= 100 || force) {
            this.lastUpdate = now;
            if(this.visualSocket) {
                this.sendWsJson(this.visualSocket, this.visualAwareness);
            }
            if(this.audibleSocket) {
                if (this.oneTimeAudioAwareness) {
                    this.oneTimeAudioAwareness.entities =
                      this.oneTimeAudioAwareness.entities.concat(this.audioAwareness.entities);
                    this.sendWsJson(this.audibleSocket, this.oneTimeAudioAwareness);
                    this.oneTimeAudioAwareness = null;
                }
                else {
                    this.sendWsJson(this.audibleSocket, this.audioAwareness);
                }
            }
        }
    }

}

export default LPSService;
