import Router = require('router');
import {
    HTTPWSService,
    JiboServerRequest,
    JiboServerResponse,
    ServiceOptions,
    WebSocket,
} from 'jibo-service-framework';
import http = require('http');
import {GlobalCommand, GlobalCommandMap} from 'jibo-common-types';
import SkillsService from '../skills/SkillsService';
import SkillsServiceSim from '../../sim-services/skills/SkillsServiceSim';
import {SSMService} from '../../SSMService';
import {Event as TypedEvent} from 'jibo-typed-events';
import {api as jetstream, types, HotwordModeToken} from '@jibo/jetstream-client';

import rootLog from '../log';
export const log:typeof rootLog = rootLog.createChild('GlobalService');

const GLOBAL_RULES = ['globals/global_commands_launch'];

/**
 * @description
 * This class handles incoming requests to subscribe to global commands and manages
 * the state of those commands by accepting not only the command to which a skill
 * wants to subscribe and keeping track of all of the different global event stacks,
 * but also maintains knowledge of which skill subscribed to that global.
 * Because this service also handles relaunching and launching skills, at each skill
 * launch (or relaunch) it automatically unsubscribes that skill from the global event
 * stacks, so state is maintained across skill instances.
 * @class GlobalManagerService
 */
class GlobalManagerService extends HTTPWSService implements SSMService {

    private static _instance: GlobalManagerService;

    /**
     * Map from global command to whether jibo can handle it
     * @type {Map<GlobalCommand, boolean>}
     * @readonly
     */
    public globalHandlers: Map<GlobalCommand, boolean>;
    /**
     * Event to let other parts of SSM know we have fired a skillRelaunch
     * @type {TypedEvent<jibo.jetstream.types.ListenResult>}
     * @readonly
     */
    public skillRelaunch: TypedEvent<types.ListenResult>;
    /**
     * Event to let other parts of SSM know we have gotten a global event
     * @type {TypedEvent<jibo.jetstream.types.ListenResult>}
     * @readonly
     */
    public globalEvent: TypedEvent<types.ListenResult>;
    private globalSocket: WebSocket;
    private globalRuleToken: HotwordModeToken;

    public static get instance(): GlobalManagerService {
        return GlobalManagerService._instance;
    }

    constructor(options: ServiceOptions, rootDir: string) {
        super('global-manager', options, rootDir);
        if (GlobalManagerService._instance) {
            throw new Error('Cannot instantiate GlobalManagerService more than once');
        }
        GlobalManagerService._instance = this;
        this.onSetGlobal = this.onSetGlobal.bind(this);
        this.handleSkillLaunch = this.handleSkillLaunch.bind(this);
        this.skillRelaunch = new TypedEvent<types.ListenResult>('Skill relaunch sent through socket.');
        this.globalEvent = new TypedEvent<types.ListenResult>('Global event sent through socket.');

        // initialize map of global handlers
        this.globalHandlers = new Map<GlobalCommand, boolean>();
        Object.keys(GlobalCommand).forEach((command) => {
            log.debug('handling', command);
            this.globalHandlers.set(GlobalCommand[command], false);
        });
        log.info('Instantiated');
    }

    public init(callback: (err?: Error) => void) {
        super.init((err: Error) => {
            //clear any globals hanging around from previous SSMs/Be
            jetstream.unsubscribeAllGlobals()
            .catch((err) => {
                log.info('Unable to unsubscribe globals when starting up', err);
            })
            .then(() => {
                jetstream.events.skillSwitch.on(this.handleSkillLaunch);
                this.globalRuleToken = jetstream.setHotwordMode(jetstream.types.HotwordListenMode.Custom_NLU_Added, GLOBAL_RULES);
                this.globalRuleToken.match.on((result) => {
                    this.onGlobalParse(result);
                });
                log.info("Initialized");
                callback(err);
            });
        });
    }

    public routes(url: Router) {
        super.routes(url);
        url.post('/global', (req: JiboServerRequest, res: JiboServerResponse) => {
            this.onSetGlobal(req, res);
        });
        url.post('/clean_relaunch', (req: JiboServerRequest, res: JiboServerResponse) => {
            this.onCleanRelaunch(req, res);
        });
    }

    public onConnection(client: WebSocket, request:http.IncomingMessage): void {
        super.onConnection(client, request);
        if (client.url === '/globals') {
            this.globalSocket = client;
        }
    }

    public sendWsJson(client: WebSocket, json: Object | string): Promise<boolean> {
        if (client) {
            return super.sendWsJson(client, json);
        } else {
            return Promise.resolve(false);
        }
    }

    protected onMessage(command: any, client: WebSocket) {
        return;
    }

    protected onClose(): void {
        // Happens on skill crash!
        this.globalSocket = undefined;
    }

    /**
     * Launch or relaunch a skill
     * Send out actual event for which skills will listen.
     * Alert Skills Service to switch skills.
     * @intdocs
     */
    public handleSkillLaunch(result: types.SkillSwitchResult|types.ListenResult) {
        log.debug('handling skill launch', result);

        const instance = SkillsService.instance || SkillsServiceSim.instance;

        let skillName:string;
        let parse:types.ListenResult;
        if (result instanceof types.ListenResult) {
            skillName = result.match.skillID;
            parse = result;
        } else {
            skillName = result.onRobot ? result.skillID : '@be/nimbus';
            let matchPayload: types.GlobalAndCloudMatchResponseData = {
                skillID: skillName,
                onRobot: result.onRobot,
                isProactive: result.isProactive,
                skipSurprises: result.skipSurprises,
            };
            // If it's a Nimbus/cloud-skill, attach the cloud-skill name onto the match payload
            if (!result.onRobot) {
                matchPayload.cloudSkill = result.skillID;
            }
            const data:types.ListenResult = result.data || {asr: null, nlu: null} as any;
            parse = new types.ListenResult(data.asr, data.nlu, matchPayload);
            parse.transID = result.transID;
        }
        // relaunch
        if (instance &&
            instance.currentSkill && (
                instance.currentSkill.name === skillName ||
                instance.currentSkill.name.startsWith('@be/'))) {
            log.debug('Emitting skillRelaunch');
            this.skillRelaunch.emit(parse);
            let body = this.returnType('OK', 'skill-relaunch', '', parse);
            this.sendWsJson(this.globalSocket, body);
        }
        // launch
        else {
            log.debug('Emitting launch');
            let body: any = this.returnType('OK', 'skill-launch', '', parse);
            this.sendWsJson(this.globalSocket, body);
        }
        return;
    }

    private onGlobalParse(data:types.SuccessTurnResult):void {
        log.debug("onGlobalParse");
        let intent:string = data.result.nlu.intent;
        //special case volume because it has a few intents that all start with 'volume'
        if (intent.match(/^volume/)) {
            intent = 'volume';
        }

        const result = new types.ListenResult(data.result.asr, data.result.nlu);

        // The global grammar parsed this, but we're not expecting it!
        const command = GlobalCommandMap.get(intent);

        if(!command) {
            //Disable old behavior of complaining, because how we detect global commands will
            //change in some way in the near future. Currently skill launches will hit this block

            //log.error("unrecognized global command", intent);
            //this.sendNonInterrupting();
            return;
        }
        // Jibo module has said it can handle global event
        else if(this.canHandleGlobal(command)) {
            log.debug("Letting skill handle global", intent);
            this.emitGlobal(command, result);
        }
        else {
            log.debug("default global behavior for ", intent);
            switch(command) {
                case GlobalCommand.STOP:
                    // no one in jibo can handle stop, handle launch with @be/idle
                    result.match = {
                        skillID: '@be/idle',
                        onRobot: true
                    };
                    this.handleSkillLaunch(result);
                    break;
                case GlobalCommand.HELP:
                    result.match = {
                        skillID: '@be/friendly-tips',
                        onRobot: true
                    };
                    this.handleSkillLaunch(result);
                    break;
                case GlobalCommand.SLEEP:
                    result.match = {
                        skillID: '@be/idle',
                        onRobot: true
                    };
                    this.handleSkillLaunch(result);
                    break;
                case GlobalCommand.PAUSE:
                    result.match = {
                        skillID: '@be/idle',
                        onRobot: true
                    };
                    this.handleSkillLaunch(result);
                    break;
                case GlobalCommand.HOLDON:
                    result.match = {
                        skillID: '@be/idle',
                        onRobot: true
                    };
                    this.handleSkillLaunch(result);
                    break;
                case GlobalCommand.WHATCANIDO:
                    result.match = {
                        skillID: '@be/friendly-tips',
                        onRobot: true
                    };
                    this.handleSkillLaunch(result);
                    break;
                case GlobalCommand.VOLUME:
                    log.info("not yet setting volume in SSM");
                    // inform anything listening in the skill that we aren't interrupting state
                    // and it is okay to continue
                    this.sendNonInterrupting();
                    break;
                case GlobalCommand.OVERHERE:
                    this.sendNonInterrupting();
                    break;
                case GlobalCommand.TURNAROUND:
                // intentionally let this fall to TURNAWAY until we differentiate between TurnAround and TurnAway
                case GlobalCommand.TURNAWAY:
                    result.match = {
                        skillID: '@be/idle',
                        onRobot: true
                    };
                    this.handleSkillLaunch(result);
                    break;
                default:
                    log.error('Unrecognized global command: ', command);
                    this.sendNonInterrupting();
                    break;
            }
        }
    }

    /**
     * Given a global command, returns whether or not the jibo module has registered to handle it.
     * @param {GlobalCommand} command to query if jibo module has said it can handle
     * @returns {Boolean} returns whether or not the jibo module can handle the global command.
     * @private
     */
    private canHandleGlobal(command: GlobalCommand) {
        log.debug(`getting canHandle ${command} which is ${this.globalHandlers.get(command)}`);
        return this.globalHandlers.get(command);
    }

    private emitGlobal(command: GlobalCommand, globalResults: types.ListenResult) {
        log.debug('emitting global', globalResults);
        this.globalEvent.emit(globalResults);
        let body: any = this.returnType('OK', 'global', '', globalResults);
        this.sendWsJson(this.globalSocket, body);
    }

    private sendNonInterrupting():void {
        let body = this.returnType('OK', 'non-interrupting-global', '', {});
        this.sendWsJson(this.globalSocket, body);
    }

    /**
     * Parse out global command subscribers
     * @param req {JiboServerRequest} the request data to be processed.
     * @param res {JiboServerResponse} the response to send through WS.
     * @private
     */
    private onSetGlobal(req: JiboServerRequest, res: JiboServerResponse) {
        let rawData = '';
        req.on('data', (chunk) => {
            rawData += chunk;
        });
        req.on('end', () => {
            let data:any;
            try {
                data = JSON.parse(rawData);
            } catch (e) {
                log.warn('Unable to parse set global JSON:', rawData);
                let body = this.returnType('ERROR', 'Unable to parse request', '', {});
                this.sendJson(res, JSON.stringify(body), 400);
                return;
            }
            this.globalHandlers.set(data.action, data.canHandle);
            let body = this.returnType('OK', JSON.stringify(data.action + ':' + data.canHandle), '', {});
            this.sendJson(res, JSON.stringify(body), 200);
        });
    }

    /**
     * Cleanly shut down listeners and kill the current skill and relaunch
     * @param req {JiboServerRequest} the request data to be processed.
     * @param res {JiboServerResponse} the response to send through WS.
     * @private
     */
    private onCleanRelaunch(req: JiboServerRequest, res: JiboServerResponse): void {
        req.on('data', (chunk) => {
            // req doesn't like it when you have an `end` but no data handler.
        });
        req.on('end', () => {
            //fake a types.SkillMatchResult
            const data = {
                onRobot: true,
                skillID: '@be/idle',
                data: new types.ListenResult(
                    {
                        text: 'stop',
                        confidence: 1
                    },
                    {
                        intent: 'stop',
                        rules: null,
                        entities: {}
                    }
                )
            };
            this.handleSkillLaunch(data);
            let body = this.returnType('OK', null, '', {});
            this.sendJson(res, JSON.stringify(body), 200);
        });
    }

    /**
     * Wrapper to create a return type
     * @param status {string} status of response
     * @param message {string} accompanying message of response
     * @param id {string} listener id if applicable
     * @param data {data} result of web request
     * @private
     */
    private returnType(status: string, message: string, id: string, data: any) {
        let body = {
            status: status,
            message: message,
            id: id,
            result: data || {},
            moreinfo: ''
        };
        return body;
    }
}

export default GlobalManagerService;
