import { ProcessResult } from 'jibo-cai-utils';
import { spawn, ChildProcess, SpawnOptions} from 'child_process';
import parentLog from '../log';
const log = parentLog.createChild('StatusRunner');
// log.outputs.syslog = 'debug';


// Export so consumers know what to parse
export { ProcessResult } from 'jibo-cai-utils';

/**
 * Structured results of process output
 */
export class StatusResult<T>{
    public error?: any;
    public data?: T;
}

/**
 * A description of how to update a status from a shell command.
 * @param T Type of status data
 */
export class StatusDescriptor<T> {

    /**
     * chell command to execute
     */
    public cmd: string;

    /**
     * Arguments of the shell command
     */
    public args: string[];

    /**
     * Additional options to use when creating the process (optional)
     * @see child_process.SpawnOptions
     */
    public options?: SpawnOptions;

    public input?:string;

    /**
     * Parser to convert the process output into structured results
     */
    public parser?: (res:ProcessResult)=>StatusResult<T>;
}

/**
 * Class for gathing status from an external CLI process. There are two kinds of
 * processes: fast and slow.
 * - Fast process: This takes a (relatively) small amount of time to run and
 *      is expected to quit on its own.
 * - Slow process: This is expected to run for as long as possible and will
 *      need to be killed to gather results.
 * @param {StatusDescriptor<T>} desc Description of how to update the status.
 */
export class StatusProcess<T> {

    private static _sema4: Set<string> ;

    private _status: StatusResult<T>;

    private _desc: StatusDescriptor<T>;

    private _name: string;

    private _proc: ChildProcess;

    private _res: ProcessResult;

    private _promiseData: Promise<StatusResult<T>>;

    private _timer: NodeJS.Timer;

    private _log: typeof log;


    constructor(desc:StatusDescriptor<T>, name?: string){
        if(!StatusProcess._sema4){
            StatusProcess._sema4 = new Set<string>();
        }
        this._desc = desc;
        this._status = undefined;
        this._name = (name || desc.cmd).replace('.','_');

        // Log all events of this process in a child named for it
        this._log = log.createChild(this._name) ;

        // Catch and forward SIGINT to child to make sure it dies.
        (process as NodeJS.EventEmitter).on('SIGINT',()=>{
            this._log.info(`received SIGINT: stopping process with pid:${this._proc.pid}`);
            this.stop();
        });

        // start the process and begin populating status
        this.start(this._desc);
    }

    /**
     * Fetch the descriptor for this process.
     * @return Frozen copy of the descriptor
     */
    public get descriptor(): StatusDescriptor<T> {
        return Object.freeze(this._desc);
    }

    /**
     * Fetch the status returned from the process
     * @return Frozen copy of the stat
     */
    public get status(): StatusResult<T> {
        return Object.freeze(this._status);
    }

    public get name(): string {
        return this._name;
    }

    /**
     * Start the process. Don't use this unless you explicitly called stop() before.
     * @param desc [description]
     */
    public start(desc?:StatusDescriptor<T>): Promise<StatusResult<T>> {
        this._log.debug('starting process');
        // Guarantee that there is onlt one of each name running
        if(StatusProcess._sema4.has(this.name)){
            this._log.error(`process with name '${this.name}' is already running`);
            throw new Error(`Duplicated process request: ${this.name}`);
        }else{
            StatusProcess._sema4.add(this.name);
        }
        // Overwrite the descriptor if provided
        if(desc){
            this._desc = desc;
        }
        // Build the promise
        this._promiseData = new Promise<StatusResult<T>>( (resolve, reject) => {
            this._res = undefined;
            // Start the shell executable
            this._proc = spawn(
                this._desc.cmd,     // The comand to execute
                this._desc.args,    // The argumants of the command
                this._desc.options  // Options specifying how to execute
            );
            let res = new ProcessResult();

            // Store the last STDOUT and STDERR of the subprocess
            // We don't want to store more than that so as to preserve memory
            this._proc.stdout.on('data', (data:Buffer) => {
                res.stdout = new Buffer(data).toString('utf8', 0);
                this._log.debug('stdout: ',res.stdout);
            });
            this._proc.stderr.on('data', (data:Buffer) => {
                res.stderr = new Buffer(data).toString('utf8', 0);
                this._log.debug('stderr: ',res.stderr);
            });

            this._proc.on('error', (err) => {
                res.error = err;
                res.code = (err as any).code;
                this._log.debug('error: ',res.error);
                this._status = this._desc.parser(this._res = res);
                this._log.debug('result: ',this._status);
                reject(this.status);
            });

            this._proc.on('close', (code) => {
                res.code = code;
                this._log.debug('close: ',res.code);
                StatusProcess._sema4.delete(this.name);
                // TODO: Should we reject at all? This makes consumers call both then *and* catch
                try{
                    this._status = this._desc.parser(this._res = res);
                    this._log.debug('result: ',this._status);
                    if (code === 0) {
                        resolve(this.status);
                    }else{
                        reject(this.status);
                    }
                }catch(err){
                    this._status = {error: err};
                    reject(this.status);
                }
            });
            if(this._desc.input){
                this._proc.stdin.write(this._desc.input);
            }
        });
        return this._promiseData;
    }

    /**
     * Stop the process if it is running.
     * @return  Did the process need to be killed?
     *          [true]  It was a slow process.
     *          [false] It was a fast process.
     */
    public stop(): boolean {
        // If the process has not yet produced results ...
        // If the process has not yet been killed ...
        if(!this._res && !this._proc.killed){
            // ... then kill it
            this._log.debug('killing process');
            this._proc.kill('SIGINT');
            return true;
        }else{
            // ... otherwise do nothing
            return false;
        }
    }

    /**
     * Refresh the status. Return results of most recent run. Runs again before
     * returning if deemed fast enough.
     * @return {Promise<StatusResult<T>>} The parsed status.
     *
     */
    public async refresh(): Promise<StatusResult<T>> {
        this._log.debug('refresh status');

        // We differentiate long and short proccess by whether or not
        // they need to be stopped.
        if(this.stop()){
            // If it is a long process, return the result from the *last* run
            // Since it's still running, we need to wait for it to die
            const ret = await Promise.race([this._promiseData])
                .then(res=>res)
                .catch(err=>err);
            this.start();
            this._log.debug('new status: ',ret);
            return ret;
        }else{
            // If it is a short process, return the result from the *next* run
            this.start();
            // Wait for the new run to finish
            const ret = await Promise.race([this._promiseData])
                .then(res=>res)
                .catch(err=>err);
            this._log.debug('new status: ',ret);
            return ret;
        }
    }

    /**
     * Autoamtically update the status on some period.
     * @param seconds   Period between updates in seconds; minimum 1 second.
     *                  Less will cancel all updates.
     */
    public autoUpdate(seconds:number): void {
        if(this._timer){
            this._log.debug('clearing update timer');
            clearTimeout(this._timer);
        }
        if(seconds < 1){
            this._log.debug('stopping auto update');
            return;
        }
        this._log.info(`setting auotUpdate: period = ${seconds}s`);
        this._timer = setInterval(()=>{
            this.refresh();
        }, seconds * 1000 );
    }

}
