import {ServiceOptions, HTTPWSService, WebSocket} from 'jibo-service-framework';
import {types} from "@jibo/jetstream-client";
import GlobalManagerService from "../global-manager/GlobalManagerService";
import ConnectionManager from './ConnectionManager';
import AssetServer from './assets/AssetServer';
import RunMode from '../../utils/RunMode';
import {InterProcessMessages, ConnectMessage, DisconnectMessage, SendErrorMessage} from './Messages';
import parentLog from './log';
const log = parentLog.createChild('RemoteService');
import {SSMService} from '../../SSMService';

/**
 * RemoteService is for passing messages to the skill process where the RemoteSkill and
 * jibo-command-library lives. This is only because much of what Remote needs to do is in the `jibo`
 * module, not the SSM.
 */
export default class RemoteService extends HTTPWSService implements SSMService {

    private static _instance:RemoteService;

    private assetServer: AssetServer;

    public static get instance():RemoteService {
        return RemoteService._instance;
    }

    private get localSocket() {
        //should only allow one connection at a time, we'll ignore anything else
        return this.connections[0];
    }

    constructor(options:ServiceOptions, rootDir:string) {
        super('remote', options, rootDir);
        if (RemoteService._instance) {
            throw new Error('Cannot instantiate RemoteService more than once');
        }
        RemoteService._instance = this;
        this.assetServer = new AssetServer();
        log.info('Instantiated');
    }

    protected async onMessage(command:any, client:WebSocket) {
        try {
            //see if the data is a message we should be handling here
            const message:InterProcessMessages = typeof command === 'string' ? JSON.parse(command) : command;
            if (message.type === 'message') {
                switch(message.status) {
                    case 'handleAsset':
                    case 'cancelAsset':
                        this.assetServer.handleMessage(message);
                        break;
                    case 'close':
                        ConnectionManager.instance.close(message.code, message.reason);
                        break;
                    case 'launchSkill':
                        log.info('Redirecting to skill');
                        // send to GMS to handle skill launching with parse results.
                        const launch = new types.ListenResult(message.result.asr, message.result.nlu, message.result.match);
                        GlobalManagerService.instance.handleSkillLaunch(launch);
                        break;
                }
                return;
            }
            //send the message from jibo-command-library on the skill side through the external
            //socket to the jibo-command-requester
            try {
                await ConnectionManager.instance.send(command);
            } catch (e) {
                //if it failed to send the message, then send it back up
                const message:SendErrorMessage = {
                    type: 'message',
                    status: 'sendError',
                    message: command
                };
                this.localSocket.send(JSON.stringify(message));
            }
        } catch (e) {
            log.warn('could not parse message from skill side', e);
        }
    }

    public init(callback: (err?:Error)=>void) {
        super.init((err?:any) => {
            if (err) {
                return callback(err);
            }
            //first get of `instance` creates a new ConnectionManager
            ConnectionManager.instance.on('connected', (appData) => {
                log.info('on connected');
                //send along an event so that the other end can start doing clock syncing, etc
                const message:ConnectMessage = {
                    type: 'message',
                    status: 'connected',
                    appData: appData
                };
                this.localSocket.send(JSON.stringify(message));
            });
            ConnectionManager.instance.on('disconnected', (isComplete:boolean) => {
                log.info('on disconnected');
                //exit current skill - need to tell remote to exit, because otherwise it is
                //uninterruptible
                if (this.localSocket) {
                    const message:DisconnectMessage = {
                        type: 'message',
                        status: 'disconnected',
                        wasError: !isComplete
                    };
                    this.localSocket.send(JSON.stringify(message));
                }
                this.assetServer.removeAll();
                //TODO: Remove this test listen when we have actual authentication coming down from server
                setTimeout(() => {
                    ConnectionManager.instance.listen(this.assetServer, RunMode.runMode === RunMode.RunMode.SIMULATOR);
                }, 10);
            });
            //pass external messages through to the skill side service
            ConnectionManager.instance.on('message', (command) => {
                this.localSocket.send(command);
            });

            // if (RunMode.runMode === RunMode.RunMode.SIMULATOR) {
            //     //if running in the simulator, then add a secret method so that we can test stuff
            //     //locally
            //     (global as any).listenForRemote = () => {
            //         ConnectionManager.instance.listen(this.assetServer, true);
            //     };
            // }
            //TODO: Remove this test listen when we have actual authentication coming down from server
            ConnectionManager.instance.listen(this.assetServer, RunMode.runMode === RunMode.RunMode.SIMULATOR);

            log.info('Initialized');
            callback();
        });
    }
}
