import {ServiceRemoteObject, RemoteService} from 'jibo-service-framework';
import {AttentionMode, AcquireOptions} from 'jibo-common-types';
import WebSocket = require('ws');
import {AttentionManager} from 'jibo-attention-manager';
import {Time, Clock} from 'animation-utilities';
import parentLog from './log';

const log = parentLog.createChild('Acquire');

export default class AcquireHandle extends ServiceRemoteObject {

    public timeFinishedInteraction:Time = null;

    private acquireHandle:any;
    private attentionHandle:any;

    constructor(
        superOptions:{base:RemoteService, owner:WebSocket},
        private options:AcquireOptions,
        private attention:AttentionManager) {
        super(superOptions);
        this.waitForPromise();
    }

    public async cancel():Promise<void> {
        if(this.acquireHandle) {
            this.acquireHandle.cancel();
            await this.acquireHandle.promise;
        }else{
            log.debug("cancel called on already-done AquireHandle");
        }
    }

    public destroy() {
        if(this.acquireHandle) {
            this.acquireHandle.cancel();
        }
        if(this.attentionHandle) {
            this.attentionHandle.release();
        }
        this.acquireHandle = undefined;
        this.attentionHandle = undefined;

        this.remove();
    }

    private async waitForPromise():Promise<void> {
        this.attentionHandle = this.attention.pushMode(AttentionMode.COMMAND);
        this.acquireHandle = this.attention.attendToTarget(
            this.options.position,
            this.options.entity
        );
        const result:any = await this.acquireHandle.promise;
        if(this.isDestroyed) { //this means the related socket was closed, and also that destroy() was called
            return;
        }
        const status = result.status;
        if (this.attentionHandle) {
            this.attentionHandle.release();
            this.attentionHandle = undefined;
        }

        //push message off stack, and after all promises resolve, to allow notification of
        //acquireTarget starting to send before these follow-up messages
        setImmediate(()=>{
            this.sendMessage<void>('onPromise', [status], true);
        });

        this.acquireHandle = undefined;

        this.timeFinishedInteraction = Clock.currentTime();
    }
}
