import * as fs from 'fs';
import * as os from 'os';
import * as path from 'path';
import axios from 'axios';
import {JSC} from '../../clients/jibo-server';
import {Log} from 'jibo-log';
import {NotificationsDispatcher} from 'jibo-service-framework';
import {RegistryClient, RegistrationRecord} from 'jibo-service-framework';
import {SecurityServer, SecurityServerOptions} from './SecurityServer';
import {SSMService} from '../../SSMService';
import {CommandRequestNotification} from './CommandRequestNotification';
import {CancelTokenSession} from 'jibo-cai-utils';

import parentLog from '../log';
const log = parentLog.createChild('SCS');

const EXTERNAL_PORT = 7160;
const INTERNAL_PORT = 8160;
const COMMAND_SOCKET_CONNECTION_TIMEOUT = 60 * 1000;  // 1 minute max to connect

export type ErrCallback = (err?:Error)=>void;
export type StreamCallback = (err:Error, stream?:NodeJS.ReadWriteStream)=>void;

export interface SecurityControllerOptions {
}

// https://confluence.jibo.com/display/ENG/System+Manager
enum DynamicFirewallMode {
    off = 'off',                            // no holes have been poked
    remote_operation = 'remote_operation',  // TCP port 7160 is opened
}

enum RunMode {
    SIMULATOR  = 'SIMULATOR',
    REMOTELY   = 'REMOTELY',
    ON_ROBOT   = 'ON_ROBOT',
    UNIT_TESTS = 'UNIT_TESTS',  // dev mode, no SSM
}


enum SCSState {
    INITING,
    STOPPED,
    STARTING,
    RUNNING,
    STOPPING,
}



class SecurityControllerService implements SSMService {
    private static _instance:SecurityControllerService;
    private securityServer: SecurityServer;
    private jscROMClient;
    private systemManagerURL: string;
    private connectionTimeout: NodeJS.Timer;
    private cancelToken: CancelTokenSession;
    private __state: SCSState;


    static get instance():SecurityControllerService {
        return SecurityControllerService._instance;
    }

    constructor(options?:SecurityControllerOptions, rootDir?: string) {
        if (SecurityControllerService._instance) {
            throw new Error('Cannot instantiate SecurityControllerService more than once');
        }
        SecurityControllerService._instance = this;
        log.info('Instantiated');
    }


    init(callback: (err?:Error)=>void) {
        log.info('Inititalizing');
        if (this.state !== undefined) {
            let err = new Error('SCS init seems to have been called more than once');
            log.error(err);
            return callback(err);
        }
        this.state = SCSState.INITING;

        this._attemptNotificationsDispatcherInit();
        this._setupJSCClients();

        // close the firewall just in case we crashed with it open and we were restarted
        this._closeFirewall(callback);
        log.info('Initialized');
    }


    private _attemptNotificationsDispatcherInit() {
        NotificationsDispatcher.instance.init(async err => {
            if (err) {
                log.info('Error initializing NotificationsDispatcher (will try again)', err);
                setTimeout( () => this._attemptNotificationsDispatcherInit(), 500);
            } else {
                log.info('NotificationsDispatcher inited.');
                try {
                    await Log.handleLogLevelNotifications(
                        NotificationsDispatcher.instance,
                    );
                }
                catch(err) {
                    log.error('Failed to set up log level notification handler', err);
                }

                this.state = SCSState.STOPPED;

                log.info('registering for "RomConnectionRequested" notifications');  // old name
                NotificationsDispatcher.instance.on('RomConnectionRequested', this._handleCommandRequestNotification.bind(this));
                log.info('registering for "CommandRequest" notifications');  // new name
                NotificationsDispatcher.instance.on('CommandRequest', this._handleCommandRequestNotification.bind(this));
            }
        });
    }


    private _handleCommandRequestNotification(commandRequest: CommandRequestNotification) {
        log.warn('CommandRequest notification', commandRequest);

        // ask the command controller if we should accept this command request
        // the access control object (ACO) is passed in here too
        let url = `http://127.0.0.1:${INTERNAL_PORT}/request`;
        let params = commandRequest;
        if (this.cancelToken) {
            this.cancelToken.cancel();
            this.cancelToken = null;
        }
        this.cancelToken = new CancelTokenSession();
        this.cancelToken.wrap(axios.post(url, params)).then(
            async (res) => {
                this.cancelToken = null;
                if (!res.data) {
                    log.error('empty response from aco to command controller');
                    return;
                }
                log.debug('posted aco to command controller and it replied', res.data);

                if (res.data.accept) {
                    if (this.state !== SCSState.STOPPED) {
                        // turn off any current connections
                        this.state = SCSState.STOPPING;
                        this._stopSecurityServer();
                        this.state = SCSState.STOPPED;
                    }

                    this._callROMSetupServer( (err, data) => {
                        if (err) {
                            log.error('error calling ROM#serverSetup, not starting security server');
                        } else {
                            //log.debug('startServer result', err, data);
                            this._startSecurityServer(data.private, data.cert, commandRequest.certFingerprint);
                        }
                    });
                }
            },
            err => {
                this.cancelToken = null;
                log.error('error posting aco to command controller', err);
            },
        );
    }


    private _startSecurityServer(serverPrivateKey, serverCertificate, clientFingerprint) {
        this.state = SCSState.STARTING;
        const securityOptions: SecurityServerOptions = {
            port: EXTERNAL_PORT,
            commandControllerPort: INTERNAL_PORT,
            key: serverPrivateKey,
            cert: serverCertificate,
            clientFingerprint,
        };

        this.securityServer = new SecurityServer(securityOptions);

        this.securityServer.on('serverStartup', () => {
            this._openFirewall( () => {
                this.state = SCSState.RUNNING;
            });
        });

        this._startTimeout();
        this.securityServer.on('commandSocketConnected', () => this._clearTimeout());
        this.securityServer.on('commandSocketDisconnected', () => this._closeFirewallStopSecurityServer());

        this.securityServer.on('invalidCertificate', () => this._onInvalidCertificate());

        this.securityServer.init( (err) => {
            if (err) {
                log.error('error starting SecurityServer', err);
            } else {
                log.info('SecurityServer started on port', this.securityServer.port);
            }
            if ((process as any)._getActiveHandles) {  // _getActiveHandles() is undocumented
                // track any leaking sockets over time
                try {
                    log.info('open socket count is', (process as any)._getActiveHandles().length);
                } catch(e) {
                    // ok continue anyway
                }
            }
        });
    }


    private _startTimeout() {
        this._clearTimeout();
        this.connectionTimeout = global.setTimeout( () => this._closeFirewallStopSecurityServer(), COMMAND_SOCKET_CONNECTION_TIMEOUT);
    }


    private _clearTimeout() {
        if (this.connectionTimeout) {
            global.clearTimeout(this.connectionTimeout);
            this.connectionTimeout = null;
        }
    }


    private _onInvalidCertificate() {
        //log.info('invalid certificate, closing server');
        //this._closeFirewallStopSecurityServer();  // this was too aggressive, didn't let a second app connect
        log.info('invalid certificate, connection rejected');
    }


    private _closeFirewallStopSecurityServer() {
        log.debug('_closeFirewallStopSecurityServer');
        this.state = SCSState.STOPPING;
        this._clearTimeout();
        this._closeFirewall();
        this._stopSecurityServer();
        this.state = SCSState.STOPPED;
    }


    private _stopSecurityServer() {
        log.debug('_stopSecurityServer');
        this._clearTimeout();
        if (this.securityServer) {
            this.securityServer.shutdown();
            this.securityServer.destroy();  // not sure we really want this
            this.securityServer = null;
            log.info('SecurityServer shut down');
        }
    }


    // send our information to the ROM cloud API indicating that we are ready
    private _callROMSetupServer(callback) {
        let ipAddress = this._getOurIPAddress();
        if (!ipAddress) {
            log.error('could not determine our ip address');
            return;
        }
        log.debug('our ip address is', ipAddress);

        this.jscROMClient.setupServer({ipAddress}, (err, data) => {
            if (err) {
                log.error('error calling ROM.setupServer()', err);
            }
            callback(err, data);
        });
    }


    private get state(): SCSState {
        return this.__state;
    }


    private set state(value: SCSState) {
        this.__state = value;
        log.debug('state set to', SCSState[this.__state]);
    }


    private _getOurIPAddress() {
        // TODO this will need more work, esp for windows and linux
        // TODO server is going to support multiple IP addresses (mainly for IPv6 support)
        let interfaces = os.networkInterfaces();
        let oneInterface;
        if (this._onRobot) {
            oneInterface = interfaces['wlan0'];
        } else {
            oneInterface = interfaces['en0'];  // osx
        }

        let ipAddress;
        oneInterface.forEach( (address) => {
            if (address.family === 'IPv4') {
                ipAddress = address.address;
            }
        });

        return ipAddress;
    }


    private _closeFirewall(callback?: Function) {
        this._setDynamicFirewallMode(DynamicFirewallMode.off, (err) => {
            log.iferr(err, 'error while closing firewall');
            if (callback) {
                callback(err);
            }
        });
    }


    private _openFirewall(callback?: Function) {
        this._setDynamicFirewallMode(DynamicFirewallMode.remote_operation, (err) => {
            log.iferr(err, 'error while opening command port on firewall');
            if (callback) {
                callback(err);
            }
        });
    }


    private _setDynamicFirewallMode(dynamicFirewallMode: DynamicFirewallMode, callback?: Function) {
        this._setupSystemManagerURL( (err) => {
            if (err) {
                if (callback) {
                    callback(err);
                }
                return;
            }

            let url = this.systemManagerURL + '/dynamic_firewall';
            let params = {mode: dynamicFirewallMode};
            axios.post(url, params).then(
                res => {
                    log.debug('_setDynamicFirewallMode response', res.data);
                    if (callback) {
                        callback(null);
                    }
                },
                err => {
                    log.error('error setting dynamic firewall mode to ', dynamicFirewallMode, err);
                    if (callback) {
                        callback(err);
                    }
                },
            );
        });
    }


    private _setupSystemManagerURL(callback: Function) {
        if (this.systemManagerURL) {
            return process.nextTick(callback);
        }

        RegistryClient.instance.getRecordByName('system-manager', (err, record:RegistrationRecord) => {
            if (err) {
                let err = new Error('Could not find system-manager in registry.');
                log.error(err);
                return callback(err);
            }
            this.systemManagerURL = `http://127.0.0.1:${record.port}`;
            callback();
        });
    }


    private _setupJSCClients() {
        // set credentials first before creating client or
        // the client won't have them
        let filename;
        if (this._onRobot) {
            filename = '/var/jibo/credentials.json';
        } else {
            filename = path.join(process.env.HOME || process.env.USERPROFILE,
                                 '.jibo', 'credentials.json');
        }

        let credentials;
        try {
            let data = fs.readFileSync(filename, 'utf8');
            credentials = JSON.parse(data);
        } catch (e) {
            log.error('could not read/parse credentials file', filename);
        }

        if (credentials) {
            JSC.config.update(credentials);
            //JSC.config.update({maxRetries: 1});  // default is 3 which is too many
            this.jscROMClient = new JSC.ROM();
        }
    }


    private get _onRobot():boolean {
        let runMode = process.env.runMode || process.env.RUNMODE;
        if (!runMode && process.platform === 'linux' && process.arch === 'arm') {
            // only default to ON_ROBOT under Linux
            // this lets all the existing unit tests run unmodified
            runMode = RunMode.ON_ROBOT;
        }
        return (runMode === RunMode.ON_ROBOT);
    }
}


export default SecurityControllerService;
