    private async createAnimationFromOptions(options:AnimationOptions<string[]>):Promise<CreateAnimationInstanceResult> {
        //if no data was provided, then load the data
        if(!options.data) {
            try {
                const data = await Async.promisify<string>(cb => fs.readFile(options.src, 'utf8', cb));
                options.data = JSON.parse(data);
            }
            catch(e) {
                throw new Error(`Could not load or parse anim file at ${options.src}\n${e.message}`);
            }
        }

        // If no set of DOf names were supplied, we synthesize them from the anim data.
        if (!options.dofs) {
            options.dofs = this.getDofsFromAnim(options.data);
        }

        const intersectionDofs:DOFSet = this.getIntersectionDofs(options);
        const unionDofs:DOFSet = this.getUnionDofs(options);

        this.setDOFs(intersectionDofs, unionDofs, options.data);

        // Do any transformation of the DOFs requested by the skill
        this.transformAnimObject(options, options.data);
        this.transformAnimLayers(options, options.data);

        //create the builder and set the options
        const builder:AnimationBuilder = this.animate.createAnimationBuilderFromData(options.data, options.path);
        this.setBuilderOptions(builder, options);

        if(options.cacheName === undefined) {
            options.cacheName = "";
        }
        const id = options.path + '##' + uuid.v4();
        //this.cache.addObjectToCache(builder, id, options.cacheName); //not taking advantage of these yet, skip caching for now.
        return this.createAnimationInstance(builder, id, builder.getDOFs(), options.cacheName);
    }

    private createAnimationInstance(builder:AnimationBuilder, id:string, dofs:string[], cacheName:string):CreateAnimationInstanceResult {
        const animInstance = new AnimationInstance(
            {base:this.base, owner: this.callee},
            builder,
            id,
            this.dofArbiter,
            cacheName
        );

        const instantiateResult = {
            instanceId:animInstance.instanceId,
            state: {id, dofs}
        };

        return {
            animationInstance:animInstance,
            instantiateResult:instantiateResult
        };
    }

    private setBuilderOptions(builder:AnimationBuilder, options:CloneOptions<string[]>) {
        if(options.speed !== undefined) {
            builder.setSpeed(options.speed);
        }
        if(options.loops !== undefined) {
            builder.setNumLoops(options.loops);
        }
        if(options.layer !== undefined) {
            builder.setLayer(options.layer);
        }
    }
