import {ServiceOptions, HTTPService, JiboServerRequest, JiboServerResponse} from 'jibo-service-framework';
import OTAUpdater from "../../utils/OTAUpdater";
import {OTARecord} from "../../utils/OTAUpdater";
import {types} from "@jibo/jetstream-client";
import GlobalManagerService from "../global-manager/GlobalManagerService";
import Router = require('router');
import Scheduler = require('node-schedule');
import uuid = require('uuid');
import parentLog from '../log';
import {systemManager} from 'jibo-service-clients';
import {SSMService} from '../../SSMService';

const log:typeof parentLog = parentLog.createChild('Scheduler');



declare type SkillData = {
    skill:string;
    domain:string;
    intent:string;
};

interface SchedulerOptions extends ServiceOptions {
    otaFilter:string;
}

//
// SchedulerService class that can arbitrarily start cron jobs with crontab-syntax redirect and intent once fired.
//
class SchedulerService extends HTTPService implements SSMService {
    private static _instance:SchedulerService;

    public static get instance():SchedulerService {
        return SchedulerService._instance;
    }

    constructor(public options:SchedulerOptions, rootDir:string) {
        super('scheduler', options, rootDir);
        if (SchedulerService._instance) {
            throw new Error('Cannot instantiate SchedulerService more than once');
        }
        SchedulerService._instance = this;

        // initialize the OTAUpdater
        OTAUpdater.createInstance(log, options.otaFilter);

        log.info("Instantiated");
    }

    public init(callback:(error?:Error) => void):void {
        super.init((error:Error) => {
            if(error) {
                return callback(error);
            }

            // initialize some stuff in ota updater
            OTAUpdater.instance.init(() => {
                log.info('Initialized');
                callback();
            });

            //setup shutdown handler:
            systemManager.onShutdown.once(this._launchShutdownAnimation.bind(this));
        });
    }

    public routes(url:Router):void {
        super.routes(url);

         url.post('/ota-update', (req:JiboServerRequest, res:JiboServerResponse) => {
             let chunk = "";
             req.on('data', data => chunk += data);
             req.on('end', () => {
                 OTAUpdater.instance.downloadAndInstall((error?:Error) => {
                    if (error) {
                        return this.sendJson(res, {status: 'Error', message: error.message}, 500);
                    }

                    return this.sendJson(res, {status: 'OK'});
                });
             });
         });

        url.post('/download-status', (req:JiboServerRequest, res:JiboServerResponse) => {
            let chunk = "";
            req.on('data', data => chunk += data);
            req.on('end', () => {
                OTAUpdater.instance.downloadStatus((error:Error, data?:any) => {
                    if (error) {
                        return this.sendJson(res, {status: 'Error', message: error.message}, 500);
                    }

                    return this.sendJson(res, {status: 'OK', data});
                });
            });
        });

        url.post('/backup-status', (req:JiboServerRequest, res:JiboServerResponse) => {
            let chunk = "";
            req.on('data', data => chunk += data);
            req.on('end', () => {
                OTAUpdater.instance.backupStatus((error:Error, data?:any) => {
                    if (error) {
                        return this.sendJson(res, {status: 'Error', message: error.message}, 500);
                    }

                    return this.sendJson(res, {status: 'OK', data});
                });
            });
        });

        url.post('/backup-robot', (req:JiboServerRequest, res:JiboServerResponse) => {
            let chunk = "";
            req.on('data', data => chunk += data);
            req.on('end', () => {
                // true === immediate return (i.e. don't wait for backup to finish)
                OTAUpdater.instance.backupRobot(true, (error?:Error) => {
                    if (error) {
                        return this.sendJson(res, {status: 'Error', message: error.message}, 500);
                    }

                    return this.sendJson(res, {status: 'OK'});
                });
            });
        });

        url.post('/check-updates', (req:JiboServerRequest, res:JiboServerResponse) => {
            let chunk = "";
            req.on('data', data => chunk += data);
            req.on('end', () => {
                OTAUpdater.instance.checkForUpdates((error:Error, data?:Array<OTARecord>) => {
                    if (error) {
                        return this.sendJson(res, {status: 'Error', message: error.message}, 500);
                    }

                    return this.sendJson(res, {status: 'OK', data});
                });
            });
        });

        url.post('/add', (req:JiboServerRequest, res:JiboServerResponse) => {
            this._addJob(req, res);
        });

        url.post('/remove', (req:JiboServerRequest, res:JiboServerResponse) => {
            this._removeJob(req, res);
        });

        url.post('/list', (req:JiboServerRequest, res:JiboServerResponse) => {
            this._listJobs(req, res);
        });

        url.post('/has-job', (req:JiboServerRequest, res:JiboServerResponse) => {
            this._hasJob(req, res);
        });
    }

    // Add a job specifying a crontab string and any function that lives in the current process.
    // Returns a jobiId if successful; null otherwise.
    public addJob(schedule:string, func:any):string {
        let jobId = uuid.v4();
        let job = Scheduler.scheduleJob(jobId, schedule, func);

        let msg = 'Successfully scheduled job';
        if (!job) {
            msg = 'Could not schedule job';
            jobId = null;
        }

        log.info(msg, schedule, jobId);

        return jobId;
    }

    // Removes a job specified by ID.
    // Returns true if successful; false otherwise
    public removeJob(jobId:string):boolean {
        let success = Scheduler.cancelJob(jobId);

        let msg = 'Successfully removed job';

        if (!success) {
            msg = 'Could not cancel job';
        }

        log.info(msg, jobId);

        return success;
    }

    // Removes all jobs that are currently scheduled.
    // Returns callback with any errors.
    public removeAllJobs(callback:(err?:Error) => void):void {
        let list = this.listJobs();

        // remove all jobs
        let errList = null;
        for (let jobId in list) {
            let success = this.removeJob(jobId);
            if (!success) {
                let temp = " " + jobId;
                errList += temp;
            }
        }

        callback(errList ? Error("Error removing jobs: " + errList) : null);
    }

    // Get the current list of scheduled jobs.
    // Returns an object with jobIds as keys and job objects as values. NOTE: this is a reference
    // to currently scheduled objects and can be volatile (change under the hood).
    public listJobs():typeof Scheduler.scheduledJobs{
        return Scheduler.scheduledJobs;  // this holds references!
    }

    // Check if a specific jobId is currently scheduled.
    // Returns true if found; false otherwise.
    public hasJob(jobId:string):boolean {
        return this.listJobs().hasOwnProperty(jobId);
    }


    private _addJob(req:JiboServerRequest,  res:JiboServerResponse) {
        let chunk = "";
        req.on('data', data => chunk += data);
        req.on('end', () => {
            try {
                let data = JSON.parse(chunk);
                if (!data.schedule || !data.skillData) {
                    return this.sendJson(res, {status: 'error', message: 'could not schedule job because did not specify schedule and/or skill launch data'}, 500);
                }

                //var func = this._trigger.bind(null, data.skillData);
                let jobId = this.addJob(data.schedule, this._trigger.bind(this, data.skillData));

                if (jobId !== null) {
                    return this.sendJson(res, {status: 'OK', job: jobId});
                }
                else {
                    return this.sendJson(res, {status: 'error', message: 'could not schedule job'}, 500);
                }
            }
            catch(e) {
                log.warn('Scheduler._addJob cannot parse ', chunk);
                this.sendJson(res, {status: 'error', message: 'could not parse json', json: chunk}, 400);
            }
        });
    }

    // construct an object to trigger a skill relaunch
    private _trigger(skillData:SkillData): void {

        let parseResults = new types.ListenResult({
            text: '',
            confidence: 1
        }, {
            intent: skillData.intent,
            entities: {
                skill: skillData.skill,
                domain: skillData.domain
            },
            rules: null
        });
        parseResults.match = {
            skillID: skillData.skill,
            onRobot: true
        };

        log.info('Trigger job', skillData);

        // send to GMS to handle skill launching with parse results.
        GlobalManagerService.instance.handleSkillLaunch(parseResults);
    }

    private _removeJob(req:JiboServerRequest,  res:JiboServerResponse) {
        let chunk = "";
        req.on('data', data => chunk += data);
        req.on('end', () => {
            try {
                let data = JSON.parse(chunk);
                let success = this.removeJob(data.jobId);
                if (success) {
                    return this.sendJson(res, {status: 'OK'});
                }

                this.sendJson(res, {error: 'Error removing job'}, 500);
            }
            catch(e) {
                log.warn('Scheduler._removeJob cannot parse ', chunk);
                this.sendJson(res, {status: 'error', message: 'could not parse json', json: chunk}, 400);
            }
        });
    }

    private _listJobs(req:JiboServerRequest,  res:JiboServerResponse) {
        let chunk = "";
        req.on('data', data => chunk += data);
        req.on('end', () => {
            const jobs = this.listJobs();
            this.sendJson(res, {status: 'OK', jobs});
        });
    }

    private _hasJob(req:JiboServerRequest, res:JiboServerResponse) {
        let chunk = "";
        req.on('data', data => chunk += data);
        req.on('end', () => {
            try {
                let data = JSON.parse(chunk);
                if (this.hasJob(data.jobId)) {
                    let list = this.listJobs();
                    return this.sendJson(res, {status: 'OK', jobData: list[data.jobId]});
                }
                else {
                    return this.sendJson(res, {status: 'OK', jobData: null});
                }

            }
            catch(e) {
                console.warn('Scheduler._hasJob cannot parse ', chunk);
                this.sendJson(res, {status: 'error', message: 'could not parse json', json: chunk}, 400);
            }
        });
    }

    private _launchShutdownAnimation(){
        this._trigger({
            skill: '@be/settings',
            domain: 'settings',
            intent: 'shutdownAnimation'
        });
    }
}

export default SchedulerService;
