import Scan from "./Scan";
import {SystemManagerClient} from "jibo-client-framework";
import {WifiCallback} from 'jibo-service-framework';
import {PromiseUtils} from 'jibo-cai-utils';
const promisify = PromiseUtils.promisify;

import parentLog from '../log';
const log:typeof parentLog = parentLog.createChild("ActiveScan");

const SCAN_RESULTS = /^<3>CTRL-EVENT-SCAN-RESULTS/;

// @TODO - add comments/documentation
export default class ActiveScan extends Scan {
    private listener:WifiCallback;

    constructor() {
        super();
        this.listener = null;
    }
    
    public handleWSMessage(message:string) {
        if (SCAN_RESULTS.test(message)) {
            //get results from this scan, making them available as the most recent results for
            //anyone calling scanResults()
            this._fetchResults();
            //also feed those results to our listener, if we have one
            if (this.listener) {
                this.scanResults().then(this.listener);
            }
        }
    }

    public scan(): Promise<any> {
        return promisify((cb) => SystemManagerClient.instance.scan(cb));
    }

    public listen(interval:number, listener:WifiCallback) {
        this.listener = listener;
        SystemManagerClient.instance.activeAutoScan(interval, (err) => {
            if (err) {
                log.warn('Error setting active auto scan:', err);
            }
        });
    }

    public stopListener() {
        this.listener = null;
    }
}
