import {
    Event,
    EventPlaybackOptions,
    PlaybackService,
    Recording,
    RecordingDefinitions,
    RecordingType,
    TimeConfig,
} from './types';
import events = require('events');
import fs = require('fs');
import getHomeDir = require('os-homedir');
import log from './log';
import parallel = require('async-parallel');
import path = require('path');
import {PromiseUtils} from 'jibo-cai-utils';
import {rbTimeToMs, RBTime} from '../../utils/robot-boot-time';
import {SIMULATED_SERVICES} from '../../FactoryDeps';
import {SSMService} from '../../SSMService';
import WebSocket = require('ws');

const DEFAULT_PATH = path.join(getHomeDir(), 'Desktop', 'recordings');
const promisify = PromiseUtils.promisify;


export default class EventPlayback extends events.EventEmitter
    implements SSMService
{
    static get instance(): EventPlayback {
        return this._instance;
    }

    private static _instance: EventPlayback;

    private _concurrentReads: number;
    private _playbackLoop: NodeJS.Timer;
    private _playbackStart: number;
    private _playbackStop: number;
    private _queueSize: number;
    private _recordingDefinitions: RecordingDefinitions;
    private _recordings: Recording[];
    private _rbTimeOffset: number;
    private _recordingStart: number;
    private _recordingStop: number;
    private _recordingTypes: RecordingType[];
    private _timeConfigFile: string;
    private _updateLoopTimeout: number;

    constructor(options: EventPlaybackOptions, rootDir: string) {
        super();
        if (EventPlayback._instance) {
            throw new Error('Cannot instantiate EventPlayback more than once');
        }
        EventPlayback._instance = this;
        this._recordingDefinitions = options.recordings || {};
        this._concurrentReads = options.concurrentReads || 1;
        this._queueSize = options.queueSize || 100;
        this._timeConfigFile = options.timeConfigFile;
        this._updateLoopTimeout = options.updateLoopTimeout || 10; // 100 Hz
        log.info('Instantiated');
        log.debug('Recording definitions:', this._recordingDefinitions);
    }

    debug(): void {
        this.load().then(
            () => this.start(),
            err => log.error('Error with the load:', err, err.list),
        );
    }

    init(callback: (err?: Error) => void): void {
        this._recordingTypes = Object.keys(this._recordingDefinitions)
        .map(name => {
            const definition = this._recordingDefinitions[name];
            const serviceName = definition.service;
            const service =
                SIMULATED_SERVICES[serviceName].instance as PlaybackService;
            const sockets = definition.sockets;
            const subdir = definition.subdir;
            const tsEpochMillis = definition.tsEpochMillis;
            const tsProp = definition.tsProp;
            return {name, service, sockets, subdir, tsEpochMillis, tsProp};
        });
        (global as any).EventPlayback = this;
        log.info('Initialized');
        callback();
    }

    async load(recordingsPath: string = DEFAULT_PATH): Promise<void> {
        const filePath = path.join(recordingsPath, this._timeConfigFile);
        const timeConfig: TimeConfig = JSON.parse(
            await promisify<string>(cb => fs.readFile(filePath, 'utf-8', cb)));
        this._rbTimeOffset =
            timeConfig.robot_utc_time - timeConfig.robot_boot_time;
        // Load each recording that was defined in init
        const loader = async (
            recordings: Recording[],
            recordingType: RecordingType,
        ): Promise<Recording[]> => {
            const recording = await this._loadRecording(
                path.join(recordingsPath, recordingType.subdir),
                recordingType,
            );
            log.info(`loaded ${recording.name} which has ${recording.eventFiles.length} events and start time of ${recording.startTs}`);
            return [...recordings, recording];
        };
        this._recordings = await parallel.reduce<RecordingType, Recording[]>(
            this._recordingTypes,
            loader,
            [],
            this._concurrentReads,
        );
        // Determine the earliest start time
        this._recordingStart = this._recordings.reduce((earliest, recording) =>
            recording.startTs < earliest ? recording.startTs : earliest,
            Number.MAX_VALUE,
        );
        // Let listeners know the loading is done
        this.emit('loaded');
        log.info(`loaded ${this._recordings.length} types of recordings`);
        log.info(`Earliest start time: ${this._recordingStart}`);
        log.debug('Recordings:', this._recordings.map(recording => recording.name));
    }

    start(): void {
        this.stop();
        this._recordings.forEach(recording => recording.emitted = 0);
        this.pauseServices();
        this._playbackStart = Date.now();
        this._playbackLoop = setTimeout(this._tick, this._updateLoopTimeout);
        log.info(`Event playback started: ${this._playbackStart}`);
        this.emit('started');
    }

    pause(): void {
        if (this._playbackLoop) {
            clearTimeout(this._playbackLoop);
            this.emit('paused');
        }
    }

    resume(): void {
        if (!this._playbackLoop) {
            this._playbackLoop =
                setTimeout(this._tick, this._updateLoopTimeout);
            this.emit('resumed');
        }
    }

    stop(): void {
        if (this._playbackLoop) {
            clearTimeout(this._playbackLoop);
            this.resumeServices();
            this.emit('stopped', Date.now() - this._playbackStart);
        }
    }

    pauseServices() {
        this._uniqueServices.forEach(service => {
            service.pause();
        });
    }

    resumeServices() {
        this._uniqueServices.forEach(service => {
            service.resume();
        });
    }

    private static _getNested<T>(obj: Object, path: string, sep = '.'): T {
        const reducer = (obj: Object, property: string) => obj[property];
        return path
            .replace('[', sep)
            .replace(']', '')
            .split(sep)
            .reduce(reducer, obj);
    }

    private async _loadRecording(
        dir: string,
        recordingType: RecordingType,
    ): Promise<Recording> {
        // List of all files and dirs in the dir
        const dirContents = await promisify<string[]>(cb => fs.readdir(dir, cb));
        // Only the files in the dir that end with .json
        const eventFiles = await parallel.filter(
            dirContents,
            async dirContent =>
                (await promisify<fs.Stats>(cb => fs.stat(path.join(dir, dirContent), cb))).isFile() && dirContent.endsWith('.json'),
            this._concurrentReads,
        );
        // Sort the file list in numerical order
        eventFiles.sort(function(fileA, fileB) {
            const a = parseInt(fileA.replace(/[^\d.]/g, ''));
            const b = parseInt(fileB.replace(/[^\d.]/g, ''));
            return a - b;
        });
        const eventQueue = await this._fillQueue(
            dir,
            [],
            eventFiles,
            0,
            this._queueSize,
            recordingType.tsEpochMillis,
            recordingType.tsProp,
        );
        // Return a structure representing the recording
        return {
            dir,
            emitted: 0,
            eventFiles,
            eventQueue,
            lastTs: eventQueue[eventQueue.length - 1].ts,
            loaded: eventQueue.length,
            name: recordingType.name,
            service: recordingType.service,
            sockets: recordingType.sockets,
            startTs: eventQueue[0].ts,
            tsEpochMillis: recordingType.tsEpochMillis,
            tsProp: recordingType.tsProp,
        };
    }

    private async _fillQueue(
        dir: string,
        queue: Event[],
        files: string[],
        offset: number,
        toFill: number,
        tsEpochMillis: boolean,
        tsProp: string,
    ): Promise<Event[]> {
        // The reducer reads the next file from disk, and returns a copy of the
        // events passed in, with the new file contents added
        const toRead = files.slice(offset, offset + toFill);
        const newEvents = await parallel.map<string, Event>(
            toRead,
            async file => {
                const filepath = path.join(dir, file);
                log.debug(`Loading in ${filepath}`);
                const stringContent = await promisify<string>(cb =>
                    fs.readFile(filepath, 'utf-8', cb));
                const content: Object = JSON.parse(stringContent);
                const ts: number = tsEpochMillis
                    ? EventPlayback._getNested<number>(content, tsProp)
                    : (
                        rbTimeToMs(
                            EventPlayback._getNested<RBTime>(content, tsProp)
                        ) + this._rbTimeOffset
                    );
                return {content, ts, filepath};
            },
            this._concurrentReads);
        return [...queue, ...newEvents];
    }

    private get _uniqueServices(): PlaybackService[] {
        return this._recordingTypes
            // Get a list of the services of each recording type
            .map(recording => recording.service)
            // Get a list of only unique values from the list of services
            .filter((service, index, services) =>
                services.indexOf(service) === index);
    }

    private _tick = async (): Promise<void> => {
        const tickStart = Date.now();
        // Refill the queue
        await this._refillQueues();
        // Emit messages
        try {
            // Time elapsed since playback started
            const elapsedTime = Date.now() - this._playbackStart;
            // Whether or not anything was emitted
            let emitted = false;
            this._recordings.forEach(recording => {
                emitted = EventPlayback._emitPastEvents(
                    this._recordingStart,
                    elapsedTime,
                    recording,
                    recording.service,
                    recording.sockets,
                ) || emitted;
            });
            // Let listeners know if events were sent
            if (emitted) {
                this.emit('progress', elapsedTime);
            }
            // Compare number of events emitted to total number of events
            if (this._recordings.some(
                recording => recording.emitted < recording.eventFiles.length)
            ) {
                // Continue only if there are more events to emit
                const tickTime = Date.now() - tickStart;
                const updateTime = this._updateLoopTimeout - tickTime;
                this._playbackLoop = setTimeout(this._tick, updateTime);
            }
            // Let listeners know the playback is over
            else {
                this._playbackStop = Date.now();
                this._ended(elapsedTime);
            }
        } catch (err) {
            log.error('Error emitting events', err, err.list);
            this.resumeServices();
            this.emit('error', err.list && err.list[0].message || err.message);
        }
    }

    private async _refillQueues(): Promise<void> {
        try {
            // Don't use async-parallel here: parallelism is achieved across
            // files, per recording
            await Promise.all(this._recordings.map(async recording => {
                const remainingEvents = 
                    recording.eventFiles.length - recording.loaded;
                if (remainingEvents) {
                    const toFill =
                        Math.min(remainingEvents, this._queueSize - recording.eventQueue.length);
                    recording.eventQueue = await this._fillQueue(
                        recording.dir,
                        recording.eventQueue,
                        recording.eventFiles,
                        recording.loaded,
                        toFill,
                        recording.tsEpochMillis,
                        recording.tsProp,
                    );
                    const lastEvent =
                        recording.eventQueue[recording.eventQueue.length - 1];
                    recording.lastTs = lastEvent.ts;
                    recording.loaded = recording.loaded + toFill;
                }
            }));
        } catch (err) {
            log.error('Error refilling the queue', err, err.list);
            this.resumeServices();
            this.emit('error', err.list && err.list[0].message || err.message);
        }
    }

    private static _emitPastEvents(
        recordingStart: number,
        elapsedTime: number,
        recording: Recording,
        service: PlaybackService,
        sockets: string,
    ): boolean {
        const webSockets: WebSocket[] =
            Array.isArray(service[sockets]) ? service[sockets]
            : service[sockets] ? [service[sockets]]
            : [];
        if (!webSockets.length) {
            log.warn(`No client connections to ${service.name}`);
            return;
        }
        const eventsToEmit: Event[] = [];
        // Iterate over the events that haven't been emitted
        // `every` will break when false is returned (first event not in past)
        recording.eventQueue.every(event => {
            // Check if this event's timestamp is in the past
            const recordingDiff = event.ts - recordingStart;
            const inPast = recordingDiff < elapsedTime;
            log.debug('filepath ', event.filepath);
            log.debug(`diff < elapsedTime ${recordingDiff} < ${elapsedTime} evaluates to ${inPast}`);
            // Only emit the event if it is in the past
            if (inPast) {
                eventsToEmit.push(event);
            }
            // Keep going until an event is in the future
            return inPast;
        });
        eventsToEmit.forEach(event => {
            log.debug(`Emitting filepath: ${event.filepath}`);
            log.debug('Emitting content', event.content);
            webSockets.forEach(socket =>
                service.sendWsJson(socket, event.content));
            recording.emitted++;
        });
        recording.eventQueue = recording.eventQueue.slice(eventsToEmit.length);
        return eventsToEmit.length > 0;
    }

    private _ended(elapsedTime: number): void {
        log.info(`Event playback finished: ${this._playbackStop}`);
        // Determine the latest stop time
        this._recordingStop = this._recordings.reduce((latest, recording) =>
            recording.lastTs > latest ? recording.lastTs : latest,
            0,
        );
        log.info(`Latest stop time: ${this._recordingStop}`);
        // Calcuate and print out recording duration
        const recordingDuration = this._recordingStop - this._recordingStart;
        log.info(`Recording duration was: ${recordingDuration}`);
        // Calcuate and print out playback duration
        const playbackDurationMs = this._playbackStop - this._playbackStart;
        log.info(`Playback duration was: ${playbackDurationMs}`);
        // Print out summary
        this._recordings.forEach(recording => {
            log.info(`${recording.name} recording failed to emit ${recording.loaded - recording.emitted} events and in its queue ${recording.eventQueue.length} remaining events`);
        });
        this.resumeServices();
        this.emit('ended', elapsedTime);
    }
}