import * as net from 'net';
import * as http from 'http';
import * as httpProxy from 'http-proxy';
import { TLSSocket } from 'tls';
import Router = require('router');
import { HTTPSTLSService, ServiceOptions } from './HTTPSTLSService';

import parentLog from '../log';
const log = parentLog.createChild('SecurityServer');

export interface SecurityServerOptions extends ServiceOptions {
    clientFingerprint: string;
    commandControllerPort: number;
}


// specifically not using HTTPService here, using local HTTPSTLSService
// class which is intended to have a strong security stance with
// minimal surface area (e.g. no body parser, no query string parsing,
// no static serving). keeping it a local file is also intentional so
// functionality that might have otherwise been added to serve other
// needs does not accidentally introduce potential security issues here
export class SecurityServer extends HTTPSTLSService {
    private clientFingerprint: string;
    private commandControllerPort: number;
    private commandConnected: boolean;
    private socketSet:Set<net.Socket>;
    private proxy:httpProxy;

    constructor(options: SecurityServerOptions) {
        super('security-controller', options);
        this.clientFingerprint = options.clientFingerprint;
        this.commandControllerPort = options.commandControllerPort;
        if (!this.clientFingerprint || !this.commandControllerPort) {
            throw new Error('missing required parameter');
        }
        this.socketSet = new Set();
    }


    init(callback) {
        super.init( (err?:Error) => {
            if (err) {
                callback(err);
            } else {
                // add a handler to check the cert fingerprint
                // as soon as the tls layer is negotiated
                this.server.on('secureConnection', this._validateSocket.bind(this));

                // also check it after the http request is established
                // (paranoid belt and suspenders approach)
                this.app.use(this._validateRequest.bind(this));

                // handle websocket upgrade requests
                this.server.on('upgrade', (req, socket, head) => this._onUpgrade(req, socket, head));

                // record all opened sockets so we can force everything closed
                this.server.on('connection', (socket) => this._trackAllSockets(socket));

                let targetUrl = `http://127.0.0.1:${this.commandControllerPort}`;
                this.proxy = httpProxy.createProxyServer({target: targetUrl});

                this.proxy.on('close', () => this._webSocketClosed());

                this.proxy.on('proxyReq', (proxyReq, req, res, options) => {
                    this._trackAllSockets((proxyReq as any).socket);  // not sure why the cast was needed
                    this._trackAllSockets(req.socket);
                });
                this.proxy.on('proxyReqWs', (proxyReqWs, req, res, options) => {
                    //_trackAllSockets(proxyReqWs.socket);  // seems to be null at this point, might be why we leak sockets
                    this._trackAllSockets(req.socket);
                });

                this.proxy.on('error', (err, req, res) => {  // if we don't handle this it become an unhandled exception
                    log.error('error on proxy connection', err);
                });

                callback();
            }
        });
    }


    shutdown() {
        this.removeAllListeners();
        this.destroyAllSockets();
    }


    destroyAllSockets() {
        this.socketSet.forEach( (connection) => {
            connection.end();
            connection.destroy();
        });
        this.socketSet.clear();
    }


    destroy() {
        super.destroy();
    }


    routes(url:Router) {
        //super.routes(url);  // no, don't call super, we do not want any default routes
        url.get('/assets/*', (req, res) => this._proxySideChannel(req, res));  // FIXME need to fixup the command layer urls
    }


    private _proxySideChannel(req, res) {
        // only allow the sidechannel when the websocket is connected
        if (this.commandConnected) {
            this.proxy.web(req, res);
        } else {
            res.errorCode = 403;  // considered using 418 here
            res.end();
        }
    }


    private _onUpgrade(req, socket, head) {
        // check the websocket path (so we can support multiple websockets someday)
        if (req.url === '/') {  // FIXME need to fixup the command layer urls
            if (!this.commandConnected) {
                this.proxy.ws(req, socket, head);
                this.commandConnected = true;
                this.emit('commandSocketConnected');
                socket.on('close', () => this._webSocketClosed());
                socket.on('error', () => this._webSocketClosed());
            } else {
                socket.destroy();
            }
        } else {
            socket.destroy();
        }
    }


    private _trackAllSockets(socket) {
        this.socketSet.add(socket);

        const removeSocket = () => {
            log.debug('removing socket from set');
            this.socketSet.delete(socket);
            log.debug('socket removed');
        };
        socket.on('close', removeSocket);
        socket.on('error', removeSocket);
    }


    private _webSocketClosed() {
        this.commandConnected = false;
        this.emit('commandSocketDisconnected');
    }


    private _validateSocket(socket:TLSSocket) {
        let clientCert = this._getCertificate(socket);
        if (!this._validateCertificate(clientCert)) {
            log.warn('rejecting this tls connection');
            socket.destroy();
            this.emit('invalidCertificate');
        }
    }


    private _validateRequest(req: http.ServerRequest, res: http.ServerResponse, next) {
        let clientCert = this._getCertificate(req.socket as TLSSocket);
        if (!this._validateCertificate(clientCert)) {
            log.warn('rejecting this http connection');
            next(new Error('client certificate did not validate'));
            this.emit('invalidCertificate');
        } else {
            next();
        }
    }


    private _validateCertificate(clientCert) {
        if (!clientCert) {
            log.warn('client certificate not provided');
            return false;
        }

        if (!clientCert.fingerprint) {
            log.warn('problem checking client fingerprint');
            return false;
        }

        if (clientCert.fingerprint.toUpperCase() !== this.clientFingerprint.toUpperCase()) {
            log.warn('client certificate mismatch');
            return false;
        }

        // certificate validated!
        return true;
    }


    private _getCertificate(socket:TLSSocket) {
        let clientCert = socket.getPeerCertificate();
        // if there is no certificate an empty object is returned
        if (Object.keys(clientCert).length === 0) {
            clientCert = null;
        }
        return clientCert;
    }
}
