import querystring = require('querystring');

//Jibo owned API key
const GOOGLE_API = 'AIzaSyA-oFAphgwxCBys-mouBuVQ6gI3yP4TaU8';

export interface TimezoneData {
    /**
     * Milliseconds by which the time is off from UTC, including active Daylight Savings Time
     */
    offsetUTC:number;
    /**
     * Long name of timezone, like "Eastern Standard Time"
     */
    name:string;
    /**
     * "tz" id of the timezone, like "America/Los_Angeles"
     */
    id:string;
    /**
     * JSON serialization key used by the utility class in be-framework
     */
    __type:'Timezone';
}

export function lookUpTimezone(lat:number, lng:number):Promise<TimezoneData> {
    return new Promise<TimezoneData>((resolve, reject) => {
        const query = querystring.stringify({
            key:GOOGLE_API,
            //UTC, in seconds
            timestamp: Math.floor(Date.now()/1000),
            location: `${lat},${lng}`
        });
        const url = `https://maps.googleapis.com/maps/api/timezone/json?${query}`;
        const request:XMLHttpRequest = new XMLHttpRequest();
        request.open('GET', url, true);
        request.responseType = 'json';
        request.timeout = 10000;
        request.addEventListener('timeout', () => { reject('XHR Timeout'); }, false);
        request.addEventListener('error', () => { reject('XHR Error'); }, false);
        request.addEventListener('abort', () => { reject('XHR Aborted'); }, false);
        request.addEventListener('load', () => {
            if (request.status === 200 && request.response && request.response.status === 'OK') {
                const results = request.response;
                //milliseconds by which the time is off from UTC, including active Daylight Savings Time
                const offsetUTC = (results.rawOffset + results.dstOffset) * 1000;
                //long name of timezone, like "Eastern Standard Time"
                const name = results.timeZoneName;
                //"tz" id of the timezone, like "America/Los_Angeles"
                const id = results.timeZoneId;
                const timezone:TimezoneData = {
                    offsetUTC,
                    name,
                    id,
                    __type: 'Timezone'
                };
                resolve(timezone);
            } else {
                //try out the full range of possible error messages
                let error:string = 'Invalid response';
                if (request.response) {
                    if (request.response.error) {
                        error = request.response.error;
                    } else if (request.response.error_message) {
                        error = request.response.status + ': ' + request.response.error_message;
                    } else if (request.response.status) {
                        error = request.response.status;
                    }
                }
                reject(error);
            }
        }, false);
        request.send();
    });
}