// a class which sorts elements according to a callback provided to determine order

class PriorityQueue<T> {
    private _queue: Array<T> = [];

    // a comparison method to sort and compare elements
    private _compareMethod: (a:T, b:T)=>number = null;
    // a boolean to allow (or not) duplicate elements in the priority queue
    private _allowDuplicates = true;

    // a callback which is fired if an item is successfully added
    // if an array of items were added, this callback fires if any items were added successfully
    private _onItemAddedCallback: (items:Array<T>)=> void = null;
    // a callback which is fired if an item is successfully removed
    // if an array of items were removed, this callback fires if any items were removed successfully
    private _onItemRemovedCallback: (items:Array<T>)=> void = null;

    constructor(compareMethod?: (a:T, b:T)=>number, allowDuplicates: boolean = true) {
        this._compareMethod = compareMethod;
        if(!compareMethod) {
            this._compareMethod = (a:any, b:any)=>{
                if(a > b) {
                    return 1;
                } else if (a < b) {
                    return -1;
                } else {
                    return 0;
                }
            };
        }
        this._allowDuplicates = allowDuplicates;
    }

    /**
     * get the onItemAdded callback method
     * @return {Function} the callback method which supplies the list of added items as a parameter
     */
    public get onItemAdded(): (items:Array<T>)=> void {
        return this._onItemAddedCallback;
    }

    /**
     * set the onItemAdded callback method
     * @param value {Function} the callback method which supplies the list of added items as a parameter
     */
    public set onItemAdded(value: (items:Array<T>)=> void) {
        this._onItemAddedCallback = value;
    }

    /**
     * get the onItemRemoved callback method
     * @return {Function} the callback method which supplies the list of removed items as a parameter
     */
    public get onItemRemoved(): (items:Array<T>)=> void {
        return this._onItemRemovedCallback;
    }

    /**
     * set the onItemRemoved callback method
     * @param value {Function} the callback method which supplies the list of removed items as a parameter
     */
    public set onItemRemoved(value: (items:Array<T>)=> void) {
        this._onItemRemovedCallback = value;
    }

    /**
     * Add an item to add to the priority queue. This will be compared and sorted according to the
     * compare method.
     *
     * @param element {Array<T>} an array of items to add to the priority queue
     * @return {boolean} true if any of the items were successfully added / false otherwise
     */
    public add(element: Array<T>): boolean;
    /**
     * @param element {T} the item to add to the priority queue
     * @return {boolean} true if the item was successfully added / false otherwise
     */
    public add(element: T): boolean;

    public add(element: T|Array<T>): boolean {
        if(!Array.isArray(element)) {
            let addedElement = this._addElement(element);
            if(addedElement && this._onItemAddedCallback) {
                this._onItemAddedCallback([element]);
            }
            return addedElement;
        }
        // if element is an array
        else {
            let addedElements = [];
            for(let i = 0; i < element.length; ++i) {
                if(this._addElement(element[i])) {
                    addedElements.push(element[i]);
                }
            }
            if(addedElements.length > 0 && this._onItemAddedCallback) {
                this._onItemAddedCallback(addedElements);
            }
            return addedElements.length > 0;
        }
    }

    /**
     * Delete an item from the priority queue
     *
     * @param element {Array<T>} the items to delete
     * @return {boolean} true if any of the items were successfully deleted / false otherwise
     */
    public delete(element: Array<T>): boolean;
    /**
     * @param element {T} the item to delete
     * @return {boolean} true if the item was successfully deleted / false otherwise
     */
    public delete(element: T): boolean;

    public delete(element: T|Array<T>): boolean {
        if(!Array.isArray(element)) {
            let deletedElement = this._deleteElement(element);
            if(deletedElement && this._onItemRemovedCallback) {
                this._onItemRemovedCallback([element]);
            }
            return deletedElement;
        }
        // if element is an array
        else {
            let deletedElements = [];
            for(let i = 0; i < element.length; ++i) {
                if(this._deleteElement(element[i])) {
                    deletedElements.push(element[i]);
                }
            }
            if(deletedElements.length > 0 && this._onItemRemovedCallback) {
                this._onItemRemovedCallback(deletedElements);
            }
            return deletedElements.length > 0;
        }
    }

    /**
     * Get the highest priority item from the priority queue
     * @return {T} The highest priority item. null if there are no items in the priority queue
     */
     public peek(): T {
         return this._queue.length > 0 ? this._queue[0] : null;
     }

     /**
      * Get and remove the highest priority item from the priority queue
      * @return {T} The highest priority item. null if there are no items in the priority queue
      */
     public shift(): T {
         let element = this._queue.length > 0 ? this._queue.shift() : null;
         if(element && this._onItemRemovedCallback) {
             this._onItemRemovedCallback([element]);
         }
         return element;
     }

     /**
      * Search to see if the priority queue contains a given item
      * @param element {T} the item to search for
      * @return {boolean} True if the element exists in the priority queue. false otherwise
      */
    public contains(element: T): boolean {
        return this._tryGetIndex(element) !== -1;
    }

    /**
     * Return the element at the underlying array index. null if index out of bounds
     * @param index {number} the index of the item to return
     * @return {T} the element found at the index paramter. null if index out of bounds
     */
    public getIndex(index: number): T {
        if(index < 0 || index >= this._queue.length) {
            return null;
        }
        else {
            return this._queue[index];
        }
    }

    /**
     * Get the current number of elements in the priority queue
     * @return {number} The current number of elements in the priority queue
     */
    public get length(): number {
        return this._queue.length;
    }

    /**
     * Remove all elements from the priority queue
     */
    public clear(): void {
        this._queue = [];
    }

    /**
     * The actual implementation of adding an element to separate the method overloading logic from the priority queue insertion logic
     * @param element {T} the item to add to the priority queue
     * @return {boolean} true if the item was successfully added / false otherwise
     */
    private _addElement(element: T): boolean {
        if(this.contains(element) && !this._allowDuplicates) {
            return false;
        }

        let lowerBound = 0;
        let upperBound = this._queue.length;
        while(lowerBound !== upperBound) {
            let midPoint = Math.floor((upperBound - lowerBound) / 2) + lowerBound;
            let compareValue = this._compareMethod(element, this._queue[midPoint]);
            // element is less than array value
            if(compareValue < 0) {
                upperBound = midPoint;
            }
            // element is greater than array value
            else if(compareValue > 0) {
                lowerBound = midPoint + 1;
            }
            // element is equal to array value
            else {
                // we found the spot to insert into
                lowerBound = upperBound = midPoint;
            }
        }

        let insertIndex = lowerBound;
        this._queue.splice(insertIndex, 0, element);

        return true;
    }

    /**
     * The actual implementation of deleting an element to separate the method overloading logic from the priority queue insertion logic
     * @param element {T} the item to delete
     * @return {boolean} true if the item was successfully deleted / false otherwise
     */
    private _deleteElement(element: T): boolean {
        let foundIndex = this._tryGetIndex(element);
        if(foundIndex === -1) {
            return false;
        } else {
            this._queue.splice(foundIndex, 1);
            return true;
        }
    }

    /**
     * Try to find the index in the priority queue for a given element.
     * @param element {T} the element to lookup
     * @returns {number} The index of the element or -1 if the element is not found
     */
    private _tryGetIndex(element: T): number {
        let lowerBound = 0;
        let upperBound = this._queue.length;
        while(lowerBound !== upperBound) {
            let midPoint = Math.floor((upperBound - lowerBound) / 2) + lowerBound;
            let compareValue = this._compareMethod(element, this._queue[midPoint]);
            // element is less than array value
            if(compareValue < 0) {
                upperBound = midPoint;
            }
            // element is greater than array value
            else if(compareValue > 0) {
                lowerBound = midPoint + 1;
            }
            // element is equal to array value
            else {
                // we found the spot to insert into
                lowerBound = upperBound = midPoint;
            }
        }

        let foundIndex = lowerBound;
        // check the length because in the case where it's an empty array this._queue[0] is going to be undefined
        if(foundIndex < this._queue.length && this._compareMethod(element, this._queue[foundIndex]) === 0) {
            return foundIndex;
        } else {
            return -1;
        }
    }
}

export default PriorityQueue;
