import {HTTPService, ServiceOptions} from 'jibo-service-framework';
import {IPerformanceService} from '../../services/performance/PerformanceService';
import {SSMService} from '../../SSMService';
import parentLog from '../log';


//we want to stub out this service if the configuration does not call for it.
export default class PerformanceServiceSim extends HTTPService implements IPerformanceService, SSMService {
    private static _instance:PerformanceServiceSim;
    private _log = parentLog.createChild('PerformanceService');

    constructor(public options:ServiceOptions, rootDir:string) {
        super('performance', options, rootDir);
        if (PerformanceServiceSim._instance) {
            throw new Error('Cannot instantiate PerformanceServiceSim more than once');
        }
        PerformanceServiceSim._instance = this;
        this._log.info('Instantiated');
    }

    public static get instance():IPerformanceService {
        return PerformanceServiceSim._instance;
    }

    init(callback:(error?:Error) => void):void {
        this._log.info('Initialized');
        callback();
    }

    log(time:number, type:string, description?:string):void {
        return;
    }
}
