import {Point3} from './VisualAwareness';


let audioEntityIndex:number = 0;


export class AudioEntity {
    public ts:[number, number];
    public type:number;
    public id:number;
    public position:Point3 = new Point3();
    public confidence:number = 1;

	constructor(type = 0) {
  	    this.type = type;
				const now = process.hrtime();
				this.ts = [now[0], Math.round(now[1]/1000)]; // Convert to seconds and microseconds
        this.id = audioEntityIndex++;
	}

    public updatePosition(point:Point3):void {
        this.position.x = point.x;
        this.position.y = point.y;
        this.position.z = point.z;
    }
}

export default class AudioAwareness {
    public entities:AudioEntity[] = [];
}
