import Router = require('router');
import {JiboServerRequest, JiboServerResponse, ServiceOptions, RegistrationRecord, HTTPService} from 'jibo-service-framework';
import {SSMService} from '../../SSMService';

import parentLog from '../log';
const log = parentLog.createChild('Registry');

let initalEntries:RegistrationRecord[] = [];

class RegistryService extends HTTPService implements SSMService {

    private static _instance:RegistryService;

    public registry:Registry;

    public static get instance():RegistryService {
        return RegistryService._instance;
    }

    constructor(options:ServiceOptions, rootDir:string) {
        super('registry', options, rootDir);
        if (RegistryService._instance) {
            throw new Error('Cannot instantiate RegistryService more than once');
        }
        this.registry = new Registry(initalEntries);
        RegistryService._instance = this;

        log.info("Instantiated");
    }

    routes(url:Router) {
        url.get('/registry', (req:JiboServerRequest, res:JiboServerResponse) => {
            this.sendJson(res, this.registry);
        });

        url.put('/registry', (req:JiboServerRequest, res:JiboServerResponse) => {
            let entry = req.body;
            this.registry.put(entry);
            this.finishNoContent(res);
        });

        url.post('/registry', (req:JiboServerRequest, res:JiboServerResponse) => {
            let entry = req.body;
            if (!this.registry.get(entry.name)) {
                this.finish(res, new Error('error during POST: no such entry '+entry.name));
            } else {
                if (this.registry.post(entry)) {
                    log.info('updating registry entry for', entry.name);
                }
                this.finishNoContent(res);
            }
        });

        url.delete('/registry', (req:JiboServerRequest, res:JiboServerResponse) => {
            let entry = req.body;
            // console.log('deleting registry entry for', entry.name);
            this.registry.delete(entry.name);
            this.finishNoContent(res);
        });
    }
}


class Registry {
    public records:RegistrationRecord[];

    constructor(initialEntries:RegistrationRecord[]=[]) {
        this.records = [];
        if (initialEntries) {
            for (let i=0; i<initialEntries.length; i++) {
                this.put(initialEntries[i]);
            }
        }
    }

    get(name:string) {
        for (let i=0; i<this.records.length; i++) {
            if (name === this.records[i].name) {
                return this.records[i];
            }
        }
        return null;
    }

    put(entry:RegistrationRecord) {
        if (!this.get(entry.name)) {
            this.records.push(entry);
            return true;
        }
        return false;
    }

    post(entry:RegistrationRecord) {
        for (let i=0; i<this.records.length; i++) {
            if (entry.name === this.records[i].name) {
                return this.updateRecord(this.records[i], entry);
            }
        }
        return false;
    }

    delete(name:string) {
        for (let i=0; i<this.records.length; i++) {
            if (name === this.records[i].name) {
                this.records.splice(i, 1);
                return true;
            }
        }
        return false;
    }

    //update record, return true if host, port, or path changed, false if not
    //update ttl and tls every time, but don't return true for such changes
    private updateRecord(current:RegistrationRecord, update:RegistrationRecord):boolean {
        // don't compare name, as presumably we already did that to get the records to compare
        const significantChange = current.host !== update.host ||
                current.port !== update.port ||
                current.path !== update.path;
        if (significantChange) {
            current.host = update.host;
            current.port = update.port;
            current.path = update.path;
        }
        current.ttl = update.ttl;
        current.tls = update.tls;
        return significantChange;
    }
}


export default RegistryService;
