const fs = require('fs');
const path = require('path');
const async = require('async');

// function to list the contents of a directory with stat records
// (file size, modification timestamps, etc...)
// and return the results sorted by reverse time (like `ls -lart`)
// filenames returned are joined with the the dir parameter

const lsdashlart = (dir, callback) => {
    fs.readdir(dir, (err, list) => {
        if (err) {
            callback(err);
        } else {
            let fullnames = list.map( (file) => {
                return path.join(dir, file);
            });

            let doStat = (fullname, callback) => {
                fs.lstat(fullname, (err, stat) => {
                    callback(err, {filename: fullname, stat: stat});
                });
            };

            async.map(fullnames, doStat, (err, files) => {
                if (!err && files) {
                    files.sort( (a, b) => { return a.stat.mtime.getTime() - b.stat.mtime.getTime(); });
                }
                callback(err, files);
            });
        }
    });
};


export default lsdashlart;
