// a class to re-emit an error based on the error's rescheduler timeout
import JiboError from './JiboError';

class Reschedule {
    private _error: JiboError = null;
    private _timeoutId: NodeJS.Timer = null;

    constructor(error: JiboError, timeoutId: NodeJS.Timer) {
        this._error = error;
        this._timeoutId = timeoutId;
    }

    get error(): JiboError {
        return this._error;
    }

    get timeoutId(): NodeJS.Timer {
        return this._timeoutId;
    }
}

class ErrorRescheduler {
    private _errorTimeoutMap: { [key: string]: Reschedule } = {};

    /**
     * returns an array representation of all present JiboError objects
     *
     * @return {Array<JiboError>} an array of all present JiboError objects
     */
    public toArray(): Array<Error> {
        let array = [];
        for(let key in this._errorTimeoutMap) {
            array.push(this._errorTimeoutMap[key].error);
        }
        return array;
    }

    /**
     * A method to check for the presence of an error by id
     *
     * @param errorId {string} the error to search for
     * @return {boolean} true if the error is present / false otherwise
     */
    public contains(errorId: string): boolean {
        return this._errorTimeoutMap.hasOwnProperty(errorId);
    }

    /**
     * Add an error associated with a callback which is called based on the error's repeatTime property
     *
     * @param error {JiboError} the error add
     * @param rescheduleCallback {Function} the method which is called after the error's repeatTime has passed from now
     * @return {boolean} true if the error has been successfully added to the rescheduler / false otherwise
     */
    public add(error: JiboError, rescheduleCallback: (error: JiboError)=>void):boolean {
        // do not stomp over previously added error timeouts
        if(this._errorTimeoutMap.hasOwnProperty(error.id)) {
            return false;
        } else {
            let errorTimerId = global.setTimeout(()=>{
                this.remove(error.id);
                rescheduleCallback(error);
            }, error.repeatTime);

            this._errorTimeoutMap[error.id] = new Reschedule(error, errorTimerId);
            return true;
        }
    }

    /**
     * Remove the error from the rescheduler which prevents the callback from being called
     *
     * @param errors {Array<JiboError>} an array with the the errors to add
     * @return {boolean} true if at least one error has been successfully removed from the rescheduler / false otherwise
     */
    public remove(errors: Array<JiboError>): boolean;
    /**
     * @param errorId {string} the errorId for the error to remove
     * @return {boolean} true if at least one error has been successfully removed from the rescheduler / false otherwise
     */
    public remove(errorId: string): boolean;

    public remove(element: string|Array<JiboError>): boolean {
        if(!Array.isArray(element)) {
            return this._remove(element);
        }
        // if element is an array
        else {
            let deletedElements = [];
            for(let i = 0; i < element.length; ++i) {
                if(this._remove(element[i].id)) {
                    deletedElements.push(element[i]);
                }
            }
            return deletedElements.length > 0;
        }
    }

    private _remove(errorId: string): boolean {
        if(this._errorTimeoutMap.hasOwnProperty(errorId)) {
            clearTimeout(this._errorTimeoutMap[errorId].timeoutId);
            delete this._errorTimeoutMap[errorId];
            return true;
        } else {
            return false;
        }
    }
}

export default ErrorRescheduler;
