import DevToolsClient from '../../clients/DevToolsClient';
import DevShellClient from '../../clients/DevShellClient';
import GlobalManagerService from '../global-manager/GlobalManagerService';
import parentLog from '../log';
import PerformanceService from '../performance/PerformanceService';
import {PromiseUtils} from 'jibo-cai-utils';
import ScreenScheduler from '../../background/screen/ScreenScheduler';
import {
    ServiceOptions, HTTPWSService,
    JiboServerRequest, JiboServerResponse
} from 'jibo-service-framework';
import {SkillRecord} from 'jibo-client-framework';
import {SSMService} from '../../SSMService';
import {SystemManagerClient} from 'jibo-client-framework';
import async = require('async');
import findRoot = require('find-root');
import fs = require('fs');
import parallel = require('async-parallel');
import path = require('path');
import rimraf = require('rimraf');
import Router = require('router');
import WebSocket = require('ws');
import {types} from "@jibo/jetstream-client";

const log = parentLog.createChild('Skills');
const prfyTo = PromiseUtils.promisifyTo;

export interface SkillsServiceOptions extends ServiceOptions {
    singleSkill:boolean;
    startSkill?:string;
}

 /**
  * @class SkillsService
  * @extends HTTPWSService
  */
class SkillsService extends HTTPWSService implements SSMService {

    private static _instance:SkillsService;

    public currentSkill:SkillRecord;

    public static get instance():SkillsService {
        return SkillsService._instance;
    }
    
    constructor(public options:SkillsServiceOptions, rootDir:string) {
        super('skills-service', options, rootDir);
        if (SkillsService._instance) {
            throw new Error('Cannot instantiate SkillsService more than once');
        }
        SkillsService._instance = this;

        log.info("Instantiated");
    }

    public init(callback:(error?:Error) => void) {
        super.init((error:Error) => {
            if (error) {
                return callback(error);
            }
            ScreenScheduler.stopTimerAndTurnOn().then(() => {
                // Per JIBO-4384, kill any running skill on SSM startup
                this.terminate((error?:Error) => {
                    // If there's an issue, log a warning, but continue anyway
                    if (error) {
                        log.warn(`Could not terminate running skill`, error);
                    }
                    //if there is no start skill set no launch rules
                    if (!this.options.startSkill) {
                        log.info('initialized');
                        return callback();
                    }
                    //If the SSM is in single skill mode
                    if (this.options.singleSkill) {
                        log.warn("SSM operating in single skill mode");
                        //get the single skill record
                        SystemManagerClient.instance.getSkillRecordByName(this.options.startSkill, (error:Error, skillRecord:SkillRecord) => {
                            if (error) {
                                return callback(error);
                            }
                            if (!skillRecord) {
                                return callback(new Error(`Skill ${this.options.startSkill} not found`));
                            }
                            this.launch(this.options.startSkill, {}, callback);
                        });
                    }
                });
            });
        });
    }

    /**
     * @method SkillsService#routes
     * @param {Router} url
     */
    public routes(url:Router):void {
        super.routes(url);

        url.get('/skill/list', (req:JiboServerRequest, res:JiboServerResponse) => {
            SystemManagerClient.instance.list((error:Error, skills:Array<SkillRecord>) => {
                if(error) {
                    return this.sendJson(res, {error: error.message}, 500);
                }
                this.sendJson(res, {skills: skills});
            });
        });

        url.get('/devtools', (req:JiboServerRequest, res:JiboServerResponse) => {
            DevToolsClient.createInstance('127.0.0.1', 9191).getJson((err:any, json:any) => {
                this.sendJson(res, json);
            });
        });

        url.get('/ssm-devtools', (req:JiboServerRequest, res:JiboServerResponse) => {
            // Only allow this endpoint when the robot is in int-developer mode
            SystemManagerClient.instance.getMode((error:Error, mode?:string) => {
                if(error) {
                    this.sendJson(res, {error: error.message}, 500);
                    log.error('Error getting mode to determine if we should enable the SSM dev-tools proxy', error);
                    return;
                }
                if(mode === 'int-developer') {
                    DevToolsClient.createInstance('127.0.0.1', 12345).getJson((err:any, json:any) => {
                        this.sendJson(res, json);
                    });
                }
                else {
                    this.sendJson(res, {error: 'Not found'}, 404);
                    return;
                }
            });
        });

        url.get('/version', (req:JiboServerRequest, res:JiboServerResponse) => {
            const root:string = findRoot(__dirname);
            const packageInfo:any = require(path.join(root, 'package.json'));
            this.sendJson(res, {version: packageInfo.version});
        });

        url.post('/launch-dev', (req:JiboServerRequest, res:JiboServerResponse) => {
            let chunk = "";
            req.on('data', (data) => {
                chunk += (data);
            });

            req.on('end', () => {
                let data;
                try {
                    data = JSON.parse(chunk);
                }
                catch (e) {
                    this.sendJson(res, {
                        Status: 'ERROR',
                        Message: 'Invalid request from launch. Request body is not valid JSON'
                    }, 200);
                    return;
                }
                log.info('attempting to run skill', data.command);
                this.launch(data.command, {}, (error?:Error) => {
                    if (error) {
                        log.error('error running skill', data.command, error);
                        this.sendJson(res, {
                            Status: 'ERROR',
                            Message: 'Skill "' + data.command + '" does not exist or could not be launched. Make sure to run `jibo sync`'
                        }, 200);
                    }
                    else {
                        log.info('System Manager launched skill', data.command);
                        this.sendJson(res, {
                            Status: 'OK',
                            Message: 'Skill "' + data.command + '" started successfully'
                        }, 200);
                    }
                });

            });

        });

        // Used by static/skills/index.tsx page (:8779) to determine
        // whether or not to show the SSM Debug button
        url.get('/mode', (req:JiboServerRequest, res:JiboServerResponse) => {
            SystemManagerClient.instance.getMode((error:Error, mode?: string) => {
                if(error) {
                    return this.sendJson(res, {error: error.message}, 500);
                }
                this.sendJson(res, {mode, electron: !!global['window']});
            });
        });

        url.post('/terminate', (req:JiboServerRequest, res:JiboServerResponse) => {
            let chunk = "";
            req.on('data', (data) => {
                chunk += (data);
            });

            req.on('end', () => {
                let data;
                try {
                    data = JSON.parse(chunk);
                }
                catch (e) {
                    this.sendJson(res, {
                        Status: 'ERROR',
                        Message: 'Invalid request from launch. Request body is not valid JSON'
                    }, 200);
                    return;
                }
                SystemManagerClient.instance.terminate(data.command, (error:Error) => {
                    log.info('screen scheduler timer: skills service post terminate');
                    this.emit('show');
                    ScreenScheduler.start();
                    this.currentSkill = null;
                    this.finishNoContent(res);
                });
            });
        });

        url.post('/reset-proxy/:serverPort',  (req:JiboServerRequest, res:JiboServerResponse) => {
            let serverPort = req.params.serverPort;
            DevShellClient.createInstance('127.0.0.1', 8686).resetProxy(serverPort, (err) => {
                this.finishNoContent(res);
            });
        });
    }

    /**
     * @method SkillsService#launch
     * @param skillName {string}
     * @param parse {any}
     * @param callback {function}
     */
    public launch(skillName:string, parse:any, callback:(error?:Error|string) => void):void {
        PerformanceService.instance.log(Date.now(), 'JiboLaunch');


        const launch = (skill:SkillRecord) => {
            this.currentSkill = skill;
            SystemManagerClient.instance.launch(skill.name, (error: Error) => {
                if (error) {
                    log.error('Unable to reset NLU memory', error);
                    return callback(error);
                }
                ScreenScheduler.stopTimerAndTurnOn().then(() => {
                    callback();
                }).catch((error) => {
                    callback(error);
                });
            });
        };

        log.info(`Launching skill, getting skill record from SystemManager`);
        SystemManagerClient.instance.getSkillRecordByName(skillName, (error:Error, skill:SkillRecord) => {
            PerformanceService.instance.log(Date.now(), 'JiboLaunchGetSkillRecordByName');
            if (error) {
                log.error(`During launch(), failed to get skill record`, error);
                return callback(error);
            }
            log.info(`During launch(), got skill record for ${skillName}`);
            if (this.currentSkill) {
                log.info(`Going to launch ${skillName} but need to terminate ${this.currentSkill.name} first`);
                SystemManagerClient.instance.terminate(this.currentSkill.name, (error:Error) => {
                    PerformanceService.instance.log(Date.now(), 'JiboLaunchTerminateCurrentSkill');
                    if (error) {
                        // current skill may have crashed or been killed, so just warn and proceed (SDK-1052)
                        log.warn('error terminating current skill', this.currentSkill, error);
                    }
                    launch(skill);
                });
            }
            else {
                launch(skill);
            }
        });
    }

    /**
     * Terminate currently running skill
     * @method SkillsService#terminate
     * @param [error] {Error}
     * @return string
     */
    public terminate(callback: (err?: Error) => void): void {
        if (this.currentSkill) {
            return SystemManagerClient.instance.terminate(this.currentSkill.name, (err?: Error) => {
                if (err) {
                    log.warn('Error terminating skills', err);
                }
                this.currentSkill = null;
                this._doneTerminate(err, callback);
            });
        }
        // Don't trust that this SSM instance actually started the skill and
        // kept track of it; check SystemManager for a running skill, in case
        // this is a restart after an SSM crash (we close skills on startup)
        SystemManagerClient.instance.list((err: Error, skills: Array<SkillRecord>) => {
            if (err) {
                return callback(err);
            }
            // Sure, we're only running one skill at a time in V1, but since
            // the service returns a list with a bool, an async.each seems
            // appropriate. Effectively, this is the same as a find and operate
            // on the one, if it exists
            const runningSkills = skills.filter(skill => skill.running);
            async.each<SkillRecord, Error>(runningSkills, (skill, done) => {
                log.info(`Terminating unknown, running skill ${skill.name}`);
                SystemManagerClient.instance.terminate(skill.name, done);
            }, err => {
                if (err) {
                    log.warn('Error terminating skills', err);
                }
                this._doneTerminate(err, callback);
            });
        });
    }

    /**
     * Called when a client sends a message over WebSocket
     * @param command {any}
     * @param client {WebSocket}
     * @method SkillsService#onMessage
     */
    protected onMessage(command:any, client:WebSocket):void {

        if (command.command === 'initDone') {
            log.info(this.currentSkill.name, 'launched and initialized');
            this.emit('hide');
            this.sendWsJson(client, {
                command: 'show'
            });
        }
        else if (command.command === 'finished') {
            if(this.currentSkill.name === '@be/be') {
                const relaunchResults = new types.ListenResult(null, null, {
                    skillID: '@be/idle',
                    onRobot: true
                });
                GlobalManagerService.instance.handleSkillLaunch(relaunchResults);
            }
        }
    }

    /**
     * Overrides onWipeRequest() method in HTTPService. Wipes the data in the
     * skill users' home directories.
     *
     * @method SkillsService#onWipeRequest
     * @param req {JiboServerRequest} request to service
     * @param res {JiboServerResponse} response to send from service.
     * @protected
     */
    protected async onWipeRequest(req:JiboServerRequest, res:JiboServerResponse) {
        let errors = false;
        // Get list of full pathnames of files and directories in /opt/home
        const [homeDirErr, homeFileNames] =
            await prfyTo<string[]>(cb => fs.readdir('/opt/home', cb));
        const homeFiles =
            homeFileNames.map(file => path.join('/opt/home', file));
        if (homeDirErr) {
            res.statusCode = 500;
            const message = 'Error reading list of home directories';
            log.error(message, homeDirErr);
            return res.end(message);
        }
        // Filter those to ensure we have a list of only directories
        const homeDirs = await parallel.filter(homeFiles, async file => {
            // Get stats for the file
            const [statsErr, stats] =
                await prfyTo<fs.Stats>(cb => fs.stat(file, cb));
            // Skip anything we can't stat, but log a warning
            if (statsErr) {
                log.warn(`Error getting stats for ${file}`, statsErr);
                errors = true;
                return false;
            }
            // Return only directories that we could stat
            return stats.isDirectory();
        });
        // Loop over the home directories asynchronously
        await parallel.each(homeDirs, async homeDir => {
            // Get a list of the contents of the directory
            const [filesErr, fileNames] =
                await prfyTo<string[]>(cb => fs.readdir(homeDir, cb));
            const files = fileNames.map(file => path.join(homeDir, file));
            if (filesErr) {
                res.statusCode = 500;
                const message = `Error reading list of files in ${homeDir}`;
                log.warn(message, filesErr);
                errors = true;
                return;
            }
            // Delete each file or directory with rimraf (recursive)
            await parallel.each(files, async file => {
                const [rmErr] = await prfyTo<void>(cb => rimraf(file, cb));
                if (rmErr) {
                    log.warn(`Error removing ${file}`, rmErr);
                    errors = true;
                }
            // Limit to deleting two files or directories at a time
            }, 2);
        // Limit to one home directory at a time
        }, 1);
        log.info(`Wiped contents of home directories, with${errors ? '' : 'out'} errors.`);
        res.writeHead(204, null, {'Content-Length': '0'});
        res.end();
    }

    private _doneTerminate(err: Error, callback: (err?: Error) => void) {
        log.info('screen scheduler timer: skills service class api');
        ScreenScheduler.start();
        this.emit('show');
        callback(err);
    }
}

export default SkillsService;
