export default class AudioServiceSim extends HTTPWSService implements SSMService {

    private static _instance: AudioServiceSim;

    public inputEnergyClients: WebSocket[] = [];

    private _debugState: DebugState = {
        injectWhiteNoise: false,
        injectSine: false,
    };

    private _diagState: SEDiagState = {
        diags: [
            {
                name: 'name',
                type: 0,
                writable: true,
                value: [0, 0],
            },
        ]
    };

    static get instance(): AudioServiceSim {
        return AudioServiceSim._instance;
    }

    constructor(options: ServiceOptions, rootDir: string) {
        super('audio', options, rootDir);
        if (AudioServiceSim._instance) {
            throw new Error('Cannot instantiate AudioServiceSim more than once');
        }
        AudioServiceSim._instance = this;
        log.info("Instantiated");
    }

    init(callback: (err?: Error) => void) {
        super.init((err: Error) => {
            log.info('Initialized');
            callback(err);
        });
    }

    routes(url: Router) {
        super.routes(url);
        url.post('/beam', this._beam);
        url.get('/beam/state', this._beamState);
        url.get('/beam/info', this._beamInfo);
        url.get('/debug', this._debugGet);
        url.post('/debug', this._debugPost);
        url.get('/diag', this._diagGet);
        url.post('/diag', this._diagPost);
        // url.get('/levels', this._levels);
        // url.get('/log', this._logGet);
        // url.post('/log', this._logPost);
        // url.get('/mixer', this._mixerGet);
        // url.post('/mixer', this._mixerPost);
        // url.get('/mode', this._modeGet);
        // url.post('/mode', this._modePost);
        // url.get('/loc_cfg', this._locCfg);
        // url.get('/loc_track', this._locTrackGet);
        // url.post('/loc_track', this._locTrackPost);
        // url.post('/loc_track', this._locTrackPost);
    }

    onConnection(client: WebSocket, request:http.IncomingMessage): void {
        super.onConnection(client, request);
        switch (client.url) {
    //         case '/detection':
    //             this._detection(client, request);
    //             break;
            case '/input_energy':
                this.inputEnergyClients.push(client);
    //             this._inputEnergy(client, request);
                break;
    //         case '/streamState':
    //             this._streamState(client, request);
    //             break;
    //         case '/rin':
    //             this._rin(client, request);
    //             break;
    //         case '/rout':
    //             this._rout(client, request);
    //             break;
    //         case '/sin':
    //             this._sin(client, request);
    //             break;
    //         case '/sout':
    //             this._sout(client, request);
    //             break;
    //         case '/ref':
    //             this._ref(client, request);
    //             break;
        }
    }

    onMessage(command: any, client: WebSocket): void {
        return;
    }

    onClose(client: WebSocket): void {
        if (this.inputEnergyClients.indexOf(client) > -1) {
            this.inputEnergyClients.splice(this.inputEnergyClients.indexOf(client), 1);
        }
    }

    pause(): void {
        log.info('Pausing AudioService');
    }

    resume(): void {
        log.info('Resuming AudioService');
    }

    private _beam = (req: JiboServerRequest, res: JiboServerResponse) => {
        this.finishNoContent(res);
    }

    private _beamState = (req: JiboServerRequest, res: JiboServerResponse) => {
        const beamState: BeamState = {
            ts: [0, 0],
            manual_override: false,
            selection: 0,
        };
        this.sendJson(res, beamState);
    }

    private _beamInfo = (req: JiboServerRequest, res: JiboServerResponse) => {
        const beamInfo: BeamInfo = {
            ts: [0, 0],
            manual_override: false,
            selection: 0,
            beams: [{
                center: 0,
                range: 0,
            }],
        };
        this.sendJson(res, beamInfo);
    }

    private _debugGet = (req: JiboServerRequest, res: JiboServerResponse) => {
        this.sendJson(res, this._debugState);
    }

    private _debugPost = async (
        req: JiboServerRequest,
        res: JiboServerResponse,
    ) => {
        const [err, debugState] = await prfyTo<DebugState>(cb =>
            this.parseBody<DebugState>(req, cb));
        if (err) {
            return this.finish(res, null, err);
        }
        this._debugState = debugState;
        this.finishNoContent(res);
    }

    private _diagGet = (req: JiboServerRequest, res: JiboServerResponse) => {
        this.sendJson(res, this._diagState);
    }

    private _diagPost = async (
        req: JiboServerRequest,
        res: JiboServerResponse,
    ) => {
        const [err, diagStateIn] = await prfyTo<SEDiagState>(cb =>
            this.parseBody<SEDiagState>(req, cb));
        if (err) {
            return this.finish(res, null, err);
        }
        diagStateIn.diags.forEach(diagIn => {
            const existingDiag =
                this._diagState.diags.find(diag => diag.name === diagIn.name);
            if (existingDiag) {
                Object.assign(existingDiag, diagIn);
            } else {
                this._diagState.diags.push(Object.assign({}, diagIn));
            }
        });
        this.finishNoContent(res);
    }
}
