// Simulates the Server Service which subscribes to the cloud
// notification service and offers the notifications up on a web socket.

import fs = require('fs');
import path = require('path');
import Router = require('router');
import http = require('http');

import {ServiceOptions, HTTPWSService, WebSocket} from 'jibo-service-framework';
import {JSC} from '../../clients/jibo-server';
import {SSMService} from '../../SSMService';

import parentLog from '../log';
const log = parentLog.createChild('Server');


export type ErrCallback = (err?:Error)=>void;
export type DataCallback = (err?:Error, data?:any)=>void;


class ServerService extends HTTPWSService implements SSMService {
    private static _instance:ServerService;
    public notificationsClients:WebSocket[];
    public statusClients:WebSocket[];
    public jscNotificationClient;
    private deviceId;


    public static get instance():ServerService {
        return ServerService._instance;
    }


    constructor(public options:ServiceOptions, rootDir:string) {
        super('server', options, rootDir);
        if (ServerService._instance) {
            throw new Error('Cannot instantiate ServerService more than once');
        }
        ServerService._instance = this;
        this.notificationsClients = [];
        this.statusClients = [];
        log.info('Instatiated');
    }


    public init(callback: (err?:Error)=>void) {
        super.init((err:Error) => {
            if (!err) {
                this._initCredentials( (err) => {
                    if (err) {
                        // don't let lack of credentials hold anything else up
                        log.info('could not get credentials or identity, server-service simulator not starting');
                        callback();
                    } else {
                        this._setupClients();
                        let params = {deviceId: this.deviceId};
                        this.jscNotificationClient.connect(params, (err, hub) => {
                            log.iferr(err);
                            if (!err) {
                                log.info('jsc notification client connected');
                                hub.on('message', (message) => {
                                    this.messageReceived(message);
                                });
                                log.info('Initialized');
                            }
                            callback(err);
                        });
                    }
                });
            } else {
                callback(err);
            }
        });
    }


    protected onMessage(command:any, client:WebSocket):void {
        return;
    }


    public onConnection(client:WebSocket, request:http.IncomingMessage):void {
        super.onConnection(client, request);
        if(client.url === '/server/notifications') {
            this.notificationsClients.push(client);
        }
        else if(client.url === '/server/notifications/status') {
            this.statusClients.push(client);
        }
        else {
            log.warn('do not know what to do with this client socket', client.url);
        }
    }


    protected onClose(client:WebSocket):void {
        let i;
        while (i = this.notificationsClients.indexOf(client) > -1) {
            this.notificationsClients.splice(i, 1);
        }
        while (i = this.statusClients.indexOf(client) > -1) {
            this.statusClients.splice(i, 1);
        }
    }


    public routes(url:Router) {
        super.routes(url);
    }


    private messageReceived(message) {
        if (this.notificationsClients.length) {
            this.notificationsClients.forEach( (client) => {
                this.sendWsJson(client, message);
            });
        } else {
            log.warn('no notificationsClients! ignoring message');
        }
    }


    private _initCredentials(callback:ErrCallback) {
        log.info('getting credentials');
        //jibo.systemManager.getCredentials( (err, credentials) => {
        this._getCredentials( (err, credentials) => {
            if (!err) {
                //jibo.systemManager.getIdentity( (err, identity) => {  // warning: does not seem to have all attributes
                log.info('credentials found, updating JSC');
                JSC.config.update(credentials);
                this._getIdentity( (err, identity) => {
                    if (!err) {
                        this.deviceId = identity.name;
                    }
                    callback(err);
                });
            } else {
                callback(err);
            }
        });
    }


    private _setupClients() {
        if (!this.jscNotificationClient) {
            this.jscNotificationClient = new JSC.Notification();
        }
    }


    private _getCredentials(callback:DataCallback) {
        let filename = path.join(process.env.HOME || process.env.USERPROFILE, '.jibo', 'credentials.json');
        this._readJSON(filename, callback);
    }


    private _getIdentity(callback:DataCallback) {
        let filename = path.join(process.env.HOME || process.env.USERPROFILE, '.jibo', 'identity.json');
        this._readJSON(filename, callback);
    }


    private _readJSON(filename, callback:DataCallback) {
        fs.readFile(filename, 'utf8', (err, json) => {
            if (err) {
                callback(err);
            } else {
                let data;
                try {
                    data = JSON.parse(json);
                }
                catch (e) {
                    err = e;
                }
                log.iferr(err, `The file ${filename} has invalid JSON`);
                callback(err, data);
            }
        });
    }
}


export default ServerService;
