import * as assert from 'assert';
import * as fs from 'fs';
import * as crypto from 'crypto';
import {EventEmitter} from 'events';

import {Node, Model} from 'jibo-kb';
import {systemManager} from 'jibo-service-clients';
import {JSC} from '../../clients/jibo-server';
import {
    NotificationsDispatcher,
    RegistryClient,
    RegistrationRecord,
} from 'jibo-service-framework';
import Debouncer from '../../utils/Debouncer';
import ErrorService from '../error/ErrorService';

import parentLog from './log';
const log = parentLog.createChild('SyncManager');


export type ErrCallback = (err?:Error)=>void;
export type ChangedCallback = (err?:Error, changed?:boolean)=>void;

const SLOW_API_TRIGGER = 3 * 1000;    // 3s
const NOTIFICATIONS_DEBOUNCE_PERIOD = 5 * 1000;     // 5s
const NOTIFICATIONS_DEBOUNCE_MAX_SPAN = 60 * 1000;  // 60s
const NO_SYNC_SERVER_ERROR = 'L9-Cannot_connect_to_sync_server';

type PendingRoutine = () => void;

export type RecordCallback = (err?:Error, record?:RegistrationRecord)=>void;


/** Base class for the syncing managers (Loop, Media, Holidays...).
 *
 * @class SyncManager
 * @param {string} httpUrl Url to the KB service
 */
abstract class SyncManager extends EventEmitter {

    public static canSkipFullSync:boolean;  // public just for the holiday manager
    
    protected static credentialsInited:boolean;
    protected static credentialsHash:string;
    protected cloudTimer:any;
    protected syncing:boolean;
    protected queue:PendingRoutine[] = [];
    protected syncTimer:NodeJS.Timer;
    protected pauseDepth:number = 0;
    protected isShutdown:boolean;
    protected pastErrors:string[];
    protected onRobot:boolean;
    protected notificationsDebouncer:Debouncer;
    protected notificationsSuspended:boolean;


    constructor(
        protected httpUrl:string,
        protected name:string,
        protected syncingPeriod:number,
        protected enableCloud:boolean=true)
    {
        super();
        // this.syncing = false;
        // this.queue = [];
        // this.pauseDepth = 0;
        this.notificationsDebouncer = new Debouncer(NOTIFICATIONS_DEBOUNCE_PERIOD, NOTIFICATIONS_DEBOUNCE_MAX_SPAN);
    }


    public init(callback:ErrCallback) {
        // this is done here because it will possible be async again someday
        this.onRobot = this._onRobot();
        callback();
    }


    /** Stop syncing.
     * @method SyncManager#shutdown
     * @param {Function} callback Called when done
     */
    public shutdown(callback:ErrCallback) {
        this._notDuringSyncing( (done) => {
            // don't call 'done', we don't want to resume the sync timer
            this.isShutdown = true;
            callback(null);
        });
    }


    /** Make sure the credentials have been set once. Use the system
     * manager to get the credentials and init the JSC with them.
     */
    protected _initCredentials(callback:ErrCallback) {
        if (SyncManager.credentialsInited) {
            // credentials only need to be inited once per JSC
            process.nextTick(callback);
        } else {
            log.info('Getting credentials');
            systemManager.getCredentials( (err, credentials) => {
                if (err) {
                    log.warn('Error initializing credentials!');
                    callback(err);
                } else {
                    log.info('Credentials found, updating JSC');
                    JSC.config.update(credentials);
                    // JSC.config.update({maxRetries: 1});  // default is 3 which is too many
                    SyncManager.credentialsInited = true;
                    const hash = crypto.createHash('sha256');
                    hash.update(JSON.stringify(credentials));
                    SyncManager.credentialsHash = hash.digest('base64');

                    // JIBO-8345 require the network be present at startup
                    // as a short term fix until we can make the entire SSM
                    // resilient to not having the network available at init
                    this._networkIsRequired( (err) => {
                        if (err) {
                            ErrorService.instance.addError(NO_SYNC_SERVER_ERROR);
                        }
                        callback(err);
                    });
                }
            });
        }
    }


    protected _networkIsRequired(callback: ErrCallback) {
        const accountClient = new JSC.Account({maxRetries: 1});
        accountClient.get({}, (err, data) => {
            log.iferr(err, 'JSC server call Account#get() while testing network');
            if (!err || err.statusCode) {
                if (err) {
                    log.warn('Account#get() err, but we got a statusCode so reporting that the network is up');
                } else {
                    log.info('reporting the network is up');
                }
                // we can't just assume an error means the network is
                // down, the call might have failed for other reasons
                // (e.g. the account being invalid), so if we got a
                // status code, then we talked to the server so we use
                // *that* as an indication that the network is up
                callback();
            } else {
                log.warn('reporting the network is down');
                callback(err);
            }
        });
    }


    protected _setupCanSkipFullSync(lastCredentialsHash) {
        if (SyncManager.canSkipFullSync !== undefined) {
            log.warn('_setupCanSkipFullSync was already called, ignoring');
            return;
        }

        // default to full sync required
        SyncManager.canSkipFullSync = false;

        if (!SyncManager.credentialsHash) {
            log.warn('_setupCanSkipFullSync must be called after _initCredentials');
            return;
        }

        // full sync required if we never had a successful sync
        if (!lastCredentialsHash) {
            log.info('no previous sync done, requiring a full sync');
            return;
        }

        // full sync required if the credentials changed
        if (lastCredentialsHash !== SyncManager.credentialsHash) {
            log.info('credentials do not match, requiring a full sync');
            return;
        }

        // ok, everything checked out, we can skip the full sync startup requirement
        log.info('things look good, setting the can skip full sync flag');
        SyncManager.canSkipFullSync = true;
        return;
    }


    /** Register for notifications events with the given
     * eventName. Sync with the cloud when that notification is
     * triggered.
     */
    protected _syncOnNotification(eventName:string) {
        log.info(`registering for "${eventName}" notifications`);
        NotificationsDispatcher.instance.on(eventName, (message) => {
            // Only act once for multiple closely spaced (NOTIFICATIONS_DEBOUNCE_PERIOD, 5s)
            // notifications.  But don't wait too long (NOTIFICATIONS_DEBOUNCE_MAX_SPAN, 60s)
            // for a break in the notifications before acting (in case there is
            // an endless stream of notifications).
            this.notificationsDebouncer.trigger( () => {
                log.info(`got a notification named "${eventName}"`, message);
                if (!this.notificationsSuspended) {
                    this._syncASAP();
                } else {
                    log.info(`notifications are suspended, ignoring notification ${eventName}`);
                }
            });
        });
    }


    protected _suspendNotifications(callback) {
        this.notificationsSuspended = true;
        callback( () => {
            this.notificationsSuspended = false;
        });
    }


    /** Starts the cloud syncing process. Schedules it to happen every
     * `syncingPeriod` milliseconds. While cloud sycing is happening,
     * routines that are wrapped by `_notDuringSyncing()` are queued up
     * to be executed once syncing has finished.
     * @param {boolean} quietly Optional parameter to suppress initial message
     */
    protected _startSyncTimer(quietly?:boolean) {
        quietly = quietly === undefined ? false : quietly;  // TypeScript default params were breaking things
        if (!quietly) {
            let seconds = (Math.round((this.syncingPeriod / 1000) * 10) / 10);
            log.info(`setting ${this.name} sync with cloud every ${seconds} seconds.`);
        }
        this.syncTimer = global.setTimeout( () => { this._syncASAP(true); }, this.syncingPeriod);
    }


    /** Sync as soon as possible.
     */
    protected _syncASAP(quietly:boolean=false) {
        this._notDuringSyncing( (done) => {
            if (!quietly) {
                log.info(`syncing ${this.name} with cloud...`);
            }
            this.syncing = true;
            this._syncWithCloud( (err, changed) => {
                if (changed) {
                    this._updated( () => {
                        this.syncing = false;
                        done();
                        this._finishSyncing();
                    });
                } else {
                    this.syncing = false;
                    done();
                    this._finishSyncing();
                }
            });
        });
    }


    /** Finish a periodic sync cycle and schedule the next one.
     */
    protected _finishSyncing() {
        this._startSyncTimer(true);
        // call the routines that were deferred waiting for sync to finish
        while (this.queue.length > 0) {
            let pending = this.queue.shift();
            pending();
        }
    }


    /** Stop the timer for the next upcoming cloud sync
     */
    protected _pauseSyncTimer() {
        log.info(`pausing ${this.name} syncing`);
        if (this.pauseDepth === 0) {
            if (this.syncTimer) {
                clearTimeout(this.syncTimer);
                this.syncTimer = undefined;
            }
            this.pauseDepth = 1;
        } else if (this.pauseDepth < 0) {
            log.error('pauseDepth is < 0, something is broken!');
        } else {
            this.pauseDepth += 1;
        }
    }


    /** Reschedule the timer for cloud syncing
     */
    protected _resumeSyncTimer() {
        log.info(`resuming ${this.name} syncing`);
        if (this.pauseDepth) {
            this.pauseDepth -= 1;
            if (this.pauseDepth === 0) {
                if (!this.syncTimer) {
                    this._startSyncTimer(true);
                }
            }
        }
    }


    /* Call a routine during a time when this manager is not in the
     * process of syncing, and temporarily turn off periodic syncing
     * until the provided 'done' callback is called.
     * The routine is either called immediately if there isn't a sync
     * happening, or it is queued up to be called when the current sync
     * is finished.
     * @param {Function} callback The routine to call. Receives
     * 'done' callback which needs to be called to resume periodic
     * syncing
     * @private
     */
    protected _notDuringSyncing( callback:(done)=>void ) {
        if (this.isShutdown) {
            throw Error('tried to use ${this.name} manager after shutdown');
        }

        if (!this.syncing) {
            // not currently syncing, so pause and call callback now
            this._pauseSyncTimer();
            setImmediate( () => {
                callback( () => {
                    this._resumeSyncTimer();
                });
            });
        } else {
            // syncing, so queue up this call for after
            this.queue.push( () => {
                this._pauseSyncTimer();
                callback( () => {
                    this._resumeSyncTimer();
                });
            });
        }
    }


    // override this method to do the actual syncing
    protected abstract _syncWithCloud(callback:ChangedCallback);


    // override this method to be informed when syncing found changes
    protected abstract _updated(callback:ErrCallback);


    /** Make the target object match the source object based in the
     * given list of fields. Any other fields in the terget are left
     * alone. An optional list of fields to be renamed on the target
     * can be provided.
     */
    protected _syncObject(source:Object, target:Object, fields:string[], renames?:Object) {
        let changed = false;
        fields.forEach( (sourceField) => {
            let targetField = sourceField;
            if (renames) {
                targetField = renames[sourceField] || sourceField;
            }
            if (source.hasOwnProperty(sourceField)) {
                if (!this._deepEqual(source[sourceField], target[targetField])) {
                    target[targetField] = source[sourceField];
                    changed = true;
                }
            } else if (target.hasOwnProperty(targetField)) {
                delete target[targetField];
                changed = true;
            }
        });
        return changed;
    }


    /** Make the target object match the source object strictly. Any
     * fields on the target object that are not on the source object
     * will be removed.
     */
    protected _syncObjectStrict(source:Object, target:Object) {
        let changed = false;
        Object.keys(source).forEach( (field) => {
            if (source.hasOwnProperty(field)) {
                if (!this._deepEqual(source[field], target[field])) {
                    target[field] = source[field];
                    changed = true;
                }
            } else if (target.hasOwnProperty(field)) {
                delete target[field];
                changed = true;
            }
        });
        return changed;
    }


    /** Fetch a service registry record by name.
     */
    protected _getServiceRecord(serviceName:string, callback:RecordCallback) {
        RegistryClient.instance.getRecords( (err, records) => {
            if (err) {
                callback(err);
            } else if (!records) {
                callback(new Error('no records from registry'));
            } else {
                let found = false;
                for (let i=0; i<records.length; i++) {
                    if (records[i].name === serviceName) {
                        found = true;
                        callback(null, records[i]);
                        break;
                    }
                }
                if (!found) {
                    callback(new Error('no record for service "'+serviceName+'" found in registry'));
                }
            }
        });
    }


    protected _createNodeWithId(id:string, model:Model, type:string):Node {
        let node = new Node(type);
        node._id = id;
        model.pool[0].adoptNodeAsOurOwn(node);
        model.cache.add(node);
        return(node);
    }


    /** Check the status code of an HTTP call and generate an error
     * object if it is not in the 2xx range.
     */
    protected _checkStatusCode(err:Error, res, message:string=null):Error {
        if (!err) {  // game over if we already have an err
            if (res.statusCode < 200 || res.statusCode > 299) {
                let description = 'HTTP Error Code '+res.statusCode;
                if (message) {
                    description += message;
                }
                err = new Error(description);
            }
        }
        return err;
    }


    /** Compare two values and see if they match. Recursively checks
     * child objects and array members too.
     */
    protected _deepEqual(value1:Object, value2:Object):boolean {
        try {
            assert.deepEqual(value1, value2);
        } catch (error) {
            if (error.name !== "AssertionError") {
                throw error;
            }
            return false;
        }
        return true;
    }


    /** Issue an error once. Keep track of the error strings issued so
     * we won't repeat an error message if it exactly matches a
     * previous error.
     *
     * Since some managers try to sync in the background as frequently
     * as every 15 seconds, we don't want to overload the logs with
     * repeating messages when there is something wrong with the
     * server or account.
     *
     * param {string} errorMessage The error string to issue or suppress
     * @private
     */
    protected _errorOnce(errorMessage:string) {
        if (!this.pastErrors) {
            this.pastErrors = [];
        }

        if (this.pastErrors.indexOf(errorMessage) < 0) {
            log.error(errorMessage);
            this.pastErrors.push(errorMessage);
        }
    }


    /** Start the slow cloud call watch timer.
     */
    protected _startTimer() {
        this.cloudTimer = process.hrtime();
    }


    /** Finish the slow cloud call watch timer and report if it
     * took too long.
     */
    protected _endTimer(apiCallName:string) {
        if (this.cloudTimer) {
            const diff = process.hrtime(this.cloudTimer);
            //convert to milliseconds
            let elapsed = diff[0] * 1000 + diff[1] / 1000000;
            if (elapsed > SLOW_API_TRIGGER) {
                log.warn(apiCallName, 'was slow ('+elapsed+'ms)');
            }
        }
    }


    /** Determine if we are running on the robot or in the simulator.
     *
     * @returns {boolean} `true` if on robot.
     * @private
     */
    protected _onRobot():boolean {
        // we need a better centralized way to tell if we are on the robot FIXME
        return (process.platform === 'linux' && process.arch === 'arm' && fs.existsSync('/var/jibo'));
    }
}


export default SyncManager;
