import {api as jetstream} from '@jibo/jetstream-client';
import {UserNode} from 'jibo-kb';

import parentLog from './log';
const log = parentLog.createChild('EnrollmentLoopInformer');

export default class EnrollmentLoopInformer {
    public async update(loop:UserNode[]):Promise<void> {
        // figure out if we need to update enrolled speakers
        let currentLoopIds:string[] = [];
        let speakersToDelete:string[] = [];
        loop.forEach( (user) => {
            // if our user hasn't been deleted, keep it in our loopIds
            if (user.data.status !== 'declined' && user.data.status !== 'removed') {
                currentLoopIds.push(user._id);
            }
        });
        const enrolled = await jetstream.getEnrolledSpeakers();
        enrolled.forEach((speaker) => {
            // if our loop Ids list does not contain this speaker ID,
            // we need to delete the speaker from enrolled speakers
            if(currentLoopIds.indexOf(speaker) === -1) {
                log.info('deleting enrolled speaker with loop id', speaker);
                speakersToDelete.push(speaker);
            }
        });
        for (const speaker of speakersToDelete) {
            try {
                await jetstream.removeSpeakerModel(speaker);
            } catch (err) {
                log.warn(`Unable to remove speaker model for speaker with loop id ${speaker}`, err);
            }
        }
    }
}