
/**
 * Parse in a way that is guaranteed to return either a value or undefined
 * @param  text     String to parse from
 * @param  regex    RegEx to parse with, or null to skip parsing
 * @param  cb       Callback to apply with results
 *
 * @return          Result of callback or undefined
 * @throws          NoThrow
 */
export function safeParse<T>(text: string, regex: RegExp|null, cb: (data: RegExpMatchArray|string)=>T ): T
{
    if(!text){
        return undefined;
    }
    const result = regex ? text.match(regex) : text ;
    if(!result){
        return undefined;
    }
    try{
        return cb(result);
    }catch(e){
        return undefined;
    }
}
