
// @TODO - comment what this class does
export class NetworkContainer {
    public container: {[key:string]:NetworkProfile};
    constructor() {
        this.container = {};
    }
    
    /*
    data is a line from the wpa_supplicant list networks - ie:
    0 JIBO_TEST
    1 TEST_AP
    2 TESTING
    
    a line is passed through to see if it's a valid network(ie: 1 TEST_AP)
    */
    public addNewNetworkProfile(data:string) {
        if(data.split('\t').length === 4) {
            let prof = new NetworkProfile(data);
            if ((prof.ssid !== null) && !this.container.hasOwnProperty(prof.ssid)) {
                this.container[prof.ssid] = prof;
            }
        }
    }
    
    /*
    will iterate through scan results to determine if each network is active or not and if it has been tried
    */
    public async getBestNetwork(): Promise<NetworkProfile> {
        let best_network = new NetworkProfile('a');

        let found = false;
        for(let key in this.container) {
            if(this.container[key].active === 1 && !this.container[key].tried) {
                if(this.container[key].rssi < best_network.rssi) {
                    best_network = this.container[key];
                    found = true;
                }
            }
        }

        // Potential to mean all networks have been tried and weren't able to be connected to so clear
        // the tried flag for next time
        if(!found) {
            for(let key in this.container) {
                this.container[key].tried = false;
            }
        }

        return best_network;
    }
    
    /*
    data = raw scan results
    */
    public async updateWiFiProfiles(data): Promise<{[key:string]:NetworkProfile}> {
        let split_lines = data.split('\n');
        for(let i = 0; i < split_lines.length; ++i) {
            let tab_line = split_lines[i].split('\t');
            //means SSID is not hidden
            if(tab_line.length === 5){
                if(this.container.hasOwnProperty(tab_line[4])){
                    this.container[tab_line[4]].rssi = tab_line[2];
                    this.container[tab_line[4]].active = 1;
                    this.container[tab_line[4]].freq = tab_line[1];
                }
            }
        }
        return this.container;
    }
}

export class NetworkProfile {
    
    public ssid:string;
    public networkID:string;
    public hidden:number;
    public static:number;
    public rssi:number;
    public freq:number;
    public active:number;
    public tried:boolean;
    
    constructor(data){
        this.ssid = null;
        this.rssi = null;
        this.freq = null;
        this.active= null;
        this.networkID = null;
        this.tried = false;

        //validates it's actually a network profile
        if(data.charAt(0) >= '0' && data.charAt(0) <= '9') {
            let split_line = data.split('\t');
            this.ssid = split_line[1];
            this.networkID = split_line[0];
        }
    }
}
