type Callback = (error?: Error, data?: any) => void;

interface SimulatedSpeech {
    words: string;
    speaker: string;
    speakerId: string;
    incremental?: boolean;
    final?: boolean;
}

export enum State {
    CONNECTING_TO_CONTEXT = 'CONNECTING_TO_CONTEXT',
    IDLE = 'IDLE',
    GLOBAL_TURN = 'GLOBAL_TURN',
    LOCAL_TURN = 'LOCAL_TURN',
    VOICE_ENROLLMENT_TURN = 'VOICE_ENROLLMENT_TURN',
    PRONUNCIATION_TURN = 'PRONUNCIATION_TURN',
    WAITING_FOR_HUB = 'WAITING_FOR_HUB',
    ERROR = 'ERROR',
}

enum HJMode {
    NORMAL_HJ = 'NORMAL_HJ',
    IGNORE_HJ = 'IGNORE_HJ',
    ONLY_HJ = 'ONLY_HJ'
}

export interface SpeechOptions {
    speech?: SimulatedSpeech;
    nlu?: types.NLUResult;
    global?: boolean;
    turnOptions?: types.LocalTurnOptions;
    mimicGlobalOptions?: types.MimicGlobalTurnOptions;
    requestID?: string;
}

export interface TimeoutOptions {
    earlyEOS?: string[];
    sosTimeout: number;
    maxSpeechTimeout: number;
}

interface GlobalRuleSubscription {
    requestID: string;
    rules: string[];
}

//timeouts in seconds
const DEFAULT_LOCAL_TURN_TIMEOUTS = {
    sosTimeout: 6,
    maxSpeechTimeout: 15
};
//timeouts in seconds
const GLOBAL_TURN_TIMEOUTS = {
    sosTimeout: 4,//on robot, probably 2, but we'll be nice to devs using the simulator
    maxSpeechTimeout: 15
};

//words to use in place of the $YESNO token for EOS
const YES_NO_EOS = [
    'yes',
    'yep',
    'yeppers',
    'yeah',
    'sure',
    'no',
    'nah',
    'nope',
];

