    private vadClientSockets: WebSocket[] = [];
    private paused: boolean;
    private contextClient: HTTPClient;

    private state = State.IDLE;
    private hjMode: HJMode = HJMode.NORMAL_HJ;
    private activeGlobalRules: GlobalRuleSubscription[] = [];
    private activeExclusiveGlobalRules: GlobalRuleSubscription[] = [];

    private activeTurn: Turn;
    private activeProactiveSession: hub_session.ProactiveClientSession;
    private timedOutWatingForContext = false;
    private requestIDCounter = 0;
    private jsOptions: JetstreamOptions;
