import {HTTPClient} from 'jibo-service-framework';
import parentLog from './log';

const log = parentLog.createChild('DevTools');

class DevToolsClient extends HTTPClient {


    private static _instance:DevToolsClient;

    public static createInstance(host:string, port:number):DevToolsClient {
        return new DevToolsClient(host, port);
    }

    constructor(public host:string, public port:number) {
        super(host, port);
        DevToolsClient._instance = this;
    }

    getJson(callback: (err:Error, json:any) => void):void {
        this.get('/json', (err:Error, json:any) => {
            log.iferr(err, 'Error getting /json');
            if(!err) {
                log.debug('Got JSON', json);
            }
            callback(err, json);
        });
    }
}

export default DevToolsClient;
