import { EventEmitter } from 'events';
import WebSocket = require('ws');
import http = require('http');
import Router = require('router');
import finalhandler = require('finalhandler');
import AssetServer, {ASSET_PATH} from './assets/AssetServer';
import {CommandRequestNotification} from '../security-controller/CommandRequestNotification';
import parentLog from './log';
import * as timer from 'application-metrics';
const log = parentLog.createChild('ConnectionManager');

const EXTERNAL_PORT = 8160;
const HEARTBEAT_TIME = 10 * 1000;
const FLATLINE_TIME = 20 * 1000;

export default class ConnectionManager extends EventEmitter {

    private static _instance: ConnectionManager = null;

    private webServer: http.Server = null;
    private wsServer: WebSocket.Server = null;
    private webSocket: WebSocket = null;
    private nextPing: NodeJS.Timer = null;
    private checkHeartbeatInterval: NodeJS.Timer = null;
    private lastMessageTime: number = 0;
    private appData:any;

    public static dispose(): void {
        if (this._instance) {
            this._instance.cleanup();
            this._instance = undefined;
        }
    }

    static get instance(): ConnectionManager {
        if (!ConnectionManager._instance) {
            ConnectionManager._instance = new ConnectionManager();
        }

        return ConnectionManager._instance;
    }

    constructor() {
        super();

        this.onRequest = this.onRequest.bind(this);
        this.onConnection = this.onConnection.bind(this);
        this.onClose = this.onClose.bind(this);
        this.onMessage = this.onMessage.bind(this);
        this.checkForPulse = this.checkForPulse.bind(this);
        this.sendPing = this.sendPing.bind(this);
        this.onPong = this.onPong.bind(this);
    }

    public async listen(assets:AssetServer, isInSim:boolean) {
        //Connect our router to make it a little simpler to handle responses
        const router = new Router();
        this.webServer = http.createServer((req: any, res: any) => {
            router(req, res, finalhandler(req, res));
        });
        //set up route to handle connection requests and the aco
        router.post('/request', this.onRequest);
        //set up the asset server to handle the asset paths
        router.get(ASSET_PATH + ':url', assets.handleAssetRequest);

        //if in simulator, listen for just local connections, because the simulator is a special
        //beast that doesn't get to talk to the server in the same way
        this.webServer.listen(EXTERNAL_PORT, isInSim ? '127.0.0.1' : '0.0.0.0', 10, () => {
            console.log('REMOTE SERVICE LISTENING ON PORT ', this.webServer.address().port);
        });
        this.wsServer = new WebSocket.Server({
            server: this.webServer as http.Server
        });

        this.wsServer.on('connection', this.onConnection);
    }

    /**
     * Use to trigger a manual close originating from robot (i.e. head touch exit, inactivity timeout)
     * @param code 
     * @param reason 
     */
    public close(code:number, reason:string) {
        if (this.webSocket) {
            this.webSocket.removeListener('close', this.onClose);
            this.webSocket.close(code, reason);
            //slight delay before shutting down our server, to give the websocket a chance to
            //close normally - otherwise the code 1006 (Abnormal Closure) would have overridden ours
            setTimeout(() => {
                this.cleanup(true);
            }, 3);
        }
    }

    /**
     * Use for manual clean up, unlike close does not provide websocket with close code or reason
     */
    public reset() {
        this.cleanup(true);
    }

    /**
     * send messages along the external websocket
     * @param message 
     */
    public send(message:any):Promise<void> {
        return new Promise((resolve, reject) => {
            if (this.webSocket) {
                if (typeof message !== 'string') {
                    message = JSON.stringify(message);
                }
                this.webSocket.send(message, (err) => {
                    if (err) {
                        log.warn('Remote send failure:', err);
                        this.webSocket.terminate();
                        reject();
                        return;
                    }
                    resolve();
                });
            }
        });
    }

    /**
     * Used by SCS (Security Controller Service) to signal a new connection is coming in
     * Method decides if connection attempt is OK and replies with response
     */
    private onRequest(req:http.ServerRequest, res:http.ServerResponse): void {
        timer.start('onRequest');
        let chunk = "";
        req.on('data', data => chunk += data);
        req.on('end', () => {
            let data:CommandRequestNotification;
            try {
                data = JSON.parse(chunk);
            } catch (e) {
                log.warn('Unable to parse command mode request', e);
                let response = '{"accept": false}';
                res.setHeader('Content-Type', 'application/json');
                res.setHeader('Content-Length', response.length.toString());
                res.statusCode = 200;
                res.end(response);
                return;
            }
            // close current WebSocket, trigger an 'unclean' disconnect, session maintenance will be deteremined by the subsequent connection request
            // TODO :: maybe we want to disconnect existing connections before we OK a new connection, but it was causing errors
            // FIXME right now this is just hardwired to accept all command requests
            // FIXME and it is ignoring the ACO
            log.debug('accepting command mode request');
            this.appData = data;
            let response = '{"accept": true}';
            res.setHeader('Content-Type', 'application/json');
            res.setHeader('Content-Length', response.length.toString());
            res.statusCode = 200;
            res.end(response);
        });
    }

    /**
     * Handler for WebSocket.Server 'connection' event
     * Stores the given WebSocket and adds handlers for its events
     * @param ws 
     */
    private onConnection(ws: WebSocket): void {
        log.debug('Command Performance : time to connect after request : ' + timer.stop('onRequest') + 'ms');
        this.webSocket = ws;
        // message from Jibo
        ws.on('message', this.onMessage);

        this.lastMessageTime = Date.now();
        this.checkHeartbeatInterval = setInterval(this.checkForPulse, HEARTBEAT_TIME);
        this.sendPing();
        ws.on('pong', this.onPong);

        ws.on('close', this.onClose);
        this.emit('connected', this.appData);
        this.appData = undefined;  // don't leave a stale aco around, just in case
        log.info('websocket connected');
    }

    private sendPing():void {
        if (this.webSocket) {
            this.nextPing = null;
            try {
                this.webSocket.ping();
            } catch (e) {
                this.webSocket.terminate();
            }
        }
    }

    private onPong():void {
        this.lastMessageTime = Date.now();
        if (this.nextPing) {
            clearTimeout(this.nextPing);
        }
        this.nextPing = setTimeout(this.sendPing, HEARTBEAT_TIME);
    }

    private checkForPulse():void {
        if (Date.now() - this.lastMessageTime >= FLATLINE_TIME) {
            if (this.webSocket) {
                this.webSocket.terminate();
            }
        }
    }

    /**
     * Handler for 'message' emit from webSocket connecting to SCS
     * @param code 
     */
    private onMessage(message: string): void {
        this.lastMessageTime = Date.now();
        if (this.nextPing) {
            clearTimeout(this.nextPing);
        }
        this.nextPing = setTimeout(this.sendPing, HEARTBEAT_TIME);
        //don't bother parsing it, because we are going to send it through another websocket
        this.emit('message', message);
    }

    /**
     * Handler for 'close' emit from webSocket connecting to SCS
     * Checks code to determine if close was purposeful or in error, calls cleanup which closes connections
     * @param {number} code - a 1000 indicate a purposeful close, anythig else will be considered as a close due to error
     */
    private onClose(code:number): void {
        const endSession:boolean = code === 1000;
        log.info(`websocket client closed, sent code: ${code}, will end session: ${endSession}`);
        //if code === 1000, then it was a normal websocket close, no errors or special messages involved
        this.cleanup(endSession);
    }

    /**
     * Clears heartbeat interval, emits `disconnected`, removes listeners and closes sockets and servers connect to SCS
     * @param isNormal 
     */
    private cleanup(isNormal = true) {
        clearInterval(this.checkHeartbeatInterval);
        clearInterval(this.nextPing);
        this.cleanupWebSocket(isNormal);
        if (this.wsServer) {
            this.wsServer.removeAllListeners();
            this.wsServer.close();
            this.wsServer = null;
        }
        if (this.webServer) {
            this.webServer.close();
            this.webServer = null;
        }
    }

    private cleanupWebSocket(isNormal = true) {
        if (this.webSocket) {
            try {
                this.emit('disconnected', isNormal);
            } catch (e) {
                log.warn('Error during disconnect emit', e);
            }
            this.webSocket.removeAllListeners();
            if (this.webSocket.readyState === this.webSocket.OPEN) {
                this.webSocket.close();
            }
            this.webSocket = null;
        }
    }
}

