import {Node, Model, RobotRootNode} from 'jibo-kb';
import kb from '../../clients/KBClient';
import {systemManager} from 'jibo-service-clients';

import parentLog from '../log';
const log = parentLog.createChild('LocationManager');

import {LocationData, getLocation, geocodeWithGoogle} from './Location';
import {TimezoneData, lookUpTimezone} from './Timezone';
import KBService from "../../services/kb/KBService";
import WifiService from "../../services/wifi/WifiService";
import ErrorService from "../../services/error/ErrorService";
import SchedulerService from "../../services/scheduler/SchedulerService";
import {SystemManagerClient} from "jibo-client-framework";
import BackgroundUtilsManager from '../../utils/BackgroundUtilsManager';

//NOTE: reset-date-cache is in buildroot, not an immediate dependency of the SSM, as it uses
//native bindings
let resetDateCache:Function;
try {
    resetDateCache = require('reset-date-cache');
} catch (e) {
    //not running on robot, or running on robot not new enough to have dependency
    log.warn(`error loading reset-date-cache:`, (e.message || e));
    resetDateCache = null;
}


const GEO_LOCATION_ERROR = 'T1-Geolocation_failed';
const KB_SLICE_NAME = '/jibo/location';
const DATA_TOO_FRESH = 1000 * 60 * 30;//30 minutes in milliseconds
const DATA_TOO_OLD = 1000 * 60 * 60 * 24 * 14;//2 weeks in milliseconds

export type ErrCallback = (err?:Error)=>void;
export type NodeCallback = (err, node?:Node)=>void;
export type ChangedCallback = (err?:Error, changed?:boolean)=>void;

/**
 *
 * @class LocationManager
 * @description Determine Jibo's location, timezone, and tell the App what it is
 * @param {string} httpUrl Url to the KB service
 * @param {boolean} [enableCloud=true] Enables the cloud checking. If false, no cloud calls will be done.
 */
class LocationManager {
    private static _instance:LocationManager;

    private httpUrl:string;
    private enableCloud:boolean;
    private model:Model;
    private rootNode:Node;

    private isIntDev:Promise<boolean>;

    public static get instance() {
        return LocationManager._instance;
    }

    public static init() {
        const instance = LocationManager._instance = new LocationManager();
        //attach to global for QA purposes
        //(global as any).locationManager = instance;
        //initialize location manager, add hook to know when we first connect to Wifi
        instance.init(() => {
            //WifiService or ErrorService not initialized due to unit tests, can't do anything about it
            if (!WifiService.instance || !ErrorService.instance)
            {
                return;
            }

            WifiService.instance.verifyConnection().then((err) => {
                //verifyConnection actually resolves with an ErrorCode object, to try to stick
                //closer to previous callback behavior/usage
                if (err) {
                    log.info('on init, wifi or internet not ready - waiting for state change');
                    // if we are not connected yet, then listen for a state change
                    WifiService.instance.on('internet-connected', instance._onWifiConnected);
                    return;
                }
                //listen for any updates to the robot info, because we want about user set location
                kb.robot.events.robotUpdated.on(instance._onRobotUpdated);
                log.info('on init, wifi and internet verified - getting location');
                //for initial check if we are already connected, ensure that the current
                //location is accurate, in case we were turned off and moved
                instance.getTimezone(true)
                    .then((timezone) => {
                        //schedule a callback of _checkForChangedTimezone at 2:30AM local time
                        //every day, basically to see if daylight savings time happened to
                        //change the offset to UTC
                        SchedulerService.instance.addJob('0 30 2 * * *', instance._checkForChangedTimezone);
                });
            }, (error)=> {
                log.info('on init, wifi or internet not ready - waiting for state change');
                // if we are not connected yet, then listen for a state change
                WifiService.instance.on('internet-connected', instance._onWifiConnected);
            });
        });
    }

    private static areLocationsEqual(loc1:LocationData, loc2:LocationData):boolean {
        return loc1.lat === loc2.lat && loc1.lng === loc2.lng && loc1.isUserSet === loc2.isUserSet;
    }

    constructor(enableCloud:boolean=true) {
        // NOTE: we explicitly use 127.0.0.1 instead of localhost here (and everywhere else) see JIBO-7115
        this.httpUrl = 'http://127.0.0.1:' + KBService.instance.port;
        this.enableCloud = enableCloud;
        this._onWifiConnected = this._onWifiConnected.bind(this);
        this._checkForChangedTimezone = this._checkForChangedTimezone.bind(this);
        this._onRobotUpdated = this._onRobotUpdated.bind(this);
    }

    public init(callback:ErrCallback) {
        this.model = kb.createModel(KB_SLICE_NAME, this.httpUrl);

        this.isIntDev = new Promise<boolean>((resolve) => {
            systemManager.getMode((err, data) => {
                resolve(data === 'int-developer');
            });
        });

        this._preloadLocationModel(() => {
            log.info("KB Model Intialized");
            if (callback) {
                callback();
            }
        });
    }

    public getTimezone(refreshLocation:boolean = false):Promise<TimezoneData> {
        return this._getLocation(refreshLocation)
            .then((location) => {
                this._logIfIntDev(`Looking up timezone for ${location.lat}, ${location.lng} now`);
                return lookUpTimezone(location.lat, location.lng);
            })
            .then((timezone) => {
                return this._saveTimezone(timezone);
            })
            .catch((err) => {
                log.warn('error when looking up timezone, not setting system timezone: ' + (err.message || err));
                return null;
            });
    }


    //manually set the timezone to anything with values listed at https://en.wikipedia.org/wiki/List_of_tz_database_time_zones
    setTimezone(tzId:string, offset:string):void {
        if (!tzId || !offset) {
            this.help();
            return;
        }

        try {
            //parse the hours and minutes offset out of a string formatted like '-05:30' or '+10:00'
            const [,hours, minutes] = /^([+-]\d\d):(\d\d)$/.exec(offset);
            //milliseconds by which the time is off from UTC, including active Daylight Savings Time
            const offsetUTC = parseInt(hours) * 60 * 60 * 1000 + parseInt(minutes) * 60 * 1000;
            //long name of timezone, like "Eastern Standard Time"
            const name = 'MANUALLY SET';
            //"tz" id of the timezone, like "America/Los_Angeles"
            const id = tzId;
            const timezone:TimezoneData = {
                offsetUTC,
                name,
                id,
                __type: 'Timezone'
            };
            //save the timezone to the KB and set the system time as appropriate
            this._saveTimezone(timezone);
        } catch (e) {
            this.help();
            return;
        }
    }

    //schedules a cronjob to run the regular timezone check in 2 minutes
    resetTimezone():void {
        //add a job for 2 minutes from now
        const jobId = SchedulerService.instance.addJob('*/2 * * * *', () => {
            //run timezone check
            this._checkForChangedTimezone();
            //remove job
            SchedulerService.instance.removeJob(jobId);
        });
    }

    //causes the location error to get emitted, for manual testing that this will emit it
    breakLocation():void {
        const tempLoad = this.model.load;
        this.model.load = (id) => {
            return Promise.reject('Forcing a KB failure!');
        };
        const tempScan = WifiService.instance.getScanResults;
        WifiService.instance.getScanResults = () => Promise.reject(new Error('Forcing a WIFI failure!'));
        this.getTimezone(true).then(() => {
            WifiService.instance.getScanResults = tempScan;
            this.model.load = tempLoad;
        });
    }

    //console output for manual timezone debug/QA stuff
    help():void {
        console.log('Location Manager QA/Debug Commands:');
        console.info('locationManager.resetTimezone(): sets up a cron job for 2 minutes from now to run the regular checking of timezone for the current latitude/longitude.');
        console.info('locationManager.setTimezone(timezoneId, offset): Manually set the timezone of the robot with data from https://en.wikipedia.org/wiki/List_of_tz_database_time_zones');
        console.log('timezoneId should be a value from the TZ column. offset should be a value from the UTC offset OR the UTC DST offset column.');
        console.warn('NOTE: The system time is set only via timezoneId, so please only enable DST if that timezone is currently in DST, otherwise date/time math may be out of sync.');
        console.info('locationManager.breakLocation(): Causes the LocationManager to fail a location fetch, so that it will trigger the corresponding error in the error system.');
    }

    private _logIfIntDev(...params) {
        this.isIntDev.then((isIntDev) => {
            if (isIntDev) {
                log.info(...params);
            }
        });
    }

    private _onWifiConnected() {
        //listen for any updates to the robot info, because we want about user set location
        kb.robot.events.robotUpdated.on(this._onRobotUpdated);
        // add job when internet is connected'
        log.info('internet now connected - getting location and canceling wait');
        //only want to do this on the first connnection
        WifiService.instance.removeListener('internet-connected', this._onWifiConnected);
        //for initial check, ensure that the current location is accurate, in case
        //we were turned off and moved
        this.getTimezone(true)
            .then((timezone) => {
                //schedule a callback of _checkForChangedTimezone at 2:30AM local time //tomorrow, basically to see if daylight savings time happened to change the //offset to UTC
                SchedulerService.instance.addJob('0 30 2 * * *', this._checkForChangedTimezone);
        });
   }

    private _checkForChangedTimezone() {
        this.getTimezone();
    }

    private _onRobotUpdated() {
        //load robot data
        kb.robot.loadRoot().then((robotNode:RobotRootNode) => {
            //load current location data
            return this.model.load(this.rootNode.getEdges('home'))
            .then<any>((nodes) => {
                //compare data
                if (robotNode.data.locationOverride) {
                    //if there is a location override, and it is different than what we have, then
                    //save the override data
                    if (!nodes || !nodes.length ||
                        !LocationManager.areLocationsEqual(robotNode.data.locationOverride, nodes[0].data)) {
                        //clear error if present
                        ErrorService.instance.removeError(GEO_LOCATION_ERROR);
                        //log helpful data
                        this._logIfIntDev('Overriding location with ', robotNode.data.locationOverride);
                        log.info('User overrode location');
                        //take copy of location data, add our flags to it
                        const location:LocationData = Object.assign({
                            fetchSuccess: false,
                            isUserSet: true
                        }, robotNode.data.locationOverride);
                        return Promise.resolve(location)
                        .then((location) => {
                            //ensure that we have a country code, in case of older data that was
                            //created before we started using the country code
                            if (!location.countryCode) {
                                return geocodeWithGoogle(location.lat, location.lng)
                                .then((location) => {
                                    //take the location data, add our flags to it
                                    location.fetchSuccess = false;
                                    location.isUserSet = true;
                                    return location;
                                });
                            }
                            return location;
                        })
                        .then((location) => {
                            //save the location data
                            return this._saveLocation(location);
                        })
                        .then((location) => {
                            this._logIfIntDev(`Looking up timezone for ${location.lat}, ${location.lng} on update`);
                            return lookUpTimezone(location.lat, location.lng);
                        })
                        .then((timezone) => {
                            return this._saveTimezone(timezone);
                        })
                        .catch((err) => {
                            log.warn('error when looking up timezone, not setting system timezone: ' + (err.message || err));
                            return null;
                        });
                    }
                } else {
                    //if we don't have the override, but did previously, then clear that and
                    //get a new location
                    if (nodes && nodes.length && nodes[0].data.isUserSet) {
                        log.info('User cleared location override');
                        //flag the previous data as invalid and due for replacement
                        nodes[0].data.fetchSuccess = false;
                        nodes[0].data.isUserSet = false;
                        //save previous data, then fetch new data
                        return nodes[0].save().then(() => {
                            return this.getTimezone(true);
                        });
                    }
                }
            });
        });
    }

    private _preloadLocationModel(callback:ErrCallback) {
        this.model.loadRoot( (err, rootNode) => {
            this.rootNode = rootNode;
            callback();
        });
    }

    private _getLocation(refreshLocation:boolean):Promise<LocationData> {
        return this.model.load(this.rootNode.getEdges('home'))
            .then((nodes) => {
                //no node for some reason? - also, if KB is incorrect due to previous code, then
                //just get new data
                if (!nodes || !nodes[0] || !nodes[0].data || nodes.length > 1) {
                    log.debug('_getLocation, no node!');
                    return this._learnAndSaveLocation();
                }
                //if the data is sufficiently old, then get fresh data
                //this is to avoid hitting the server on many quick reboots
                //TODO: Figure out how to calculate our time turned off, and use that instead
                //so we only check if we've spent 30 minutes or more turned off - less than that
                //and Jibo hasn't moved enough for us to care
                const data = nodes[0].data as LocationData;
                //if the data is a user override, then just use that with no questions asked
                if (data.isUserSet) {
                    return data;
                }
                log.debug(`_getLocation - time since update vs DATA_TOO_FRESH: ${Date.now() - data.fetchedAt} > ${DATA_TOO_FRESH}; fetchSuccess: ${data.fetchSuccess}`);
                //if the data we have isn't a successful fetch, or is too old, then always check
                //our location.
                //Otherwise, on boot (refreshLocation is true) check if the data we have is
                //somewhat older, so we don't keep checking if we keep rebooting.
                if (!data.fetchSuccess || !data.fetchedAt || !data.countryCode ||
                    Date.now() - data.fetchedAt > DATA_TOO_OLD ||
                    (refreshLocation && Date.now() - nodes[0].updated > DATA_TOO_FRESH)) {
                    log.info('Fetching location data');
                    return this._learnAndSaveLocation(data);
                } else {
                    log.info('Previous location data is considered new enough, is being reused');
                    return data;
                }
            }, (err) => {
                //probably never had a location
                return this._learnAndSaveLocation();
            });
    }

    private _learnAndSaveLocation(prevLocation?:LocationData):Promise<LocationData> {
        return getLocation()
            .then((location) => {
                this._logIfIntDev('Location fetched from Google: ', location);
                //in case there is an error on screen, then clear it as we got a successful result
                ErrorService.instance.removeError(GEO_LOCATION_ERROR);
                return location;
            })
            .catch((err) => {
                log.warn('error while getting location, falling back to previous location or Boston - ' + (err.message || err));
                if (!prevLocation || !prevLocation.fetchSuccess) {
                    ErrorService.instance.addError(GEO_LOCATION_ERROR);
                }
                //if we previously had a location, just use that
                if (prevLocation) {
                    return prevLocation;
                }
                //if all else fails, use Jibo's HQ?
                return {
                    city: 'Boston',
                    state: 'Massachusetts',
                    stateAbbr: 'MA',
                    country: 'usa',
                    countryCode: 'US',
                    lat: 42.354416,
                    lng: -71.054287,
                    fetchSuccess: false,
                    isUserSet: false
                };
            })
            .then((location) => {
                return this._saveLocation(location);
            });
    }

    private _saveLocation(location:LocationData):Promise<LocationData> {
        let makeNodeProm:Promise<Node>;
        //wipe previous KB data if it was incorrect and we built up a bunch of data that might be
        //wrong
        if (this.rootNode.getEdges('home').length > 1) {
            this.rootNode.clearEdges('home');
        }
        if (this.rootNode.getEdges('home').length === 0) {
            makeNodeProm = new Promise((resolve, reject) => {
                const node = this.model.createNode('location', location);
                this.rootNode.addEdges(node, 'home');
                resolve(node);
            });
        } else {
            makeNodeProm = this.model.load(this.rootNode.getEdges('home'))
                .then((nodes) => {
                    nodes[0].data = location;
                    return nodes[0];
                });
        }

        return makeNodeProm.then((node) => {
            return Promise.all([node.save(), this.rootNode.save()]);
        }).then(() => {
            return location;
        });
    }

    private _saveTimezone(timezone:TimezoneData):Promise<TimezoneData> {
        let makeNodeProm:Promise<Node>;
        if (this.rootNode.getEdges('timezone').length === 0) {
            makeNodeProm = new Promise((resolve, reject) => {
                const node = this.model.createNode('timezone', {});
                this.rootNode.addEdges(node, 'timezone');
                resolve(node);
            });
        } else {
            makeNodeProm = this.model.load(this.rootNode.getEdges('timezone'))
                .then((nodes) => {
                    return nodes[0];
                });
        }

        let prevData:TimezoneData;
        return makeNodeProm.then((node) => {
            prevData = node.data;
            //see if we need to update the timezone
            log.info('comparing current KB timezone to fetched timezone: ', prevData, timezone);
            if (prevData.offsetUTC !== timezone.offsetUTC || prevData.id !== timezone.id) {
                //update the timezone in the KB
                log.info('KB timezone is updated');
                node.data = timezone;
            } else {
                log.info('KB timezone has not changed');
            }
            return node;
        })
        .then((node) => {
            return new Promise<Node>((resolve) => {
                SystemManagerClient.instance.getTimeZone((err, currentZone:string) => {
                    // if the id and offset has not changed, then we don't need to set the
                    // system time, and will be fine with just updating the offsetUTC in the KB
                    const dateTZOffset = new Date().getTimezoneOffset() * 60 * 1000;
                    // timezone offset from Date is in minutes, need to account
                    // for floating point error when converting to ms
                    const tzOffsetsMatch = Math.abs(dateTZOffset - timezone.offsetUTC) < 1;
                    if ((currentZone === timezone.id) && tzOffsetsMatch) {
                        return resolve(node);
                    }
                    SystemManagerClient.instance.setTimeZone(timezone.id, (err) => {
                        if (err) {
                            log.warn('Error when setting system timezone to ' + timezone.id + ': ' + (err.message || err));
                        } else {
                            log.info(`Successfully set system timezone: ${timezone.id}`);
                        }
                        //if we are on robot and have the capability to reset the date cache, we need to
                        //do so; otherwise Dates will continue to think they are in the old timezone
                        if (resetDateCache) {
                            try {
                                process.env.TZ = timezone.id;
                                resetDateCache();
                            } catch (e) {
                                //pants and suspenders error catching.
                                log.warn('Unable to reset date cache after changing the timezone');
                            }
                        }
                        //pass on the node for saving
                        resolve(node);
                    });
                });
            });
        })
        .then((node) => {
            //save no matter what, so that the 'updated' field of the node reflects that we did a
            //check
            log.info(`System time with timezone offset: ${new Date().toString()}`);
            return Promise.all([node.save(), this.rootNode.save()]);
        }).then(() => {
            return timezone;
        });
    }
}

BackgroundUtilsManager.register(() => {
    // wait 5 seconds b/c scanning needs some time after robot starts up to find every AP it can
    setTimeout(() => {
        LocationManager.init();
    }, 5000);
}, 'location');


export default LocationManager;
