import http = require('http');
import VideoStreamer from './VideoStreamer';
import PhotoHoster from './PhotoHoster';
import {VideoAssetMessage, PhotoAssetMessage, CancelAssetMessage} from '../Messages';

export const ASSET_PATH = '/assets/';

export interface RequestHandler {
    start(request:any, selfEndCallback:Function):void;
    handleRequest(res:http.ServerResponse):void;
    stop():void;
}

export default class AssetServer {
    private urlHandlers:Map<string, RequestHandler>;
    
    constructor() {
        this.urlHandlers = new Map();
        this.handleAssetRequest = this.handleAssetRequest.bind(this);
    }
    
    public handleAssetRequest(req:http.ServerRequest, res:http.ServerResponse):void {
        //do some stuff
        
        const url:string = (req as any).params.url;
        //return an error and bail if something is requested that does not exist
        if (!this.urlHandlers.has(url)) {
            res.statusCode = 404;
            res.end();
            return;
        }
        this.urlHandlers.get(url).handleRequest(res);
    }
    
    public removeHandlerForId(id:string) {
        if (!this.urlHandlers.has(id)) {
            return;
        }
        const handler = this.urlHandlers.get(id);
        handler.stop();
        this.urlHandlers.delete(id);
    }
    
    public handleMessage(message:VideoAssetMessage|PhotoAssetMessage|CancelAssetMessage): void {
        const assetUrl = message.asset.assetUrl;
        const id = assetUrl.replace(ASSET_PATH, '');
        switch (message.status) {
            case 'cancelAsset':
                this.removeHandlerForId(id);
                break;
            case 'handleAsset':
                if (this.urlHandlers.has(id)) {
                    return;
                }
                switch (message.asset.type) {
                    case 'video':
                        const streamer = new VideoStreamer();
                        this.urlHandlers.set(id, streamer);
                        streamer.start(message.asset, () => {
                            this.removeHandlerForId(id);
                        });
                        break;
                    case 'photo':
                        const hoster = new PhotoHoster();
                        this.urlHandlers.set(id, hoster);
                        hoster.start(message.asset, () => {
                            this.removeHandlerForId(id);
                        });
                        break;
                }
                break;
        }
    }
    
    public removeAll() {
        for (const id in this.urlHandlers) {
            this.removeHandlerForId(id);
        }
    }
}