import {RequestHandler} from './AssetServer';
import http = require('http');
import axios from 'axios';
import stream = require('stream');

//10 seconds to make a request to fetch the asset - after that, it disappears
const AVAILABILITY_TIMEOUT = 10000;

export interface PhotoData {
    type: 'photo';
    assetUrl: string;
    photoUrl: string;
}

export default class PhotoHostewr implements RequestHandler {
    private ongoingResponse:http.ServerResponse = null;
    private pipedImage:stream.PassThrough = null;
    private isSending:boolean = false;
    private selfEndCallback:Function = null;
    private photoUrl:string = null;
    private timeout:NodeJS.Timer = null;

    constructor() {
        //nada?
    }

    public start(request:PhotoData, selfEndCallback:Function):void {
        this.selfEndCallback = selfEndCallback;
        this.photoUrl = request.photoUrl;

        this.fetchPhoto();
        //start timeout if no request is made
        this.timeout = setTimeout(() => {
            this.selfEndCallback();
        }, AVAILABILITY_TIMEOUT);
    }

    public handleRequest(res:http.ServerResponse):void {
        //only hande one response
        if (this.ongoingResponse) {
            res.statusCode = 404;
            res.end();
            return;
        }
        clearTimeout(this.timeout);
        this.isSending = true;
        this.ongoingResponse = res;
        if (this.pipedImage) {
            this.pipeImage();
        }
        res.on('complete', (response) => {
            if (!this.isSending) {
                return;
            }
            this.isSending = false;
            this.pipedImage = null;
            this.selfEndCallback();
        });
    }

    public stop():void {
        clearTimeout(this.timeout);
        if (this.ongoingResponse) {
            this.ongoingResponse.end();
            this.ongoingResponse = null;
        }
        if (this.pipedImage) {
            this.pipedImage.unpipe();
            this.pipedImage = null;
        }
        this.isSending = false;
        this.selfEndCallback = null;
    }

    private fetchPhoto() {
        //get the photo data
        axios.get<stream.Stream>(this.photoUrl, {responseType: 'stream'}).then(
            response => {
                this.pipedImage = new stream.PassThrough();
                response.data.pipe(this.pipedImage);
                if (this.ongoingResponse) {
                    this.pipeImage();
                }
            },
            err => {
                if (this.ongoingResponse) {
                    this.ongoingResponse.statusCode = 503;
                    this.ongoingResponse.end();
                }
                this.selfEndCallback();
            },
        );
    }

    private pipeImage() {
        this.pipedImage.pipe(this.ongoingResponse);
    }
}
