import {Time, Clock} from "animation-utilities";

class AxisVelocityControllerSim {
    /**
     *
     * @param {number} initialPosition - matched with initialTime (we are at initialPosition at initialTime)
     * @param {number} velocity - proceed at this velocity starting from initial params
     * @param {Time} [initialTime] - matched with initialPosition (optional, current time is used if omitted)
     */
    constructor(public initialPosition, public velocity, public initialTime?:Time) {
        if(initialTime === null || initialTime === undefined){ //null or undefined (eqnull)
            initialTime = Clock.currentTime();
        }
        this.initialTime = initialTime;
    }

    /**
     * @param {Time} [time] - time to access position (optional: current time used if not provided)
     * @returns {number} position
     */
    public getPosition(time:Time):number {
        if(time === null || time === undefined){ //null or undefined (eqnull)
            time = Clock.currentTime();
        }
        let secondsElapsed:number = time.subtract(this.initialTime);
        return this.initialPosition + this.velocity * secondsElapsed;
    }

    /**
     * @param {Time} [time] - time to access velocity (optional: current time used if not provided)
     * @returns {number} velocity
     */
    public getVelocity(/*time*/):number {
        return this.velocity;
    }
}

export default AxisVelocityControllerSim;
