import {HTTPClient, WSClient} from 'jibo-service-framework';
import Async from '../utils/Async';
import parentLog from './log';

const log = parentLog.createChild('Body');

interface BatteryState {
    id:number;              // BatteryID
    cycles:number;          // Number of battery cycles on this battery
    capacity:number;        // Current capactiy of this bettery in amp hours
    max_capacity:number;    // Maximum capacity of this battery in amp hours
    charge_rate:number;     // Charge rate of battery negative means draining, positive means charging.
    temp:number;            // Battery temperature in Celsius
}

interface PowerState {
    ts:Array<number>;       // Chronometer timestamp
    source:string;          // Are we on 'BATTERY' or 'EXTERNAL'
    vsys:number;            // The current system voltage estimate
    battery:BatteryState;
}

class BodyClient extends HTTPClient {

    private static _instance:BodyClient;
    private _clientTouch:WSClient;
    private _clientPower:WSClient;
    private _powerState:PowerState;

    public static createInstance(host:string, port:number):BodyClient {
        return new BodyClient(host, port);
    }

    public static get instance():BodyClient {
        return BodyClient._instance;
    }

    constructor(public host:string, public port:number) {
        super(host, port);
        BodyClient._instance = this;

        // touch socket
        this._onTouchMessage = this._onTouchMessage.bind(this);
        this._clientTouch = new WSClient(`ws://127.0.0.1:${port}/touch`);
        this._clientTouch.on('message', this._onTouchMessage);

        // power socket
        this._onPowerMessage = this._onPowerMessage.bind(this);
        this._clientPower = new WSClient(`ws://127.0.0.1:${port}/power`);
        this._clientPower.on('message', this._onPowerMessage);
        this._clientPower.on('error', () => {
            log.warn(`Error opening power state socket in SSM`);
        });
    }

    async getScreen():Promise<'on'|'off'>  {
        const state:'on'|'off' = await Async.get<'on'|'off'>(cb => {
            this.get('/screen', (err:Error, res?:any) => {
                if(err) {
                    log.warn('Problem getting screen state', err);
                }
                else {
                    log.debug(`Got screen state: ${state}`);
                }
                cb(err, res);
            });
        });
        return state;
    }

    async setScreen(state:'on' | 'off'):Promise<void> {
        await Async.get<void>(cb => {
            this.postJSON('/screen', {screen: state}, (err:Error, res?:any) => {
                if(err) {
                    log.warn(`Problem setting screen state to ${state}`, err);
                }
                else {
                    log.debug(`Set screen state to ${state}`);
                }
                cb(err, res);
            });
        });
    }

    private _onTouchMessage(data:{changed:number[], pad_state:boolean[]}) {
        if(data.changed.length > 0) {
            for(let i = 0; i < data.changed.length; i++) {
                if(data.pad_state[data.changed[i]]) {
                    log.debug('touched');
                    this.emit('touched');
                    return;
                }
            }
        }
        else {
            log.debug('touched, with no data');
        }
    }

    get pluggedIn() {
        const pluggedIn = this._powerState.source === 'EXTERNAL';
        log.debug(pluggedIn ? 'plugged in' : 'not plugged in');
        return pluggedIn;
    }

    private _onPowerMessage(data:PowerState) {
        log.debug('got power message:', data);
        this._powerState = data;
    }

}


export default BodyClient;
