import Router = require('router');
import path = require('path');
import findRoot = require('find-root');
import {JiboServerRequest, JiboServerResponse, ServiceOptions, HTTPService} from 'jibo-service-framework';
import {JSC} from '../../clients/jibo-server';
import fs = require('fs');
import mkdirp = require('mkdirp');
import uuid = require('uuid');
import jimp = require('jimp');
import async = require('async');
import {SSMService} from '../../SSMService';
import parentLog from '../log';

const log = parentLog.createChild('MediaService');

interface StorePhotoResponse {
    id:string;
    thumbnails?:{[key:string]:string};
}

interface StorePhotoRequest {
    id?:string;
    buffer?:string;
    thumbnails?:{[key:string]:[number, number]};
}

interface MediaServiceOptions extends ServiceOptions {
    serverMediaService:boolean;
}

class MediaService extends HTTPService implements SSMService {

    private static _instance:MediaService;
    public contentIds:string[];
    public recordings:any;
    private lastPicturePath:string;

    public static get instance():MediaService {
        return MediaService._instance;
    }

    constructor(public options:MediaServiceOptions, rootDir:string) {
        super('media', options, rootDir);
        if (MediaService._instance) {
            throw new Error('Cannot instantiate MediaService more than once');
        }
        MediaService._instance = this;
        this.onPhoto = this.onPhoto.bind(this);
        this.onPhotoStore = this.onPhotoStore.bind(this);
        this.onPhotoGet = this.onPhotoGet.bind(this);

        this.contentIds = [];
        this.recordings = [];
        log.info('Instantiated');
    }

    public init(callback: (err?:Error)=>void) {
        super.init((err:Error) => {
            log.info('Initialized');
            callback(err);
        });
    }

    public routes(url:Router) {
        super.routes(url);
        url.post('/media/photo', this.onPhoto);
        url.get('/media/photo', this.onPhotoGet);
        url.post('/media/photo/store', this.onPhotoStore);
        url.get('/media/photo/get', this.onPhotoGet);

        url.post('/media/recording/start', this.onRecordingStart.bind(this));
        url.post('/media/recording/control', this.onRecordingStop.bind(this));
        url.post('/media/recording/play', this.onRecordingPlay.bind(this));
    }

    private getRequestData(req:JiboServerRequest, callback:(err:Error, data?:any) => void):void {
        let chunk = "";
        if (req.readable) {  // for requests that don't have proper json headers
            req.on('data', data => chunk += data);
            req.on('end', () => {
                let data;
                let err;
                try {
                    data = JSON.parse(chunk);
                }
                catch(e) {
                    err = e;
                }
                if (err) {
                    callback(err);
                } else {
                    callback(null, data);
                }
            });
        } else {
            callback(null, req.body);
        }
    }

    get mediaRootDir():string {
        let root:string = path.join(process.env.HOME || process.env.USERPROFILE, '.jibo', 'photos');
        return root;
    }

    private writeImage(id:string, filePath:string, size:[number, number], callback:(err) => void):void {
        let filename = path.join(this.mediaRootDir, `${id}.jpg`);
        jimp.read(filePath, (err, image:any) => {
            if(err) {
                return callback(err);
            }
            image.resize(size[0], size[1]).write(filename, callback);
        });
    }

    /**
     * Take a (fake) photo and and return a content id
     * @param req
     * @param res
     */
    private onPhoto(req:JiboServerRequest, res:JiboServerResponse) {
        let contentId = uuid.v4();
        this.contentIds.push(contentId);
        let json = {
            id: contentId,
            width: 1920,
            height: 1080,
            expiration: Date.now() + (60 * 1000),
            stored: false
        };
        // lastPicturePath is just for testing purposes in jibo-integration-tests
        this.lastPicturePath = this.getFakeSourceFilename(contentId);
        this.sendJson(res, json, 200);
    }

    /**
     * Stores the photo and uploads the photo to the cloud
     * @param req
     * @param res
     */
    private onPhotoStore(req:JiboServerRequest, res:JiboServerResponse) {
        this.getRequestData(req, (err:Error, data:StorePhotoRequest):void => {
            this.emit('on-photo-store', data);

            let contentId;
            let img;
            if (data.buffer) {
                contentId = uuid.v4();
                img = data.buffer;
            } else if (data.id) {
                contentId = data.id;
                if (this.contentIds.indexOf(contentId) >= 0) {
                    let filename = this.getFakeSourceFilename(contentId);
                    img = fs.readFileSync(filename);
                    for (let n=this.contentIds.length; n>0; n--) {
                        if (this.contentIds[n-1] === contentId) {
                            this.contentIds.splice(n-1, 1);
                        }
                    }
                } else {
                    return this.sendJson(res, {error: 'unknown content id'}, 500);
                }
            } else {
                return this.sendJson(res, {error: 'must specify buffer or id'}, 500);
            }

            this.photoStore(contentId, img, data.thumbnails, (err, ret) => {
                if (err) {
                    this.sendJson(res, {error: err.message}, 500);
                } else {
                    this.sendJson(res, ret, 200);
                }
            });
        });
    }

    private photoStore(contentId:string, img, thumbnails, callback) {
        if(!fs.existsSync(this.mediaRootDir)) {
            mkdirp.sync(this.mediaRootDir);
        }
        let ret:StorePhotoResponse = {
            id: contentId,
            thumbnails: {}
        };
        let filename = path.join(this.mediaRootDir, `${ret.id}.jpg`);

        fs.writeFile(filename, img, {encoding: 'base64'}, (err) => {
            if(err) {
                return callback(err);
            }
            let tasks = [];
            Object.keys(thumbnails).forEach((thumbKey:string) => {
                const id = uuid.v4();
                ret.thumbnails[thumbKey] = id;
                tasks.push((cb) => {
                    this.writeImage(id, filename, thumbnails[thumbKey], cb);
                });
            });

            async.parallel(tasks, (err) => {
                if(err) {
                    return callback(err);
                }
                //if we're in the simulator (i.e. not unit tests) then upload to the cloud
                if(this.options.serverMediaService) {
                    this.updateMedia(ret, (err) => {
                        if(err) {
                            return callback(err);
                        }
                        callback(null, ret);
                    });
                }
                else {
                    callback(null, ret);
                }
            });
        });
    }

    private getUploadPhotoFunction(loopId:string, photoId:string, type:string, reference?:string) {
        return (done) => {
            const filename = path.join(this.mediaRootDir, `${photoId}.jpg`);
            fs.readFile(filename, (err, data) => {
                if(err) {
                    return done(err);
                }
                const params:any = {
                    loopId,
                    body: data,
                    path: photoId,
                    type
                };
                if(reference) {
                    params.reference = reference;
                }
                const media = new JSC.Media();
                media.create(params, done);
            });
        };
    }

    private updateMedia(photos:StorePhotoResponse, callback:(err?:Error) => void):void {

        const loop = new JSC.Loop();
        loop.list((err, data) => {
            if(err || !data || data.length === 0) {
                return callback();
            }
            const loopId:string = data[0].id;

            async.series([
                this.getUploadPhotoFunction(loopId, photos.id, 'image'),
                this.getUploadPhotoFunction(loopId, photos.thumbnails['mobile'], 'thumb', photos.id)
            ], callback);
        });
    }

    private onPhotoGet(req:JiboServerRequest, res:JiboServerResponse) {
        let id:string = (<any>req).query.id;
        let filename;
        if (this.contentIds.indexOf(id) >= 0) {
            filename = this.getFakeSourceFilename(id);
        } else {
            filename = path.join(this.mediaRootDir, `${id}.jpg`);
        }
        let img = fs.readFileSync(filename);
        res.writeHead(200, {'Content-Type': 'image/jpeg', 'Content-Length': img.length});
        res.end(img, 'binary');
    }

    /* Audio/Video Recording */

    private onRecordingStart(req:JiboServerRequest, res:JiboServerResponse) {
        const   time = new Date(),
                recording = {
                    options: req.body,
                    startTime: Date.now(),
                    // Create a fake id similar to what platform creates on robot
                    // On robot example:
                    // "2016-08-26-00:18:03.b2d39128-8d01-4b62-9001-80022d92fda8.AX"
                    id: time.toISOString().substring(0, 10) + ":" +
                        time.toISOString().substring(11, 19) +
                        uuid.v4() + "." +
                        // .AX extension for audio
                        // .AV extension for video
                        ( (req.body.video) ? "AV": "AX" )
                };
        this.recordings.push(recording);
        this.sendJson( res, { id: recording.id }, 200 );

        // Emit events so listeners could potentially implement simulated playback
        this.emit('recording-start', recording);
    }

    private onRecordingStop(req:JiboServerRequest, res:JiboServerResponse) {
        this.sendJson( res, {}, 200 );

        // Emit events so listeners could potentially implement simulated playback
        this.emit('recording-stop');
    }

    private onRecordingPlay(req:JiboServerRequest, res:JiboServerResponse) {
        this.sendJson( res, {}, 200 );

        // Emit events so listeners could potentially implement simulated playback
        this.emit('recording-play', req.body);
    }

    private getFakeSourceFilename(contentId:string) {
        // use 2 bits to deterministically pick from 4 photos based on contentId
        let num:number = ((<any>contentId[0]) & 0x3) + 1;
        return path.join(findRoot(__dirname), `resources/images/pic${num}.jpg`);
    }
}


export default MediaService;
