// [seconds, microseconds]
export type RBTime = [number, number];

export function rbDiffMs(start: RBTime, end: RBTime): number {
    const startMs = rbTimeToMs(start);
    const endMs = rbTimeToMs(end);
    return endMs - startMs;
}

export function rbTimeToMs(robotTime: RBTime): number {
    return robotTime[0] * 1e3 + robotTime[1] * 1e-3;
}

export function rbTimesSort(times: RBTime[]): RBTime[] {
    if (!times || !times.length) {
        return null;
    }
    times.sort((left, right) => {
        const leftMs = rbTimeToMs(left);
        const rightMs = rbTimeToMs(right);
        return leftMs - rightMs;
    });
    return times;
}
