import {ServiceOptions, HTTPWSService} from 'jibo-service-framework';
import {SSMService} from '../../SSMService';
import WebSocket = require('ws');

class SystemMonitoringServiceSim extends HTTPWSService implements SSMService {

    private static _instance: SystemMonitoringServiceSim = null;

    public static get instance(): SystemMonitoringServiceSim {
        if(!SystemMonitoringServiceSim._instance) {
            console.error("system monitoring service sim instance not created");
        }
        return SystemMonitoringServiceSim._instance;
    }

    constructor(options:ServiceOptions, rootDir: string) {
        // this name matches the service path we're connecting to on the platform
        super('system-monitoring-service', options, rootDir);
        if (SystemMonitoringServiceSim._instance) {
            throw new Error('Cannot instantiate SystemMonitoringServiceSim more than once');
        }
        SystemMonitoringServiceSim._instance = this;
    }


    protected onMessage(message: any, client: WebSocket): void {
        console.log("SystemMonitoringServiceSim::OnMessage");
    }

}

export default SystemMonitoringServiceSim;
