import parentLog from '../log';
const log:typeof parentLog = parentLog.createChild("PingService");
// log.outputs.syslog = 'debug';

import {
    ProcessResult,
    StatusResult,
    StatusDescriptor,
    StatusProcess,
} from './StatusRunner';

import { safeParse } from './ParseHelper';

import PingData from './PingData';

const DOMAIN_LIST = {
    DNS: '8.8.8.8',                 // Google DNS
    API: 'api.jibo.com',            // Jibo API front end
    ASR: 'speech.googleapis.com',   // Google ASR backend
};

/// Seconds to wait betwen pings
const PING_INTERVAL = 5;

/// Stop after an hour, at max
const PING_TIMEOUT = Math.ceil((60*60)/PING_INTERVAL);

const DEFAULT_ARGS = [
    '-i', `${PING_INTERVAL}`,   // Delay between Pings
    '-c', `${PING_TIMEOUT}`,    // Max number of Pings
];

const SHELL_COMMAND = 'ping';

export type PingResult = StatusResult<PingData>;

export type PingGroup = {[domain:string]: PingResult};

export class PingService {

    private static processList: StatusProcess<PingData>[];

    constructor(addr?:string[]){
        if(!PingService.processList){
            PingService.processList = [];
        }
        for(let name of Object.keys(DOMAIN_LIST)){
            this._createProcess('Ping@'+name, this._generateDescriptor(DOMAIN_LIST[name]));
        }
        for(let ip of (addr || [])){
            this._createProcess('Ping@'+ip, this._generateDescriptor(ip));
        }
    }

    public async gatherResults(): Promise<PingGroup> {
        let results: PingGroup = {};
        for(let proc of PingService.processList){
            let stat = await proc.refresh()
                .then(  val => val)
                .catch( err => err);
            results[proc.name] = stat;
        }
        return results;
    }

    private _createProcess(name: string, desc: StatusDescriptor<PingData>): StatusProcess<PingData> {
        let contained = PingService.processList.find( (p)=>p.name.includes(name) );
        if(!contained){
            log.debug(`no existing ping for '${name}' found: creating`);
            let proc =  new StatusProcess(desc,name);
            PingService.processList.push(proc);
            return proc;
        }else{
            log.warn(`ignoring service creation for '${name}': already exists`);
            return contained;
        }
    }

    private _generateDescriptor(addr:string, args:string[] = DEFAULT_ARGS): StatusDescriptor<PingData> {
        return {
            cmd: SHELL_COMMAND,
            args: args.concat([addr]),
            parser: this._parser
        };
    }

    private _parser(res:ProcessResult): PingResult {
        const body = res.stdout || '';
        const summaryHeader = body.match(/--- (\S+) ping statistics ---/);
        if(summaryHeader){
            const stats = body.match(
                /min\/avg\/max\/\S+dev\s+=\s+(\d+\.\d*)\/(\d+\.\d*)\/(\d+\.\d*)\/(\d+\.\d*)\s+ms/
            );
            return { data:{
                addr:   summaryHeader[1] || undefined,
                tx:     safeParse(body, /(\d+)\s+packets transmitted/,   (m)=>parseInt(m[1])),
                rx:     safeParse(body, /(\d+)\s+(packets\s+)?received/, (m)=>parseInt(m[1])),
                loss:   safeParse(body, /(\d+\.?\d*)%\s+packet loss/,    (m)=>parseFloat(m[1])),
                time:   safeParse(body, /time\s+(\d+)ms/,                (m)=>parseFloat(m[1])),
                min:    safeParse(stats[1], null, parseFloat),
                avg:    safeParse(stats[2], null, parseFloat),
                max:    safeParse(stats[3], null, parseFloat),
                dev:    safeParse(stats[4], null, parseFloat),
            }};
        }else{
            return { error:{
                code: res.code,
                error: res.error,
                msg: res.stderr,
            }};
        }
    }
}
