//  check jibo-version against specified version to see if compatible

import {systemManager} from 'jibo-service-clients';
let semver = require('semver');


declare type Callback = (err?:Error) => void;

/**
 * Checks that version of platform build is compatible with specified version
 * @private
 * @param {String} versionToCheck The semver version to check against the current platform build.
 *
 */
export function versionCheck(versionToCheck:string, callback:Callback) : void {

    if (!versionToCheck) {
        callback(); // no on robot?
        return;
    }

    systemManager.getVersion( (error, currentVersion) => {
        if (error) {
            // couldn't retrieve version? hmm...
            callback(error);
            return;
        }

        let errorMsg = undefined;

        // Use semver version check
        if(!semver.satisfies(currentVersion, versionToCheck)) {
            errorMsg = "Current SSM version requires platform version " + versionToCheck + " but your current version is " + currentVersion + "!";
        }

        callback(errorMsg);
    });
}


