import {ServiceRemoteObject, RemoteService} from 'jibo-service-framework';
import {AwaitFaceOptions} from 'jibo-common-types';
import WebSocket = require('ws');
import {AttentionManager} from 'jibo-attention-manager';
import {Time, Clock} from 'animation-utilities';
import parentLog from './log';

const log = parentLog.createChild('AwaitFace');

export default class AwaitFaceHandle extends ServiceRemoteObject {

    public timeFinishedInteraction:Time = null;

    private awaitHandle:any;

    constructor(
        superOptions:{base:RemoteService, owner:WebSocket},
        private options:AwaitFaceOptions,
        private attention:AttentionManager) {
        super(superOptions);
        this.waitForPromise();
    }

    public async cancel():Promise<void> {
        if(this.awaitHandle) {
            this.awaitHandle.cancel();
        }else{
            log.debug("Cancel called on already-done AwaitFaceHandle");
        }

        this.awaitHandle = undefined;

        this.timeFinishedInteraction = Clock.currentTime();
    }

    public destroy() {
        if(this.awaitHandle) {
            this.awaitHandle.cancel();
        }
        this.awaitHandle = undefined;

        this.remove();
    }

    private async waitForPromise():Promise<void> {
        this.awaitHandle = this.attention.awaitFace(
            this.options.timeout,
            this.options.maxAngle,
            this.options.fullSearchTime
        );

        const result:any = await this.awaitHandle.promise;
        if(this.isDestroyed) {
            //we only get here if the client disconnected
            return;
        }
        await this.sendMessage<void>('onPromise', [result], true);
        this.awaitHandle = undefined;

        this.timeFinishedInteraction = Clock.currentTime();
    }
}
