import { session as hub_session } from '@jibo/hub-client';
import { types } from '@jibo/jetstream-client';
import JetstreamServiceSim, { State, SpeechOptions, TimeoutOptions } from './JetstreamServiceSim';
import parentLog from './log';
const log = parentLog.createChild('Turns');

export abstract class Turn {
    type: State.GLOBAL_TURN|State.LOCAL_TURN|State.PRONUNCIATION_TURN|State.VOICE_ENROLLMENT_TURN;
    requestID: string;
    transactionID: string|undefined;
    
    constructor(type: State.GLOBAL_TURN|State.LOCAL_TURN|State.PRONUNCIATION_TURN|State.VOICE_ENROLLMENT_TURN, id: string) {
        this.type = type;
        this.requestID = id;
    }
    
    abstract close():void;
    
    abstract update(speech: SpeechOptions, sim: JetstreamServiceSim):Promise<boolean>;
}

export class HubListenTurn extends Turn {
    type: State.GLOBAL_TURN|State.LOCAL_TURN;
    session: hub_session.ListenClientSession;
    earlyEOS: RegExp[];
    maxSpeechTimeout: number;
    hasSpeech: boolean;
    activeTimeout: NodeJS.Timer;
    sim: JetstreamServiceSim;
    
    public get global() {
        return this.type === State.GLOBAL_TURN;
    }
    public get transactionID() {
        return this.session.transactionID;
    }
    
    constructor(type:State.GLOBAL_TURN|State.LOCAL_TURN, id: string, session:hub_session.ListenClientSession, timeouts:TimeoutOptions, sim: JetstreamServiceSim) {
        super(type, id);
        this.timeout = this.timeout.bind(this);
        this.sim = sim;
        this.session = session;
        if (timeouts.earlyEOS) {
            this.earlyEOS = timeouts.earlyEOS.map((word) => {
                return new RegExp(`\\b${word}\\b`);
            });
        } else {
            this.earlyEOS = null;
        }
        this.maxSpeechTimeout = timeouts.maxSpeechTimeout * 1000;//convert to ms
        //not running maxSpeechTimeout yet
        this.hasSpeech = false;
        //turn has started, begin SOS timeout
        const sosTimeout = timeouts.sosTimeout * 1000;//convert to ms
        this.activeTimeout = setTimeout(this.timeout, sosTimeout);
    }
    
    public close() {
        this.clearTimeout();
        return this.session.close();
    }
    
    public async update(options: SpeechOptions, sim: JetstreamServiceSim) {
        if (options.nlu) {
            this.clearTimeout();
            log.info(`Received final nlu, sending fake NLU to hub`);
            this.session.writeClientNLU(options.nlu);
            await this.session.transactionDone;
            log.info(`Hub transaction completed`);
            return true;
        } else if (options.speech) {
            let words = options.speech.words;
            if (options.global) {
                // Strip out "hey jibo" from speech string
                words = words.replace('hey jibo', '').trim();
            }
            if (words.length && !this.hasSpeech) {
                this.hasSpeech = true;
                this.clearTimeout();
                this.activeTimeout = setTimeout(this.timeout, this.maxSpeechTimeout);
            }
            //if we have earlyEOS set, see if it will be triggered by a thing
            if (!options.speech.final && this.earlyEOS) {
                options.speech.final = this.earlyEOS.some(regex => regex.test(words));
            }
            // Here we have the final speech from sim
            if (options.speech.final && words.length > 1) {
                this.clearTimeout();
                log.info(`Received final speech, sending fake ASR to hub`);
                this.session.writeClientASR(words);
                await this.session.transactionDone;
                log.info(`Hub transaction completed`);
                return true;
            }
        }
        return false;
    }
    
    private timeout() {
        //cancel session, because the hub won't do it for us
        this.sim.writeToJetStreamClient({
            type: types.ServiceEventType.TURN_RESULT,
            requestID: this.requestID,
            transID: this.session.transactionID,
            ts: Date.now(),
            data: {
                global: this.type === State.GLOBAL_TURN,
                status: types.TurnResultType.TIMEOUT
            }
        });
        //cancelSpeechTurn will call close() here, which will kill the hub session
        this.sim.cancelSpeechTurn();
    }
    
    private clearTimeout() {
        if (this.activeTimeout) {
            clearTimeout(this.activeTimeout);
            this.activeTimeout = null;
        }
    }
}

export class EnrollmentTurn extends Turn {
    type: State.VOICE_ENROLLMENT_TURN;
    hjCount: number;
    goodCount: number;
    totalCount: number;
    speaker: string;
    
    constructor(id: string, options:{speakerID:string,number_of_utterances:number}) {
        super(State.VOICE_ENROLLMENT_TURN, id);
        this.speaker = options.speakerID;
        this.hjCount = options.number_of_utterances;
        this.totalCount = this.goodCount = 0;
    }
    
    public close() {
        //noop
    }
    
    public async update(options: SpeechOptions, sim: JetstreamServiceSim) {
        if (!options.speech || !options.speech.final) {
            return false;
        }
        const words = options.speech.words;
        let output:types.EnrollmentCollectionResult;
        if (words.includes('hey jibo')) {
            //success!
            this.goodCount++;
            this.totalCount++;
            output = {
                speaker: this.speaker,
                snr: 0,
                accepted: true,
                problems: [],
                good_utterance_count: this.goodCount,
                total_utterance_count: this.totalCount,
                final: this.goodCount === this.hjCount
            };
        } else {
            //failure!
            this.totalCount++;
            const problems:string[] = [];
            //give a small variety of problems
            if (words === '') {
                problems.push('NOT_SPEECH_LIKE');
            } else {
                problems.push('POOR_SNR');
            }
            output = {
                speaker: this.speaker,
                snr: 0,
                accepted: false,
                problems,
                good_utterance_count: this.goodCount,
                total_utterance_count: this.totalCount,
                final: this.goodCount === this.hjCount
            };
        }
        
        sim.writeToJetStreamClient({
            type: types.ServiceEventType.SPEAKER_ENROLLMENT,
            transID: undefined,
            requestID: this.requestID,
            ts: Date.now(),
            data: output
        });
        
        const complete = this.goodCount === this.hjCount;
        if (complete) {
            sim.writeToJetStreamClient({
                type: types.ServiceEventType.TURN_RESULT,
                transID: undefined,
                requestID: this.requestID,
                ts: Date.now(),
                data: {
                    global: false,
                    status: types.TurnResultType.SUCCEEDED,
                    result: {}
                }
            });
        }
        
        return complete;
    }
}

export class PronunciationTurn extends Turn {
    type: State.PRONUNCIATION_TURN;
    wordToLearn: string;
    
    constructor(id: string, options:{word_to_learn:string, ignoreHJ:boolean, rejectIfBusy:boolean}) {
        super(State.PRONUNCIATION_TURN, id);
        this.wordToLearn = options.word_to_learn;
    }
    
    public close() {
        //noop
    }
    
    public async update(options: SpeechOptions, sim: JetstreamServiceSim) {
        if (!options.speech || !options.speech.final) {
            return false;
        }
        const words = options.speech.words;
        if (words.toLowerCase() === this.wordToLearn.toLowerCase()) {
            //success!
            sim.writeToJetStreamClient({
                type: types.ServiceEventType.TURN_RESULT,
                transID: undefined,
                requestID: this.requestID,
                ts: Date.now(),
                data: {
                    global: false,
                    status: types.TurnResultType.SUCCEEDED,
                    message: words
                }
            });
        } else {
            //failure
            sim.writeToJetStreamClient({
                type: types.ServiceEventType.TURN_RESULT,
                transID: undefined,
                requestID: this.requestID,
                ts: Date.now(),
                data: {
                    global: false,
                    status: types.TurnResultType.FAILED,
                    message: 'wrong word'
                }
            });
        }
        return true;
    }
}