import parentLog from '../log';
const log: typeof parentLog = parentLog.createChild("IFconfigService");
// log.outputs.syslog = 'debug';

import { uptime } from 'os';

import {
    ProcessResult,
    StatusResult,
    StatusDescriptor,
    StatusProcess,
} from './StatusRunner';

import { safeParse } from './ParseHelper';

import IFconfigData from './IFconfigData';

const DEFAULT_INTERFACE = 'wlan0';

const DEFAULT_ARGS = [
    'IFACE'
];

const SHELL_COMMAND = 'ifconfig';

export type IFconfigResult = StatusResult<IFconfigData>;

export class IFconfigService {

    private _process:StatusProcess<IFconfigData>;

    constructor(iface?:string){
        this._createProcess(
            `ifconfig${ iface ? '@'+iface : '' }`,
            this._generateDescriptor(iface)
        );
    }

    public async gatherResults(): Promise<IFconfigResult> {
        return this._process.refresh();
    }

    private _createProcess(name: string, desc: StatusDescriptor<IFconfigData>): StatusProcess<IFconfigData> {
        if(this._process){
            log.warn(`ignoring service creation for '${name}': already exists`);
            return;
        }
        try{
            this._process =  new StatusProcess(desc,name);
            return this._process;
        }catch(err){
            log.warn(`ignoring service creation for '${name}': `,err);
        }
    }

    private _generateDescriptor(addr:string = DEFAULT_INTERFACE, args:string[] = DEFAULT_ARGS): StatusDescriptor<IFconfigData> {
        return {
            cmd: SHELL_COMMAND,
            args: args.map( (i) => (i === 'IFACE') ? addr : i ),
            parser: this._parser
        };
    }

    private _parser(res: ProcessResult): IFconfigResult {
        let ret: StatusResult<IFconfigData>;
        // If there is not stdout data or a bad return code, return error
        if(!res.stdout || res.code){
            ret = {error: {
                code:   res.code,
                error:  res.error,
                msg:    res.stderr,
            }};
        }else{
            // ... Else parse from stdout
            const text = res.stdout;

            const flag_ln = text.match(/^(\s+)(([A-Z]+\s)+)\s+MTU:(\d+)\s+Metric:(\d+)/m);
            const RX_pkt_ln = text.match(/^(\s+)RX (packets[\S ]+)$/m);
            const TX_pkt_ln = text.match(/^(\s+)TX (packets[\S ]+)$/m);

            ret = {data: {
                inet:           safeParse(text, /inet addr:([\d\.]+)/,          m=>m[1]),
                bcast:          safeParse(text, /Bcast:([\d\.]+)/,              m=>m[1]),
                mask:           safeParse(text, /Mask:([\d\.]+)/,               m=>m[1]),
                inet6:          safeParse(text, /inet6 addr:\s([\d\w:%\/]+)/,   m=>m[1]),
                flags:          safeParse(flag_ln[2], null, (m:string)=>m.split(' ').filter(i=>i)),
                MTU:            safeParse(flag_ln[4], null, parseInt),
                metric:         safeParse(flag_ln[5], null, parseInt),
                RX: {
                    packets:    safeParse(RX_pkt_ln[2], /packets:(\d+)/,    m=>parseInt(m[1])),
                    errors:     safeParse(RX_pkt_ln[2], /errors:(\d+)/,     m=>parseInt(m[1])),
                    dropped:    safeParse(RX_pkt_ln[2], /dropped:(\d+)/,    m=>parseInt(m[1])),
                    overruns:   safeParse(RX_pkt_ln[2], /overruns:(\d+)/,   m=>parseInt(m[1])),
                    bytes:      safeParse(text,         /RX bytes:(\d+)/,   m=>parseInt(m[1])),
                    load:       0,  //placeholder
                },
                TX: {
                    packets:    safeParse(TX_pkt_ln[2], /packets:(\d+)/,    m=>parseInt(m[1])),
                    errors:     safeParse(TX_pkt_ln[2], /errors:(\d+)/,     m=>parseInt(m[1])),
                    dropped:    safeParse(TX_pkt_ln[2], /dropped:(\d+)/,    m=>parseInt(m[1])),
                    overruns:   safeParse(TX_pkt_ln[2], /overruns:(\d+)/,   m=>parseInt(m[1])),
                    bytes:      safeParse(text,         /TX bytes:(\d+)/,   m=>parseInt(m[1])),
                    load:       0,  //placeholder
                },
            }};
            // add post-processed data
            ret.data.RX.load = ret.data.RX.bytes / uptime() || undefined;
            ret.data.TX.load = ret.data.TX.bytes / uptime() || undefined;
        }
        return ret;
    }
}
