import parentLog from '../log';
const log: typeof parentLog = parentLog.createChild("SpeedTest");

// log.outputs.syslog = 'debug';

import {
    SpeedTestData,
    SpeedTestOptions,
    SpeedTestError,
    SpeedTestRunner,
} from './SpeedTestTypes';

const SpeedTest:(options?:SpeedTestOptions)=>SpeedTestRunner = require('speedtest-net');

import {
    // ProcessResult,
    StatusResult,
    // StatusDescriptor,
    // StatusProcess,
} from './StatusRunner';

const DEFAULT_OPTIONS:SpeedTestOptions = {
    // maxTime: 5000,  // Max duration of test (5 seconds)
    maxTime: 0, // Duration of zero disabled the test.
    serverId: "5906", // GigeNET (Ashburn, VA, United States)
};

export type SpeedTestResults = StatusResult<SpeedTestData>;


export class SpeedTestService {

    private _speed: SpeedTestRunner;
    private _options: SpeedTestOptions;
    private _promise: Promise<SpeedTestResults>;

    constructor(options?:SpeedTestOptions){
        this._options = options || DEFAULT_OPTIONS;
        this._speed = undefined;
        this._promise = undefined;
    }

    public async gatherResults(): Promise<SpeedTestResults> {
        let newPromise: Promise<SpeedTestResults> = undefined;
        if(this._options.maxTime === 0){
            // Return a rejecting promise if disabled
            newPromise = new Promise<SpeedTestResults>( (resolve,reject)=>{
                reject({
                    error: 'Disabled'
                });
            });
        }else{
            // Create the call
            newPromise = new Promise<SpeedTestResults>( (resolve,reject)=>{
                this._speed = SpeedTest(this._options);

                this._speed.on('data', (data:SpeedTestData) => {
                    log.debug('data: ',data);
                    resolve({
                        data: data
                    });
                });

                this._speed.on('error', (err:SpeedTestError) => {
                    log.debug('error: ',err);
                    reject({
                        error: err
                    });
                });
            });
        }
        // Store promise and return
        this._promise = newPromise;
        return newPromise;
    }


}
