import http = require('http');
import {Clock, TrajectoryControllerSim, PosVelControllerSim} from 'animation-utilities';
import BodyState from "./BodyState";
import AxisVelocityControllerSim from "./AxisVelocityControllerSim";
import {Time} from "animation-utilities";
import {ServiceOptions, HTTPWSService, WebSocket} from 'jibo-service-framework';
import {SSMService} from '../../SSMService';

import parentLog from '../log';
let log = parentLog.createChild('Body');

//standin for window.performance.now()
const performance = {
    now: () => {
        const time = process.hrtime();
        return time[0] * 1000 + time[1] / 1000000;
    }
};

class SimController {
    public pelvis:AxisVelocityControllerSim = new AxisVelocityControllerSim(0, 0);
    public torso:AxisVelocityControllerSim = new AxisVelocityControllerSim(0, 0);
    public neck:AxisVelocityControllerSim = new AxisVelocityControllerSim(0, 0);
}

interface RenderState {
    topSection_r:number;
    middleSection_r:number;
    bottomSection_r:number;
    lightring_redChannelBn_r:number;
    lightring_greenChannelBn_r:number;
    lightring_blueChannelBn_r:number;
}

class BodyService extends HTTPWSService implements SSMService {

    private static _instance:BodyService;

    public stateSocketList:WebSocket[] = [];
    public touchSocketList:WebSocket[] = [];

    private commandSocketList:WebSocket[] = [];
    private ledSocketList:WebSocket[] = [];
    private ledState:[number, number, number] = [0, 0, 0];
    private state:BodyState = new BodyState();
    private simControllers:SimController = new SimController();
    private lastUpdate:number;
    private updateLoop: NodeJS.Timer;

    public static get instance():BodyService {
        return BodyService._instance;
    }

    constructor(options:ServiceOptions, rootDir:string) {
        super('body', options, rootDir);
        if (BodyService._instance) {
            throw new Error('Cannot instantiate BodyService more than once');
        }
        BodyService._instance = this;
        this.update = this.update.bind(this);
        log.info("Instantiated");
    }

    public init(callback: (err?:Error)=>void) {
        super.init((err:Error) => {
            this.updateLoop = setTimeout(this.update, 100);
            log.info('Initialized');
            callback(err);
        });
    }

    public reset(){
        this.state = new BodyState();
        this.simControllers = new SimController();
    }

    pause(): void {
        if (this.updateLoop) {
            log.info('Pausing BodyService');
            clearTimeout(this.updateLoop);
            this.updateLoop = null;
        }
    }

    resume(): void {
        if (!this.updateLoop) {
            log.info('Resuming BodyService');
            this.updateLoop = setTimeout(this.update, 100);
        }
    }

    protected onMessage(command:any, client:WebSocket):void {
        if(client.url === '/axis_command') {
            this.onAxisCommand(command);
        }
        else if(client.url === '/led_command') {
            this.onLEDCommand(command);
        }
    }

    protected onClose(client:WebSocket):void {
        if (this.commandSocketList.indexOf(client) > -1) {
            this.commandSocketList.splice(this.commandSocketList.indexOf(client), 1);
        } else if (this.ledSocketList.indexOf(client) > -1) {
            this.ledSocketList.splice(this.ledSocketList.indexOf(client), 1);
        } else if (this.stateSocketList.indexOf(client) > -1) {
            this.stateSocketList.splice(this.stateSocketList.indexOf(client), 1);
        } else if (this.touchSocketList.indexOf(client) > -1){
            this.touchSocketList.splice(this.touchSocketList.indexOf(client), 1);
        }
    }

    public onConnection(client:WebSocket, request:http.IncomingMessage):void {
        // console.log('******* on connection', client);
        super.onConnection(client, request);
        if(request.url === '/axis_state') {
            this.stateSocketList.push(client);
        } else if(request.url === '/axis_command') {
            this.commandSocketList.push(client);
        } else if(request.url === '/led_command') {
            this.ledSocketList.push(client);
        } else if(request.url === '/touch') {
            this.touchSocketList.push(client);
        }
        this.sendState();
    }

    private onAxisCommand(data) {
        this.lastUpdate = performance.now();

        let localTime = Clock.currentTime();
        let simControllers:SimController = this.simControllers;
        for(let dof of Object.keys(simControllers)){
            //assign appropriate controller (Velocity or Trajectory)
            if(data[dof].mode === 4) {
                simControllers[dof] = new AxisVelocityControllerSim(
                    simControllers[dof].getPosition(localTime),
                    data[dof].value[0],
                    localTime
                );
            }
            else if(data[dof].mode === 5) {
                simControllers[dof] = new TrajectoryControllerSim(
                    simControllers[dof].getPosition(localTime),
                    simControllers[dof].getVelocity(localTime),
                    localTime
                );
                simControllers[dof].updateCommand(
                    data[dof].value[1],
                    data[dof].value[0],
                    data[dof].value[2],
                    data[dof].acc_limit,
                    data[dof].vel_limit,
                    localTime
                );
            }
            else if(data[dof].mode === 7) {
                simControllers[dof] = new PosVelControllerSim(
                    simControllers[dof].getPosition(localTime),
                    simControllers[dof].getVelocity(localTime),
                    localTime
                );
                simControllers[dof].updateCommand(
                    data[dof].value[1],
                    data[dof].value[0],
                    data[dof].acc_limit,
                    data[dof].vel_limit,
                    localTime
                );
            }
            else { //stop by using a zero-velocity controller for all other cases
                simControllers[dof] = new AxisVelocityControllerSim(
                    simControllers[dof].getPosition(localTime),
                    0,
                    localTime
                );
            }
        }

        this.updateState();
        this.sendState();
    }

    private onLEDCommand(data:any) {
        if(data.color && Array.isArray(data.color) && data.color.length === 3){
            this.ledState = data.color;
        }
    }

    private updateState() {
        let localTime:Time = Clock.currentTime();
        let updatedRecently:boolean = (performance.now() - this.lastUpdate) < 500;
        for (let dof of Object.keys(this.simControllers)) {
            if(updatedRecently){
                this.state[dof].vel = this.simControllers[dof].getVelocity(localTime);
            }
            else {
                this.state[dof].vel = 0.0;
            }
            this.state[dof].pos = this.simControllers[dof].getPosition(localTime);
        }
    }

    private sendState() {
        if(this.updateLoop &&  this.stateSocketList.length > 0) {
            let ts:[number, number] = Clock.currentTime()._timestamp;
            this.state.neck.ts = ts;
            this.state.torso.ts = ts;
            this.state.pelvis.ts = ts;
            this.state.ts = ts;
            for (let stateSocket of this.stateSocketList){
                this.sendWsJson(stateSocket, this.state);
            }
        }
    }

    private update():void {
        this.updateLoop = setTimeout(this.update, 100);
        let dofs:RenderState = {
            topSection_r: this.state.neck.pos,
            middleSection_r: this.state.torso.pos,
            bottomSection_r: this.state.pelvis.pos,
            lightring_redChannelBn_r: this.ledState[0],
            lightring_greenChannelBn_r: this.ledState[1],
            lightring_blueChannelBn_r: this.ledState[2]
        };
        this.emit('update', dofs);
    }

}


export default BodyService;