import JiboError from './JiboError';

class ErrorServiceUtil {
    // scan the keys of the sourceErrorCodes object and return back an array of JiboErrors for anything that doesn't occur
    // in the newErrorCodes object
    public static getNonOccurringElements(sourceErrorCodes: { [key:string]:JiboError; }, newErrorCodes: { [key:string]:JiboError; }): JiboError[] {
        let nonOccurringElements: JiboError[] = [];

        let sourceKeys = Object.keys(sourceErrorCodes);
        for(let i = 0; i < sourceKeys.length; ++i) {
            let sourceKey = sourceKeys[i];
            if(!newErrorCodes.hasOwnProperty(sourceKey)) {
                nonOccurringElements.push(sourceErrorCodes[sourceKey]);
            }
        }

        return nonOccurringElements;
    }
}

export default ErrorServiceUtil;
