// a class which represents the errors in the ErrorCodes.json file

interface JiboErrorData {
    description: string;
    message: string;
    spokenPromptOnError: string;
    spokenPromptOnResolution: string;
    priority: number;
    repeatTime: number;
    dismissible: boolean;

    platformCode?: string;
}

class JiboError {
    private _id: string = null;
    private _priority: number = 0;
    private _platformCode: string = null;
    private _repeatTime: number = 0;
    private _dismissible: boolean = true;

    private _data: JiboErrorData = {
        description: "",
        message: "",
        spokenPromptOnError: "",
        spokenPromptOnResolution: "",
        priority: 0,
        repeatTime: -1,
        platformCode: null,
        dismissible: true
    };

    /**
     * A comparer to correctly sort JiboError objects
     * @param errorObj1 {JiboError} the first object to compare
     * @param errorObj2 {JiboError} the second object to compare
     * @return{number} -1  if errorObj1 is less than errorObj2
     *                  1  if errorObj1 is greater than errorObj2
     *                  0 if errorObj1 is equal to errorObj2
     */
    public static Comparer(errorObj1: JiboError, errorObj2: JiboError): number {
        if(errorObj1.priority > errorObj2.priority) {
            return 1;
        } else if (errorObj1.priority < errorObj2.priority) {
            return -1;
        }
        // it's ok if the error priorities are equal. this is a common case.
        // if the priorities are equal, sort based on alphabetical id
        else {
            // the errorObj1 alphabetical id is greater than errorObj2's id
            if(errorObj1.id > errorObj2.id) {
                return 1;
            // the errorObj1 alphabetical id is less than errorObj2's id
            } else if(errorObj1.id < errorObj2.id) {
                return -1;
            } else {
                // the alphabetical ids are equal
                return 0;
            }
        }
    }

    /**
     * @param id {string} the id of the error
     * @param data {Object} the raw object which was converted from a json string
     */
    constructor(id: string, data:JiboErrorData) {
        this._id = id;
        this._data = data;
        if(this._data.hasOwnProperty("priority")) {
            this._priority = this._data["priority"];
        }
        if(this._data.hasOwnProperty("platformCode")) {
            this._platformCode = this._data["platformCode"];
        }
        if(this._data.hasOwnProperty("repeatTime")) {
            this._repeatTime = this._data["repeatTime"];
        }
        if(this._data.hasOwnProperty("tapAction")) {
            // if there is a tap action which isn't none, that means we can dismiss the error
            this._dismissible = this._data["tapAction"] !== "none";
        }
    }

    public get id(): string {
        return this._id;
    }

    public get data(): any {
        return this._data;
    }

    public get priority(): number {
        return this._priority;
    }
    public get platformCode(): string {
        return this._platformCode;
    }
    public get repeatTime(): number {
        return this._repeatTime;
    }
    public get dismissible(): boolean {
        return this._dismissible;
    }
}

export default JiboError;
