import {SystemManagerClient} from "jibo-client-framework";
import {PromiseUtils} from 'jibo-cai-utils';
const promisify = PromiseUtils.promisify;
import WSListener from './WSListener';

// @TODO - document what this base class does
export default abstract class Scan implements WSListener {
    private results:Promise<any> = null;
    
    public scanResults():Promise<any> {
        //prefer an existing results fetch, but make sure we are actually fetching no matter what
        if (!this.results) {
            this._fetchResults();
        }
        return this.results;
    }
    
    public abstract handleWSMessage(message:string):void;
    
    protected _fetchResults():void {
        this.results = promisify((cb) => SystemManagerClient.instance.scanResults(cb));
    }
}
