// OTA updater
import {Node, Model} from 'jibo-kb';
import kb from '../clients/KBClient';
import WifiService from "../services/wifi/WifiService";
import KBService from "../services/kb/KBService";
import BodyClient from "../clients/BodyClient";
import {Log as JiboLog} from 'jibo-log';
import Analytics from "./analytics/Analytics";
import {systemManager} from 'jibo-service-clients';

// Knowledge-base directory
const OTA_KB = '/ota';

// error codes we care about
const PLUG_ERROR = 'OTA10';
const WIFI_ERROR = 'OTA1';
const INTERNET_ERROR = 'OTA4';
const BACKUP_ERROR = 'OTA11';
const BACKUP_OTA_ERROR = 'OTA12';
const UHOH_ERROR = 'OTAX';

// max consecutive backup failures we need to hit before we sent BACKUP_ERROR
const MAX_BACKUP_FAILURES = 3;

// Analytics events
const OTA_FAILURE = 'OTA Failure';
const OTA_ATTEMPTED = 'OTA Attempted';


export interface OTARecord {
    id:string;
    subsystem:string;
    changes:string;
    length:number;
    toVersion:string;
    dependencies:any;
    downloaded:boolean;
}

interface OTADownloadStatus {
    id:string;
    length:number;
    received:number;
    status:string;
    reason?:string;
    error?:string;
}

/**
 * A class for handling OTA checking, downloading and installing.
 *
 * @class OTAUpdater
 * @private
 */
class OTAUpdater {
    private static _instance: OTAUpdater = null;
    private _log:JiboLog = null;
    private _otaFilter:string = "";
    private _kbm:Model = null;
    private _downloadStatus:{
        updates:Array<OTARecord>,
        status?:OTADownloadStatus
    };
    private _backingUp: boolean;

    // flag that we are in our pre-download phase of 'ota-update' handler ("downloadAndInstall" API)
    private _backingBeforeUpdate: boolean;

    public static createInstance(log:JiboLog, otaFilter:string):OTAUpdater {
        if (!OTAUpdater.instance) {
            return new OTAUpdater(log, otaFilter);
        }

        return OTAUpdater.instance;
    }

    public static get instance():OTAUpdater {
        return OTAUpdater._instance;
    }

    constructor(log:JiboLog, otaFilter:string) {
        if (OTAUpdater._instance) {
            throw new Error('OTAUpdater is a singleton');
        }

        this._log = log.createChild("OTAUpdater");
        this._otaFilter = otaFilter;
        OTAUpdater._instance = this;
        this._kbm = null;

        this._resetDLStatus();
        this._backingUp = false;
        this._backingBeforeUpdate = false;

        const deets =  (this._otaFilter && (this._otaFilter.length > 0) ? ("with filter " + this._otaFilter) : "");
        this._log.info("Initialized", deets);
    }

    public init(callback:(err?:Error) => void):void {

        // create kb model
        // NOTE: we explicitly use 127.0.0.1 instead of localhost here (and everywhere else) see JIBO-7115
        const kbUrl:string = 'http://127.0.0.1:' + KBService.instance.options.port;
        try {
            this._kbm = kb.createModel(OTA_KB, kbUrl);
        }
        catch(e) {
            this._doError(e);

            // don't pass error up to SSM's init; just log it
            return callback();
        }

        // clear KB-specific flags in the event SSM crashes and restarts or we
        // are in a restore flow
        this._kbm.loadRoot((error, root)=> {

            // bail out if we couldn't get access to KB
            if (error || !root || !root.data) {
                this._doError("Couldn't load backup/OTA root KB on attempt install");

                // don't send error up to SSM's init; just log it
                return callback();
            }

            root.data.updatesAvailable = false;

            root.save((error) => {
                // don't send error up to SSM's init via callback; just got it
                if (error) {
                    this._doError("Couldn't save backup/OTA post-downloading status");
                }

                callback();
            });
        });

    }

    public downloadStatus(callback:(error:Error, data?:any) => void):void {
        if (!this._downloadStatus.updates || (this._downloadStatus.updates.length === 0)) {
            return callback(null, null); // OTA download is not running
        }

        callback(null, this._downloadStatus);
    }

    public backupStatus(callback:(error:Error, data?:any) => void):void {
        callback(null, (this._backingUp || this._backingBeforeUpdate));
    }

    //
    /**
     * Requests a backup of robot files. This call implies immediate callback
     * return and user is required to check backup-status to know if backup completed.
     * (Errors are stored in KB.)
     * @param {Function} callback Function
     */
    public backupRobot(immediate:boolean, callback:(error?:Error) => void) :void {

        this._doLog('Starting backup!');

        // return early because we don't wait for backup to finish- just check with backupStatus
        callback();

        this._backupHelper((error:Error, maxErrors:boolean) => {
            if (error) {
                // tell everybody
                this._doError(error);

                // load kb ota root so we can set error code
                this._kbm.loadRoot((error, root)=> {

                    if (error || !root || !root.data) {
                        // can't save our error code :(
                        this._doError(new Error("Couldn't load backup/OTA root KB to save backup error"));
                    }
                    else if (!maxErrors) {
                        // we only set generic backup error on non-max-error-hitting times
                        root.data.error = BACKUP_ERROR;
                        // save error code
                        root.save((err)=> {
                            if (err) {
                                this._doError("Couldn't save backup error code in KB");
                            }
                        });
                    }
                });
            }
            else {
                // tell everybody
                this._doLog('Robot backup successful.');
            }
        });
    }

    /**
     * Checks for OTA updates with given filter
     * @param {Function} callback Function
     */
    public checkForUpdates(callback:(error:Error, data?:Array<OTARecord>) => void): void {
        systemManager.checkForUpdates(callback, this._otaFilter);
    }


    /**
     * Triggers a backup, an OTA download and install if packages exist.
     * @param {Function} callback Function
     */
    public downloadAndInstall(callback:(error?:Error) => void): void {

        this._backingBeforeUpdate = true; // started

        // reset our dl status
        this._resetDLStatus();

        this._doLog('Starting backup/ota update!');
        this._analyticsEvent(OTA_ATTEMPTED);

        this._isReady((error) => {
            if (error) {
                this._analyticsEvent(OTA_FAILURE);
                this._backingBeforeUpdate = false;
                return callback(error);
            }

            callback(); // yay! return now and let stuff just keep going in background

            // attempt a backup first if OTA packages exist to download
            this._backupIfOTA((error?:Error) => {
                if (error) {
                    // don't let OTA happen if any error is returned here
                    this._analyticsEvent(OTA_FAILURE);
                    this._backingBeforeUpdate = false;
                    return this._doError(error);
                }

                // load up KB for ota-related flags
                this._kbm.loadRoot((error, kbRoot)=> {
                    // bail out if we couldn't get access to KB
                    if (error || !kbRoot || !kbRoot.data) {
                        this._analyticsEvent(OTA_FAILURE);
                        this._backingBeforeUpdate = false;

                        const msg = new Error("Couldn't load backup/OTA root KB on OTA attempt");
                        return this._doError(msg);
                    }

                    // Start recursive downloads of all available packages
                    this._startNextDownload((error:Error, ids?:Array<string>) => {
                        // if problem, return and don't install
                        if (error) {
                            this._resetDLStatus();
                            this._doError(error);
                            this._analyticsEvent(OTA_FAILURE);
                            this._backingBeforeUpdate = false;

                            // check connection to get error code
                            WifiService.instance.verifyConnection().then((error)=> {

                                // save off error code in KB if applicable
                                if (error && error.code) {
                                    kbRoot.data.error = (error.code === 1 ? WIFI_ERROR : INTERNET_ERROR);
                                }
                                else {
                                    kbRoot.data.error = UHOH_ERROR;
                                }

                                // save error code
                                kbRoot.save((err)=> {
                                    if (err) {
                                        this._doError("Couldn't save OTA download error status");
                                    }
                                });
                            });

                            return;
                        }

                        // clear KB OTA-related flags
                        kbRoot.data.updatesAvailable = false;
                        kbRoot.save((error) => {
                            // oh, not so fast...
                            if (error) {
                                const msg = new Error("Couldn't save OTA post-downloading status");
                                this._doError(msg);
                                this._analyticsEvent(OTA_FAILURE);
                                return;
                            }

                            // check again if we're ready
                            this._isReady((error) => {
                                if (error) {
                                    this._analyticsEvent(OTA_FAILURE);
                                    return;  // bail; we've already logged a bunch of stuff
                                }

                                // start installation!
                                if (this._log) {
                                    // always warn level so accessible all the time
                                    this._log.warn('Starting OTA installation:', this._otaFilter, ids);
                                }

                                systemManager.installUpdates({ids}, (error?: Error) => {
                                    if (error) {
                                        this._doError(error);
                                        this._analyticsEvent(OTA_FAILURE);
                                        return;
                                    }
                                });  // installUpdates
                            }); // isReady
                        }); // root.save
                    });  // startNextDownload
                }); // loadRoot
            }); // backupIfOTA
        }); // isReady
    }

    private _analyticsEvent(event:string): void {
        if(Analytics && Analytics.instance && Analytics.instance.logEvent) {
            Analytics.instance.logEvent(event);
        }
        else {
            this._doError(`No handler found for Analytics event: ${event}`);
        }
    }

    /**
     * Log backup error
     * @returns {boolean}
     */
    private _logBackupError(root:Node): boolean {
        // initialize if null or NaN
        if (!root.data.backupErrorCount || isNaN(root.data.backupErrorCount)) {
            root.data.backupErrorCount = 0;
        }

        // increment backup error counter
        root.data.backupErrorCount = root.data.backupErrorCount + 1;
        this._doLog(new Error("Backup error count: " + root.data.backupErrorCount));

        // did we hit our cap?
        if (root.data.backupErrorCount >= MAX_BACKUP_FAILURES) {

            // clear if we hit cap
            root.data.backupErrorCount = 0;

            // tell everyone
            this._doLog(new Error("Hit max backup errors; resetting backup error count"));

            // we've hit our max
            return true;
        }

        // we haven't hit our max (yet)
        return false;
    }

    /**
     * Backup helper
     * @param {Function} callback Function
     */
    private _backupHelper(callback:(error:Error, maxErrors:boolean) => void): void {
        // load kb slice/root node
        this._kbm.loadRoot((error, root)=> {

            if (error || !root || !root.data) {
                // Not sure if we hit the max errors here since we don't have access
                // to KB (should we pass maxErrors = true or false?)
                return callback(new Error("Couldn't load backup/OTA root KB: " + error), false);
            }

            // if we're already backing up (very small case to catch this), then
            // increment error
            if (this._backingUp) {
                // increment backup error and return if we hit max
                let maxError:boolean = this._logBackupError(root);

                // save KB flags
                root.save((error)=> {
                    if (error) {
                        this._doError(new Error("Couldn't save backup/OTA root KB: " + error));
                    }

                    callback(new Error("Cannot instantiate a backup while a backup is already running!"), maxError);
                });
            }
            else {
                // we've started backing up
                this._backingUp = true;

                // attempt a backup of robot data
                systemManager.backup((backupErr?: Error) => {

                    let maxError:boolean = false;

                    // got an error?
                    if (backupErr) {
                        // increment backup error and return if we hit max
                        maxError = this._logBackupError(root);
                    }
                    else {
                        // clear backup error counter
                        root.data.backupErrorCount = 0;
                    }

                    // save KB flags
                    root.save((error)=> {
                        let errMsg:Error = null;
                        if (error) {
                            errMsg = new Error("Couldn't save backup/OTA root KB: " + error);
                        }

                        // clear backing up flag
                        this._backingUp = false;

                        callback((backupErr ? backupErr : errMsg), maxError);
                    }); // save (KB)
                }); // backup
            }
        }); // kbm.loadRoot
    }

    /**
     * Checks if current environment is ready to start backup/OTA (download or installation).
     * @param {Function} callback Function
     */
    private _isReady(callback:(error?:Error) => void): void {
        // load up KB for ota-related flags
        this._kbm.loadRoot((error, root)=> {

            // bail out if we couldn't get access to KB
            if (error || !root || !root.data) {
                const msg = new Error("Couldn't load backup/OTA root KB on attempt install");
                this._doError(msg);

                return callback(msg);
            }

            // check if the robot is plugged in
            if (!BodyClient.instance.pluggedIn) {
                root.data.error = PLUG_ERROR;
                let msg = new Error(root.data.error + ": Couldn't start backup/OTA process cause not plugged in");
                root.save((error)=> {
                    if (error) {
                        msg = new Error(root.data.error + ": Couldn't save backup/OTA plug error status");
                        this._doError(msg);
                    }

                    return callback(msg);
                });
            }
            else {
                // Check that we have a current network (doesn't mean on internet)
                WifiService.instance.getCurrentNetwork().then((currentNetwork) => {
                    if (!currentNetwork || currentNetwork.ssid === undefined) {
                        // bail out if no network
                        throw "No network!";
                    }

                    // We have a network, but check that we are connected to AP, IP and internet
                    WifiService.instance.verifyConnection().then((error)=> {
                        // bail out if failure
                        if (error) {
                            if (error.code) {
                                root.data.error = (error.code === 1 ? WIFI_ERROR : INTERNET_ERROR);
                            }
                            else {
                                root.data.error = UHOH_ERROR;
                            }
                            let msg = new Error(root.data.error + ": Couldn't start backup/OTA process cause no internet: " + error);
                            this._doError(msg);

                            root.save((err)=> {
                                if (err) {
                                    msg = new Error(root.data.error + ": Couldn't save backup/OTA internet error status");
                                    this._doError(msg);
                                }

                                return callback(msg);
                            });
                        }
                        else {
                            // yay! we're good
                            callback(null);
                        }
                    }); // verifyConnection
                }).catch((error)=> {
                    root.data.error = WIFI_ERROR;
                    let msg = new Error(root.data.error + ": Couldn't start backup/OTA process cause no WiFi: " + error);
                    this._doError(msg);

                    root.save((error)=> {
                        if (error) {
                            msg = new Error(root.data.error + ": Couldn't save backup/OTA wifi error status");
                            this._doError(msg);
                        }

                        return callback(msg);
                    });
                }); // getCurrentNetwork
            }
        }); // loadRoot
    }

    private _backupIfOTA(callback:(error?:Error) => void) : void {

        this.checkForUpdates((error: any, data?: Array<OTARecord>) => {
            if (error || !data) {
                const msg = error ? error : 'SystemManager service temporarily unavailable.';
                return callback(new Error(msg));
            }

            const count = data.length;
            if (count === 0) {
                return callback(new Error('No updates found. No backing up is necessary.'));
            }

            // only do backup if there is an OTA
            this._backupHelper((bkError:Error, maxError:boolean) => {
                if (bkError) {
                     // Only after maximum consecutive errors should we not bail on OTA
                    if (maxError) {
                        this._doLog('Backup failed but letting OTA through');
                        callback();
                    }
                    else {
                        // load kb ota root so we can set error code
                        this._kbm.loadRoot((error, root)=> {

                            if (error || !root || !root.data) {
                                this._doError(new Error('Could not load backup/OTA root KB to save backup error: ' + error));

                                // can't save our error code; should we gate OTA for this one? hmmm...
                                callback(new Error('Could not OTA as backup failed; ' + bkError));
                            }
                            else {
                                // save BACKUP_OTA_ERROR for times we have failed backup
                                // and are gating OTA because of it
                                root.data.error = BACKUP_OTA_ERROR;

                                // save error code
                                root.save((err)=> {
                                    if (err) {
                                        this._doError('Could not save backup error code in KB');
                                    }

                                    callback(new Error('Could not OTA as backup failed; ' + bkError));
                                });
                            }
                        });
                    }
                }
                else {
                    callback();
                }
            });
        });
    }

   private _startNextDownload(callback:(error:Error, ids?:Array<string>) => void):void {
        // find next one that isn't downloaded
         this.checkForUpdates((error: any, data?: Array<OTARecord>) => {
             // reset our dl status
             this._resetDLStatus();

             if (error || !data) {
                const msg = error ? error : 'Service temporarily unavailable.';
                return callback(new Error(msg));
             }

             const count = data.length;
             if (count === 0) {
                 return callback(new Error('No updates found.'));
             }

             if(this._backingBeforeUpdate){//set false now that we have data about download status
                this._backingBeforeUpdate = false;
             }

             let nextId = [];
             let doneIds = [];
             for (let i = 0; i < count; i++) {
                 if (data[i].downloaded) {
                     doneIds.push(data[i].id);
                 }
                 else if (nextId.length === 0) {
                     // only add one
                     nextId.push(data[i].id);
                 }
             }

             if (nextId.length > 0) {
                 this._doLog('Starting ota download: ' + nextId);
                 // shallow copy of current updates
                 this._downloadStatus.updates = data.slice();

                 // download updates one at a time
                 systemManager.downloadUpdates({ids: nextId}, (err: any, dlData: any) => {

                     this._downloadStatus.status = Object.assign({}, dlData);

                     if (err || dlData.status === 'failed' || dlData.error) {
                         this._resetDLStatus();
                         const msg = (err || dlData.reason || dlData.error);
                         return callback(new Error('Error downloading OTA updates: ' + msg));
                     }

                     if (dlData.status === 'finished') {
                         this._startNextDownload(callback);
                     }

                 });
             }
             else {
                 // reset our dl status
                 this._resetDLStatus();

                 // all done!
                 callback(null, doneIds);
             }
         });
     }

     private _resetDLStatus() {
         this._downloadStatus = {
             updates: [],
             status: null
         };
     }

     private _doLog(msg:(Error|string)) {
         if (this._log) {
             this._log.info(msg);
         }
     }

     private _doError(msg:(Error|string)) {
         if (this._log) {
             this._log.warn(msg);
         }
     }
}

export default OTAUpdater;
