const prfyTo = PromiseUtils.promisifyTo;

interface DevShellOptions extends ServiceOptions {
    debugPort: number;
    syncPort: number;
    skillDest: string;
    skillUser: string;
    skillLimit: number;
    sdkDest: string;
}

interface SpeakRequest {
    words: string;
    final: boolean;
    heyJibo: boolean;
    speaker: string | undefined;
    speakerId: string | undefined;
}

interface ExecuteResult {
    result: string;
    success: boolean;
    error: string;
}

type ExecuteCallback = (result: ExecuteResult) => void;

// This is to make the JetstreamServiceSim available as a global for scripts sent
// through the devshell's execute/x end points. Specifically for faking
// speaking at Jibo in Autobot tests
(global as any).JetstreamServiceSim = JetstreamServiceSim;

export default class DevShell extends HTTPWSService implements SSMService {

    private static _instance: DevShell;
    private _syncPort: number;
    private _skillDest: string;
    private _skillUser: string;
    private _skillLimit: number;
    private _sdkDest: string;
    private _otaSocket: WebSocket;
    private _autobotSocket: WebSocket;
    private _executeCallbacks: ExecuteCallback[];

    public static get instance(): DevShell {
        return DevShell._instance;
    }

    constructor(options: DevShellOptions, rootDir: string) {
        super('dev-shell', options, rootDir);
        if (DevShell._instance) {
            throw new Error('Cannot instantiate DevShell more than once');
        }
        log.debug('constructor', options);
        DevShell._instance = this;
        this._skillDest = options.skillDest;
        this._skillUser = options.skillUser;
        this._skillLimit = options.skillLimit;
        this._sdkDest = options.sdkDest;
        this._syncPort = options.syncPort;
        this._otaSocket = null;
        this._autobotSocket = null;
        this._executeCallbacks = [];
        log.info('Instantiated');
    }

    public init(callback: (err?: Error) => void) {
        log.debug('init');

        super.init((err: Error) => {
            if (err) {
                log.warn('Error during init', err);
                return callback(err);
            }
            // Disable timeouts for all devshell sockets
            this.server.timeout = 0;
            log.info('Initialized');
            callback();
        });
    }

    public routes(url: Router) {
        super.routes(url);

        // Provide an API for simulating speech to the simulator so that frameworks
        // like jibo-autobot can generate speech in the simulator
        if( process.env.RUNMODE === RunMode.RunMode.SIMULATOR) {
            url.post('/speak', this._speak);
        }

        url.post('/execute', this._execute);

        // Don't run any of the following when in the simulator
        if( process.env.RUNMODE === RunMode.RunMode.ON_ROBOT) {
            url.post('/check-update', this._checkForUpdates);
            url.post('/delete-skill', this._deleteSkill);
            url.post('/delete-all', this._deleteAllSkills);
            url.post('/diskspace', this._diskSpace);
            url.post('/download-update', this._downloadUpdates);
            url.post('/getvolume', this._getVolume);
            url.post('/index', this._index);
            url.post('/install-update', this._installUpdates);
            url.post('/run', this._startSkill);
            url.post('/poweroff', this._poweroff);
            url.post('/reboot', this._reboot);
            url.post('/reset-proxy/:serverPort', this._resetProxy);
            url.post('/setvolume', this._setVolume);
            url.post('/stop', this._stopSkill);
            url.post('/sync-skill', this._syncSkill);
            url.post('/version', this._getVersion);
            url.post('/wifi-list', this._wifiList);
            url.post('/wifi-current', this._wifiCurrent);
            url.post('/wifi-verify', this._wifiVerify);
            url.post('/wifi-select', this._wifiSelect);
            url.post('/wifi-add', this._wifiAdd);
            url.post('/wifi-remove', this._wifiRemove);
        }
    }

    public onConnection(client: WebSocket, request:http.IncomingMessage): void {
        super.onConnection(client, request);
        if(client.url === '/download-update') {
            log.debug('Opening OTA download socket');
            this._otaSocket = client;
        } else if (client.url === '/autobot') {
            this._autobotSocket = client;
        }
    }

    protected onClose(client: WebSocket): void {
        if (client === this._otaSocket) {
            log.debug('Closing OTA download socket');
            this._otaSocket = undefined;
        }
        if (client === this._autobotSocket) {
            this._autobotSocket = null;
        }
    }

    protected onMessage(command: any, client: WebSocket): void {

        // DevShell also listens for 'execute' requests on websockets
        if( command.command === 'execute' ) {
            this._sendExecuteMessage(command.script, (result) => {
                if (this._autobotSocket) {
                    this.sendWsJson(this._autobotSocket, {
                        command: 'execute-result',
                        result: result.result,
                        success: result.success,
                        error: result.error
                    });
                }
            });
        }
        else if( command.command === 'speak' ) {
            this._say( command.words, command.heyJibo, command.speaker, command.speakerId );

            // For now just send an acknowledgement message back,
            // this could be used to wait till speaking is actually done (for non instant speaking),
            // so that connected test automation knows that speaking is finished
            this.sendWsJson(client, {
                command: 'speak-result',
                success: true
            });
        }
        else if( command.command === 'execute-result' ) {
            this._executeCallbacks[command.id](command);
        } else if (command.command === 'autobot-log') {
            //send the log along our autobot connection, if one exists
            if (this._autobotSocket) {
                this.sendWsJson(this._autobotSocket, command);
            }
        }
        return;
    }

    private _sendError(
        res: JiboServerResponse,
        err: Error|string,
        statusCode: number = 500,
    ): void {
        this.finish(res, err, null, null, statusCode);
    }

    private _syncSkill = async (
        req: JiboServerRequest,
        res: JiboServerResponse,
    ): Promise<void> => {
        log.info('Syncing skill');
        const [parseErr, data] =
            await prfyTo<{dirName: string}>(cb => this.parseBody(req, cb));
        if (parseErr) {
            return this._sendError(res, parseErr, 400);
        }
        const dest = path.join(this._skillDest, data.dirName);
        // start server for syncing...
        const verbose = true; // for now?
        log.debug('creating sync server', this._syncPort, dest, verbose);
        const jiboSyncLog = log.createChild('Server');
        try {
            this._syncPort = await JiboSync.createServer(
                this._syncPort,
                dest,
                this._skillUser,
                this._skillLimit,
                verbose,
                jiboSyncLog,
            );
        }
        catch(err) {
            return this._sendError(res, err);
        }
        log.debug(`Sync server started successfully on port ${this._syncPort}`);
        this.sendJson(res, 'Sync server started successfully');
    }

    // Called from the jibo-cli to start a skill
    private _startSkill = async (
        req: JiboServerRequest,
        res: JiboServerResponse,
    ): Promise<void> => {
        log.debug('Starting skill called');
        const [parseErr, data] =
            await prfyTo<{dirName: string}>(cb => this.parseBody(req, cb));
        if (parseErr) {
            return this._sendError(res, parseErr, 400);
        }
        log.debug('_startSkill got parsed request', data);
        let skillName: string = data.dirName;
        log.debug(`Checking if skill ${skillName} exists`);
        const [skillListErr, skillList] = await prfyTo<SkillRecord[]>(cb =>
            SystemManagerClient.instance.list(cb));
        if (skillListErr) {
            log.warn('Error getting skill list', skillListErr);
            return this._sendError(res, `Error getting list of skills`);
        }
        const skill = skillList.find(skill => skill.name === skillName);
        if (!skill) {
            log.info(`Skill ${skillName} not found`);
            return this._sendError(res, `Skill ${skillName} not found`, 404);
        }
        log.debug('Calling SkillsService.instance.launch', skillName);
        const [launchErr] = await prfyTo<{skillName: string}>(cb =>
            SkillsService.instance.launch(skillName, {}, cb));
        if (launchErr) {
            log.warn(`Error starting ${skillName}`, launchErr);
            return this._sendError(res, `Error starting "${skillName}"\n${(<Error>launchErr).message || launchErr}`);
        }
        log.debug(`Skill "${skillName}" started successfully`);
        this.sendJson(res, `Skill "${skillName}" started successfully`);
    }

    private _stopSkill = async (
        req: JiboServerRequest,
        res: JiboServerResponse,
    ): Promise<void> => {
        log.debug('Stopping skill');
        const [terminateErr] =
            await prfyTo(cb => SkillsService.instance.terminate(cb));
        if (terminateErr) {
            log.warn('Skill stop failed', terminateErr);
            return this._sendError(res, `Error stopping: ${terminateErr}`);
        }
        log.debug('Stopped skill successfully');
        this.sendJson(res, 'Stopped skill successfully.');
    }

    private _deleteSkill = async (
        req: JiboServerRequest,
        res: JiboServerResponse,
    ): Promise<void> => {
        log.info('Deleting skill');
        const [parseErr, data] =
            await prfyTo<{dirName: string}>(cb => this.parseBody(req, cb));
        if (parseErr) {
            return this._sendError(res, parseErr, 400);
        }
        const name = data.dirName;
        const dest = path.join(this._skillDest, name);
        const [accessErr] =
            await prfyTo(cb => fs.access(dest, fs.constants.W_OK, cb));
        if (accessErr) {
            const message = `Skill ${name} not installed.`;
            log.info(message, accessErr);
            this._sendError(res, message, 400);
        }
        const [rimrafErr] = await prfyTo(cb => rimraf(dest, cb));
        if (rimrafErr) {
            const message = `Error deleting skill ${name}`;
            log.error(message, rimrafErr);
            return this._sendError(res, message);
        }
        // If the skill is in a namespace directory (e.g. @be/be), check if the
        // namespace dir is empty, and if so, remove it
        if (name.startsWith('@')) {
            const nsDir = path.resolve(path.join(dest, '..'));
            const [nsListErr, nsList] =
            await prfyTo<string[]>(cb => fs.readdir(nsDir, cb));
            if (nsListErr) {
                const message = `Skill removed, but could not read contents of namespace dir ${nsDir}`;
                log.warn(message, nsListErr);
                return this._sendError(res, message);
            }
            if (nsList.length < 1) {
                const [rmdirErr] = await prfyTo(cb => fs.rmdir(nsDir, cb));
                if (rmdirErr) {
                    const message = `Skill removed, but could not remove empty namespace dir ${nsDir}`;
                    log.warn(message, rmdirErr);
                    return this._sendError(res, message);
                }
            } else {
                log.info(`Namespace dir ${nsDir} is not empty, so leaving it in place`);
            }
        }
        log.debug(`Skill ${name} deleted successfully.`);
        this.sendJson(res, 'Skill deleted successfully.');
    }

    private _deleteAllSkills = async (
        req:JiboServerRequest,
        res:JiboServerResponse,
    ): Promise<void> => {
        log.info("Deleting all skills");
        const [rimrafErr] = await prfyTo(cb => rimraf(this._skillDest, cb));
        if (rimrafErr) {
            const message = 'Error deleting all skills';
            log.error(message, rimrafErr);
            this._sendError(res, message);
        }
        const message = 'All skills deleted successfully.';
        log.debug(message);
        this.sendJson(res, message);
    }

    private _diskSpace = (
        req: JiboServerRequest,
        res: JiboServerResponse
    ): void => {
        log.info('Retrieving disk space');
        const command: string =
            path.join(this.rootDir, this._sdkDest + 'disk-space.sh');
        const proc = spawn('sh', [`${command}`, `${this._skillDest}`]);
        let data = `not found: ${command}`;
        proc.stdout.on('data', (_data: string) => {
            data = _data;
        });
        proc.on('exit', () => {
            const message = `Diskspace Usage [${this._skillDest}]:\n\n`;
            log.debug(message, data);
            this.sendJson(res, `${message} ${data}`);
        });
    }

    private _reboot = async (
        req: JiboServerRequest,
        res: JiboServerResponse,
    ): Promise<void> => {
        const [parseErr, data] =
            await prfyTo<{mode: string}>(cb => this.parseBody(req, cb));
        if (parseErr) {
            return this._sendError(res, parseErr, 400);
        }
        if (data.mode) {
            log.debug(`Setting robot mode to ${data.mode}.`);
            const [setModeErr] = await prfyTo<void>(cb =>
                systemManager.setMode(data.mode, cb));
            if (setModeErr) {
                const message: string = `Could not set mode to ${data.mode}.`;
                log.error(message, setModeErr);
                return this._sendError(res, message);
            }
            log.info(`Set robot mode to ${data.mode}.`);
        }
        log.info('Rebooting');
        const [rebootErr] = await prfyTo<void>(cb =>
            systemManager.reboot(cb));
        if (rebootErr) {
            const message = 'Error trying to reboot';
            log.warn(message, rebootErr);
            return this._sendError(res, message);
        }
        log.debug('Rebooting...');
        this.sendJson(res, 'Rebooting...');
    }

    private _poweroff = async (
        req: JiboServerRequest,
        res: JiboServerResponse,
    ): Promise<void> => {
        log.info('Powering off');
        const [powerOffErr] =
            await prfyTo<void>(cb => systemManager.poweroff(cb));
        if (powerOffErr) {
            const message = 'Error trying to power off';
            log.warn(message, powerOffErr);
            return this._sendError(res, message);
        }
        log.debug('Powering off...');
        this.sendJson(res, 'Powering off...');
    }

    private _getVersion = async (
        req: JiboServerRequest,
        res: JiboServerResponse,
    ): Promise<void> => {
        log.info('Retrieving version');
        const [versionErr, version] =
            await prfyTo<string>(cb => systemManager.getVersion(cb));
        if (versionErr) {
            const message = 'Error trying to get version';
            log.warn(message, versionErr);
            return this._sendError(res, message);
        }
        this.sendJson(res, version);
    }

    private _index = (
        req: JiboServerRequest,
        res: JiboServerResponse,
    ): Promise<void> => {
        log.info('Indexing');
        return expression.indexRobot()
        .then(result => {
            log.debug('Index result', result);
            if(result === 'FAULT') {
                throw new Error('Problem indexing robot.');
            }
            const message = result === 'SUCCEEDED'
                ? 'Robot is indexed.'
                : 'Robot indexing timed out.';
            this.sendJson(res, message);
        })
        .catch(err => {
            const message = 'Problem indexing robot.';
            log.error(message, err);
            this._sendError(res, message);
        });
    }

    private _getVolume = async (
        req: JiboServerRequest,
        res: JiboServerResponse,
    ): Promise<void> => {
        log.info('Getting volume');
        const [volumeErr, volume] =
            await prfyTo<number>(cb => system.getMasterVolume(cb));
        if (volumeErr) {
            const message = 'Could not get volume';
            log.warn(message, volumeErr);
            return this._sendError(res, message);
        }
        log.warn(`Master volume is ${volume.toFixed(2)} [0.0-1.0]`);
        this.sendJson(res, `${volume.toFixed(2)} [0.0-1.0]`);
    }

    private _setVolume = async (
        req: JiboServerRequest,
        res: JiboServerResponse,
    ): Promise<void> => {
        log.info('Setting volume');
        const [parseErr, data] =
            await prfyTo<{volume: number}>(cb => this.parseBody(req, cb));
        if (parseErr) {
            this._sendError(res, parseErr, 400);
        }
        const volume = data.volume;
        const [volumeErr] =
            await prfyTo<void>(cb => system.setMasterVolume(volume, cb));
        if (volumeErr) {
            const message = 'Cannot set master volume';
            log.warn(message, volumeErr);
            return this._sendError(res, `${message} (${volumeErr})`);
        }
        log.warn('Master volume set', volume.toFixed(2));
        this.sendJson(res, volume.toFixed(2));
    }

    // Called from the jibo-cli to check for OTA updates
    private _checkForUpdates = async (
        req: JiboServerRequest,
        res: JiboServerResponse,
    ): Promise<void> => {
        log.info('Checking for updates');
        const [parseErr, data] =
            await prfyTo<{filter: string}>(cb => this.parseBody(req, cb));
        if (parseErr) {
            this._sendError(res, parseErr, 400);
        }
        const [checkErr, updates] = await prfyTo<any>(cb =>
            systemManager.checkForUpdates(cb, data.filter));
        if (checkErr) {
            log.warn('System Manager checkForUpdates failed', checkErr);
            return this._sendError(res, (<Error>checkErr).message || checkErr);
        }
        if (!updates) {
            const message = 'Service temporarily unavilable';
            log.warn(message);
            return this._sendError(res, message);
        }
        const ids = updates.map(update => `\n${update.id}: ${update.changes}${update.downloaded ? ' [DOWNLOADED]' : ''}`).join('');
        const msg = `Found ${updates.length} update${updates.length === 1 ? '' : 's'}${ids}`;
        log.info(msg, updates);
        this.sendJson(res, {msg, updates});
    }

    // Called from the jibo-cli to download OTA updates
    private _downloadUpdates = async (
        req: JiboServerRequest,
        res: JiboServerResponse,
    ): Promise<void> => {
        const [parseErr, data] =
            await prfyTo<any>(cb => this.parseBody(req, cb));
        if (parseErr) {
            return this._sendError(res, parseErr, 400);
        }
        log.info('Downloading updates', data);
        await new Promise((resolve, reject) => {
            systemManager.downloadUpdates(
                data,
                (dlErr?: Error, dlData?: {status: string, reason: any}) => {
                    if (dlErr) {
                        log.warn('Error downloading OTA updates', dlErr);
                        this._sendError(res, `Error downloading OTA updates: ${(<Error>dlErr).message || dlErr}`);
                        return reject();
                    }
                    if (dlData.status === 'failed') {
                        log.warn('Download failed', dlData.reason);
                        this._sendError(res, dlData.reason);
                        return reject();
                    }
                    log.debug('Download update', dlData);
                    // only send socket message if still downloading...
                    if (dlData.status === 'downloading') {
                        if (this._otaSocket) {
                            log.debug('Sending websocket update');
                            this.sendWsJson(this._otaSocket, dlData);
                        }
                    } else {
                        log.info('OTA updates downloaded', dlData);
                        // otherwise send back response
                        this.sendJson(res, dlData);
                        resolve();
                    }
                });
        });
    }

    // Called from the jibo-cli to install OTA updates
    private _installUpdates = async (
        req: JiboServerRequest,
        res: JiboServerResponse,
    ): Promise<void> => {
        const [parseErr, data] =
            await prfyTo<any>(cb => this.parseBody(req, cb));
        if (parseErr) {
            return this._sendError(res, parseErr, 400);
        }
        log.info('Installing updates', data);
        const [updateErr] =
            await prfyTo<void>(cb => systemManager.installUpdates(data, cb));
        if (updateErr) {
            const message = 'Error installing OTA updates';
            log.warn(message, updateErr);
            return this._sendError(res, message);
        }
        log.debug('OTA updates installing');
        this.sendJson(res, 'Installing OTA updates! Robot will reboot a handful of times in between installations. Go get a snack.');
    }

    // Called from the ssm page before launching debuggers
    private _resetProxy = (
        req: JiboServerRequest,
        res: JiboServerResponse
    ): void => {
        let serverPort = req.params.serverPort;
        log.debug(`Resetting proxy server on port ${serverPort}`);
        TcpProxy.closeAllSocketsForServer(serverPort);
        this.finishNoContent(res);
    }

    private _wifiList = async (
        req: JiboServerRequest,
        res: JiboServerResponse,
    ): Promise<void> => {
        const [err, networks] =
            await prfyTo(cb => wifi.getSavedNetworks(cb));
        if (err) {
            const message = 'Error getting list of WiFi networks';
            log.warn(message, err);
            return this._sendError(res, new Error(message));
        }
        return this.sendJson(res, networks);
    }

    private _wifiCurrent = async (
        req: JiboServerRequest,
        res: JiboServerResponse,
    ): Promise<void> => {
        const [err, network] =
            await prfyTo(cb => wifi.getCurrentNetwork(cb));
        if (err) {
            const message = 'Error getting current WiFi network';
            log.warn(message, err);
            return this._sendError(res, new Error(message));
        }
        return this.sendJson(res, network);
    }

    private _wifiVerify = async (
        req: JiboServerRequest,
        res: JiboServerResponse,
    ): Promise<void> => {
        const [err, message] =
            await prfyTo<any[]>(cb => wifi.verifyConnection(cb));
        if (err) {
            const message = 'Error verifying current WiFi network';
            log.warn(message, err);
            return this._sendError(res, new Error(message));
        }
        return this.sendJson(res, message);
    }

    private _wifiSelect = async (
        req: JiboServerRequest,
        res: JiboServerResponse,
    ): Promise<void> => {
        const [parseErr, data] =
            await prfyTo<{ssid?: string}>(cb => this.parseBody(req, cb));
        if (parseErr) {
            return this._sendError(res, parseErr, 400);
        }
        if (!data.ssid) {
            return this._sendError(res, new Error('ssid is required'), 400);
        }
        const [getErr, networks] = await prfyTo<wifi.SavedNetworkEntry[]>(cb =>
            wifi.getSavedNetworks(cb));
        if (getErr) {
            const message = 'Error getting existing WiFi networks';
            log.warn(message, getErr);
            return this._sendError(res, new Error(message));
        }
        const existingNetwork =
            networks.find(network => network.ssid === data.ssid);
        if (!existingNetwork) {
            const message = `WiFi network ${data.ssid} not found`;
            log.warn(message);
            return this._sendError(res, new Error(message), 400);
        }
        if (existingNetwork.current) {
            const message = `WiFi network ${data.ssid} is already selected`;
            log.info(message);
            return this._sendError(res, new Error(message), 400);
        }
        const [selectErr] = await prfyTo<void>(cb =>
            wifi.selectNetwork(data.ssid, cb));
        if (selectErr) {
            const message = 'Error selecting WiFi network';
            log.warn(message, selectErr);
            return this._sendError(res, new Error(message));
        }
        return this.finishNoContent(res);
    }

    private _wifiAdd = async (
        req: JiboServerRequest,
        res: JiboServerResponse,
    ): Promise<void> => {
        const [parseErr, data] =
            await prfyTo<WiFiData>(cb => this.parseBody(req, cb));
        if (parseErr) {
            return this._sendError(res, parseErr, 400);
        }
        const {
            dns1,
            dns2,
            gateway,
            netmask,
            pswd,
            ssid,
            staticIP,
        } = data;
        const hidden = 0;
        const staticSettings = data.staticIP
            ? {staticIP, gateway, netmask, dns1, dns2}
            : null;
        const networkType = staticSettings ? 1 : 0;
        const security = pswd && pswd.length > 0 ? 'WPA-PSK' : 'NONE';
        const wifiConfig = {
            hidden,
            networkType,
            pswd,
            security,
            ssid,
            staticSettings,
        };
        const [getErr, networks] = await prfyTo<{ssid?: string}[]>(cb =>
            wifi.getSavedNetworks(cb));
        if (getErr) {
            const message = 'Error getting existing WiFi networks';
            log.warn(message, getErr);
            return this._sendError(res, new Error(message));
        }
        const existingNetwork =
            networks.find(network => wifiConfig.ssid === network.ssid);
        if (existingNetwork) {
            log.debug('removing network before adding because new SSID matches old SSID');
            const [removeErr] = await prfyTo<void>(cb =>
                wifi.removeNetwork(existingNetwork.ssid, cb));
            if (removeErr) {
                log.warn('Error removing existing WiFi network', removeErr);
            }
        }
        // Keep track of the current network (in comments below, the "old"
        // network) so we can reconnect if there are issues
        const [currentNetworkErr, currentNetwork] =
            await prfyTo<wifi.NetworkStats>(cb => wifi.getCurrentNetwork(cb));
        if (currentNetworkErr) {
            log.warn('Error getting current WiFi network', currentNetworkErr);
            // Continue anyway
        }
        // Add the new network
        const [addErr] =
            await prfyTo(cb => wifi.addNetwork(wifiConfig, 30, cb));
        if (addErr) {
            const message = 'Error adding new WiFi network';
            log.warn(message, addErr);
            // Try to select the old network to ensure connectivity
            if (currentNetwork) {
                const [reconnectErr] = await prfyTo<void>(cb =>
                    wifi.selectNetwork(currentNetwork.ssid, cb));
                if (reconnectErr) {
                    log.warn(`Error reconnecting to old network ${currentNetwork.ssid}`, reconnectErr);
                }
            }
            return this._sendError(res, new Error(message));
        }
        // Verify the connection, and try to select the old network to ensure
        // connectivity
        const [connectedErr, connected] =
            await prfyTo<boolean>(cb => wifi.verifyConnection(cb));
        if (connectedErr) {
            log.warn('Error verifying connection', connectedErr);
            // Drop through to attempt to connect to the old network
        }
        // Verify the connection, and try to select the old network to ensure
        // connectivity
        if (currentNetwork && !connected) {
            const [reconnectErr] = await prfyTo<void>(cb =>
                wifi.selectNetwork(currentNetwork.ssid, cb));
            if (reconnectErr) {
                log.warn(`Error reconnecting to old network ${currentNetwork.ssid}`, reconnectErr);
            }
        }
        this.finishNoContent(res);
    }

    private _wifiRemove = async (
        req: JiboServerRequest,
        res: JiboServerResponse,
    ): Promise<void> => {
        // Parse the data sent by the CLI
        const [parseErr, data] =
            await prfyTo<{ssid?: string}>(cb => this.parseBody(req, cb));
        if (parseErr) {
            return this._sendError(res, parseErr, 400);
        }
        // Make sure there's an SSID in the data
        if (!data.ssid) {
            return this._sendError(res, new Error('ssid is required'), 400);
        }
        // Get a list of the networks already on the robot
        const [getErr, networks] = await prfyTo<{ssid?: string}[]>(cb =>
            wifi.getSavedNetworks(cb));
        if (getErr) {
            const message = 'Error getting existing WiFi networks';
            log.warn(message, getErr);
            return this._sendError(res, new Error(message));
        }
        // Make sure the requested network exists in the list
        if (!networks.find(network => network.ssid === data.ssid)) {
            const message = `WiFi network ${data.ssid} not found`;
            log.warn(message);
            return this._sendError(res, new Error(message), 400);
        }
        // Get the currently-connected network
        const [currentErr, currentNetwork] =
            await prfyTo<{ssid?: string}>(cb => wifi.getCurrentNetwork(cb));
        if (currentErr) {
            const message = 'Error getting current WiFi network';
            log.warn(message, currentErr);
            return this._sendError(res, new Error(message));
        }
        // Make sure the request isn't to delete the current network
        // This would leave a developer-mode robot permanently without WiFi
        if (currentNetwork.ssid === data.ssid) {
            const message = `Cannot delete ${data.ssid} because it is the currently-connected network`;
            log.info(message);
            return this._sendError(res, new Error(message), 400);
        }
        // Remove the network
        const [removeErr] = await prfyTo<void>(cb =>
            wifi.removeNetwork(data.ssid, cb));
        if (removeErr) {
            const message = 'Error removing WiFi network';
            log.warn(message, removeErr);
            return this._sendError(res, new Error(message));
        }
        // Return OK status
        return this.finishNoContent(res);
    }

    private _say = (words:string , heyJibo:boolean, speaker:string, speakerId:string) => {
        // Make sure TTS is in Test mode so that he speaks instantaneously
        TTSService.instance.setMode(TTSPlaybackMode.Test);

        // Asr service expects to have syntax removed, I assume this is
        // how ASR services return results? If I didn't do this, there were many
        // recognition issues
        words = words.toLowerCase().trim().replace(/[\|&;\$%@"#<>\(\)\+,?.]/g, "");

        if(heyJibo){
            JetstreamServiceSim.instance.onWordsReceived({
                words: "hey jibo",
                final: false,
                speaker: speaker,
                speakerId: speakerId
            });
            words = "hey jibo " + words;
        }

        JetstreamServiceSim.instance.onWordsReceived({
            words: words,
            final: true,
            speaker: speaker,
            speakerId: speakerId
        });

        // Insert chat message to make it easier to see what
        // was said
        (global as any).chatView.refs.chat.messageHandler({
            words: words,
            speaker: speakerId
        });

        log.debug(`Attempting to generate speech:`, words, speakerId );
    }

    /*
     * Developers can simulate speaking in the simulator
     */
    private _speak = async (
        req: JiboServerRequest,
        res: JiboServerResponse,
    ): Promise<void> => {
        try {
            const [parseErr, json] =
                await prfyTo<SpeakRequest>(cb => this.parseBody(req, cb));
            if (parseErr) {
                throw new Error("Couldn't parse payload");
            }

            this._say( json.words, json.heyJibo, json.speaker, json.speakerId );

            this.sendJson( res, {
                success: true
            });
        } catch(error){
            this._sendError(res, error);
        }
    }

    /*
     * Developers can send a string of arbitrary javascript that will be executed and then
     * the results returned
     */
    // Execute code inside the skill process
    private _execute = async (
        req: JiboServerRequest,
        res: JiboServerResponse,
    ): Promise<void> => {
        try {
            const [parseErr, json] =
                await prfyTo<{script: any}>(cb => this.parseBody(req, cb));
            if (parseErr) {
                throw new Error("Couldn't parse payload");
            }


            this._sendExecuteMessage(json.script, (result) => {
                this.sendJson( res, {
                    result: result.result,
                    success: result.success,
                    error: result.error
                });
            });

            // let result:any = eval(json.script);
            //

        } catch(error){
            this._sendError(res, error);
        }
    }

    private _sendExecuteMessage( script: string, cb: ExecuteCallback ) {
        // Send a message to the skills process using the skill service's websocket
        const id = uuidv4();
            // Because we don't know which connected client is the skill process, we send this
            // message to each connected process.
        this.connections.forEach( (connection) => {
            // don't spam the autobot or OTA connections with this message though
            if (connection === this._autobotSocket || connection === this._otaSocket) {
                return;
            }
            this.sendWsJson(connection, {
                command: "execute",
                id,
                script
            });
        });

        log.debug(`Attempting to execute remote skill script: ${script}`);

        this._executeCallbacks[id] = (result) => {
            cb(result);
            delete this._executeCallbacks[id];
        };
    }
}

