import {
    HTTPWSService,
    JiboServerRequest,
    JiboServerResponse,
    RegistrationRecord,
    RegistryClient,
    ServiceOptions,
    WSClient,
} from 'jibo-service-framework';
import WebSocket = require('ws');
import {Node} from 'jibo-kb';
import KBService from '../kb/KBService';
import kb from '../../clients/KBClient';
import Router = require('router');
import PriorityQueue from './PriorityQueue';
import { types } from '@jibo/jetstream-client';
import JiboError from './JiboError';
import DebugErrorReporter from './DebugErrorReporter';
import ErrorServiceUtil from './ErrorServiceUtil';
import ErrorRescheduler from './ErrorRescheduler';
import ErrorLogger from './ErrorLogger';
import GlobalManagerService from "../global-manager/GlobalManagerService";
import {PromiseUtils} from 'jibo-cai-utils';
import RunMode from '../../utils/RunMode';
import {EventEmitter} from 'events';
import {SSMService} from '../../SSMService';

import parentLog from '../log';
const log = parentLog.createChild('Error');

const errorCodesJson = require('./ErrorCodes.json');

const prify = PromiseUtils.promisify;
const prto = PromiseUtils.promisifyTo;

class ErrorService extends HTTPWSService implements SSMService {

    public static Types = {
        JiboError,
        DebugErrorReporter,
        PriorityQueue,
        ErrorServiceUtil,
        ErrorRescheduler,
        ErrorLogger
    };

    private static _instance: ErrorService = null;

    //Emit events with error IDs when errors are added or removed:
    private _errorAddedEmitter:EventEmitter = new EventEmitter();
    private _errorRemovedEmitter:EventEmitter = new EventEmitter();

    // the current "active" error which would be reporting to Be/Settings.
    // if this is not equal to what the priority queue thinks is the highest priority error, we need to update Be/Settings on
    // what the highest priority skill currently is
    private _currentError: JiboError = null;
    // stores a list of errors sorted by priority (and then error id as a secondary comparison field)
    private _errorPriorityQueue: PriorityQueue<JiboError> = null;
    private _errorRescheduler: ErrorRescheduler = null;
    private _errorLogger: ErrorLogger = null;

    // connects to either the platform system monitoring service or the simulated version when running in the sim
    private _systemMonitoringServiceSocket: WSClient = null;
    private _errorCodesKBRootNode: Node = null;
    // a mapping of support error id -> error objects.
    private _errorCodeMap: { [key:string]:JiboError; } = {};
    // a mapping of platform id -> support error code
    private _platformErrorCodeMap: { [key:string]:string; } = {};
    // this data structure stores what the platform has reported for errors the previous time the reporting function was called
    private _lastErrors: { [key:string]:JiboError; } = {};

    // a registration record to store ip and port info about the system monitoring service
    private _systemMonitoringService: RegistrationRecord = null;
    private _debugErrorReporter: DebugErrorReporter = null;
    private _mockErrorsEnabled: boolean = false;

    // by default when receiving errors, we want to switch into the settings skill
    // toggling this variable disables that switch
    private _disableSkillSwitch: boolean = false;
    private _errorSubscribeCallback: ()=>void = null;

    private _subscribedErrorObject: JiboError = null;

    public static get instance(): ErrorService {
        return ErrorService._instance;
    }

    constructor(options:ServiceOptions, rootDir: string) {
        super('error-service', options, rootDir);
        if (ErrorService._instance) {
            throw new Error('Cannot instantiate ErrorService more than once');
        }
        ErrorService._instance = this;

        this._errorPriorityQueue = new PriorityQueue<JiboError>(JiboError.Comparer, false);
        this._errorRescheduler = new ErrorRescheduler();
        this._errorLogger = new ErrorLogger(log.createChild('Logger'));

        // always enable the debug errors when running on the simulator
        if(RunMode.runMode === RunMode.RunMode.SIMULATOR) {
            this._mockErrorsEnabled = true;
        }

        // set up the mapping for the error codes and platform codes
        Object.keys(errorCodesJson.errorCodes).forEach((errorCodeId)=>{
            let errorCode = errorCodesJson.errorCodes[errorCodeId];
            let jiboError = new JiboError(errorCodeId, errorCode);
            this._errorCodeMap[jiboError.id] = jiboError;
            if(jiboError.platformCode) {
                this._platformErrorCodeMap[jiboError.platformCode] = jiboError.id;
            }
        });

        log.info("Instantiated");
    }

    // seed the KB with all the errors, find the system monitoring service, and start the connection
    public init(callback: (err?:Error)=>void) {
        super.init((err:Error) => {
            RegistryClient.instance.getRecords((err:Error, records:Array<RegistrationRecord>)=>{
                if(err) {
                    return callback(err);
                }
                // store all the errors into the KB
                let url = "http://" + RegistryClient.instance.host + ":" + KBService.instance.port;
                let model = kb.createModel('/error-codes', url);
                model.loadRoot((err, rootNode)=>{
                    if (err) {
                        return callback(err);
                    }
                    this._errorCodesKBRootNode = rootNode;
                    this._errorCodesKBRootNode.data.errorCodes = errorCodesJson.errorCodes;
                    this._errorCodesKBRootNode.save(err => {
                        if (err) {
                            return callback(err);
                        }
                        this._systemMonitoringService = records.find(record => record.name === 'system-monitoring-service');
                        this._connectToSystemMonitor();
                        // Continue along with SSM startup, even if the system
                        // monitor isn't yet available
                        log.info('Initialized');
                        callback();
                    });
                });
            });
        });
    }

    public routes(url:Router):void {
        super.routes(url);

        // handle requests for mocking errors from the error service debug page
        url.post('/mockErrorCodes', (req:JiboServerRequest, res:JiboServerResponse) => {
            this._mockErrorCodes(req, res);
        });

        // handle requests for getting data about the errors
        url.post('/errorCodeData', (req:JiboServerRequest, res:JiboServerResponse) => {
            this._sendErrorCodeData(req, res);
        });

        url.post('/getErrorCount', (req:JiboServerRequest, res:JiboServerResponse) => {
            this._getErrorCount(req, res);
        });

        url.post('/subscribeError', (req:JiboServerRequest, res:JiboServerResponse) => {
            this._subscribeError(req, res);
        });

        url.post('/processedError', (req:JiboServerRequest, res:JiboServerResponse) => {
            this._processedError(req, res);
        });

        url.post('/disableSkillSwitching', (req:JiboServerRequest, res:JiboServerResponse) => {
            this._disableSkillSwitching(req, res);
        });

        url.post('/getCurrentErrorId', (req:JiboServerRequest, res:JiboServerResponse) => {
            this._getCurrentErrorId(req, res);
        });

        url.post('/getContents', (req:JiboServerRequest, res:JiboServerResponse) => {
            this._getContents(req, res);
        });
    }

    public addError(supportErrorId:string): boolean {
        if(this._errorCodeMap.hasOwnProperty(supportErrorId) &&
            // don't add the error if it is lurking in the error rescheduler.  it will re-add itself to the priority queue when it's timer is up
            !this._errorRescheduler.contains(supportErrorId)) {

            let error = this._errorCodeMap[supportErrorId];
            this._errorLogger.addError(error);
            this._errorAddedEmitter.emit(error.id);
            if(error.priority !== -1) {
                return this._errorPriorityQueue.add(error);
            }
        }
        return false;
    }

    public removeError(supportErrorId:string): boolean {
        if(this._errorCodeMap.hasOwnProperty(supportErrorId)) {
            // remove it from the rescheduler in case it's waiting to be rescheduled
            this._errorRescheduler.remove(supportErrorId);

            let error = this._errorCodeMap[supportErrorId];
            this._errorLogger.removeError(error);
            this._errorRemovedEmitter.emit(error.id);
            return this._errorPriorityQueue.delete(error);
        }
        return false;
    }

    public addErrorAddedListener(errorId:string, callback:()=>void){
        this._errorAddedEmitter.on(errorId, callback);
    }
    public removeErrorAddedListener(errorId:string, callback:()=>void){
        this._errorAddedEmitter.removeListener(errorId, callback);
    }
    public addErrorRemovedListener(errorId:string, callback:()=>void){
        this._errorRemovedEmitter.on(errorId, callback);
    }
    public removeErrorRemovedListener(errorId:string, callback:()=>void){
        this._errorRemovedEmitter.removeListener(errorId, callback);
    }

    /*
     * @description returns whether or not an error of given ID exists in ErrorCodes data
     * @method WifiService#onHealth
     * @param errorId {String} error ID to check
     * @public
     * @returns {Boolean} whether or not errorId exists in _errorCodeMap
     */
    public errorExists(errorId):boolean{
        return this._errorCodeMap.hasOwnProperty(errorId);
    }

    protected onMessage(message: any, client: WebSocket): void {
        return;
    }

    private async _connectToSystemMonitor() {
        let attempt = 1;
        while (!this._systemMonitoringService) {
            attempt++;
            const [err, record] = await prto<RegistrationRecord>(cb => RegistryClient.instance.getRecordByName('system-monitoring-service', cb));
            if (err) {
                log.warn(`Couldn't connect to system monitoring service on attempt ${attempt}`, err);
                await prify(cb => setTimeout(cb, 1000));
            } else {
                this._systemMonitoringService = record;
            }
        }
        const uri = "ws://" + this._systemMonitoringService.host + ":" + this._systemMonitoringService.port + "/errors/codes";
        this._systemMonitoringServiceSocket = new WSClient(uri);
        this._systemMonitoringServiceSocket.once('open', () => {
            this._systemMonitoringServiceSocket.on('message', this._receivedSystemMonitoringServiceErrors.bind(this));
            this._systemMonitoringServiceSocket.on('error', this._onSocketError.bind(this));
            const message = `connected to the system-monitoring/error/codes after ${attempt} attempt${attempt > 1 ? 's' : ''}`;
            if(attempt > 1) {
                log.info(message);
            } else {
                log.debug(message);
            }
        });
        // set up the DebugErrorReporter at the point where we're connected to the system monitoring service
        this._debugErrorReporter = new DebugErrorReporter(this._errorCodeMap, this.addError.bind(this), this.removeError.bind(this), this._receivedMockErrors.bind(this));
        this._errorPriorityQueue.onItemAdded = this._errorsAdded.bind(this);
        this._errorPriorityQueue.onItemRemoved = this._errorsRemoved.bind(this);
    }

    private _disableSkillSwitching(req:JiboServerRequest, res:JiboServerResponse): void {
        this.parseBody(req, (err, disableSkillSwitchingJson) => {
            if (err) {
                return this.sendJson(res, { status: 'error', message: typeof err === 'string' ? err : err.message }, 500);
            }
            if(disableSkillSwitchingJson.hasOwnProperty('disabled')) {
                this._disableSkillSwitch = disableSkillSwitchingJson.disabled;

                if(!this._disableSkillSwitch && this._errorPriorityQueue.peek() !== null) {
                    this._launchErrorSkill();
                }

                this.sendJson(res, { status: 'OK' });
            } else {
                this.sendJson(res, { status: 'error', message: 'disabled property does not exist on json object' }, 500);
            }
        });
    }

    private _getCurrentErrorId(req:JiboServerRequest, res:JiboServerResponse): void {
        this._currentError = this._errorPriorityQueue.peek();
        let currentErrorId = ((this._currentError !== null) ? this._currentError.id : null);
        this.sendJson(res, { status: 'OK', currentErrorId: currentErrorId });
    }

    // reply to routes endpoint with all active priority queue errors and rescheduler errors
    private _getContents(req:JiboServerRequest, res:JiboServerResponse): void {
        let array = [];
        for(let i = 0; i < this._errorPriorityQueue.length; ++i) {
            array.push(this._errorPriorityQueue.getIndex(i));
        }
        let priorityQueueArrayJSON = JSON.stringify(array);
        let reschedulerArrayJSON = JSON.stringify(this._errorRescheduler.toArray());
        this.sendJson(res, {
            status: 'OK',
            priorityQueueErrors: priorityQueueArrayJSON,
            reschedulerErrors: reschedulerArrayJSON
        });
    }

    private _processedError(req:JiboServerRequest, res:JiboServerResponse): void {
        this.parseBody(req, (err, processedErrorJson) => {
            if (err) {
                return this.sendJson(res, { status: 'error', message: typeof err === 'string' ? err : err.message }, 500);
            }
            if(processedErrorJson.hasOwnProperty('errorCode')) {
                const processedErrorCode = processedErrorJson.errorCode;
                let successfullyProcessedError = false;
                if(this._currentError &&
                    this._currentError.id === processedErrorCode &&
                    this._currentError.dismissible
                ) {
                    successfullyProcessedError = true;
                    const processedError = this._errorPriorityQueue.peek();
                    // all processed errors automatically get added to the rescheduler
                    // we should add the error to the rescheduler before removing from the priority queue
                    // in order for reporting accurately whether the error is resolved.  if we remove the error from the priority queue
                    // first then we fire the subscription callback and the error is marked as resolved because
                    // the error neither exists in the rescheduler or in the priority queue
                    this._errorRescheduler.add(processedError, (error)=>{
                        this.addError(error.id);
                    });
                    // only remove the most relevant error if we've processed the correct error
                    this._errorPriorityQueue.shift();
                }
                this.sendJson(res, { status: 'OK', processedError: successfullyProcessedError });
            } else {
                this.sendJson(res, { status: 'error', message: 'Client did not send errorCode' }, 500);
            }
        });
    }

    private _subscribeError(req:JiboServerRequest, res:JiboServerResponse): void {
        // this disables the timeout for subsribing to an error. this is necessary in the case where it takes
        // the user a long time to resolve an error. we don't want to force a failed request and trigger a faulty callback firing
        req.socket.setTimeout(0);
        this.parseBody(req, (err, subscribeErrorJson) => {
            if (err) {
                return this.sendJson(res, { status: 'error', message: typeof err === 'string' ? err : err.message }, 500);
            }
            if(subscribeErrorJson.hasOwnProperty('errorCode')) {
                const subscribedErrorCode = subscribeErrorJson.errorCode;
                if(this._errorCodeMap.hasOwnProperty(subscribedErrorCode)) {
                    this._subscribedErrorObject = this._errorCodeMap[subscribedErrorCode];
                    this._errorSubscribeCallback = ()=>{
                        // if the error we subscribed to is not in the priority queue AND it's not in the rescheduler
                        // that means it has already been resolved
                        const resolved = (!this._errorPriorityQueue.contains(this._subscribedErrorObject) &&
                                        !this._errorRescheduler.contains(this._subscribedErrorObject.id));
                        const subscribedErrorId = this._subscribedErrorObject.id;

                        const nextErrorId = ((this._currentError !== null) ? this._currentError.id : null);
                        this._errorSubscribeCallback = null;
                        this._subscribedErrorObject = null;
                        this.sendJson(res, {
                            status: 'OK',
                            nextErrorId: nextErrorId,
                            subscribedErrorId: subscribedErrorId,
                            resolved: resolved
                        });
                    };
                    // if the error we subscribe to is not the current error we should fire the callback immediately
                    if(!this._currentError ||
                        JiboError.Comparer(this._currentError, this._subscribedErrorObject) !== 0) {
                        this._errorSubscribeCallback();
                    }
                } else {
                    this.sendJson(res, { status: 'error', message: `Error code ${subscribedErrorCode} is not a valid error code` }, 500);
                }
            } else {
                this.sendJson(res, { status: 'error', message: 'Client did not send errorCode' }, 500);
            }
        });
    }

    private _getErrorCount(req:JiboServerRequest, res:JiboServerResponse): void {
        this.sendJson(res,
            {
                status: 'OK',
                errorCount: this._errorPriorityQueue.length
            }
        );
    }

    // a method to handle mock errors from the error service debug page
    // this routes the errors to the debugErrorReporter
    private _mockErrorCodes(req:JiboServerRequest, res:JiboServerResponse):void {
        this.parseBody(req, (err, mockErrorsJson) => {
            if (err) {
                return this.sendJson(res, { status: 'error', message: typeof err === 'string' ? err : err.message }, 500);
            }
            // always enable the debug errors when running on the simulator
            if(RunMode.runMode === RunMode.RunMode.SIMULATOR) {
                this._mockErrorsEnabled = true;
            } else {
                this._mockErrorsEnabled = mockErrorsJson.enabled;
            }
            this._debugErrorReporter.mockErrorRequest(mockErrorsJson);
            this.sendJson(res, { status: 'OK' });
        });
    }

    // send the full data json structure for all errors
    private _sendErrorCodeData(req:JiboServerRequest, res:JiboServerResponse): void {
        if(this._errorCodeMap) {
            this.sendJson(res,
                {
                    status: 'OK',
                    errorList: this._errorCodeMap
                }
            );
        } else {
            this.sendJson(res, { status: 'error', message: 'error codes in KB not found' }, 500);
        }
    }

    private _onSocketError(error:Error):void {
        log.error("system-monitoring/error/codes socket error", error);
    }

    // the callback which we receive errors from the error service debug page
    private _receivedMockErrors(message:any) {
        // only send errors if we've enabled debug errors on the error service page
        if(this._mockErrorsEnabled) {
            this._receivedPlatformErrors(message);
        }
    }

    // the callback which we receive errors from the system monitoring service
    private _receivedSystemMonitoringServiceErrors(message:any) {
        // only send errors if we've disabled debug errors from coming through on the error service page
        if(!this._mockErrorsEnabled) {
            this._receivedPlatformErrors(message);
        }
    }

    // receive errors from the platform layer
    private _receivedPlatformErrors(message:any) {
        let newPlatformIdToError:{ [key:string]:JiboError; } = {};

        if(message.codes && this._platformErrorCodeMap && this._errorCodeMap) {
            // log.debug("error status", message.codes);
            // translate the incoming errors into objects to add
            // at the point where this class has a public API to add errors, we should keep a separate list of active errors reported internally from the SSM
            // then merge that list with the current list of errors here.  otherwise calling the updateElements method will delete errors being reported from the SSM
            for(let i = 0; i < message.codes.length; ++i) {
                let platformErrorCode = message.codes[i];
                if(this._platformErrorCodeMap.hasOwnProperty(platformErrorCode)){
                    let supportErrorCode = this._platformErrorCodeMap[platformErrorCode];
                    if(this._errorCodeMap.hasOwnProperty(supportErrorCode)){
                        let errorCodeObject = this._errorCodeMap[supportErrorCode];
                        if(errorCodeObject && errorCodeObject.platformCode) {
                            newPlatformIdToError[message.codes[i]] = errorCodeObject;
                        }
                    }
                }
            }

            // if there are no message.codes, nothing can be added. only do the operation if there is content in the messsage.codes
            let addedErrors = ErrorServiceUtil.getNonOccurringElements(newPlatformIdToError, this._lastErrors);
            this._errorLogger.addErrors(addedErrors);
            for(let error of addedErrors) {
                this._errorAddedEmitter.emit(error.id);
            }

            // remove any added errors which are present in the rescheduler.  these will re-add themselves to the priority queue when their time is up
            addedErrors = addedErrors.filter((addedError: JiboError)=>{
                return !this._errorRescheduler.contains(addedError.id) && addedError.priority !== -1;
            });
            this._errorPriorityQueue.add(addedErrors);
        }

        // if there are no keys, nothing can be removed. only do the operation if there is content in the last frame errors
        if(Object.keys(this._lastErrors)) {
            // remove error codes from the priority queue if they are no longer being reported by the platform service
            let removedErrors = ErrorServiceUtil.getNonOccurringElements(this._lastErrors, newPlatformIdToError);
            this._errorPriorityQueue.delete(removedErrors);

            this._errorLogger.removeErrors(removedErrors);
            for(let error of removedErrors) {
                this._errorRemovedEmitter.emit(error.id);
            }

            // remove it from the rescheduler in case any errors are waiting to be rescheduled
            this._errorRescheduler.remove(removedErrors);
        }

        this._lastErrors = newPlatformIdToError;
    }

    // a callback which is called when an error(s) is successfully added to the error priority queue
    private _errorsAdded(errors: Array<JiboError>): void {
        let lastCurrentError = this._currentError;
        this._currentError = this._errorPriorityQueue.peek();

        // resolve any already subscribed error if it is not the current error with the new error information
        if(this._subscribedErrorObject && this._errorSubscribeCallback &&
            (!this._currentError || JiboError.Comparer(this._currentError, this._subscribedErrorObject) !== 0)) {
                this._errorSubscribeCallback();
        }
        // otherwise, if there is a new current error, we should launch into the error skill
        else if(this._currentError && this._currentError !== lastCurrentError){
            this._launchErrorSkill();
        }
    }

    // a callback which is called when an error(s) is successfully removed from the error priority queue
    private _errorsRemoved(errors: Array<JiboError>): void {
        this._currentError = this._errorPriorityQueue.peek();

        // if we've removed (resolved) an error that someone has subscribed to, fire the callback
        if(this._subscribedErrorObject && this._errorSubscribeCallback) {
            // search to see if the error we've subscribed to is present in the array of removed errors
            let didRemoveSubscribedError = errors.find((error)=>{ return JiboError.Comparer(error, this._subscribedErrorObject) === 0; });
            if(didRemoveSubscribedError) {
                this._errorSubscribeCallback();
            }
        }
    }

    // construct an object to trigger a skill relaunch into the Be/Settings error skill with a payload
    // of the highest priority error id
    private _launchErrorSkill(): void {
        const parseResults = new types.ListenResult({
            text: '',
            confidence: 1
        }, {
            intent: 'launch',
            entities: {
                skill: '@be/settings',
                errorId: this._currentError.id
            },
            rules: null
        });
        parseResults.match = {
            skillID: '@be/settings',
            onRobot: true
        };
        if(!this._disableSkillSwitch) {
            // send to GMS to handle skill launching with parse results.
            GlobalManagerService.instance.handleSkillLaunch(parseResults);
        }
    }
}

export default ErrorService;
