// a class to keep track of errors which we want to log but not bubble up to the user
// this class provides an api to add / remove errors and only log the error for a unique instance of the error
// unique error instances count as an add and remove operation.  simultaneous multiple adds or multiple removes do not result in additional logs

import {Log} from 'jibo-log';
import JiboError from './JiboError';

class ErrorLogger {
    private _log:Log = null;
    // a map of errors from id string to JiboError object which we're keeping track of for log only
    private _errorMap: { [key:string]:JiboError; } = {};

    /**
     * @param log {Log} the logger to use when an error gets added or removed
     */
    constructor(log:Log) {
        this._log = log;
    }

    /**
     * @param errors {Array<JiboError>} an array of errors to add. only unique errors are added
     * @return {boolean} true if any of the errors in the array are added, false otherwise
     */
    public addErrors(errors:Array<JiboError>): boolean {
        let addedError = false;
        for(let i = 0; i < errors.length; ++i) {
            // return true if we've added at least one error
            addedError = this.addError(errors[i]) || addedError;
        }

        return addedError;
    }

    /**
     * @param error {JiboError} the error to add. it will only be added if it has not already been added or had been previously removed
     * @return {boolean} true if the error was successfully added, false otherwise
     */
    public addError(error:JiboError): boolean {
        if(!this._errorMap.hasOwnProperty(error.id)) {
            this._errorMap[error.id] = error;
            this._log.info("Added", error.id);
            return true;
        }

        return false;
    }

    /**
     * @param errors {Array<JiboError>} an array of errors to remove
     * @return {boolean} true if any of the errors in the array have been removed, false otherwise
     */
    public removeErrors(errors:Array<JiboError>): boolean {
        let removedError = false;
        for(let i = 0; i < errors.length; ++i) {
            // return true if we've removed at least one error
            removedError = this.removeError(errors[i]) || removedError;
        }

        return removedError;
    }

    /**
     * @param error {JiboError} the error to remove.
     * @return {boolean} true if the error was successfully removed (if it was present in the first place), false otherwise
     */
    public removeError(error:JiboError): boolean {
        if(this._errorMap.hasOwnProperty(error.id)) {
            delete this._errorMap[error.id];
            this._log.info("Removed", error.id);
            return true;
        }

        return false;
    }

    /**
     * @param error {JiboError} the error to search for
     * @return {boolean} true if the error is currently registered. false otherwise
     */
    public contains(error:JiboError): boolean {
        return this._errorMap.hasOwnProperty(error.id);
    }
}

export default ErrorLogger;
