import BackgroundUtilsManager from '../../utils/BackgroundUtilsManager';
import BodyClient from '../../clients/BodyClient';
import parentLog from '../log';

const TIME_TO_BLANK: number = 1000 * 5 * 60; // 5 minutes

const log = parentLog.createChild('ScreenScheduler');

export default class ScreenScheduler {

    private static _timeoutId: NodeJS.Timer;
    private static _started: boolean = false;

    public static start(restartOnly = false) {
        //if we shouldn't override the started state, but just want to restart the timer, then
        //see if we should bail
        if (restartOnly && !ScreenScheduler._started) {
            return;
        }
        log.info('starting screen timeout timer');
        ScreenScheduler._started = true;
        clearTimeout(ScreenScheduler._timeoutId);
        ScreenScheduler._timeoutId = setTimeout(() => {
            log.info('Screen timed out - turning off');
            BodyClient.instance.setScreen('off');
            ScreenScheduler._headTouchOn();
        }, TIME_TO_BLANK);
    }

    public static async stopTimerAndTurnOn() {
        ScreenScheduler._started = false;
        clearTimeout(ScreenScheduler._timeoutId);
        ScreenScheduler._headTouchOff();
        await BodyClient.instance.setScreen('on');
    }

    private static _headTouchOn() {
        BodyClient.instance.removeListener('touched', ScreenScheduler._onHeadTouched);
        BodyClient.instance.once('touched', ScreenScheduler._onHeadTouched);
    }

    private static _headTouchOff() {
        BodyClient.instance.removeListener('touched', ScreenScheduler._onHeadTouched);
    }

    private static async _onHeadTouched():Promise<void> {
        log.info('onHeadTouched - turning screen on');
        // This async process takes about a full second. Meanwhile, it's
        // possible that a skill start may call stopTimerAndTurnOn
        await BodyClient.instance.setScreen('on');
        // Don't restart the timer if stopTimerAndTurnOn was called - this
        // prevents a rare race condition where Jibo's head is touched just
        // after a skill starts, resulting in Jibo's face turning off while
        // running Be
        if (ScreenScheduler._started) {
            // headTouchOff was already called if _started isn't true
            ScreenScheduler._headTouchOff();
            ScreenScheduler.start();
        }
    }
}

BackgroundUtilsManager.register((mode: string, startSkill: string) => {
    // if we're in developer or int-developer mode, and there's no start skill
    // defined (or its length is zero)
    if(mode && mode.indexOf('developer') > -1 && !startSkill) {
        ScreenScheduler.start();
    }
}, 'screen');
